def source_matches_bounce_target(source: str, target: str) -> bool:
    if target in {"tapped_creature", "untapped_creature"}:
        return source_matches_target_constraint(source, target)
    text = source or ""
    if target == "creature":
        return (
            "TargetCreaturePermanent" in text
            or "TargetOpponentsCreaturePermanent" in text
            or "FilterCreaturePermanent" in text
            or "FILTER_PERMANENT_CREATURE" in text
            or "FILTER_OPPONENTS_PERMANENT_CREATURE" in text
            or "FILTER_ANOTHER_CREATURE" in text
            or "FILTER_ANOTHER_TARGET_CREATURE" in text
        )
    if target == "non_spirit_creature":
        return (
            "FilterCreaturePermanent" in text
            and ("SubType.SPIRIT" in text or "non-Spirit creature" in text)
        )
    if target == "nonland_permanent":
        return "TargetNonlandPermanent" in text or "FilterNonlandPermanent" in text or "nonland permanent" in text
    if target == "historic_permanent":
        return "HistoricPredicate" in text and (
            "TargetPermanent" in text
            or "TargetControlledPermanent" in text
            or "FilterPermanent" in text
            or "FilterControlledPermanent" in text
        )
    if target == "permanent":
        return (
            "TargetPermanent" in text
            or "TargetControlledPermanent" in text
            or "FilterPermanent" in text
            or "FilterControlledPermanent" in text
        )
    if target == "artifact":
        return "TargetArtifactPermanent" in text or "FilterArtifactPermanent" in text or "artifact" in text
    if target == "enchantment":
        return "TargetEnchantmentPermanent" in text or "FilterEnchantmentPermanent" in text or "enchantment" in text
    if target == "creature_or_enchantment":
        return (
            ("CardType.CREATURE" in text and "CardType.ENCHANTMENT" in text)
            or "creature or enchantment" in text
            or source_matches_target_constraint(source, target)
        )
    if target == "land":
        return "TargetLandPermanent" in text or "FilterLandPermanent" in text or "land" in text
    return source_matches_target_constraint(source, target)


def source_matches_bounce_target_controller(source: str, target_controller: str) -> bool:
    text = source or ""
    controller = str(target_controller or "any").lower()
    if controller in {"", "any", "all"}:
        return True
    if controller in {"self", "you", "controller", "controlled"}:
        return (
            "TargetControlledPermanent" in text
            or "TargetControlledCreaturePermanent" in text
            or "FilterControlledPermanent" in text
            or "FILTER_CONTROLLED" in text
            or "you control" in text
        )
    if controller in {"opponent", "opponents"}:
        return (
            "TargetOpponentsCreaturePermanent" in text
            or "FILTER_OPPONENTS" in text
            or "TargetController.OPPONENT" in text
            or "opponent controls" in text
        )
    return False


def etb_bounce_target_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = strip_parenthetical_reminders(oracle_text_after_leading_static_keywords(metadata))
    text = re.sub(r"\s+", " ", text).strip()
    text = re.sub(r"^[a-z0-9' -]+\s+[—-]\s+", "", text)
    etb_subject = r"(?:this creature|.+?)"
    if not re.match(rf"^when {etb_subject} enters(?: the battlefield)?, ", text):
        return None
    optional = " you may return " in text
    up_to_one = " return up to one " in text
    target_controller = "any"
    if " you control " in text:
        target_controller = "self"
    elif " opponent controls" in text or " opponents control" in text:
        target_controller = "opponent"
    target_patterns: list[tuple[str, str, str]] = [
        ("tapped_creature", "remove_creature", r"target tapped creature(?: an opponent controls| you control)?"),
        ("untapped_creature", "remove_creature", r"target untapped creature(?: an opponent controls| you control)?"),
        ("non_spirit_creature", "remove_creature", r"target non-spirit creature(?: an opponent controls| you control)?"),
        ("historic_permanent", "remove_permanent", r"target historic permanent(?: an opponent controls| you control)?"),
        ("nonland_permanent", "remove_permanent", r"target nonland permanent(?: an opponent controls| you control)?"),
        ("artifact_or_enchantment", "remove_permanent", r"target artifact or enchantment(?: an opponent controls| you control)?"),
        ("creature_or_enchantment", "remove_permanent", r"target creature or enchantment(?: an opponent controls| you control)?"),
        ("creature_or_planeswalker", "remove_permanent", r"target creature or planeswalker(?: an opponent controls| you control)?"),
        ("permanent", "remove_permanent", r"target permanent(?: an opponent controls| you control)?"),
        ("creature", "remove_creature", r"target creature(?: an opponent controls| you control)?"),
        ("artifact", "remove_permanent", r"target artifact(?: an opponent controls| you control)?"),
        ("enchantment", "remove_permanent", r"target enchantment(?: an opponent controls| you control)?"),
        ("land", "remove_permanent", r"target land(?: an opponent controls| you control)?"),
    ]
    for target, effect, target_phrase in target_patterns:
        pattern = (
            rf"^when {etb_subject} enters(?: the battlefield)?, "
            rf"(?:you may )?return (?:up to one )?(?:(?:other|another) )?{target_phrase} "
            rf"to (?:its|their) owner's hand\.?$"
        )
        if not re.match(pattern, text):
            continue
        result: dict[str, Any] = {
            "effect": effect,
            "target": target,
            "target_controller": target_controller,
            "optional": optional,
            "up_to_one": up_to_one,
            "exclude_source": " other target " in text or " another target " in text,
        }
        return result
    return None


def etb_bounce_source_supported(source: str, oracle_spec: dict[str, Any]) -> str | None:
    text = source or ""
    if len(re.findall(r"new\s+ReturnToHandTargetEffect\s*\(", text)) != 1:
        return "etb_bounce_source_effect_count_not_supported"
    if "TargetPointer" in text or ".setTargetPointer" in text or "TargetAdjuster" in text:
        return "etb_bounce_source_multi_target_not_supported"
    if ".withInterveningIf" in text or "InterveningIf" in text:
        return "etb_bounce_source_condition_not_supported"
    if oracle_spec.get("target_controller") == "self" and not oracle_spec.get("exclude_source"):
        return "etb_bounce_self_without_exclude_source_not_supported"
    target = str(oracle_spec.get("target") or "")
    if not source_matches_bounce_target(text, target):
        return "etb_bounce_source_target_not_supported"
    if oracle_spec.get("up_to_one") and not re.search(r"\(\s*0\s*,\s*1\b", text):
        return "etb_bounce_source_up_to_count_mismatch"
    if oracle_spec.get("target_controller") == "opponent" and not (
        "TargetOpponentsCreaturePermanent" in text
        or "FILTER_OPPONENTS_PERMANENT_CREATURE" in text
        or "TargetController.OPPONENT" in text
        or "opponent controls" in text
    ):
        return "etb_bounce_source_controller_mismatch"
    if oracle_spec.get("target_controller") == "self" and not (
        "TargetControlledPermanent" in text
        or "FilterControlledPermanent" in text
        or "FILTER_ANOTHER_TARGET_CREATURE_YOU_CONTROL" in text
        or "you control" in text
    ):
        return "etb_bounce_source_controller_mismatch"
    return None


def exile_target_from_oracle(metadata: dict[str, Any]) -> tuple[str, str] | None:
    text = primary_removal_action_text(metadata, "exile")
    restricted = restricted_battlefield_target_from_oracle(metadata, "exile")
    if restricted is not None:
        return ("remove_creature" if restricted_target_base(restricted) == "creature" else "remove_permanent"), restricted
    patterns: list[tuple[str, tuple[str, str]]] = [
        (r"^exile target artifact or enchantment\.?$", ("remove_permanent", "artifact_or_enchantment")),
        (r"^exile target creature or planeswalker\.?$", ("remove_permanent", "creature_or_planeswalker")),
        (r"^exile target creature or enchantment\.?$", ("remove_permanent", "creature_or_enchantment")),
        (r"^exile target nonland permanent\.?$", ("remove_permanent", "nonland_permanent")),
        (r"^exile target permanent\.?$", ("remove_permanent", "permanent")),
        (r"^exile target creature\.?$", ("remove_creature", "creature")),
        (r"^exile target artifact\.?$", ("remove_permanent", "artifact")),
        (r"^exile target enchantment\.?$", ("remove_permanent", "enchantment")),
        (r"^exile target land\.?$", ("remove_permanent", "land")),
    ]
    for pattern, result in patterns:
        if re.match(pattern, text):
            return result
    return None


def bounce_target_from_oracle(metadata: dict[str, Any]) -> tuple[str, str, str] | None:
    text = re.sub(
        r"\s+",
        " ",
        " ".join(oracle_effect_lines_without_neutral_auxiliary(metadata)).strip().lower(),
    )
    target_controller = "any"
    controller_rewrites = [
        (r"\s+you control to ", "self"),
        (r"\s+an opponent controls to ", "opponent"),
        (r"\s+opponents control to ", "opponent"),
    ]
    for pattern, controller in controller_rewrites:
        if re.search(pattern, text):
            text = re.sub(pattern, " to ", text)
            target_controller = controller
            break
    patterns: list[tuple[str, tuple[str, str]]] = [
        (r"^return target tapped creature to its owner's hand\.?$", ("remove_creature", "tapped_creature")),
        (r"^return target untapped creature to its owner's hand\.?$", ("remove_creature", "untapped_creature")),
        (
            r"^return target creature or vehicle to its owner's hand\.?$",
            ("remove_permanent", "creature_or_vehicle"),
        ),
        (
            r"^return target enchanted permanent to its owner's hand\.?$",
            ("remove_permanent", "enchanted_permanent"),
        ),
        (
            r"^return target artifact, enchantment, or land to its owner's hand\.?$",
            ("remove_permanent", "artifact_or_enchantment_or_land"),
        ),
        (
            r"^return target artifact or enchantment to its owner's hand\.?$",
            ("remove_permanent", "artifact_or_enchantment"),
        ),
        (
            r"^return target creature or enchantment to its owner's hand\.?$",
            ("remove_permanent", "creature_or_enchantment"),
        ),
        (
            r"^return target creature or planeswalker to its owner's hand\.?$",
            ("remove_permanent", "creature_or_planeswalker"),
        ),
        (
            r"^return target nonland permanent to its owner's hand\.?$",
            ("remove_permanent", "nonland_permanent"),
        ),
        (r"^return target permanent to its owner's hand\.?$", ("remove_permanent", "permanent")),
        (r"^return target creature to its owner's hand\.?$", ("remove_creature", "creature")),
        (r"^return target artifact to its owner's hand\.?$", ("remove_permanent", "artifact")),
        (r"^return target enchantment to its owner's hand\.?$", ("remove_permanent", "enchantment")),
        (r"^return target land to its owner's hand\.?$", ("remove_permanent", "land")),
    ]
    for pattern, result in patterns:
        if re.match(pattern, text):
            effect, target = result
            return effect, target, target_controller
    return None


def removal_multi_target_oracle_text(metadata: dict[str, Any], action: str) -> str:
    if action in {"destroy", "exile"}:
        return primary_removal_action_text(metadata, action)
    return re.sub(
        r"\s+",
        " ",
        " ".join(oracle_effect_lines_without_neutral_auxiliary(metadata)).strip().lower(),
    )


def removal_multi_target_from_phrase(phrase: str) -> tuple[str, str] | None:
    normalized = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    normalized = normalized.removesuffix(".")
    normalized = normalized.replace(" and/or ", " or ")
    normalized = normalized.replace(", and/or ", " or ")
    mapping = {
        "creature": ("remove_creature", "creature"),
        "creatures": ("remove_creature", "creature"),
        "artifact": ("remove_permanent", "artifact"),
        "artifacts": ("remove_permanent", "artifact"),
        "enchantment": ("remove_permanent", "enchantment"),
        "enchantments": ("remove_permanent", "enchantment"),
        "land": ("remove_permanent", "land"),
        "lands": ("remove_permanent", "land"),
        "permanent": ("remove_permanent", "permanent"),
        "permanents": ("remove_permanent", "permanent"),
        "nonland permanent": ("remove_permanent", "nonland_permanent"),
        "nonland permanents": ("remove_permanent", "nonland_permanent"),
        "artifact or enchantment": ("remove_permanent", "artifact_or_enchantment"),
        "artifacts or enchantments": ("remove_permanent", "artifact_or_enchantment"),
        "creature or enchantment": ("remove_permanent", "creature_or_enchantment"),
        "creatures or enchantments": ("remove_permanent", "creature_or_enchantment"),
    }
    return mapping.get(normalized)


def fixed_multi_target_removal_from_oracle(
    metadata: dict[str, Any],
    action: str,
) -> dict[str, Any] | None:
    text = removal_multi_target_oracle_text(metadata, action)
    count_token = r"one|two|three|four|five|six|seven|eight|nine|ten|\d+"
    if action == "return":
        pattern = (
            rf"^return (?P<upto>up to )?(?P<count>{count_token}) target "
            rf"(?P<phrase>.+?) to their owners' hands?\.?$"
        )
        destination = "hand"
    elif action == "destroy":
        pattern = rf"^destroy (?P<upto>up to )?(?P<count>{count_token}) target (?P<phrase>.+?)\.?$"
        destination = "graveyard"
    elif action == "exile":
        pattern = rf"^exile (?P<upto>up to )?(?P<count>{count_token}) target (?P<phrase>.+?)\.?$"
        destination = "exile"
    else:
        return None
    match = re.match(pattern, text)
    if not match:
        return None
    count = word_count_value(match.group("count"))
    if count is None or count <= 1:
        return None
    mapped = removal_multi_target_from_phrase(match.group("phrase"))
    if mapped is None:
        return None
    effect, target = mapped
    up_to = bool(match.group("upto"))
    return {
        "effect": effect,
        "target": target,
        "count": int(count),
        "target_count_min": 0 if up_to else int(count),
        "target_count_max": int(count),
        "up_to_count": up_to,
        "destination": destination,
    }


def fixed_multi_target_count_from_source(source_text: str) -> dict[str, Any] | str | None:
    text = str(source_text or "")
    if "XTargetsCountAdjuster" in text or "GetXValue" in text or "ManacostVariableValue" in text:
        return "multi_target_source_x_count_not_supported"
    if "TargetPointer" in text or ".setTargetPointer" in text:
        return "multi_target_source_target_pointer_not_supported"
    target_matches = list(
        re.finditer(
            r"new\s+(?P<class>Target(?:Creature|Artifact|Enchantment|Land)?Permanent|TargetNonlandPermanent)\s*\(",
            text,
        )
    )
    if len(target_matches) != 1:
        return "multi_target_source_target_constructor_not_single"
    constructor = target_matches[0].group("class")
    args = extract_constructor_args(text[target_matches[0].start() :], constructor)
    if args is None:
        return "multi_target_source_target_constructor_not_supported"
    parts = split_top_level_args(args)
    numeric_parts = [int(part) for part in parts[:2] if re.fullmatch(r"\d+", str(part or "").strip())]
    if not numeric_parts:
        return None
    if len(numeric_parts) >= 2:
        target_min, target_max = numeric_parts[0], numeric_parts[1]
    else:
        target_min = target_max = numeric_parts[0]
    if target_max <= 1:
        return None
    return {
        "target_count_min": int(target_min),
        "target_count_max": int(target_max),
        "up_to_count": int(target_min) == 0,
    }


def counter_target_from_oracle(metadata: dict[str, Any]) -> str | None:
    text = re.sub(
        r"\s+",
        " ",
        " ".join(oracle_effect_lines_without_neutral_auxiliary(metadata)),
    ).strip().lower()
    change_equation_text = (
        "choose one — • counter target spell with mana value 2 or less. "
        "• counter target red or green spell with mana value 6 or less."
    )
    if text == change_equation_text:
        return "spell_mana_value_2_or_less_or_red_green_spell_mana_value_6_or_less"
    if text == "counter target spell with mana value x.":
        return "spell_mana_value_x"
    mana_value_patterns: list[tuple[str, str]] = [
        (
            r"^counter target creature spell with mana value (?P<value>\d+) or less\.?$",
            "creature_spell_mana_value_{value}_or_less",
        ),
        (r"^counter target spell with mana value (?P<value>\d+) or greater\.?$", "spell_mana_value_{value}_or_greater"),
        (r"^counter target spell with mana value (?P<value>\d+) or less\.?$", "spell_mana_value_{value}_or_less"),
        (r"^counter target spell with mana value (?P<value>\d+)\.?$", "spell_mana_value_{value}"),
        (
            r"^counter target creature spell with power or toughness (?P<value>\d+) or less\.?$",
            "creature_spell_power_or_toughness_{value}_or_less",
        ),
    ]
    for pattern, target_template in mana_value_patterns:
        match = re.match(pattern, text)
        if match:
            return target_template.format(value=int(match.group("value")))
    patterns: list[tuple[str, str]] = [
        (
            r"^counter target spell, activated ability, or triggered ability\.?$",
            "spell_or_activated_or_triggered_ability",
        ),
        (
            r"^counter target activated ability, triggered ability, or legendary spell\.?$",
            "activated_or_triggered_ability_or_legendary_spell",
        ),
        (r"^counter target red or green spell\.?$", "red_or_green_spell"),
        (r"^counter target blue instant spell\.?$", "blue_instant_spell"),
        (r"^counter target creature or sorcery spell\.?$", "creature_or_sorcery_spell"),
        (r"^counter target creature or aura spell\.?$", "creature_or_aura_spell"),
        (r"^counter target spirit or arcane spell\.?$", "spirit_or_arcane_spell"),
        (r"^counter target artifact or creature spell\.?$", "artifact_or_creature_spell"),
        (r"^counter target creature or planeswalker spell\.?$", "creature_or_planeswalker_spell"),
        (r"^counter target creature or enchantment spell\.?$", "creature_or_enchantment_spell"),
        (r"^counter target artifact or enchantment spell\.?$", "artifact_or_enchantment_spell"),
        (r"^counter target instant or sorcery spell\.?$", "instant_or_sorcery_spell"),
        (r"^counter target spell that targets one or more creatures\.?$", "spell_targeting_creature"),
        (r"^counter target spell that targets a creature\.?$", "spell_targeting_creature"),
        (
            r"^counter target spell that targets you or a permanent you control\.?$",
            "spell_targeting_you_or_permanent_you_control",
        ),
        (
            r"^counter target spell that targets a permanent you control\.?$",
            "spell_targeting_permanent_you_control",
        ),
        (
            r"^counter target instant or aura spell that targets a permanent you control\.?$",
            "instant_or_aura_spell_targeting_permanent_you_control",
        ),
        (r"^counter target spell that targets a player\.?$", "spell_targeting_player"),
        (r"^counter target spell that's the second spell cast this turn\.?$", "spell_second_spell_this_turn"),
        (r"^counter target spell cast from a graveyard\.?$", "spell_cast_from_graveyard"),
        (r"^counter up to two target spells\.?$", "spell"),
        (r"^counter target noncreature spell\.?$", "noncreature_spell"),
        (r"^counter target nonartifact spell\.?$", "nonartifact_spell"),
        (r"^counter target non-faerie spell\.?$", "nonfaerie_spell"),
        (r"^counter target colorless spell\.?$", "colorless_spell"),
        (r"^counter target nonblue spell\.?$", "nonblue_spell"),
        (r"^counter target multicolored spell\.?$", "multicolored_spell"),
        (r"^counter target creature spell\.?$", "creature_spell"),
        (r"^counter target artifact spell\.?$", "artifact_spell"),
        (r"^counter target enchantment spell\.?$", "enchantment_spell"),
        (r"^counter target instant spell\.?$", "instant_spell"),
        (r"^counter target sorcery spell\.?$", "sorcery_spell"),
        (r"^counter target blue spell\.?$", "blue_spell"),
        (r"^counter target white spell\.?$", "white_spell"),
        (r"^counter target black spell\.?$", "black_spell"),
        (r"^counter target red spell\.?$", "red_spell"),
        (r"^counter target green spell\.?$", "green_spell"),
        (r"^counter target spell\.?$", "spell"),
    ]
    for pattern, target in patterns:
        if re.match(pattern, text):
            return target
    return None


def counter_draw_target_from_oracle(metadata: dict[str, Any]) -> str | None:
    text = oracle_text(metadata)
    if not text.endswith(" draw a card."):
        return None
    return counter_target_from_oracle({"oracle_text": text.removesuffix(" draw a card.").strip()})


def counter_target_count_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = re.sub(r"\s+", " ", strip_parenthetical_reminders(oracle_text(metadata))).strip().lower()
    match = re.match(r"^counter up to (?P<count>\w+) target spells\.?$", text)
    if not match:
        return None
    count = counter_count_from_text(match.group("count"))
    if count is None or count <= 1:
        return None
    return {
        "target_count_min": 0,
        "target_count_max": int(count),
        "up_to_count": True,
    }


def counter_target_count_from_source(source_text: str) -> dict[str, Any] | str | None:
    text = str(source_text or "")
    target_matches = list(re.finditer(r"new\s+TargetSpell\s*\(", text))
    if len(target_matches) != 1:
        return "counter_multi_target_source_target_constructor_not_single"
    args = extract_constructor_args(text[target_matches[0].start() :], "TargetSpell")
    if args is None:
        return "counter_multi_target_source_target_constructor_not_supported"
    parts = split_top_level_args(args)
    numeric_parts = [
        int(str(part).strip())
        for part in parts[:2]
        if re.fullmatch(r"\d+", str(part or "").strip())
    ]
    if not numeric_parts:
        return None
    if len(numeric_parts) >= 2:
        target_min, target_max = numeric_parts[0], numeric_parts[1]
    else:
        target_min = target_max = numeric_parts[0]
    if target_max <= 1:
        return None
    return {
        "target_count_min": int(target_min),
        "target_count_max": int(target_max),
        "up_to_count": int(target_min) == 0,
    }


def fixed_counter_scry_from_oracle(metadata: dict[str, Any]) -> tuple[str, int] | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    text = re.sub(r"\s+", " ", text).strip()
    match = re.match(r"^(?P<counter>counter target .+?)\. scry (?P<scry>\d+)\.?$", text)
    if not match:
        return None
    target = counter_target_from_oracle({"oracle_text": match.group("counter")})
    if target is None:
        return None
    return target, int(match.group("scry"))


def fixed_counter_scry_from_source(source_text: str) -> tuple[str, int] | None:
    text = str(source_text or "")
    counter_matches = list(re.finditer(r"new\s+CounterTargetEffect\s*\(", text))
    scry_match = fixed_scry_count_match_from_source(text)
    if len(counter_matches) != 1 or scry_match is None:
        return None
    scry_count, scry_index = scry_match
    if counter_matches[0].start() > scry_index:
        return None
    if not re.search(r"new\s+TargetSpell\s*\(\s*\)", text):
        return None
    return "spell", scry_count


def fixed_counter_gain_life_from_oracle(metadata: dict[str, Any]) -> tuple[str, int] | None:
    text = oracle_text(metadata)
    match = re.match(r"^(?P<counter>counter target .+?)\. you gain (?P<life>\d+) life\.?$", text)
    if not match:
        return None
    target = counter_target_from_oracle({"oracle_text": match.group("counter")})
    if target is None:
        return None
    return target, int(match.group("life"))


def fixed_counter_gain_life_from_source(source_text: str) -> tuple[int, str] | None:
    text = str(source_text or "")
    counter_matches = list(re.finditer(r"new\s+CounterTargetEffect\s*\(", text))
    gain_matches = list(re.finditer(r"new\s+GainLifeEffect\s*\(", text))
    if len(counter_matches) != 1 or len(gain_matches) != 1:
        return None
    if counter_matches[0].start() > gain_matches[0].start():
        return None
    life_gain = java_constructor_int(text, "GainLifeEffect")
    if life_gain is None or life_gain <= 0:
        return None
    if "new TargetSpell()" in text:
        target = "spell"
    else:
        return None
    return life_gain, target


def counter_target_from_source(source_text: str) -> str | None:
    text = str(source_text or "")
    if (
        "TalesEndPredicate" in text
        or "activated ability, triggered ability, or legendary spell" in text
    ):
        return "activated_or_triggered_ability_or_legendary_spell"
    if (
        "FilterCreatureSpell" in text
        and "PowerPredicate(ComparisonType.FEWER_THAN, 3)" in text
        and "ToughnessPredicate(ComparisonType.FEWER_THAN, 3)" in text
    ):
        return "creature_spell_power_or_toughness_2_or_less"
    if "new TargetStackObject()" in text or re.search(r"new\s+TargetStackObject\s*\(\s*\)", text):
        return "spell_or_activated_or_triggered_ability"
    if (
        "new TargetSpell()" in text
        or "new TargetSpell(StaticFilters.FILTER_SPELL)" in text
        or re.search(r"new\s+TargetSpell\s*\([^)]*StaticFilters\.FILTER_SPELL(?!_)", text)
    ):
        if "XManaValueTargetAdjuster" in text:
            return "spell_mana_value_x"
        return "spell"
    if (
        "ManaValuePredicate(ComparisonType.FEWER_THAN, 3)" in text
        and "ManaValuePredicate(ComparisonType.FEWER_THAN, 7)" in text
        and "ColorPredicate(ObjectColor.RED)" in text
        and "ColorPredicate(ObjectColor.GREEN)" in text
    ):
        return "spell_mana_value_2_or_less_or_red_green_spell_mana_value_6_or_less"
    mana_value_less_match = re.search(
        r"ManaValuePredicate\s*\(\s*ComparisonType\.FEWER_THAN\s*,\s*(?P<limit>\d+)\s*\)",
        text,
    )
    if mana_value_less_match:
        max_value = max(0, int(mana_value_less_match.group("limit")) - 1)
        if "FilterCreatureSpell" in text:
            return f"creature_spell_mana_value_{max_value}_or_less"
        return f"spell_mana_value_{max_value}_or_less"
    if "Predicates.not(SubType.FAERIE.getPredicate())" in text or "non-Faerie spell" in text:
        return "nonfaerie_spell"
    if "CardType.CREATURE.getPredicate()" in text and "CardType.ENCHANTMENT.getPredicate()" in text:
        return "creature_or_enchantment_spell"
    if (
        "FILTER_SPELL_NON_CREATURE" in text
        or "FILTER_SPELL_A_NON_CREATURE" in text
        or "FilterNonCreatureSpell" in text
    ):
        return "noncreature_spell"
    if (
        "FILTER_SPELL_CREATURE" in text
        or "FILTER_SPELL_A_CREATURE" in text
        or "FilterCreatureSpell" in text
    ):
        return "creature_spell"
    if "FILTER_SPELL_AN_ARTIFACT" in text:
        return "artifact_spell"
    if "FILTER_SPELL_AN_ENCHANTMENT" in text:
        return "enchantment_spell"
    if "FILTER_SPELL_AN_INSTANT_OR_SORCERY" in text or "FilterInstantOrSorcerySpell" in text:
        return "instant_or_sorcery_spell"
    if "FILTER_SPELL_A_MULTICOLORED" in text:
        return "multicolored_spell"
    if (
        "HinderingLightPredicate" in text
        or "spell that targets you or a permanent you control" in text
    ):
        return "spell_targeting_you_or_permanent_you_control"
    if (
        "TargetsPermanentPredicate" in text
        and (
            "FILTER_CONTROLLED_PERMANENT" in text
            or "FilterControlledPermanent" in text
            or "spell that targets a permanent you control" in text
        )
    ):
        if (
            "CardType.INSTANT.getPredicate()" in text
            and "SubType.AURA.getPredicate()" in text
        ):
            return "instant_or_aura_spell_targeting_permanent_you_control"
        return "spell_targeting_permanent_you_control"
    if "TargetsPlayerPredicate" in text or "spell that targets a player" in text:
        return "spell_targeting_player"
    if "SecondSpellPredicate" in text or "SecondSpellThisTurn" in text:
        return "spell_second_spell_this_turn"
    if (
        "TargetsPermanentPredicate" in text
        and (
            "FilterCreaturePermanent" in text
            or "FILTER_PERMANENT_CREATURE" in text
            or "spell that targets a creature" in text
            or "spell that targets one or more creatures" in text
        )
    ):
        return "spell_targeting_creature"
    if (
        "LaquatussDisdainPredicate" in text
        or "spell cast from a graveyard" in text
        or ("Zone.GRAVEYARD" in text and "instanceof Spell" in text)
    ):
        return "spell_cast_from_graveyard"
    return None


def counter_target_exile_replacement_from_oracle(metadata: dict[str, Any]) -> str | None:
    text = re.sub(
        r"\s+",
        " ",
        " ".join(oracle_effect_lines_without_neutral_auxiliary(metadata)),
    ).strip().lower()
    match = re.match(
        r"^(?P<counter>counter target .+?)\. if that spell is countered this way, "
        r"exile (?:it|that spell) instead of putting (?:it )?into its owner's graveyard\.?$",
        text,
    )
    if not match:
        return None
    return counter_target_from_oracle({"oracle_text": match.group("counter")})


def counter_target_exile_replacement_from_source(source_text: str) -> str:
    text = str(source_text or "")
    effect_matches = list(re.finditer(r"new\s+CounterTargetWithReplacementEffect\s*\(", text))
    if len(effect_matches) != 1:
        return "counter_replacement_source_effect_not_single"
    if not re.search(r"CounterTargetWithReplacementEffect\s*\(\s*PutCards\.EXILED\s*\)", text):
        return "counter_replacement_source_not_exile"
    target = counter_target_from_source(text)
    if target is None:
        return "counter_replacement_source_target_not_supported"
    return target


def counter_target_top_library_replacement_from_oracle(metadata: dict[str, Any]) -> str | None:
    text = re.sub(
        r"\s+",
        " ",
        " ".join(oracle_effect_lines_without_neutral_auxiliary(metadata)),
    ).strip().lower()
    match = re.match(
        r"^(?P<counter>counter target .+?)\. if that spell is countered this way, "
        r"put (?:it|that spell|that card) on top of its owner's library "
        r"instead of into that player's graveyard\.?$",
        text,
    )
    if not match:
        return None
    return counter_target_from_oracle({"oracle_text": match.group("counter")})


def counter_target_top_library_replacement_from_source(source_text: str) -> str:
    text = str(source_text or "")
    effect_matches = list(re.finditer(r"new\s+CounterTargetWithReplacementEffect\s*\(", text))
    if len(effect_matches) != 1:
        return "counter_replacement_source_effect_not_single"
    if not re.search(r"CounterTargetWithReplacementEffect\s*\(\s*PutCards\.TOP_ANY\s*\)", text):
        return "counter_replacement_source_not_top_library"
    target = counter_target_from_source(text)
    if target is None:
        return "counter_replacement_source_target_not_supported"
    return target


def fixed_counter_target_controller_life_loss_from_oracle(
    metadata: dict[str, Any],
) -> tuple[str, int] | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    text = re.sub(r"\s+", " ", text).strip()
    match = re.match(
        r"^(?P<counter>counter target .+?)\. its controller loses (?P<life>\d+) life\.?$",
        text,
    )
    if not match:
        return None
    target = counter_target_from_oracle({"oracle_text": match.group("counter")})
    if target is None:
        return None
    return target, int(match.group("life"))


def fixed_counter_target_controller_life_loss_from_source(
    source_text: str,
) -> tuple[str, int] | None:
    text = str(source_text or "")
    counter_matches = list(re.finditer(r"new\s+CounterTargetEffect\s*\(", text))
    life_matches = list(re.finditer(r"new\s+LoseLifeTargetControllerEffect\s*\(", text))
    if len(counter_matches) != 1 or len(life_matches) != 1:
        return None
    if counter_matches[0].start() > life_matches[0].start():
        return None
    life_loss = java_constructor_int(text, "LoseLifeTargetControllerEffect")
    if life_loss is None or life_loss <= 0:
        return None
    target = counter_target_from_source(text)
    if target is None:
        return None
    return target, life_loss


def fixed_counter_unless_pays_from_oracle(metadata: dict[str, Any]) -> tuple[str, int, bool] | None:
    text = oracle_text(metadata)
    match = re.match(
        r"^(?P<counter>counter target .+?) unless its controller pays \{(?P<cost>\d+)\}"
        r"(?P<exile>\. if that spell is countered this way, exile it instead of putting (?:it )?into its owner's graveyard)?\.?$",
        text,
    )
    if not match:
        return None
    target = counter_target_from_oracle({"oracle_text": match.group("counter")})
    if target is None:
        return None
    return target, int(match.group("cost")), bool(match.group("exile"))


def fixed_counter_unless_pays_from_source(source_text: str) -> tuple[int, bool] | None:
    text = str(source_text or "")
    effect_matches = list(re.finditer(r"new\s+CounterUnlessPaysEffect\s*\(", text))
    if len(effect_matches) != 1:
        return None
    match = re.search(
        r"new\s+CounterUnlessPaysEffect\s*\(\s*new\s+GenericManaCost\s*\(\s*(?P<cost>\d+)\s*\)\s*(?:,\s*(?P<exile>true|false)\s*)?\)",
        text,
    )
    if not match:
        return None
    if "new TargetSpell" not in text:
        return None
    return int(match.group("cost")), match.group("exile") == "true"


def fixed_counter_unless_pays_draw_from_oracle(
    metadata: dict[str, Any],
) -> tuple[str, int, int, bool] | None:
    text = oracle_text(metadata)
    match = re.match(
        r"^(?P<counter>counter target .+? unless its controller pays \{(?P<cost>\d+)\})\. "
        r"draw (?P<draw>[^.]+)\.?$",
        text,
    )
    if not match:
        return None
    counter = fixed_counter_unless_pays_from_oracle(
        {"oracle_text": f"{match.group('counter')}."}
    )
    if counter is None:
        return None
    draw_count = fixed_draw_count_from_oracle_sentence(f"draw {match.group('draw')}.")
    if draw_count is None or draw_count <= 0:
        return None
    target, cost, exile_if_countered = counter
    return target, cost, draw_count, exile_if_countered


def dynamic_counter_unless_pays_from_oracle(
    metadata: dict[str, Any],
) -> tuple[str, dict[str, Any], bool] | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    text = re.sub(r"\s+", " ", text).strip()
    text = re.sub(r"^domain\s+(?:—|-)\s+", "", text).strip()
    base_pattern = (
        r"^(?P<counter>counter target .+?) unless its controller pays "
        r"(?P<cost>.+?)"
        r"(?P<exile>\. if that spell is countered this way, exile it instead of putting (?:it )?into its owner's graveyard)?\.?$"
    )
    match = re.match(base_pattern, text)
    if not match:
        return None
    target = counter_target_from_oracle({"oracle_text": match.group("counter")})
    if target is None:
        return None
    cost_text = match.group("cost").strip().rstrip(".").strip()
    exile_if_countered = bool(match.group("exile"))
    spec: dict[str, Any] | None = None
    if cost_text == "{x}":
        spec = {"counter_unless_pays_amount_source": "x_value"}
    elif cost_text == "{x}, where x is your devotion to blue":
        spec = {"counter_unless_pays_amount_source": "devotion_to_blue"}
    elif re.fullmatch(r"\{1\} for each basic land type among lands you control", cost_text):
        spec = {
            "counter_unless_pays_amount_source": "domain_basic_land_types",
            "counter_unless_pays_per": 1,
        }
    elif re.fullmatch(r"\{2\} for each wizard on the battlefield", cost_text):
        spec = {
            "counter_unless_pays_amount_source": "battlefield_subtype_count",
            "counter_unless_pays_subtype": "wizard",
            "counter_unless_pays_battlefield_scope": "all_battlefields",
            "counter_unless_pays_per": 2,
        }
    elif re.fullmatch(r"\{2\} plus an additional \{1\} for each faerie you control", cost_text):
        spec = {
            "counter_unless_pays_amount_source": "controlled_subtype_count",
            "counter_unless_pays_subtype": "faerie",
            "counter_unless_pays_base": 2,
            "counter_unless_pays_per": 1,
        }
    elif re.fullmatch(
        r"\{1\} plus an additional \{1\} for each creature in your party",
        cost_text,
    ):
        spec = {
            "counter_unless_pays_amount_source": "party_count",
            "counter_unless_pays_base": 1,
            "counter_unless_pays_per": 1,
        }
    if spec is None:
        return None
    return target, spec, exile_if_countered


def dynamic_counter_unless_pays_from_source(source_text: str) -> tuple[dict[str, Any], bool] | None:
    text = str(source_text or "")
    effect_matches = list(re.finditer(r"new\s+CounterUnlessPaysEffect\s*\(", text))
    if len(effect_matches) != 1:
        return None
    if "new TargetSpell" not in text:
        return None
    exile_if_countered = bool(
        re.search(
            r"new\s+CounterUnlessPaysEffect\s*\(\s*GetXValue\.instance\s*,\s*true\s*\)",
            text,
        )
    )
    if re.search(r"new\s+CounterUnlessPaysEffect\s*\(\s*GetXValue\.instance\s*(?:,\s*true\s*)?\)", text):
        return {"counter_unless_pays_amount_source": "x_value"}, exile_if_countered
    if "new CounterUnlessPaysEffect(DomainValue.REGULAR)" in text:
        return {
            "counter_unless_pays_amount_source": "domain_basic_land_types",
            "counter_unless_pays_per": 1,
        }, False
    if "new CounterUnlessPaysEffect(DevotionCount.U)" in text:
        return {"counter_unless_pays_amount_source": "devotion_to_blue"}, False
    if "PartyCount.instance" in text and re.search(r"new\s+IntPlusDynamicValue\s*\(\s*1\s*,\s*PartyCount\.instance\s*\)", text):
        return {
            "counter_unless_pays_amount_source": "party_count",
            "counter_unless_pays_base": 1,
            "counter_unless_pays_per": 1,
        }, False
    if (
        "SubType.WIZARD" in text
        and re.search(r"new\s+PermanentsOnBattlefieldCount\s*\(\s*FILTER\s*,\s*2\s*\)", text)
        and "FilterControlledPermanent" not in text
    ):
        return {
            "counter_unless_pays_amount_source": "battlefield_subtype_count",
            "counter_unless_pays_subtype": "wizard",
            "counter_unless_pays_battlefield_scope": "all_battlefields",
            "counter_unless_pays_per": 2,
        }, False
    if (
        "SubType.FAERIE" in text
        and "FilterControlledPermanent" in text
        and re.search(r"new\s+IntPlusDynamicValue\s*\(\s*2\s*,\s*faerieCount\s*\)", text)
    ):
        return {
            "counter_unless_pays_amount_source": "controlled_subtype_count",
            "counter_unless_pays_subtype": "faerie",
            "counter_unless_pays_base": 2,
            "counter_unless_pays_per": 1,
        }, False
    return None


def counter_target_constraints_for(target: str) -> dict[str, Any]:
    constraints: dict[str, Any] = {"zone": "stack", "stack_object": "spell"}
    if target == "spell_or_activated_or_triggered_ability":
        return {
            "zone": "stack",
            "any_of": [
                {"stack_object": "spell"},
                {"stack_object": "activated_ability"},
                {"stack_object": "triggered_ability"},
            ],
        }
    if target == "activated_or_triggered_ability_or_legendary_spell":
        return {
            "zone": "stack",
            "any_of": [
                {"stack_object": "activated_ability"},
                {"stack_object": "triggered_ability"},
                {"stack_object": "spell", "require_legendary": True},
            ],
        }
    mana_value_match = re.match(r"^spell_mana_value_(?P<value>\d+)(?P<op>_or_greater|_or_less)?$", target)
    if mana_value_match:
        value = int(mana_value_match.group("value"))
        op = mana_value_match.group("op") or ""
        if op == "_or_greater":
            constraints["counter_target_mana_value_min"] = value
        elif op == "_or_less":
            constraints["counter_target_mana_value_max"] = value
        else:
            constraints["counter_target_mana_value"] = value
    elif target == "spell_mana_value_x":
        constraints["counter_target_mana_value_source"] = "x_value"
    elif target == "spell_mana_value_2_or_less_or_red_green_spell_mana_value_6_or_less":
        constraints["any_of"] = [
            {"stack_object": "spell", "counter_target_mana_value_max": 2},
            {
                "stack_object": "spell",
                "spell_colors": ["R", "G"],
                "counter_target_mana_value_max": 6,
            },
        ]
    elif (power_toughness_match := re.match(
        r"^creature_spell_power_or_toughness_(?P<value>\d+)_or_less$",
        target,
    )):
        constraints["card_types"] = ["creature"]
        constraints["power_or_toughness_max"] = int(power_toughness_match.group("value"))
    elif (creature_mana_value_match := re.match(
        r"^creature_spell_mana_value_(?P<value>\d+)_or_less$",
        target,
    )):
        constraints["card_types"] = ["creature"]
        constraints["counter_target_mana_value_max"] = int(creature_mana_value_match.group("value"))
    elif target == "red_or_green_spell":
        constraints["spell_colors"] = ["R", "G"]
    elif target == "blue_instant_spell":
        constraints["spell_types"] = ["instant"]
        constraints["spell_colors"] = ["U"]
    elif target == "creature_or_sorcery_spell":
        constraints["any_of"] = [
            {"card_types": ["creature"]},
            {"spell_types": ["sorcery"]},
        ]
    elif target == "creature_or_aura_spell":
        constraints["any_of"] = [
            {"card_types": ["creature"]},
            {"spell_subtypes": ["aura"]},
        ]
    elif target == "spirit_or_arcane_spell":
        constraints["spell_subtypes"] = ["spirit", "arcane"]
    elif target == "artifact_or_creature_spell":
        constraints["card_types"] = ["artifact", "creature"]
    elif target == "creature_or_planeswalker_spell":
        constraints["card_types"] = ["creature", "planeswalker"]
    elif target == "creature_or_enchantment_spell":
        constraints["card_types"] = ["creature", "enchantment"]
    elif target == "artifact_or_enchantment_spell":
        constraints["card_types"] = ["artifact", "enchantment"]
    elif target == "instant_or_sorcery_spell":
        constraints["spell_types"] = ["instant", "sorcery"]
    elif target == "spell_targeting_creature":
        constraints["spell_targets"] = "creature"
    elif target == "spell_targeting_permanent_you_control":
        constraints["spell_targets"] = "permanent_you_control"
    elif target == "spell_targeting_you_or_permanent_you_control":
        constraints["spell_targets"] = "you_or_permanent_you_control"
    elif target == "instant_or_aura_spell_targeting_permanent_you_control":
        constraints["any_of"] = [
            {"spell_types": ["instant"]},
            {"spell_subtypes": ["aura"]},
        ]
        constraints["spell_targets"] = "permanent_you_control"
    elif target == "spell_targeting_player":
        constraints["spell_targets"] = "player"
    elif target == "spell_second_spell_this_turn":
        constraints["spell_order_this_turn"] = 2
    elif target == "spell_cast_from_graveyard":
        constraints["source_zone"] = "graveyard"
    elif target == "noncreature_spell":
        constraints["exclude_card_types"] = ["creature"]
    elif target == "nonartifact_spell":
        constraints["exclude_card_types"] = ["artifact"]
    elif target == "nonfaerie_spell":
        constraints["exclude_spell_subtypes"] = ["faerie"]
    elif target == "colorless_spell":
        constraints["spell_color_count_exact"] = 0
    elif target == "nonblue_spell":
        constraints["exclude_spell_colors"] = ["U"]
    elif target == "multicolored_spell":
        constraints["spell_color_count_min"] = 2
    elif target in {"creature_spell", "artifact_spell", "enchantment_spell"}:
        constraints["card_types"] = [target.removesuffix("_spell")]
    elif target in {"instant_spell", "sorcery_spell"}:
        constraints["spell_types"] = [target.removesuffix("_spell")]
    elif target in {"blue_spell", "white_spell", "black_spell", "red_spell", "green_spell"}:
        color_symbols = {
            "blue_spell": "U",
            "white_spell": "W",
            "black_spell": "B",
            "red_spell": "R",
            "green_spell": "G",
        }
        constraints["spell_colors"] = [color_symbols[target]]
    return constraints


def recursion_target_constraints_for(
    target: str,
    *,
    controller: str = "self",
    mana_value_max: int | None = None,
    mana_value_max_from_x: bool = False,
    total_mana_value_max: int | None = None,
    requires_different_names: bool = False,
    graveyard_from_battlefield_this_turn: bool = False,
) -> dict[str, Any]:
    constraints: dict[str, Any] = {"zone": "graveyard", "controller": controller}
    color_creature_targets = {
        "white_creature": "W",
        "blue_creature": "U",
        "black_creature": "B",
        "red_creature": "R",
        "green_creature": "G",
    }
    if target == "any_card":
        constraints["scope"] = "any_card"
    elif target in color_creature_targets:
        constraints["card_types"] = ["creature"]
        constraints["colors"] = [color_creature_targets[target]]
    elif target == "green_card":
        constraints["colors"] = ["G"]
    elif target == "multicolored_card":
        constraints["min_colors"] = 2
    elif target == "goblin_card":
        constraints["subtypes"] = ["goblin"]
    elif target == "arcane_card":
        constraints["subtypes"] = ["arcane"]
    elif target == "zombie_card":
        constraints["subtypes"] = ["zombie"]
    elif target == "pirate_card":
        constraints["subtypes"] = ["pirate"]
    elif target == "knight_card":
        constraints["subtypes"] = ["knight"]
    elif target == "mercenary_card":
        constraints["subtypes"] = ["mercenary"]
    elif target == "elf_card":
        constraints["subtypes"] = ["elf"]
    elif target == "vampire_or_wizard_creature":
        constraints["card_types"] = ["creature"]
        constraints["subtypes"] = ["vampire", "wizard"]
    elif target == "mount_card":
        constraints["subtypes"] = ["mount"]
    elif target == "vehicle_card":
        constraints["subtypes"] = ["vehicle"]
    elif target == "creature_no_abilities":
        constraints["card_types"] = ["creature"]
        constraints["requires_no_abilities"] = True
    elif target == "ally_creature":
        constraints["card_types"] = ["creature"]
        constraints["subtypes"] = ["ally"]
    elif target == "outlaw_creature":
        constraints["card_types"] = ["creature"]
        constraints["subtype_group"] = "outlaw"
        constraints["subtypes"] = ["assassin", "mercenary", "pirate", "rogue", "warlock"]
    elif target == "shared_creature_type":
        constraints["card_types"] = ["creature"]
        constraints["shared_subtype_group"] = "creature_type"
    elif target in {"creature", "artifact", "enchantment", "sorcery", "instant", "land"}:
        constraints["card_types"] = [target]
    elif target == "planeswalker":
        constraints["card_types"] = ["planeswalker"]
    elif target == "noncreature_permanent":
        constraints["card_types"] = ["artifact", "enchantment", "planeswalker", "battle", "land"]
        constraints["exclude_card_types"] = ["creature"]
    elif target == "nonland_permanent":
        constraints["card_types"] = ["artifact", "creature", "enchantment", "planeswalker", "battle"]
        constraints["exclude_card_types"] = ["land"]
    elif target == "rebel_permanent":
        constraints["card_types"] = ["artifact", "creature", "enchantment", "planeswalker", "battle", "land"]
        constraints["subtypes"] = ["rebel"]
    elif target == "aura_card":
        constraints["subtypes"] = ["aura"]
    elif target == "human_creature":
        constraints["card_types"] = ["creature"]
        constraints["subtypes"] = ["human"]
    elif target == "non_human_creature":
        constraints["card_types"] = ["creature"]
        constraints["exclude_subtypes"] = ["human"]
    elif target == "basic_land":
        constraints["card_types"] = ["land"]
        constraints["supertypes"] = ["basic"]
    elif target == "instant_or_sorcery":
        constraints["card_types"] = ["instant", "sorcery"]
    elif target == "spirit_instant_or_sorcery":
        constraints["any_of"] = [
            {"subtypes": ["spirit"]},
            {"card_types": ["instant"]},
            {"card_types": ["sorcery"]},
        ]
    elif target == "artifact_or_enchantment":
        constraints["card_types"] = ["artifact", "enchantment"]
    elif target == "artifact_or_creature":
        constraints["card_types"] = ["artifact", "creature"]
    elif target == "artifact_creature_or_land":
        constraints["card_types"] = ["artifact", "creature", "land"]
    elif target == "artifact_or_creature_or_enchantment":
        constraints["card_types"] = ["artifact", "creature", "enchantment"]
    elif target == "artifact_or_enchantment_or_planeswalker":
        constraints["card_types"] = ["artifact", "enchantment", "planeswalker"]
    elif target == "creature_or_land":
        constraints["card_types"] = ["creature", "land"]
    elif target == "creature_or_vehicle":
        constraints["any_of"] = [
            {"card_types": ["creature"]},
            {"subtypes": ["vehicle"]},
        ]
    elif target == "creature_or_enchantment":
        constraints["card_types"] = ["creature", "enchantment"]
    elif target == "creature_or_food":
        constraints["any_of"] = [
            {"card_types": ["creature"]},
            {"subtypes": ["food"]},
        ]
    elif target == "artifact_creature":
        constraints["card_types"] = ["artifact", "creature"]
        constraints["all_card_types_required"] = True
    elif target == "noncreature_nonland":
        constraints["exclude_card_types"] = ["creature", "land"]
    elif target == "permanent":
        constraints["card_types"] = ["artifact", "creature", "enchantment", "planeswalker", "battle", "land"]
    else:
        constraints["target"] = target
    if mana_value_max is not None:
        constraints["mana_value_max"] = mana_value_max
    if mana_value_max_from_x:
        constraints["mana_value_max_source"] = "x_value"
    if target == "nonland_permanent" and mana_value_max_from_x:
        constraints["mana_value_max_source"] = "x_value"
    if total_mana_value_max is not None:
        constraints["total_mana_value_max"] = total_mana_value_max
    if requires_different_names:
        constraints["requires_different_names"] = True
    if graveyard_from_battlefield_this_turn:
        constraints["graveyard_from_battlefield_this_turn"] = True
    return constraints


def with_graveyard_permanent_count_mana_value_constraint(constraints: dict[str, Any]) -> dict[str, Any]:
    updated = dict(constraints)
    updated["mana_value_max_source"] = "graveyard_permanent_count"
    return updated


def library_pick_target_constraints_for(target: str) -> dict[str, Any]:
    constraints: dict[str, Any] = {"zone": "library", "controller": "self"}
    if target == "any_card":
        constraints["scope"] = "any_card"
    elif target in {"creature", "land", "enchantment", "artifact", "instant", "sorcery"}:
        constraints["card_types"] = [target]
    elif target == "creature_or_land":
        constraints["card_types"] = ["creature", "land"]
    elif target == "artifact_creature_or_land":
        constraints["card_types"] = ["artifact", "creature", "land"]
    elif target == "creature_or_enchantment":
        constraints["card_types"] = ["creature", "enchantment"]
    elif target == "enchantment_or_land":
        constraints["card_types"] = ["enchantment", "land"]
    elif target == "instant_or_sorcery":
        constraints["card_types"] = ["instant", "sorcery"]
    elif target == "human_card":
        constraints["subtypes"] = ["human"]
    elif target == "green_card":
        constraints["colors"] = ["G"]
    elif target == "artifact_or_pirate":
        constraints["any_of"] = [{"card_types": ["artifact"]}, {"subtypes": ["pirate"]}]
    elif target == "land_or_double_faced":
        constraints["any_of"] = [{"card_types": ["land"]}, {"layout": "double_faced"}]
    elif target == "mount_creature_or_plains":
        constraints["any_of"] = [
            {"card_types": ["creature"], "subtypes": ["mount"]},
            {"card_types": ["land"], "subtypes": ["plains"]},
        ]
    elif target in {
        "goblin_swamp_or_mountain",
        "elf_swamp_or_forest",
        "elemental_island_or_mountain",
        "kithkin_forest_or_plains",
        "merfolk_plains_or_island",
    }:
        subtype, first_land, second_land = {
            "goblin_swamp_or_mountain": ("goblin", "swamp", "mountain"),
            "elf_swamp_or_forest": ("elf", "swamp", "forest"),
            "elemental_island_or_mountain": ("elemental", "island", "mountain"),
            "kithkin_forest_or_plains": ("kithkin", "forest", "plains"),
            "merfolk_plains_or_island": ("merfolk", "plains", "island"),
        }[target]
        constraints["any_of"] = [
            {"subtypes": [subtype]},
            {"card_types": ["land"], "subtypes": [first_land]},
            {"card_types": ["land"], "subtypes": [second_land]},
        ]
    elif target == "colorless_card":
        constraints["colorless"] = True
    elif target == "snow_permanent":
        constraints["card_types"] = ["artifact", "creature", "enchantment", "planeswalker", "battle", "land"]
        constraints["supertypes"] = ["snow"]
    else:
        constraints["target"] = target
    return constraints


def recursion_component(target: str, count: int = 1) -> dict[str, Any]:
    return {
        "target": target,
        "target_constraints": recursion_target_constraints_for(target),
        "count": count,
        "destination": "hand",
        "target_controller": "self",
    }


def recursion_choose_one_or_both_from_text(text: str) -> list[dict[str, Any]] | None:
    text = re.sub(r"\s+", " ", str(text or "").strip().lower())
    if not text.startswith("choose one or both"):
        return None
    target_map = {
        "artifact": "artifact",
        "creature": "creature",
        "enchantment": "enchantment",
        "human creature": "human_creature",
        "land": "land",
        "non-human creature": "non_human_creature",
        "planeswalker": "planeswalker",
    }
    matches = re.findall(
        r"return target ([a-z-]+(?: [a-z-]+)?) card from your graveyard to your hand",
        text,
    )
    components: list[dict[str, Any]] = []
    for phrase in matches:
        target = target_map.get(phrase.strip())
        if target is None:
            return None
        components.append(recursion_component(target))
    if len(components) != 2:
        return None
    return components


def recursion_battlefield_component(target: str, count: int = 1) -> dict[str, Any]:
    return {
        "target": target,
        "target_constraints": recursion_target_constraints_for(target),
        "count": count,
        "destination": "battlefield",
        "target_controller": "self",
        "target_graveyard_controller": "self",
        "battlefield_controller": "self",
    }


def recursion_battlefield_choose_one_or_both_from_text(text: str) -> list[dict[str, Any]] | None:
    normalized = re.sub(r"\s+", " ", str(text or "").strip().lower())
    if not normalized.startswith("choose one or both"):
        return None
    components: list[dict[str, Any]] = []
    if "return target creature card from your graveyard to the battlefield" in normalized:
        components.append(recursion_battlefield_component("creature"))
    if "return target aura card from your graveyard to the battlefield" in normalized:
        components.append(recursion_battlefield_component("aura_card"))
    if len(components) != 2:
        return None
    return components


def source_supports_battlefield_choose_one_or_both_recursion(source_text: str) -> bool:
    text = str(source_text or "")
    return (
        "getModes().setMinModes(1)" in text
        and "getModes().setMaxModes(2)" in text
        and text.count("ReturnFromGraveyardToBattlefieldTargetEffect") >= 2
        and "FILTER_CARD_CREATURE_YOUR_GRAVEYARD" in text
        and "SubType.AURA.getPredicate" in text
    )


def recursion_component_up_to_one(target: str) -> dict[str, Any]:
    component = recursion_component(target, 1)
    component["up_to_count"] = True
    return component


def recursion_for_each_color_creature_components_from_text(text: str) -> list[dict[str, Any]] | None:
    normalized = re.sub(r"\s+", " ", str(text or "").strip().lower())
    if normalized != (
        "for each color, return up to one target creature card of that color "
        "from your graveyard to your hand."
    ):
        return None
    return [
        recursion_component_up_to_one("white_creature"),
        recursion_component_up_to_one("blue_creature"),
        recursion_component_up_to_one("black_creature"),
        recursion_component_up_to_one("red_creature"),
        recursion_component_up_to_one("green_creature"),
    ]


def recursion_for_each_color_creature_components_from_oracle(
    metadata: dict[str, Any],
) -> list[dict[str, Any]] | None:
    return recursion_for_each_color_creature_components_from_text(oracle_text(metadata))


def source_supports_for_each_color_creature_recursion(source_text: str) -> bool:
    text = str(source_text or "")
    return (
        "ReturnFromGraveyardToHandTargetEffect" in text
        and "ColorAssignment" in text
        and "TargetCardInYourGraveyard" in text
        and "FilterCreatureCard" in text
        and "ColorlessPredicate" in text
    )


def recursion_up_to_one_multi_target_components_from_text(text: str) -> list[dict[str, Any]] | None:
    normalized = re.sub(r"\s+", " ", str(text or "").strip().lower())
    if normalized == (
        "return up to one target creature card, up to one target mount card, "
        "up to one target vehicle card, and up to one target creature card with "
        "no abilities from your graveyard to your hand."
    ):
        return [
            recursion_component_up_to_one("creature"),
            recursion_component_up_to_one("mount_card"),
            recursion_component_up_to_one("vehicle_card"),
            recursion_component_up_to_one("creature_no_abilities"),
        ]
    return None


def recursion_up_to_one_multi_target_components_from_oracle(
    metadata: dict[str, Any],
) -> list[dict[str, Any]] | None:
    return recursion_up_to_one_multi_target_components_from_text(oracle_text(metadata))


def source_supports_up_to_one_multi_target_recursion(
    source_text: str,
    components: list[dict[str, Any]],
) -> bool:
    text = str(source_text or "")
    if (
        "ReturnFromGraveyardToHandTargetEffect" not in text
        or "EachTargetPointer" not in text
        or text.count("TargetCardInYourGraveyard") < len(components)
    ):
        return False
    required_by_target = {
        "creature": ("StaticFilters.FILTER_CARD_CREATURE",),
        "mount_card": ("SubType.MOUNT",),
        "vehicle_card": ("SubType.VEHICLE",),
        "creature_no_abilities": ("NoAbilityPredicate",),
    }
    return all(
        any(needle in text for needle in required_by_target.get(str(component.get("target")), ()))
        for component in components
    )


def recursion_exile_self_components_from_text(text: str) -> list[dict[str, Any]] | None:
    text = re.sub(r"\s+", " ", str(text or "").strip().lower())
    if not text.startswith("return up to one target "):
        return None
    if not text.endswith(" from your graveyard to your hand."):
        return None
    body = text.removesuffix(" from your graveyard to your hand.")
    phrases = re.findall(r"up to one target ([a-z ]+?) card", body)
    target_map = {
        "artifact": "artifact",
        "enchantment": "enchantment",
        "instant": "instant",
        "sorcery": "sorcery",
        "planeswalker": "planeswalker",
        "creature": "creature",
        "noncreature permanent": "noncreature_permanent",
    }
    targets = [target_map.get(phrase.strip()) for phrase in phrases]
    if any(target is None for target in targets):
        return None
    if targets == ["artifact", "enchantment", "instant", "sorcery", "planeswalker"]:
        return [recursion_component_up_to_one(str(target)) for target in targets]
    if targets == ["creature", "noncreature_permanent"]:
        return [recursion_component_up_to_one(str(target)) for target in targets]
    return None


def recursion_to_hand_exile_self_components_from_oracle(
    metadata: dict[str, Any],
) -> list[dict[str, Any]] | None:
    text = oracle_text_without_trailing_self_exile(metadata)
    if text is None:
        return None
    return recursion_exile_self_components_from_text(text)


def source_supports_exile_self_recursion_target(source_text: str, target: str) -> bool:
    text = str(source_text or "")
    if target == "any_card":
        return (
            "TargetCardInYourGraveyard" in text
            and (
                "FILTER_CARD_FROM_YOUR_GRAVEYARD" in text
                or "new TargetCardInYourGraveyard()" in text
                or re.search(r"TargetCardInYourGraveyard\s*\(\s*\d+\s*,", text, re.S)
            )
        )
    if target == "multicolored_card":
        return "MulticoloredPredicate" in text
    if target == "noncreature_permanent":
        return "FilterPermanentCard" in text and "Predicates.not(CardType.CREATURE.getPredicate())" in text
    checks = {
        "artifact": ("FilterArtifactCard", "FILTER_CARD_ARTIFACT"),
        "enchantment": ("FilterEnchantmentCard", "FilterEnchantmentCard"),
        "instant": ("CardType.INSTANT", "instant card"),
        "sorcery": ("CardType.SORCERY", "sorcery card"),
        "instant_or_sorcery": ("FilterInstantOrSorceryCard", "instant and/or sorcery", "instant or sorcery"),
        "planeswalker": ("FilterPlaneswalkerCard", "planeswalker card"),
        "creature": ("FILTER_CARD_CREATURE", "FilterCreatureCard"),
    }
    return any(needle in text for needle in checks.get(target, ()))


def source_supports_exile_self_recursion_components(
    source_text: str,
    components: list[dict[str, Any]],
) -> bool:
    text = str(source_text or "")
    if "ExileSpellEffect" not in text or "ReturnFromGraveyardToHandTargetEffect" not in text:
        return False
    if "EachTargetPointer" not in text:
        return False
    targets = [str(component.get("target") or "") for component in components]
    return all(source_supports_exile_self_recursion_target(text, target) for target in targets)


def recursion_choose_one_from_text(text: str) -> list[dict[str, Any]] | None:
    text = re.sub(r"\s+", " ", str(text or "").strip().lower())
    if not text.startswith("choose one") or text.startswith("choose one or both"):
        return None
    if "return target creature card from your graveyard to your hand" not in text:
        return None
    subtype_patterns = {
        "zombie": "zombie_card",
        "pirate": "pirate_card",
    }
    for subtype, target in subtype_patterns.items():
        if f"return two target {subtype} cards from your graveyard to your hand" in text:
            return [
                recursion_component("creature"),
                recursion_component(target, 2),
            ]
    if "return two target creature cards that share a creature type from your graveyard to your hand" in text:
        component = recursion_component("shared_creature_type", 2)
        component["shared_subtype_group"] = "creature_type"
        return [
            recursion_component("creature"),
            component,
        ]
    return None


def source_supports_choose_one_or_both_recursion(source_text: str) -> bool:
    text = str(source_text or "")
    return (
        "getModes().setMinModes(1)" in text
        and "getModes().setMaxModes(2)" in text
        and text.count("ReturnFromGraveyardToHandTargetEffect") >= 2
    )


def source_supports_choose_one_recursion(source_text: str) -> bool:
    text = str(source_text or "")
    return (
        "addMode" in text
        and text.count("ReturnFromGraveyardToHandTargetEffect") >= 2
    )


