def recursion_to_hand_from_oracle(metadata: dict[str, Any]) -> tuple[str, int, bool] | None:
    return recursion_to_hand_from_text(oracle_text(metadata))


def attack_damage_recursion_target_from_phrase(phrase: str) -> dict[str, Any] | None:
    normalized = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    normalized = normalized.replace("multicoloured", "multicolored")
    patterns: list[tuple[str, dict[str, Any]]] = [
        (r"^card$", {"target": "any_card"}),
        (r"^creature card$", {"target": "creature"}),
        (r"^permanent card$", {"target": "permanent"}),
        (r"^arcane card$", {"target": "arcane_card"}),
        (
            r"^artifact, creature, or enchantment card$",
            {"target": "artifact_or_creature_or_enchantment"},
        ),
        (
            r"^creature or vehicle card with mana value (?P<mv>\d+) or less$",
            {"target": "creature_or_vehicle", "mana_value_max_group": "mv"},
        ),
    ]
    for pattern, spec in patterns:
        match = re.match(pattern, normalized)
        if not match:
            continue
        result = {"target": spec["target"], "count": 1, "destination": "hand"}
        if spec.get("mana_value_max_group"):
            result["mana_value_max"] = int(match.group(str(spec["mana_value_max_group"])))
        return result
    return None


def triggered_graveyard_to_hand_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = oracle_text_after_leading_static_keywords(metadata)
    if "deals damage to an opponent" in text:
        return "triggered_recursion_damage_to_opponent_not_supported"
    trigger = None
    match = re.search(
        r"whenever (?:this creature|this vehicle|[^,]+?) attacks, (?P<body>.+)$",
        text,
    )
    if match:
        trigger = "attack"
    else:
        match = re.search(
            r"whenever (?:this creature|[^,]+?) deals combat damage to a player, (?P<body>.+)$",
            text,
        )
        if match:
            trigger = "combat_damage_to_player"
    if not match or trigger is None:
        return "triggered_recursion_oracle_trigger_not_supported"
    body = match.group("body").strip()
    activation_cost_mana = None
    cost_match = re.match(
        r"you may pay (?P<cost>(?:\{[0-9wubrgc]+\})+)\. if you do, (?P<body>.+)$",
        body,
    )
    if cost_match:
        activation_cost_mana = cost_match.group("cost").upper()
        body = cost_match.group("body").strip()
    body = body.removeprefix("you may ").strip()
    target_match = re.match(
        r"return target (?P<phrase>.+?) from your graveyard to your hand\.?$",
        body,
    )
    if not target_match:
        return "triggered_recursion_oracle_target_not_supported"
    target = attack_damage_recursion_target_from_phrase(target_match.group("phrase"))
    if target is None:
        return "triggered_recursion_oracle_target_not_supported"
    result = {"trigger": trigger, **target}
    if activation_cost_mana:
        parsed = parse_mana_cost_text(activation_cost_mana)
        if parsed is None:
            return "triggered_recursion_oracle_cost_not_supported"
        result["trigger_cost_mana"] = activation_cost_mana
        result["trigger_cost_generic"] = parsed[0]
        result["trigger_cost_colors"] = parsed[1]
    return result


def triggered_graveyard_to_hand_target_from_source(source_text: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    lowered = text.lower()
    if "creature or Vehicle card with mana value 2 or less".lower() in lowered:
        target = "creature_or_vehicle"
        mana_value_max = 2
    elif "artifact, creature, or enchantment card" in lowered:
        target = "artifact_or_creature_or_enchantment"
        mana_value_max = None
    elif "FilterPermanentCard" in text or "permanent card from your graveyard" in lowered:
        target = "permanent"
        mana_value_max = None
    elif "SubType.ARCANE.getPredicate" in text or "arcane card from your graveyard" in lowered:
        target = "arcane_card"
        mana_value_max = None
    elif (
        "FILTER_CARD_CREATURE_YOUR_GRAVEYARD" in text
        or "FilterCreatureCard" in text
        or "creature card from your graveyard" in lowered
    ):
        target = "creature"
        mana_value_max = None
    elif "new TargetCardInYourGraveyard()" in text:
        target = "any_card"
        mana_value_max = None
    else:
        return "triggered_recursion_source_target_not_supported"
    result = {"target": target, "count": 1, "destination": "hand"}
    if mana_value_max is not None:
        result["mana_value_max"] = mana_value_max
    return result


def triggered_graveyard_to_hand_from_source(source_text: str, expected_trigger: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    if len(re.findall(r"ReturnFromGraveyardToHandTargetEffect\s*\(", text)) != 1:
        return "triggered_recursion_source_effect_count_not_supported"
    if len(re.findall(r"TargetCardInYourGraveyard\s*\(", text)) != 1:
        return "triggered_recursion_source_target_count_not_supported"
    if expected_trigger == "attack":
        if "AttacksTriggeredAbility" not in text:
            return "triggered_recursion_source_trigger_mismatch"
    elif expected_trigger == "combat_damage_to_player":
        if "DealsCombatDamageToAPlayerTriggeredAbility" not in text:
            return "triggered_recursion_source_trigger_mismatch"
    else:
        return "triggered_recursion_source_trigger_mismatch"
    target = triggered_graveyard_to_hand_target_from_source(text)
    if isinstance(target, str):
        return target
    cost_match = re.search(
        r'DoIfCostPaid\s*\(.*?ReturnFromGraveyardToHandTargetEffect\s*\(\s*\).*?ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)',
        text,
        re.S,
    )
    if cost_match:
        cost_text = cost_match.group(1)
        parsed = parse_mana_cost_text(cost_text)
        if parsed is None:
            return "triggered_recursion_source_cost_not_supported"
        target["trigger_cost_mana"] = cost_text
        target["trigger_cost_generic"] = parsed[0]
        target["trigger_cost_colors"] = parsed[1]
    return target


def recursion_to_hand_x_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text(metadata)
    match = re.match(r"^return x target creature cards from your graveyard to your hand\.?$", text)
    if not match:
        return None
    return {
        "target": "creature",
        "count": 0,
        "count_from_x": True,
        "up_to_count": False,
    }


def mill_then_return_target_from_phrase(phrase: str) -> str | None:
    normalized = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    mapping = {
        "creature or land": "creature_or_land",
        "permanent": "permanent",
        "creature": "creature",
        "land": "land",
    }
    return mapping.get(normalized)


def mill_then_return_from_text(text: str) -> dict[str, Any] | None:
    normalized = re.sub(r"\s+", " ", str(text or "").strip().lower())
    normalized = re.sub(r"\s*\([^)]*\)", "", normalized).strip()
    normalized = re.sub(
        r"^when (?:this creature|[^,]+?) enters(?: the battlefield)?,\s*",
        "",
        normalized,
    )
    match = re.match(
        r"^(?:put the top (?P<put_count>\w+|\d+) cards? of your library into your graveyard|"
        r"mill (?P<mill_count>\w+|\d+) cards?), then you may return "
        r"(?:a|an|one) (?P<phrase>.+?) card from your graveyard to your hand\.?$",
        normalized,
    )
    if not match:
        return None
    count_raw = match.group("put_count") or match.group("mill_count")
    mill_count = word_count_value(count_raw)
    target = mill_then_return_target_from_phrase(match.group("phrase"))
    if mill_count is None or target is None:
        return None
    return {
        "mill_count": mill_count,
        "target": target,
        "count": 1,
        "up_to_count": True,
    }


def mill_then_return_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    return mill_then_return_from_text(oracle_text(metadata))


def source_mill_then_return_target(source_text: str) -> str | None:
    text = str(source_text or "")
    if "FilterPermanentCard" in text:
        return "permanent"
    if "FILTER_CARD_LAND_FROM_YOUR_GRAVEYARD" in text:
        return "land"
    if "FILTER_CARD_CREATURE_YOUR_GRAVEYARD" in text or "FILTER_CARD_CREATURES_YOUR_GRAVEYARD" in text:
        return "creature"
    if "CardType.CREATURE.getPredicate()" in text and "CardType.LAND.getPredicate()" in text:
        return "creature_or_land"
    return None


def mill_then_return_from_source(source_text: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    mill_matches = re.findall(r"MillCardsControllerEffect\s*\(\s*(\d+)\s*\)", text)
    if len(mill_matches) != 1:
        return "mill_return_source_mill_count_not_supported"
    return_effect_matches = re.findall(r"ReturnCardChosenFromGraveyardEffect\s*\(", text)
    if len(return_effect_matches) != 1:
        return "mill_return_source_return_effect_count_not_supported"
    mill_index = text.find("MillCardsControllerEffect")
    return_index = text.find("ReturnCardChosenFromGraveyardEffect")
    if mill_index < 0 or return_index < 0 or mill_index > return_index:
        return "mill_return_source_effect_order_not_supported"
    if "PutCards.HAND" not in text:
        return "mill_return_source_destination_not_supported"
    target = source_mill_then_return_target(text)
    if target is None:
        return "mill_return_source_target_not_supported"
    return {
        "mill_count": int(mill_matches[0]),
        "target": target,
        "count": 1,
        "up_to_count": "ReturnCardChosenFromGraveyardEffect(true" in text,
    }


def oracle_text_without_trailing_self_exile(metadata: dict[str, Any]) -> str | None:
    text = oracle_text(metadata)
    card_name = re.sub(r"\s+", " ", str(metadata.get("name") or "").strip().lower())
    if not card_name:
        return None
    match = re.fullmatch(rf"(?P<body>.+?)\.?\s+exile {re.escape(card_name)}\.?", text)
    if not match:
        return None
    return match.group("body").strip() + "."


def recursion_to_hand_exile_self_from_oracle(metadata: dict[str, Any]) -> tuple[str, int, bool] | None:
    text = oracle_text_without_trailing_self_exile(metadata)
    if text is None:
        return None
    return recursion_to_hand_from_text(text)


def recursion_to_hand_exile_self_x_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text_without_trailing_self_exile(metadata)
    if text is None:
        return None
    patterns: list[tuple[str, dict[str, Any]]] = [
        (
            r"^return x target cards from your graveyard to your hand\.?$",
            {"target": "any_card", "up_to_count": False},
        ),
        (
            r"^return up to x target instant and/or sorcery cards from your graveyard to your hand\.?$",
            {"target": "instant_or_sorcery", "up_to_count": True},
        ),
    ]
    for pattern, spec in patterns:
        if re.match(pattern, text):
            return {
                "target": spec["target"],
                "count": 0,
                "count_from_x": True,
                "up_to_count": bool(spec["up_to_count"]),
            }
    return None


def recursion_to_battlefield_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text(metadata)
    patterns: list[tuple[str, dict[str, Any]]] = [
        (
            r"^(?:fathomless descent — )?return to the battlefield target nonland permanent card in your graveyard "
            r"with mana value less than or equal to the number of permanent cards in your graveyard\.?$",
            {
                "target": "nonland_permanent",
                "count": 1,
                "target_graveyard_controller": "self",
                "battlefield_controller": "self",
                "mana_value_max_from_graveyard_permanent_count": True,
                "oracle_complexity_supported": True,
            },
        ),
        (
            r"^choose target creature card in your graveyard that was put there from the battlefield this turn\. "
            r"return it to the battlefield tapped\.?$",
            {
                "target": "creature",
                "count": 1,
                "target_graveyard_controller": "self",
                "battlefield_controller": "self",
                "enters_tapped": True,
                "graveyard_from_battlefield_this_turn": True,
                "oracle_complexity_supported": True,
            },
        ),
        (
            r"^return target rebel permanent card with mana value (?P<mana_value_max>\d+) or less from your graveyard to the battlefield\.?$",
            {
                "target": "rebel_permanent",
                "count": 1,
                "target_graveyard_controller": "self",
                "battlefield_controller": "self",
            },
        ),
        (
            r"^return up to six target creature cards with different names from your graveyard to the battlefield\.?$",
            {
                "target": "creature",
                "count": 6,
                "up_to_count": True,
                "requires_different_names": True,
                "oracle_complexity_supported": True,
            },
        ),
        (
            r"^return up to three target creature cards with total mana value (?P<total_mana_value_max>\d+) or less from your graveyard to the battlefield\.?$",
            {
                "target": "creature",
                "count": 3,
                "up_to_count": True,
                "oracle_complexity_supported": True,
            },
        ),
        (
            r"^return any number of target ally creature cards with total mana value (?P<total_mana_value_max>\d+) or less from your graveyard to the battlefield\.?$",
            {
                "target": "ally_creature",
                "count": 99,
                "up_to_count": True,
                "oracle_complexity_supported": True,
            },
        ),
        (
            r"^choose up to two target permanent cards in your graveyard that were put there from the battlefield this turn\. return them to the battlefield tapped\.?$",
            {
                "target": "permanent",
                "count": 2,
                "up_to_count": True,
                "target_graveyard_controller": "self",
                "battlefield_controller": "self",
                "enters_tapped": True,
                "graveyard_from_battlefield_this_turn": True,
                "oracle_complexity_supported": True,
            },
        ),
        (
            r"^choose up to four target creature cards in your graveyard that were put there from the battlefield this turn\. return them to the battlefield\.?$",
            {
                "target": "creature",
                "count": 4,
                "up_to_count": True,
                "target_graveyard_controller": "self",
                "battlefield_controller": "self",
                "graveyard_from_battlefield_this_turn": True,
                "oracle_complexity_supported": True,
            },
        ),
        (
            r"^choose target creature card in a graveyard that was put there from the battlefield this turn\. put that card onto the battlefield under your control\.?$",
            {
                "target": "creature",
                "count": 1,
                "target_graveyard_controller": "any_player",
                "battlefield_controller": "self",
                "graveyard_from_battlefield_this_turn": True,
                "oracle_complexity_supported": True,
            },
        ),
        (
            r"^return target permanent card from your graveyard to the battlefield\.?$",
            {"target": "permanent", "count": 1},
        ),
        (
            r"^return target artifact card from your graveyard to the battlefield\.?$",
            {"target": "artifact", "count": 1},
        ),
        (
            r"^return target enchantment card from your graveyard to the battlefield\.?$",
            {"target": "enchantment", "count": 1},
        ),
        (
            r"^return target creature card from your graveyard to the battlefield\.?$",
            {"target": "creature", "count": 1},
        ),
        (
            r"^return target creature card with mana value (?P<mana_value_max>\d+) or less from your graveyard to the battlefield(?P<tapped> tapped)?\.?$",
            {
                "target": "creature",
                "count": 1,
                "target_graveyard_controller": "self",
                "battlefield_controller": "self",
            },
        ),
        (
            r"^return target creature card with mana value x or less from your graveyard to the battlefield(?P<tapped> tapped)?\.?$",
            {
                "target": "creature",
                "count": 1,
                "target_graveyard_controller": "self",
                "battlefield_controller": "self",
                "mana_value_max_from_x": True,
            },
        ),
        (
            r"^return x target outlaw creature cards from your graveyard to the battlefield\.?(?: \([^)]*\))?$",
            {
                "target": "outlaw_creature",
                "count": 0,
                "target_graveyard_controller": "self",
                "battlefield_controller": "self",
                "count_from_x": True,
            },
        ),
        (
            r"^put target creature card from an opponent's graveyard onto the battlefield under your control\.?$",
            {
                "target": "creature",
                "count": 1,
                "target_graveyard_controller": "opponent",
                "battlefield_controller": "self",
            },
        ),
        (
            r"^put target creature card from a graveyard onto the battlefield under your control\.?$",
            {
                "target": "creature",
                "count": 1,
                "target_graveyard_controller": "any_player",
                "battlefield_controller": "self",
            },
        ),
    ]
    for pattern, spec in patterns:
        match = re.match(pattern, text)
        if not match:
            continue
        result = {
            "target": spec["target"],
            "count": spec["count"],
            "target_graveyard_controller": spec.get("target_graveyard_controller", "self"),
            "battlefield_controller": spec.get("battlefield_controller", "self"),
            "enters_tapped": bool(spec.get("enters_tapped") or match.groupdict().get("tapped")),
        }
        if match.groupdict().get("mana_value_max"):
            result["mana_value_max"] = int(match.group("mana_value_max"))
        if spec.get("mana_value_max_from_x"):
            result["mana_value_max_from_x"] = True
        if spec.get("mana_value_max_from_graveyard_permanent_count"):
            result["mana_value_max_from_graveyard_permanent_count"] = True
        if match.groupdict().get("total_mana_value_max"):
            result["recursion_total_mana_value_max"] = int(match.group("total_mana_value_max"))
        for flag in (
            "up_to_count",
            "count_from_x",
            "requires_different_names",
            "graveyard_from_battlefield_this_turn",
            "oracle_complexity_supported",
        ):
            if spec.get(flag):
                result[flag] = True
        return result
    return None


def recursion_multi_zone_target_from_phrase(phrase: str) -> str | None:
    normalized = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    mapping = {
        "creature": "creature",
        "permanent": "permanent",
        "nonland permanent": "nonland_permanent",
        "land": "land",
    }
    return mapping.get(normalized)


def recursion_multi_zone_destination_from_phrase(phrase: str) -> str | None:
    normalized = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    if normalized == "your hand":
        return "hand"
    if normalized == "the battlefield":
        return "battlefield"
    return None


def recursion_multi_zone_component(
    target: str,
    count: int,
    destination: str,
    *,
    enters_tapped: bool = False,
) -> dict[str, Any]:
    component = {
        "target": target,
        "target_constraints": recursion_target_constraints_for(target),
        "count": count,
        "up_to_count": True,
        "destination": destination,
        "target_controller": "self",
        "target_graveyard_controller": "self",
    }
    if destination == "battlefield":
        component["battlefield_controller"] = "self"
    if enters_tapped:
        component["enters_tapped"] = True
    return component


def recursion_multi_zone_components_from_oracle(metadata: dict[str, Any]) -> list[dict[str, Any]] | None:
    text = re.sub(r"\s+", " ", oracle_text(metadata)).strip().lower()
    pattern = (
        r"^return up to (?P<count_a>one|two|\d+) target (?P<target_a>creature|permanent|nonland permanent|land) "
        r"cards? from your graveyard to (?P<destination_a>your hand|the battlefield)(?P<tapped_a> tapped)?"
        r"(?:, then return|\. return) up to (?P<count_b>one|two|\d+) target "
        r"(?P<target_b>creature|permanent|nonland permanent|land) cards? from your graveyard to "
        r"(?P<destination_b>your hand|the battlefield)(?P<tapped_b> tapped)?\.?$"
    )
    match = re.match(pattern, text)
    if not match:
        return None
    components: list[dict[str, Any]] = []
    for suffix in ("a", "b"):
        count = _count_word_to_int(match.group(f"count_{suffix}"))
        target = recursion_multi_zone_target_from_phrase(match.group(f"target_{suffix}"))
        destination = recursion_multi_zone_destination_from_phrase(match.group(f"destination_{suffix}"))
        if count is None or count <= 0 or target is None or destination is None:
            return None
        components.append(
            recursion_multi_zone_component(
                target,
                count,
                destination,
                enters_tapped=bool(match.groupdict().get(f"tapped_{suffix}")),
            )
        )
    if {component["destination"] for component in components} != {"hand", "battlefield"}:
        return None
    return components


def _source_has_recursion_multi_zone_target(source_text: str, target: str) -> bool:
    text = str(source_text or "")
    if target == "creature":
        return "FILTER_CARD_CREATURE_YOUR_GRAVEYARD" in text or "FilterCreatureCard" in text
    if target == "permanent":
        return "FilterPermanentCard" in text or "permanent card from your graveyard" in text.lower()
    if target == "nonland_permanent":
        return "FilterNonlandCard" in text and "PermanentPredicate.instance" in text
    if target == "land":
        return "FILTER_CARD_LAND_FROM_YOUR_GRAVEYARD" in text or "FilterLandCard" in text
    return False


def source_supports_recursion_multi_zone_components(
    source_text: str,
    components: list[dict[str, Any]],
) -> dict[str, Any] | str:
    text = str(source_text or "")
    if len(components) != 2:
        return "recursion_multi_zone_component_count_not_supported"
    if has_additional_cost(text):
        return "recursion_multi_zone_additional_cost_not_supported"
    effect_order = [
        "battlefield" if class_name == "ReturnFromGraveyardToBattlefieldTargetEffect" else "hand"
        for class_name in re.findall(
            r"new\s+(ReturnFromGraveyardToBattlefieldTargetEffect|ReturnFromGraveyardToHandTargetEffect)\s*\(",
            text,
        )
    ]
    expected_order = [str(component.get("destination")) for component in components]
    if effect_order != expected_order:
        return "recursion_multi_zone_source_effect_order_mismatch"
    if "SecondTargetPointer" not in text:
        return "recursion_multi_zone_source_target_pointer_not_supported"
    for component in components:
        target = str(component.get("target") or "")
        count = int(component.get("count") or 0)
        if not _source_has_recursion_multi_zone_target(text, target):
            return "recursion_multi_zone_source_target_not_supported"
        if not re.search(rf"TargetCardInYourGraveyard\s*\(\s*0\s*,\s*{count}\s*,", text, re.S):
            return "recursion_multi_zone_source_count_not_supported"
        if component.get("enters_tapped") and not re.search(
            r"ReturnFromGraveyardToBattlefieldTargetEffect\s*\(\s*true\s*\)",
            text,
            re.S,
        ):
            return "recursion_multi_zone_source_tapped_not_supported"
    return {"recursion_components": components}


def recursion_all_to_battlefield_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text(metadata)
    patterns: list[tuple[str, dict[str, Any]]] = [
        (
            r"^return all enchantment cards from your graveyard to the battlefield(?P<tapped> tapped)?\.?$",
            {"target": "enchantment"},
        ),
        (
            r"^return all creature cards with mana value (?P<mana_value_max>\d+) or less from your graveyard to the battlefield(?P<tapped> tapped)?\.?$",
            {"target": "creature"},
        ),
        (
            r"^return all artifact and enchantment cards from your graveyard to the battlefield(?P<tapped> tapped)?\.?$",
            {"target": "artifact_or_enchantment"},
        ),
        (
            r"^return all artifact, enchantment, and planeswalker cards from your graveyard to the battlefield(?P<tapped> tapped)?\.?$",
            {"target": "artifact_or_enchantment_or_planeswalker"},
        ),
    ]
    for pattern, spec in patterns:
        match = re.match(pattern, text)
        if not match:
            continue
        result = {
            "target": spec["target"],
            "target_graveyard_controller": "self",
            "battlefield_controller": "self",
            "return_all_matching": True,
            "enters_tapped": bool(match.groupdict().get("tapped")),
        }
        if match.groupdict().get("mana_value_max"):
            result["mana_value_max"] = int(match.group("mana_value_max"))
        return result
    if re.match(
        r"^return each artifact and creature card with mana value x from your graveyard to the battlefield\.?$",
        text,
    ):
        return {
            "target": "artifact_or_creature",
            "target_graveyard_controller": "self",
            "battlefield_controller": "self",
            "return_all_matching": True,
            "mana_value_exact_from_x": True,
        }
    return None


def recursion_all_to_battlefield_from_source(source_text: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    constructors = re.findall(r"new\s+ReturnFromYourGraveyardToBattlefieldAllEffect\s*\(", text)
    if len(constructors) != 1:
        return "recursion_battlefield_all_source_not_single_effect"
    if has_additional_cost(text):
        return "recursion_battlefield_all_source_additional_cost_not_supported"
    if "PayVariableLifeCost" in text:
        return "recursion_battlefield_all_source_variable_life_cost_not_supported"
    enters_tapped = bool(
        re.search(r"ReturnFromYourGraveyardToBattlefieldAllEffect\s*\([^;]*,\s*true\s*\)", text, re.S)
    )
    target: str | None = None
    mana_value_max: int | None = None
    mana_value_exact_from_x = False
    lowered = text.lower()
    if (
        "FILTER_CARD_ENCHANTMENTS" in text
        or "FILTER_CARD_ENCHANTMENT" in text
        or "FilterEnchantmentCard" in text
        or "enchantment cards" in lowered
    ):
        target = "enchantment"
    if "FilterCreatureCard" in text or "FILTER_CARD_CREATURE" in text or "creature cards" in lowered:
        if target is not None:
            return "recursion_battlefield_all_source_target_not_supported"
        target = "creature"
    if "FilterArtifactOrEnchantmentCard" in text or "artifact and enchantment cards" in lowered:
        target = "artifact_or_enchantment"
    if (
        "CardType.ARTIFACT.getPredicate" in text
        and "CardType.ENCHANTMENT.getPredicate" in text
        and "CardType.PLANESWALKER.getPredicate" in text
    ):
        target = "artifact_or_enchantment_or_planeswalker"
    if (
        "CardType.ARTIFACT.getPredicate" in text
        and "CardType.CREATURE.getPredicate" in text
        and "GetXValue.instance" in text
        and "getManaValue() ==" in text
    ):
        target = "artifact_or_creature"
        mana_value_exact_from_x = True
    mana_value_match = re.search(
        r"ManaValuePredicate\s*\(\s*ComparisonType\.FEWER_THAN\s*,\s*(\d+)\s*\)",
        text,
    )
    if mana_value_match:
        mana_value_max = int(mana_value_match.group(1)) - 1
    if target is None:
        return "recursion_battlefield_all_source_target_not_supported"
    result = {
        "target": target,
        "target_graveyard_controller": "self",
        "battlefield_controller": "self",
        "return_all_matching": True,
        "enters_tapped": enters_tapped,
    }
    if mana_value_max is not None:
        result["mana_value_max"] = mana_value_max
    if mana_value_exact_from_x:
        result["mana_value_exact_from_x"] = True
    return result


def recursion_to_battlefield_with_counter_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text(metadata)
    patterns: list[tuple[str, dict[str, Any]]] = [
        (
            r"^return target creature card from your graveyard to the battlefield "
            r"with two additional \+1/\+1 counters on it\.?$",
            {
                "target": "creature",
                "count": 1,
                "target_graveyard_controller": "self",
                "battlefield_controller": "self",
                "counter_type": "+1/+1",
                "counter_amount": 2,
                "additional_counter": True,
            },
        ),
        (
            r"^return target creature card from your graveyard to the battlefield "
            r"with a lifelink counter on it\.?$",
            {
                "target": "creature",
                "count": 1,
                "target_graveyard_controller": "self",
                "battlefield_controller": "self",
                "counter_type": "lifelink",
                "counter_amount": 1,
                "keywords": ["lifelink"],
            },
        ),
        (
            r"^put one, two, or three target creature cards from graveyards onto the battlefield "
            r"under your control\. each of them enters with an additional -1/-1 counter on it\.?$",
            {
                "target": "creature",
                "count": 3,
                "target_count_min": 1,
                "target_graveyard_controller": "any_player",
                "battlefield_controller": "self",
                "counter_type": "-1/-1",
                "counter_amount": 1,
                "additional_counter": True,
            },
        ),
    ]
    for pattern, spec in patterns:
        if re.match(pattern, text):
            return dict(spec)
    return None


def recursion_battlefield_counter_from_source(source_text: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    effect_constructors = re.findall(
        r"new\s+ReturnFromGraveyardToBattlefieldWithCounterTargetEffect\s*\(",
        text,
    )
    if len(effect_constructors) != 1:
        return "recursion_battlefield_counter_source_not_single_effect"
    if "TargetCardInYourGraveyard" in text:
        target_graveyard_controller = "self"
    elif "TargetCardInGraveyard" in text and "TargetCardInYourGraveyard" not in text:
        target_graveyard_controller = "any_player"
    else:
        return "recursion_battlefield_counter_source_target_not_supported"
    if "FILTER_CARD_CREATURE" not in text and "FilterCreatureCard" not in text:
        return "recursion_battlefield_counter_source_target_not_supported"

    counter_matches = re.findall(
        r"CounterType\.(P1P1|M1M1|LIFELINK)\.createInstance\s*\(\s*(\d*)\s*\)",
        text,
    )
    if len(counter_matches) != 1:
        return "recursion_battlefield_counter_source_counter_not_supported"
    counter_symbol, raw_count = counter_matches[0]
    counter_type = {
        "P1P1": "+1/+1",
        "M1M1": "-1/-1",
        "LIFELINK": "lifelink",
    }[counter_symbol]
    counter_amount = int(raw_count or "1")

    count = 1
    target_count_min: int | None = None
    count_match = re.search(r"TargetCardInGraveyard\s*\(\s*(\d+)\s*,\s*(\d+)\s*,", text, re.S)
    if count_match:
        target_count_min = int(count_match.group(1))
        count = int(count_match.group(2))
    elif re.search(r"TargetCardInYourGraveyard\s*\(\s*0\s*,\s*(\d+)\s*,", text, re.S):
        return "recursion_battlefield_counter_source_target_not_supported"

    return {
        "target": "creature",
        "count": count,
        "target_count_min": target_count_min,
        "target_graveyard_controller": target_graveyard_controller,
        "battlefield_controller": "self",
        "counter_type": counter_type,
        "counter_amount": counter_amount,
    }


def source_supports_battlefield_recursion_target(source_text: str, target_graveyard_controller: str) -> bool:
    text = str(source_text or "")
    controller = str(target_graveyard_controller or "self")
    if controller == "self":
        return "TargetCardInYourGraveyard" in text
    if controller == "opponent":
        return "TargetCardInOpponentsGraveyard" in text
    if controller in {"any", "any_player"}:
        return "TargetCardInGraveyard" in text and "TargetCardInYourGraveyard" not in text
    return False


def source_supports_battlefield_recursion_target_type(source_text: str, target_type: str) -> bool:
    text = str(source_text or "")
    lowered = text.lower()
    target = str(target_type or "")
    if target == "creature":
        return (
            "FILTER_CARD_CREATURE" in text
            or "FilterCreatureCard" in text
            or "creature card" in lowered
        )
    if target == "land":
        return "FILTER_CARD_LAND" in text or "FilterLandCard" in text or "land card" in lowered
    if target == "artifact":
        return "FILTER_CARD_ARTIFACT" in text or "FilterArtifactCard" in text or "artifact card" in lowered
    if target == "vampire_or_wizard_creature":
        return (
            "FilterCreatureCard" in text
            and "SubType.VAMPIRE.getPredicate" in text
            and "SubType.WIZARD.getPredicate" in text
        ) or "vampire or wizard creature card" in lowered
    if target == "ally_creature":
        return "FilterCreatureCard" in text and "SubType.ALLY.getPredicate" in text
    if target == "outlaw_creature":
        return "FilterCreatureCard" in text and "OutlawPredicate" in text
    if target == "rebel_permanent":
        return "FilterPermanentCard" in text and "SubType.REBEL.getPredicate" in text
    if target == "aura_card":
        return "SubType.AURA.getPredicate" in text or "Aura card" in text
    if target == "nonland_permanent":
        return "FilterNonlandCard" in text and "PermanentPredicate" in text
    if target == "enchantment":
        return (
            "FILTER_CARD_ENCHANTMENT" in text
            or "FilterEnchantmentCard" in text
            or "enchantment card" in lowered
        )
    if target == "permanent":
        return "FilterPermanentCard" in text or "permanent card" in lowered
    return False


def source_supports_battlefield_recursion_mana_value(source_text: str, mana_value_max: int | None) -> bool:
    if mana_value_max is None:
        return True
    expected_exclusive = int(mana_value_max) + 1
    pattern = (
        r"ManaValuePredicate\s*\(\s*ComparisonType\.FEWER_THAN\s*,\s*"
        rf"{expected_exclusive}\s*\)"
    )
    return bool(re.search(pattern, source_text or ""))


def source_supports_battlefield_recursion_graveyard_permanent_count_mana_value(source_text: str) -> bool:
    text = str(source_text or "")
    return (
        "PermanentPredicate.instance" in text
        and "FilterNonlandCard" in text
        and "count(StaticFilters.FILTER_CARD_PERMANENT" in text
        and "getManaValue()" in text
    )


def source_supports_battlefield_recursion_x_mana_value(source_text: str) -> bool:
    text = str(source_text or "")
    return (
        "XManaValueTargetAdjuster" in text
        and "ComparisonType.OR_LESS" in text
    )


def source_supports_recursion_x_target_count(source_text: str) -> bool:
    text = str(source_text or "")
    return "XTargetsCountAdjuster" in text or (
        "TargetsCountAdjuster" in text and "GetXValue.instance" in text
    )


def source_supports_battlefield_recursion_total_mana_value(
    source_text: str,
    total_mana_value_max: int | None,
) -> bool:
    if total_mana_value_max is None:
        return True
    text = str(source_text or "")
    return (
        "checkCanTargetTotalValueLimit" in text
        and "checkPossibleTargetsTotalValueLimit" in text
        and "MageObject::getManaValue" in text
        and re.search(rf"\b{int(total_mana_value_max)}\s*,\s*game", text) is not None
    )


def source_supports_battlefield_recursion_different_names(source_text: str, required: bool) -> bool:
    if not required:
        return True
    text = str(source_text or "")
    lowered = text.lower()
    return (
        "different names" in lowered
        and "getTargets().contains" in text
        and "Collectors.toSet" in text
    )


def source_supports_battlefield_recursion_this_turn(source_text: str, required: bool) -> bool:
    if not required:
        return True
    text = str(source_text or "")
    return (
        "PutIntoGraveFromBattlefieldThisTurnPredicate" in text
        and "CardsPutIntoGraveyardWatcher" in text
    )


def recursion_effect_text_from_oracle(metadata: dict[str, Any]) -> str | None:
    text = oracle_text(metadata)
    if not text:
        return None
    for sentence in re.split(r"(?<=\.)\s+", text):
        candidate = sentence.strip()
        if not candidate:
            continue
        if not candidate.endswith("."):
            candidate = candidate + "."
        if (
            candidate.startswith(("return ", "put "))
            and "from your graveyard" in candidate
            and "flashback" not in candidate
            and "cycling" not in candidate
        ):
            return candidate
    return None


def auxiliary_cost_from_oracle(metadata: dict[str, Any], keyword: str) -> str | None:
    match = re.search(
        rf"\b{re.escape(keyword.lower())}\s+(?P<cost>(?:\{{[0-9wubrg]+\}})+)",
        oracle_text(metadata),
    )
    if not match:
        return None
    cost = canonical_mana_cost_text(match.group("cost"))
    return cost if parse_mana_cost_text(cost) is not None else None


def parse_flashback_cost_from_source(source_text: str) -> str | None:
    text = str(source_text or "")
    match = re.search(
        r"new\s+FlashbackAbility\s*\(\s*this\s*,\s*new\s+ManaCostsImpl<[^>]*>\s*\(\s*"
        r'"(?P<cost>[^"]+)"\s*\)\s*\)',
        text,
        re.S,
    )
    if not match:
        return None
    cost = canonical_mana_cost_text(match.group("cost"))
    return cost if parse_mana_cost_text(cost) is not None else None


def parse_cycling_cost_from_source(source_text: str) -> str | None:
    text = str(source_text or "")
    mana_match = re.search(
        r"new\s+CyclingAbility\s*\(\s*new\s+ManaCostsImpl<[^>]*>\s*\(\s*"
        r'"(?P<cost>[^"]+)"\s*\)\s*\)',
        text,
        re.S,
    )
    if mana_match:
        cost = canonical_mana_cost_text(mana_match.group("cost"))
        return cost if parse_mana_cost_text(cost) is not None else None
    generic_match = re.search(
        r"new\s+CyclingAbility\s*\(\s*new\s+GenericManaCost\s*\(\s*(?P<generic>\d+)\s*\)\s*\)",
        text,
        re.S,
    )
    if generic_match:
        return "{" + generic_match.group("generic") + "}"
    return None


def auxiliary_recursion_spell_fields_from_source(
    metadata: dict[str, Any],
    source_text: str,
    abilities: set[str],
) -> dict[str, Any] | str:
    if not is_spell(metadata):
        return "recursion_auxiliary_not_spell"
    if not abilities:
        return {}
    unsupported = abilities - AUXILIARY_RECURSION_SPELL_ABILITY_CLASSES
    if unsupported:
        return "recursion_auxiliary_ability_class_not_supported"

    fields: dict[str, Any] = {
        "xmage_auxiliary_ability_classes": sorted(abilities),
    }
    if "FlashbackAbility" in abilities:
        source_cost = parse_flashback_cost_from_source(source_text)
        oracle_cost = auxiliary_cost_from_oracle(metadata, "flashback")
        if not source_cost or not oracle_cost:
            return "recursion_auxiliary_flashback_cost_not_supported"
        if source_cost != oracle_cost:
            return "recursion_auxiliary_flashback_cost_mismatch"
        fields["flashback_cost"] = source_cost
        fields["flashback_status"] = "runtime_executor_v1"
    if "CyclingAbility" in abilities:
        source_cost = parse_cycling_cost_from_source(source_text)
        oracle_cost = auxiliary_cost_from_oracle(metadata, "cycling")
        if not source_cost or not oracle_cost:
            return "recursion_auxiliary_cycling_cost_not_supported"
        if source_cost != oracle_cost:
            return "recursion_auxiliary_cycling_cost_mismatch"
        fields["cycling_cost"] = source_cost
        fields["cycling_status"] = "runtime_executor_v1"
    return fields


def _count_word_to_int(value: str) -> int | None:
    text = str(value or "").strip().lower()
    if text.isdigit():
        return int(text)
    return NUMBER_WORDS.get(text)


def primary_graveyard_exile_text_from_oracle(metadata: dict[str, Any]) -> str | None:
    text = oracle_text(metadata)
    if not text:
        return None
    for sentence in re.split(r"(?<=\.)\s+", text):
        candidate = sentence.strip()
        if not candidate:
            continue
        if not candidate.endswith("."):
            candidate = candidate + "."
        if candidate.startswith("exile ") and "graveyard" in candidate:
            return candidate
    return None


def graveyard_exile_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = primary_graveyard_exile_text_from_oracle(metadata)
    if text is None:
        return "graveyard_exile_oracle_not_simple"
    if re.match(r"^exile target card from a graveyard\.?$", text):
        return {
            "target": "any_card",
            "count": 1,
            "target_controller": "any",
            "single_graveyard": False,
            "up_to_count": False,
            "target_count_from_x": False,
        }
    match = re.match(
        r"^exile up to (?P<count>[a-z0-9]+) target cards from a single graveyard\.?$",
        text,
    )
    if match:
        count = _count_word_to_int(match.group("count"))
        if count is None:
            return "graveyard_exile_oracle_count_not_supported"
        return {
            "target": "any_card",
            "count": count,
            "target_controller": "any",
            "single_graveyard": True,
            "up_to_count": True,
            "target_count_from_x": False,
        }
    if re.match(r"^exile x target cards from a single graveyard\.?$", text):
        return {
            "target": "any_card",
            "count": 1,
            "target_controller": "any",
            "single_graveyard": True,
            "up_to_count": False,
            "target_count_from_x": True,
        }
    return "graveyard_exile_oracle_not_simple"


def graveyard_exile_from_source(source_text: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    if len(re.findall(r"new\s+ExileTargetEffect\s*\(", text)) != 1:
        return "graveyard_exile_source_not_single_effect"
    if "TargetCardInASingleGraveyard" in text:
        match = re.search(
            r"TargetCardInASingleGraveyard\s*\(\s*(?P<min>\d+)\s*,\s*(?P<max>\d+)\s*,",
            text,
            re.S,
        )
        if not match:
            return "graveyard_exile_source_target_not_supported"
        min_count = int(match.group("min"))
        max_count = int(match.group("max"))
        return {
            "target": "any_card",
            "count": max_count,
            "target_controller": "any",
            "single_graveyard": True,
            "up_to_count": min_count == 0,
            "target_count_from_x": "XTargetsCountAdjuster" in text,
        }
    if "TargetCardInGraveyard" in text:
        return {
            "target": "any_card",
            "count": 1,
            "target_controller": "any",
            "single_graveyard": False,
            "up_to_count": False,
            "target_count_from_x": False,
        }
    return "graveyard_exile_source_target_not_supported"


def graveyard_to_library_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text(metadata)
    patterns: list[tuple[str, dict[str, Any]]] = [
        (
            r"^put target card from your graveyard on top of your library\.?$",
            {"target": "any_card", "count": 1, "destination": "library_top", "up_to_count": False},
        ),
        (
            r"^put target card from your graveyard on the bottom of your library\.?$",
            {
                "target": "any_card",
                "count": 1,
                "destination": "library_bottom",
                "up_to_count": False,
                "target_graveyard_controller": "self",
                "library_controller": "self",
            },
        ),
        (
            r"^put target card from a graveyard on the bottom of its owner's library\.?$",
            {
                "target": "any_card",
                "count": 1,
                "destination": "library_bottom",
                "up_to_count": False,
                "target_graveyard_controller": "any",
                "library_controller": "owner",
            },
        ),
        (
            r"^put up to one target card from a graveyard on the bottom of its owner's library\.?$",
            {
                "target": "any_card",
                "count": 1,
                "destination": "library_bottom",
                "up_to_count": True,
                "target_graveyard_controller": "any",
                "library_controller": "owner",
            },
        ),
        (
            r"^put target creature card from your graveyard on top of your library\.?$",
            {"target": "creature", "count": 1, "destination": "library_top", "up_to_count": False},
        ),
        (
            r"^put target creature card from your graveyard on the bottom of your library\.?$",
            {"target": "creature", "count": 1, "destination": "library_bottom", "up_to_count": False},
        ),
        (
            r"^put up to three target creature cards from your graveyard on top of your library\.?$",
            {"target": "creature", "count": 3, "destination": "library_top", "up_to_count": True},
        ),
        (
            r"^put up to three target creature cards from your graveyard on the bottom of your library\.?$",
            {"target": "creature", "count": 3, "destination": "library_bottom", "up_to_count": True},
        ),
    ]
    for pattern, result in patterns:
        if re.match(pattern, text):
            parsed = dict(result)
            parsed.setdefault("target_graveyard_controller", "self")
            parsed.setdefault("library_controller", "self")
            return parsed

    generic_patterns: list[tuple[str, str]] = [
        (
            r"^put target (?P<phrase>.+?) card from your graveyard on top of your library\.?$",
            "library_top",
        ),
        (
            r"^put target (?P<phrase>.+?) card from your graveyard on the bottom of your library\.?$",
            "library_bottom",
        ),
        (
            r"^put up to (?P<count>one|two|three|\d+) target (?P<phrase>.+?) cards? "
            r"from your graveyard on top of your library\.?$",
            "library_top",
        ),
        (
            r"^put up to (?P<count>one|two|three|\d+) target (?P<phrase>.+?) cards? "
            r"from your graveyard on the bottom of your library\.?$",
            "library_bottom",
        ),
    ]
    count_words = {"one": 1, "two": 2, "three": 3}
    for pattern, destination in generic_patterns:
        match = re.match(pattern, text)
        if not match:
            continue
        target = etb_recursion_target_from_phrase(match.group("phrase"))
        if target is None:
            continue
        raw_count = match.groupdict().get("count")
        count = count_words.get(raw_count or "", int(raw_count) if raw_count and raw_count.isdigit() else 1)
        return {
            "target": target,
            "count": count,
            "destination": destination,
            "up_to_count": bool(raw_count),
            "target_graveyard_controller": "self",
            "library_controller": "self",
        }
    return None


def graveyard_shuffle_to_library_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = oracle_text(metadata)
    match = re.match(
        r"^target player shuffles up to (?P<count>one|two|three|four|\d+) "
        r"target cards? from their graveyard into their library\.(?: .*)?$",
        text,
    )
    if not match:
        return "graveyard_shuffle_to_library_oracle_not_simple"
    count_words = {"one": 1, "two": 2, "three": 3, "four": 4}
    raw_count = match.group("count")
    count = count_words.get(raw_count, int(raw_count) if raw_count.isdigit() else 0)
    if count <= 0:
        return "graveyard_shuffle_to_library_oracle_count_not_supported"
    return {
        "target": "any_card",
        "count": count,
        "destination": "library_shuffle",
        "up_to_count": True,
        "target_graveyard_controller": "target_player",
        "target_controller": "target_player",
        "library_controller": "target_player",
    }


def graveyard_to_library_from_source(source_text: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    effect_matches = re.findall(r"new\s+PutOnLibraryTargetEffect\s*\(\s*(true|false)\s*\)", text)
    if len(effect_matches) != 1:
        return "graveyard_to_library_source_not_single_effect"
    destination = "library_top" if effect_matches[0] == "true" else "library_bottom"
    if "EachTargetPointer" in text or ".setTargetPointer" in text:
        return "graveyard_to_library_source_target_not_supported"
    target_graveyard_controller = "self"
    library_controller = "self"
    if "TargetCardInGraveyard" in text and "TargetCardInYourGraveyard" not in text:
        if not re.search(r"TargetCardInGraveyard\s*\(\s*(?:\)|0\s*,\s*\d+\s*\))", text):
            return "graveyard_to_library_source_target_not_supported"
        target = "any_card"
        target_graveyard_controller = "any"
        library_controller = "owner"
    elif "FILTER_CARD_ARTIFACT_OR_CREATURE" in text:
        target = "artifact_or_creature"
    elif "FILTER_CARD_INSTANT_OR_SORCERY_FROM_YOUR_GRAVEYARD" in text or "FilterInstantOrSorceryCard" in text:
        target = "instant_or_sorcery"
    elif (
        "FilterNonlandCard" in text
        and "Predicates.not" in text
        and "CardType.CREATURE.getPredicate()" in text
    ):
        target = "noncreature_nonland"
    elif "FILTER_CARD_CREATURES_YOUR_GRAVEYARD" in text or "FILTER_CARD_CREATURE_YOUR_GRAVEYARD" in text:
        target = "creature"
    elif re.search(r"TargetCardInYourGraveyard\s*\(\s*\)", text):
        target = "any_card"
    else:
        return "graveyard_to_library_source_target_not_supported"
    count = 1
    up_to = False
    count_match = re.search(r"TargetCardIn(?:Your)?Graveyard\s*\(\s*0\s*,\s*(\d+)", text, re.S)
    if count_match:
        count = int(count_match.group(1))
        up_to = True
    return {
        "target": target,
        "count": count,
        "destination": destination,
        "up_to_count": up_to,
        "target_graveyard_controller": target_graveyard_controller,
        "library_controller": library_controller,
    }


def graveyard_shuffle_to_library_from_source(source_text: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    if len(re.findall(r"TargetPlayerShufflesTargetCardsEffect\s*\(", text)) != 1:
        return "graveyard_shuffle_to_library_source_not_single_effect"
    if len(re.findall(r"new\s+TargetPlayer\s*\(", text)) != 1:
        return "graveyard_shuffle_to_library_source_target_player_not_supported"
    target_match = re.search(r"TargetCardInTargetPlayersGraveyard\s*\(\s*(\d+)\s*\)", text)
    if not target_match:
        return "graveyard_shuffle_to_library_source_target_cards_not_supported"
    count = int(target_match.group(1))
    if count <= 0 or count > 20:
        return "graveyard_shuffle_to_library_source_count_not_supported"
    return {
        "target": "any_card",
        "count": count,
        "destination": "library_shuffle",
        "up_to_count": True,
        "target_graveyard_controller": "target_player",
        "target_controller": "target_player",
        "library_controller": "target_player",
    }


def activated_graveyard_to_library_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text(metadata)).strip().lower()
    if text.count(":") != 1:
        return "activated_graveyard_to_library_oracle_not_simple"
    effect_text = text.rsplit(":", 1)[1].strip()
    parsed = graveyard_to_library_from_oracle({"oracle_text": effect_text})
    if parsed is None:
        return "activated_graveyard_to_library_oracle_not_simple"
    return parsed


def activated_graveyard_to_library_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    risky_cost_classes = {
        "CompositeCost",
        "DiscardCardCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "MillCardsCost",
        "OrCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "RevealTargetFromHandCost",
        "TapTargetCost",
    }
    present_risky = sorted(cost for cost in risky_cost_classes if cost in text)
    if present_risky:
        return "activated_graveyard_to_library_source_cost_not_supported"
    if "Zone.GRAVEYARD" in text:
        return "activated_graveyard_to_library_source_not_battlefield"
    effect_matches = re.findall(r"PutOnLibraryTargetEffect\s*\(", text)
    if len(effect_matches) != 1:
        return "activated_graveyard_to_library_source_not_single_effect"
    if len(re.findall(r"SimpleActivatedAbility\s*\(", text)) != 1:
        return "activated_graveyard_to_library_source_multiple_abilities_not_supported"
    effect_index = text.find("PutOnLibraryTargetEffect")
    window = text[max(0, effect_index - 500) : effect_index + 1800]
    if "SimpleActivatedAbility" not in window:
        return "activated_graveyard_to_library_source_not_simple_activated"
    parsed_target = graveyard_to_library_from_source(text)
    if isinstance(parsed_target, str):
        return "activated_graveyard_to_library_" + parsed_target.removeprefix("graveyard_to_library_")
    cost_text = "{0}"
    mana_match = re.search(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_match = re.search(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    colored_match = re.search(r"ColoredManaCost\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)", window)
    if mana_match:
        cost_text = mana_match.group(1)
    elif generic_match:
        cost_text = "{" + generic_match.group(1) + "}"
    elif colored_match:
        cost_text = "{" + colored_match.group(1) + "}"
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_graveyard_to_library_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    return {
        **parsed_target,
        "activation_cost_mana": canonical_mana_cost_text(cost_text),
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": "TapSourceCost" in window,
        "activation_requires_sacrifice": "SacrificeSourceCost" in window,
    }


def etb_graveyard_to_library_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = oracle_text_after_leading_static_keywords(metadata)
    trigger_prefix = r"^when (?:this creature|[^,]+?) enters(?: the battlefield)?, (?:you may )?"
    match = re.match(
        trigger_prefix
        + r"(?P<effect>put .+? from (?:your|a) graveyard .+? (?:your|its owner's) library\.?)$",
        text,
    )
    if not match:
        return "etb_graveyard_to_library_oracle_not_simple"
    parsed = graveyard_to_library_from_oracle({"oracle_text": match.group("effect")})
    if parsed is None:
        return "etb_graveyard_to_library_oracle_not_simple"
    return parsed


def etb_graveyard_to_library_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if "EntersBattlefieldTriggeredAbility" not in text:
        return "etb_graveyard_to_library_source_not_etb_trigger"
    if "SimpleActivatedAbility" in text:
        return "etb_graveyard_to_library_source_not_etb_trigger"
    if len(re.findall(r"PutOnLibraryTargetEffect\s*\(", text)) != 1:
        return "etb_graveyard_to_library_source_not_single_effect"
    parsed_target = graveyard_to_library_from_source(text)
    if isinstance(parsed_target, str):
        return "etb_" + parsed_target
    return parsed_target


def destroy_all_spec_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text(metadata)
    patterns: list[tuple[str, dict[str, Any]]] = [
        (r"^destroy all creatures(?:\. they can't be regenerated\.)?\.?$", ["creature"]),
        (r"^destroy all artifacts(?:\. they can't be regenerated\.)?\.?$", ["artifact"]),
        (r"^destroy all enchantments(?:\. they can't be regenerated\.)?\.?$", ["enchantment"]),
        (r"^destroy all artifacts and enchantments(?:\. they can't be regenerated\.)?\.?$", ["artifact", "enchantment"]),
        (r"^destroy all creatures and lands(?:\. they can't be regenerated\.)?\.?$", ["creature", "land"]),
        (
            r"^destroy all artifacts, creatures, and enchantments(?:\. they can't be regenerated\.)?\.?$",
            ["artifact", "creature", "enchantment"],
        ),
    ]
    for pattern, card_types in patterns:
        if re.match(pattern, text):
            return {"destroy_card_types": card_types}
    match = re.match(
        r"^destroy all (?P<subtype>plains|islands|swamps|mountains|forests)(?:\. they can't be regenerated\.)?\.?$",
        text,
    )
    if match:
        subtype = {
            "plains": "plains",
            "islands": "island",
            "swamps": "swamp",
            "mountains": "mountain",
            "forests": "forest",
        }[match.group("subtype")]
        return {
            "destroy_card_types": ["land"],
            "destroy_required_subtypes": [subtype],
        }
    match = re.match(
        r"^destroy all (?P<color>white|blue|black|red|green) (?P<kind>creatures|permanents)(?:\. they can't be regenerated\.)?\.?$",
        text,
    )
    if match:
        return {
            "destroy_card_types": ["creature" if match.group("kind") == "creatures" else "permanent"],
            "destroy_required_colors": [TOKEN_COLOR_WORDS[match.group("color")]],
        }
    match = re.match(
        r"^destroy all non(?P<color>white|blue|black|red|green) creatures(?:\. they can't be regenerated\.)?\.?$",
        text,
    )
    if match:
        return {
            "destroy_card_types": ["creature"],
            "destroy_excluded_colors": [TOKEN_COLOR_WORDS[match.group("color")]],
        }
    if re.match(r"^destroy all creatures you don't control(?:\. they can't be regenerated\.)?\.?$", text):
        return {"destroy_card_types": ["creature"], "destroy_controller": "opponents_control"}
    if re.match(r"^destroy all nonland permanents(?:\. they can't be regenerated\.)?\.?$", text):
        return {"destroy_card_types": ["permanent"], "destroy_exclude_card_types": ["land"]}
    if re.match(r"^destroy all nonartifact creatures(?:\. they can't be regenerated\.)?\.?$", text):
        return {"destroy_card_types": ["creature"], "destroy_exclude_card_types": ["artifact"]}
    if re.match(r"^destroy all nonartifact permanents(?:\. they can't be regenerated\.)?\.?$", text):
        return {"destroy_card_types": ["permanent"], "destroy_exclude_card_types": ["artifact"]}
    if re.match(r"^destroy all tapped creatures(?:\. they can't be regenerated\.)?\.?$", text):
        return {"destroy_card_types": ["creature"], "destroy_tapped_state": "tapped"}
    if re.match(r"^destroy all nonbasic lands(?:\. they can't be regenerated\.)?\.?$", text):
        return {"destroy_card_types": ["land"], "destroy_nonbasic_lands": True}
    match = re.match(
        r"^destroy all creatures with mana value (?P<value>\d+) or less(?:\. they can't be regenerated\.)?\.?$",
        text,
    )
    if match:
        return {"destroy_card_types": ["creature"], "destroy_mana_value_lte": int(match.group("value"))}
    match = re.match(
        r"^destroy all creatures with power (?P<value>\d+) or greater(?:\. they can't be regenerated\.)?\.?$",
        text,
    )
    if match:
        return {"destroy_card_types": ["creature"], "destroy_power_gte": int(match.group("value"))}
    match = re.match(
        r"^destroy all creatures with toughness (?P<value>\d+) or greater(?:\. they can't be regenerated\.)?\.?$",
        text,
    )
    if match:
        return {"destroy_card_types": ["creature"], "destroy_toughness_gte": int(match.group("value"))}
    return None


def destroy_all_types_from_oracle(metadata: dict[str, Any]) -> list[str] | None:
    spec = destroy_all_spec_from_oracle(metadata)
    if not spec:
        return None
    return list(spec.get("destroy_card_types") or [])


def damage_all_spec_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text(metadata)
    if re.match(r"^.+ deals? \d+ damage to each creature\.?$", text):
        return {"damage_scope": "each_creature"}
    if re.match(r"^.+ deals? \d+ damage to each creature and each planeswalker\.?$", text):
        return {"damage_scope": "each_creature_and_planeswalker"}
    if re.match(r"^.+ deals? \d+ damage to each creature your opponents control\.?$", text):
        return {"damage_scope": "each_creature_opponents_control"}
    if re.match(r"^.+ deals? \d+ damage to each creature with flying\.?$", text):
        return {"damage_scope": "each_flying_creature"}
    if re.match(r"^.+ deals? \d+ damage to each creature without flying\.?$", text):
        return {"damage_scope": "each_creature_without_flying"}
    if re.match(r"^.+ deals? \d+ damage to each attacking creature\.?$", text):
        return {"damage_scope": "each_attacking_creature"}
    if re.match(r"^.+ deals? \d+ damage to each blocking creature and each blocked creature\.?$", text):
        return {"damage_scope": "each_blocking_or_blocked_creature"}
    if re.match(r"^.+ deals? \d+ damage to each creature dealt damage this turn\.?$", text):
        return {"damage_scope": "each_creature_dealt_damage_this_turn"}
    if re.match(r"^.+ deals? \d+ damage to each tapped creature\.?$", text):
        return {"damage_scope": "each_tapped_creature"}
    if re.match(r"^.+ deals? \d+ damage to each untapped creature\.?$", text):
        return {"damage_scope": "each_untapped_creature"}
    if re.match(r"^.+ deals? \d+ damage to each nonartifact creature\.?$", text):
        return {"damage_scope": "each_nonartifact_creature"}
    if re.match(r"^.+ deals? \d+ damage to each non[- ]?token creature\.?$", text):
        return {
            "damage_scope": "each_creature",
            "damage_exclude_tokens": True,
        }
    color_match = re.match(
        r"^.+ deals? \d+ damage to each (?P<colors>(?:white|blue|black|red|green)(?: and/or (?:white|blue|black|red|green))*) creature\.?$",
        text,
    )
    if color_match:
        color_words = [
            part.strip()
            for part in re.split(r"\s+and/or\s+", color_match.group("colors"))
            if part.strip()
        ]
        color_symbols = [
            TOKEN_COLOR_WORDS[color_word]
            for color_word in color_words
            if color_word in TOKEN_COLOR_WORDS
        ]
        if color_symbols and len(color_symbols) == len(color_words):
            return {
                "damage_scope": "each_creature",
                "damage_required_colors": ordered_color_symbols(color_symbols),
            }
    excluded_subtype = re.match(
        r"^.+ deals? \d+ damage to each non[- ](?P<subtype>[a-z][a-z ]*) creature\.?$",
        text,
    )
    if excluded_subtype:
        subtype = re.sub(r"\s+", " ", excluded_subtype.group("subtype")).strip().lower()
        if subtype and subtype not in {"artifact", "token"}:
            return {
                "damage_scope": "each_creature",
                "damage_excluded_subtypes": [subtype],
            }
    return None


def damage_all_scope_from_oracle(metadata: dict[str, Any]) -> str | None:
    spec = damage_all_spec_from_oracle(metadata)
    if not spec:
        return None
    return str(spec["damage_scope"])


def dynamic_damage_all_scope_from_phrase(phrase: str) -> dict[str, Any] | None:
    token = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    if token == "each creature":
        return {"damage_scope": "each_creature"}
    if token == "each creature and each planeswalker":
        return {"damage_scope": "each_creature_and_planeswalker"}
    if token == "each creature and planeswalker you don't control":
        return {"damage_scope": "each_creature_and_planeswalker_opponents_control"}
    if token == "each creature with flying":
        return {"damage_scope": "each_flying_creature"}
    return None


def x_damage_all_spec_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    if re.match(r"^.+ deals? x damage to each creature\.?$", text):
        return {"damage_scope": "each_creature"}
    if re.match(r"^.+ deals? x damage to each creature with flying\.?$", text):
        return {"damage_scope": "each_flying_creature"}
    return None


def x_damage_all_source_blocker(source: str, spec: dict[str, Any]) -> str | None:
    text = source or ""
    if has_additional_cost(text):
        return "board_wipe_x_damage_additional_cost_not_supported"
    constructor_args = extract_constructor_args(text, "DamageAllEffect")
    if constructor_args is None:
        return "board_wipe_x_damage_source_not_supported"
    parts = split_top_level_args(constructor_args)
    if not parts:
        return "board_wipe_x_damage_source_not_supported"
    first_arg = re.sub(r"\s+", "", parts[0])
    x_value = first_arg in {"GetXValue.instance", "ManacostVariableValue.instance"} or (
        first_arg == "xValue"
        and re.search(
            r"(?:DynamicValue\s+)?xValue\s*=\s*(?:GetXValue|ManacostVariableValue)\.instance",
            text,
        )
    )
    if not x_value:
        return "board_wipe_x_damage_source_not_supported"
    damage_scope = str(spec.get("damage_scope") or "")
    if damage_scope == "each_flying_creature" and "FILTER_CREATURE_FLYING" not in text:
        return "board_wipe_damage_source_scope_mismatch"
    if damage_scope == "each_creature" and "FILTER_CREATURE_FLYING" in text:
        return "board_wipe_damage_source_scope_mismatch"
    return None


def dynamic_damage_all_spec_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    where_match = re.match(
        r"^.+ deals? x damage to (?P<target>.+?), where x is (?P<filter>.+?)\.?$",
        text,
    )
    if where_match:
        damage_spec = dynamic_damage_all_scope_from_phrase(where_match.group("target"))
        if damage_spec is None:
            return "board_wipe_dynamic_damage_scope_not_supported"
        filter_text = re.sub(r"^the number of\s+", "", where_match.group("filter").strip())
        count_fields = _dynamic_damage_count_fields_from_filter(filter_text)
        if isinstance(count_fields, str):
            return count_fields
        if count_fields is None:
            return "dynamic_count_damage_oracle_filter_not_supported"
        amount_source = str(count_fields.pop("damage_amount_source"))
        return {
            **damage_spec,
            "damage_amount_source": amount_source,
            "damage_base_amount": 0,
            "damage_per_count": 1,
            **count_fields,
        }
    equal_match = re.match(
        r"^.+ deals? damage to (?P<target>.+?) equal to (?P<filter>.+?)\.?$",
        text,
    )
    if equal_match:
        damage_spec = dynamic_damage_all_scope_from_phrase(equal_match.group("target"))
        if damage_spec is None:
            return "board_wipe_dynamic_damage_scope_not_supported"
        count_fields = _dynamic_damage_count_fields_from_filter(equal_match.group("filter"))
        if isinstance(count_fields, str):
            return count_fields
        if count_fields is None:
            return "dynamic_count_damage_oracle_filter_not_supported"
        amount_source = str(count_fields.pop("damage_amount_source"))
        return {
            **damage_spec,
            "damage_amount_source": amount_source,
            "damage_base_amount": 0,
            "damage_per_count": 1,
            **count_fields,
        }
    return None


def dynamic_damage_all_source_spec_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    if has_additional_cost(text):
        return "board_wipe_dynamic_damage_additional_cost_not_supported"
    if len(re.findall(r"new\s+DamageAllEffect\s*\(", text)) != 1:
        return "board_wipe_dynamic_damage_source_not_single"
    constructor_args = extract_constructor_args(text, "DamageAllEffect")
    if constructor_args is None:
        return "board_wipe_dynamic_damage_source_not_supported"
    parts = split_top_level_args(constructor_args)
    if not parts:
        return "board_wipe_dynamic_damage_source_not_supported"
    spec = _dynamic_count_damage_source_spec_from_expr(text, parts[0])
    if isinstance(spec, str) or spec is None:
        return spec
    return {
        "damage_base_amount": int(spec.get("damage_base_amount") or 0),
        "damage_per_count": int(spec.get("damage_per_count") or 1),
        **{
            key: value
            for key, value in spec.items()
            if key not in {"damage_base_amount", "damage_per_count"}
        },
    }


def dynamic_damage_all_source_matches_spec(source: str, oracle_spec: dict[str, Any], source_spec: dict[str, Any]) -> bool:
    if not damage_all_source_matches_spec(source, oracle_spec):
        return False
    comparable_keys = {
        "damage_amount_source",
        "damage_base_amount",
        "damage_per_count",
        "battlefield_count_scope",
        "battlefield_count_card_types",
        "battlefield_count_subtypes",
        "graveyard_count_scope",
        "graveyard_count_card_types",
        "graveyard_count_subtypes",
        "mana_symbol_count_color",
    }
    for key in comparable_keys:
        if oracle_spec.get(key) != source_spec.get(key):
            return False
    return True


def damage_all_source_matches_spec(source: str, spec: dict[str, Any]) -> bool:
    damage_scope = str(spec.get("damage_scope") or "")
    if damage_scope == "each_creature_and_planeswalker_opponents_control":
        text = source or ""
        if "FilterCreatureOrPlaneswalkerPermanent" not in text or "TargetController.NOT_YOU" not in text:
            return False
    if damage_scope == "each_flying_creature" and "FILTER_CREATURE_FLYING" not in (source or ""):
        return False
    if damage_scope == "each_creature" and "FILTER_CREATURE_FLYING" in (source or ""):
        return False
    if (
        damage_scope == "each_creature_dealt_damage_this_turn"
        and "WasDealtDamageThisTurnPredicate.instance" not in (source or "")
    ):
        return False
    if damage_scope == "each_blocking_or_blocked_creature":
        text = source or ""
        if "BlockingPredicate.instance" not in text or "BlockedPredicate.instance" not in text:
            return False
    if spec.get("damage_exclude_tokens") and "TokenPredicate.FALSE" not in (source or ""):
        return False
    required_colors = ordered_color_symbols(
        [
            str(value or "").strip().upper()
            for value in as_list(spec.get("damage_required_colors"))
            if str(value or "").strip()
        ]
    )
    if required_colors:
        object_color_symbols = {
            "WHITE": "W",
            "BLUE": "U",
            "BLACK": "B",
            "RED": "R",
            "GREEN": "G",
        }
        source_colors = ordered_color_symbols(
            [
                object_color_symbols[color]
                for color in re.findall(
                    r"ColorPredicate\s*\(\s*ObjectColor\.(WHITE|BLUE|BLACK|RED|GREEN)\s*\)",
                    source or "",
                )
            ]
        )
        if set(source_colors) != set(required_colors):
            return False
    excluded_subtypes = [
        str(value or "").strip().lower()
        for value in as_list(spec.get("damage_excluded_subtypes"))
        if str(value or "").strip()
    ]
    for subtype in excluded_subtypes:
        subtype_constant = re.sub(r"[^A-Z0-9]+", "_", subtype.upper()).strip("_")
        if not re.search(
            rf"Predicates\.not\s*\(\s*SubType\.{re.escape(subtype_constant)}\.getPredicate\s*\(\s*\)\s*\)",
            source or "",
            flags=re.DOTALL,
        ):
            return False
    return True


def board_wipe_source_blocker(source: str, classes: set[str]) -> str | None:
    text = source or ""
    if classes == {"DestroyAllEffect"}:
        if len(re.findall(r"new\s+DestroyAllEffect\s*\(", text)) != 1:
            return "board_wipe_source_multiple_destroy_all_effects"
        if re.search(r"\bnew\s+Mode\s*\(", text) or ".addMode(" in text:
            return "board_wipe_source_modal_not_supported"
        return None
    if classes == {"DamageAllEffect"}:
        if len(re.findall(r"new\s+DamageAllEffect\s*\(", text)) != 1:
            return "board_wipe_source_multiple_damage_all_effects"
        blockers = {
            "ColorsOfManaSpentToCastCount": "board_wipe_damage_amount_not_fixed",
            "DealtDamageToCreatureBySourceDies": "board_wipe_damage_replacement_not_supported",
        }
        for needle, reason in blockers.items():
            if needle in text:
                return reason
        if re.search(r"additional\s+\d+\s+damage", text, re.I):
            return "board_wipe_damage_scope_not_supported"
        return None
    if classes == {"SacrificeAllEffect"}:
        if len(re.findall(r"new\s+SacrificeAllEffect\s*\(", text)) != 1:
            return "board_wipe_source_multiple_sacrifice_all_effects"
        if "GetXValue" in text:
            return "board_wipe_sacrifice_count_not_fixed"
        return None
    return None


def fixed_sacrifice_count_word(value: str) -> int | None:
    token = str(value or "").strip().lower()
    if token in {"a", "an"}:
        return 1
    if token in NUMBER_WORDS:
        return int(NUMBER_WORDS[token])
    if token.isdigit():
        return int(token)
    return None


def each_player_sacrifice_spec_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str | None:
    text = oracle_text(metadata)
    text = re.sub(r"\s*\([^)]*\)\s*", " ", text)
    text = re.sub(r"\s+foretell\s+(?:\{[0-9wubrg]+\})+\s*$", "", text)
    text = re.sub(r"\s+", " ", text).strip()
    match = re.match(
        r"^each player sacrifices (?P<count>a|an|one|two|three|four|five|\d+) "
        r"(?P<target>creatures?|lands?|permanents?|enchantments?|multicolored permanents?)"
        r"(?: of their choice)?\.?$",
        text,
    )
    if not match:
        return "board_wipe_sacrifice_oracle_not_exact"
    count = fixed_sacrifice_count_word(match.group("count"))
    if count is None or count <= 0:
        return "board_wipe_sacrifice_count_not_fixed"
    target = match.group("target").strip()
    target_map = {
        "creature": ["creature"],
        "creatures": ["creature"],
        "land": ["land"],
        "lands": ["land"],
        "permanent": ["permanent"],
        "permanents": ["permanent"],
        "enchantment": ["enchantment"],
        "enchantments": ["enchantment"],
        "multicolored permanent": ["permanent"],
        "multicolored permanents": ["permanent"],
    }
    card_types = target_map.get(target)
    if card_types is None:
        return "board_wipe_sacrifice_target_not_supported"
    spec: dict[str, Any] = {
        "sacrifice_count": count,
        "sacrifice_card_types": card_types,
        "sacrifice_scope": "each_player",
        "sacrifice_choice": "controller_choice_lowest_value",
    }
    if target.startswith("multicolored"):
        spec["sacrifice_requires_multicolored"] = True
    return spec


def each_player_sacrifice_spec_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if "GetXValue" in text:
        return "board_wipe_sacrifice_count_not_fixed"
    matches = list(re.finditer(r"new\s+SacrificeAllEffect\s*\((?P<args>.*?)\)\s*;", text, re.S))
    if len(matches) != 1:
        return "board_wipe_source_multiple_sacrifice_all_effects"
    args = matches[0].group("args")
    count_match = re.match(r"\s*(\d+)\s*,", args, re.S)
    count = int(count_match.group(1)) if count_match else 1
    window = text
    lowered_args = args.lower()
    if "FILTER_PERMANENT_CREATURE" in args or "FilterControlledCreaturePermanent" in window:
        card_types = ["creature"]
    elif "FilterControlledLandPermanent" in window:
        card_types = ["land"]
    elif "FilterControlledEnchantmentPermanent" in window:
        card_types = ["enchantment"]
    elif re.search(r'FilterControlledPermanent\s*\(\s*"permanent"', window):
        card_types = ["permanent"]
    elif "MulticoloredPredicate" in window and re.search(r'FilterControlledPermanent\s*\(\s*"multicolored permanent"', window):
        card_types = ["permanent"]
    else:
        return "board_wipe_sacrifice_source_target_not_supported"
    spec: dict[str, Any] = {
        "sacrifice_count": count,
        "sacrifice_card_types": card_types,
        "sacrifice_scope": "each_player",
        "sacrifice_choice": "controller_choice_lowest_value",
    }
    if "multicoloredpredicate" in lowered_args or "MulticoloredPredicate" in window:
        spec["sacrifice_requires_multicolored"] = True
    return spec


COUNTER_WORD_NUMBERS = {
    "a": 1,
    "an": 1,
    "one": 1,
    "two": 2,
    "three": 3,
    "four": 4,
    "five": 5,
    "six": 6,
    "seven": 7,
    "eight": 8,
    "nine": 9,
    "ten": 10,
}


def counter_count_from_text(value: str) -> int | None:
    token = str(value or "").strip().lower()
    if token.isdigit():
        return int(token)
    return COUNTER_WORD_NUMBERS.get(token)


def fixed_counter_target_from_source(source: str) -> tuple[str, int] | None:
    matches = re.findall(
        r"AddCountersTargetEffect\s*\(\s*CounterType\.(P1P1|M1M1)\.createInstance\s*\(\s*(\d*)\s*\)",
        source or "",
    )
    if len(matches) != 1:
        return None
    if len(re.findall(r"\.addTarget\s*\(\s*new\s+TargetCreaturePermanent\s*\(", source or "")) != 1:
        return None
    if not re.search(r"\.addTarget\s*\(\s*new\s+TargetCreaturePermanent\s*\(\s*\)\s*\)", source or ""):
        return None
    counter_class, raw_count = matches[0]
    counter_type = "+1/+1" if counter_class == "P1P1" else "-1/-1"
    return counter_type, int(raw_count or "1")


def fixed_counter_source_from_source(source: str) -> tuple[str, int] | None:
    matches = re.findall(
        r"AddCountersSourceEffect\s*\(\s*CounterType\.(P1P1|M1M1)\.createInstance\s*\(\s*(\d*)\s*\)",
        source or "",
    )
    if len(matches) != 1:
        return None
    counter_class, raw_count = matches[0]
    counter_type = "+1/+1" if counter_class == "P1P1" else "-1/-1"
    return counter_type, int(raw_count or "1")


def fixed_counter_target_from_oracle(metadata: dict[str, Any]) -> tuple[str, int] | None:
    text = oracle_text(metadata)
    match = re.match(
        r"^put (a|an|one|two|three|four|five|six|seven|eight|nine|ten|\d+) "
        r"(\+1/\+1|-1/-1) counters? on target creature\.?$",
        text,
    )
    if not match:
        return None
    count = counter_count_from_text(match.group(1))
    if count is None or count <= 0:
        return None
    return match.group(2), count


def activated_self_counter_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(
        r"\s+",
        " ",
        oracle_text_after_leading_static_keywords(metadata),
    ).strip().lower()
    if text.count(":") != 1:
        return "activated_self_add_counters_oracle_not_simple"
    cost_text, effect_text = [part.strip() for part in text.split(":", 1)]
    normalized_card_name = normalize_name(str(metadata.get("name") or ""))
    self_aliases = {
        alias
        for alias in {
            normalized_card_name,
            normalize_name(normalized_card_name.split(",", 1)[0]),
        }
        if alias
    }
    self_alias_pattern = "|".join(re.escape(alias) for alias in sorted(self_aliases, key=len, reverse=True))
    match = re.fullmatch(
        r"put (?P<count>a|an|one|two|three|four|five|six|seven|eight|nine|ten|\d+) "
        r"(?P<counter>\+1/\+1|-1/-1) counters? on "
        rf"(?P<target>this (?:creature|artifact|permanent)|it|{self_alias_pattern})\.?",
        effect_text,
    )
    if not match:
        return "activated_self_add_counters_oracle_not_simple"
    count = counter_count_from_text(match.group("count"))
    if count is None or count <= 0:
        return "activated_self_add_counters_oracle_count_not_supported"
    activation = activation_cost_from_oracle_prefix(cost_text)
    if isinstance(activation, str):
        return str(activation).replace(
            "activated_self_boost", "activated_self_add_counters"
        )
    return {
        "counter_type": match.group("counter"),
        "counter_count": count,
        **activation,
    }


def activated_self_counter_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    risky_cost_classes = {
        "CompositeCost",
        "DiscardCardCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "OrCost",
        "PayLifeCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "SacrificeSourceCost",
        "SacrificeTargetCost",
        "TapTargetCost",
        "UntapSourceCost",
    }
    counter = fixed_counter_source_from_source(text)
    if counter is None:
        return "activated_self_add_counters_source_counter_not_fixed"
    effect_index = text.find("AddCountersSourceEffect")
    window = text[max(0, effect_index - 500) : effect_index + 2000]
    if "SimpleActivatedAbility" not in window:
        return "activated_self_add_counters_source_not_simple_activated"
    present_risky = sorted(cost for cost in risky_cost_classes if cost in window)
    if present_risky:
        return "activated_self_add_counters_source_cost_not_supported"
    activation = activated_self_boost_cost_from_source(window)
    if isinstance(activation, str):
        return str(activation).replace(
            "activated_self_boost", "activated_self_add_counters"
        )
    counter_type, count = counter
    return {
        "counter_type": counter_type,
        "counter_count": count,
        **activation,
    }


def activated_target_counter_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip().lower()
    if text.count(":") != 1:
        return "activated_target_add_counters_oracle_not_simple"
    cost_text, effect_text = [part.strip() for part in text.split(":", 1)]
    match = re.fullmatch(
        r"put (?P<count>a|an|one|two|three|four|five|six|seven|eight|nine|ten|\d+) "
        r"(?P<counter>\+1/\+1|-1/-1) counters? on target creature\.?",
        effect_text,
    )
    if not match:
        return "activated_target_add_counters_oracle_not_simple"
    count = counter_count_from_text(match.group("count"))
    if count is None or count <= 0:
        return "activated_target_add_counters_oracle_count_not_supported"
    activation = activation_cost_from_oracle_prefix(cost_text)
    if isinstance(activation, str):
        return str(activation).replace("activated_self_boost", "activated_target_add_counters")
    return {
        "counter_type": match.group("counter"),
        "counter_count": count,
        "target": "creature",
        "target_constraints": {"card_types": ["creature"]},
        **activation,
    }


def activated_target_counter_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    risky_cost_classes = {
        "CompositeCost",
        "DiscardCardCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "OrCost",
        "PayLifeCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "SacrificeSourceCost",
        "SacrificeTargetCost",
        "TapTargetCost",
        "UntapSourceCost",
    }
    present_risky = sorted(cost for cost in risky_cost_classes if cost in text)
    if present_risky:
        return "activated_target_add_counters_source_cost_not_supported"
    counter = fixed_counter_target_from_source(text)
    if counter is None:
        return "activated_target_add_counters_source_counter_or_target_not_fixed"
    effect_index = text.find("AddCountersTargetEffect")
    window = text[max(0, effect_index - 500) : effect_index + 2000]
    if "SimpleActivatedAbility" not in window:
        return "activated_target_add_counters_source_not_simple_activated"
    activation = activated_self_boost_cost_from_source(window)
    if isinstance(activation, str):
        return str(activation).replace("activated_self_boost", "activated_target_add_counters")
    counter_type, count = counter
    return {
        "counter_type": counter_type,
        "counter_count": count,
        "target": "creature",
        "target_constraints": {"card_types": ["creature"]},
        **activation,
    }


def etb_counter_target_from_oracle(metadata: dict[str, Any]) -> tuple[str, int] | None:
    text = strip_leading_parenthetical_reminders(
        re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    )
    match = re.match(
        r"^(?:when|whenever) (?:this creature|.+) enters(?: the battlefield)?, put "
        r"(a|an|one|two|three|four|five|six|seven|eight|nine|ten|\d+) "
        r"(\+1/\+1|-1/-1) counters? on target creature\.?$",
        text,
    )
    if not match:
        return None
    count = counter_count_from_text(match.group(1))
    if count is None or count <= 0:
        return None
    return match.group(2), count


def etb_counter_target_spec(
    *,
    counter_type: str,
    counter_count: int,
    target_controller: str = "any",
    target_count_max: int = 1,
    up_to_count: bool = False,
    exclude_source: bool = False,
    required_subtypes: list[str] | None = None,
    excluded_keywords: list[str] | None = None,
) -> dict[str, Any]:
    constraints: dict[str, Any] = {"card_types": ["creature"]}
    if target_controller == "self":
        constraints["controller_scope"] = "self"
    if exclude_source:
        constraints["exclude_source"] = True
    if required_subtypes:
        constraints["required_subtypes"] = [
            str(subtype or "").strip().lower()
            for subtype in required_subtypes
            if str(subtype or "").strip()
        ]
    if excluded_keywords:
        constraints["excluded_keywords"] = [
            str(keyword or "").strip().lower().replace(" ", "_")
            for keyword in excluded_keywords
            if str(keyword or "").strip()
        ]
    spec: dict[str, Any] = {
        "counter_type": counter_type,
        "counter_count": int(counter_count),
        "target": "creature",
        "target_controller": target_controller,
        "target_constraints": constraints,
    }
    if target_count_max > 1:
        spec["target_count_min"] = 0 if up_to_count else target_count_max
        spec["target_count_max"] = int(target_count_max)
    if up_to_count:
        spec["up_to_count"] = True
    return spec


def etb_counter_filter_spec_from_source(source: str) -> dict[str, Any] | None:
    text = source or ""
    target_controller = "self" if (
        "FilterControlled" in text
        or "TargetController.YOU.getControllerPredicate()" in text
        or "StaticFilters.FILTER_ANOTHER_TARGET_CREATURE_YOU_CONTROL" in text
        or "StaticFilters.FILTER_OTHER_CONTROLLED_CREATURES" in text
        or "StaticFilters.FILTER_CONTROLLED_CREATURES" in text
        or "StaticFilters.FILTER_CONTROLLED_ANOTHER_CREATURE" in text
    ) else "any"
    exclude_source = (
        "AnotherPredicate.instance" in text
        or "StaticFilters.FILTER_ANOTHER_TARGET_CREATURE_YOU_CONTROL" in text
        or "StaticFilters.FILTER_OTHER_CONTROLLED_CREATURES" in text
        or "StaticFilters.FILTER_CONTROLLED_ANOTHER_CREATURE" in text
    )
    required_subtypes = [
        value.lower()
        for value in re.findall(
            r"new\s+Filter(?:Controlled)?(?:Creature)?Permanent\s*\(\s*SubType\.([A-Z_]+)",
            text,
        )
    ]
    required_subtypes += [
        value.lower()
        for value in re.findall(r"filter\.add\s*\(\s*SubType\.([A-Z_]+)\.getPredicate\s*\(\s*\)\s*\)", text)
    ]
    excluded_keywords: list[str] = []
    if re.search(r"Predicates\.not\s*\(\s*new\s+AbilityPredicate\s*\(\s*FlyingAbility\.class\s*\)\s*\)", text):
        excluded_keywords.append("flying")
    if (
        target_controller == "any"
        and not exclude_source
        and not required_subtypes
        and not excluded_keywords
    ):
        return None
    return {
        "target_controller": target_controller,
        "exclude_source": exclude_source,
        "required_subtypes": sorted(set(required_subtypes)),
        "excluded_keywords": sorted(set(excluded_keywords)),
    }


def etb_counter_target_count_from_source(source: str) -> tuple[int, bool] | None:
    text = source or ""
    max_matches = re.findall(
        r"new\s+(?:TargetCreaturePermanent|TargetControlledCreaturePermanent|TargetPermanent)"
        r"\s*\(\s*0\s*,\s*(\d+|Integer\.MAX_VALUE)\s*,",
        text,
    )
    max_matches += re.findall(
        r"new\s+(?:TargetCreaturePermanent|TargetControlledCreaturePermanent)"
        r"\s*\(\s*0\s*,\s*(\d+|Integer\.MAX_VALUE)\s*\)",
        text,
    )
    if not max_matches:
        return 1, False
    if len(max_matches) != 1:
        return None
    raw_max = max_matches[0]
    if raw_max == "Integer.MAX_VALUE":
        return None
    return int(raw_max), True


def etb_counter_target_spec_from_source(source: str) -> dict[str, Any] | None:
    text = source or ""
    counter = re.findall(
        r"AddCountersTargetEffect\s*\(\s*CounterType\.(P1P1|M1M1)\.createInstance\s*\(\s*(\d*)\s*\)",
        text,
    )
    if len(counter) != 1:
        return None
    if len(re.findall(r"\.addTarget\s*\(", text)) != 1:
        return None
    target_count = etb_counter_target_count_from_source(text)
    if target_count is None:
        return None
    counter_class, raw_count = counter[0]
    counter_type = "+1/+1" if counter_class == "P1P1" else "-1/-1"
    target_count_max, up_to_count = target_count
    if re.search(r"new\s+TargetControlledCreaturePermanent\s*\(", text):
        return etb_counter_target_spec(
            counter_type=counter_type,
            counter_count=int(raw_count or "1"),
            target_controller="self",
            target_count_max=target_count_max,
            up_to_count=up_to_count,
        )
    if re.search(r"new\s+TargetCreaturePermanent\s*\(", text):
        return etb_counter_target_spec(
            counter_type=counter_type,
            counter_count=int(raw_count or "1"),
            target_controller="any",
            target_count_max=target_count_max,
            up_to_count=up_to_count,
        )
    if re.search(r"new\s+Target(?:Controlled)?Permanent\s*\(", text):
        filter_spec = etb_counter_filter_spec_from_source(text)
        if filter_spec is None:
            return None
        return etb_counter_target_spec(
            counter_type=counter_type,
            counter_count=int(raw_count or "1"),
            target_controller=str(filter_spec["target_controller"]),
            target_count_max=target_count_max,
            up_to_count=up_to_count,
            exclude_source=bool(filter_spec.get("exclude_source")),
            required_subtypes=list(filter_spec.get("required_subtypes") or []),
            excluded_keywords=list(filter_spec.get("excluded_keywords") or []),
        )
    return None


def etb_counter_target_spec_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = strip_leading_parenthetical_reminders(
        re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    )
    match = re.match(
        r"^(?:when|whenever) (?:this creature|.+) enters(?: the battlefield)?, put "
        r"(a|an|one|two|three|four|five|six|seven|eight|nine|ten|\d+) "
        r"(\+1/\+1|-1/-1) counters? on (?:(each of up to "
        r"(one|two|three|four|five|six|seven|eight|nine|ten|\d+) )?(.+?))\.?$",
        text,
    )
    if not match:
        return None
    count = counter_count_from_text(match.group(1))
    if count is None or count <= 0:
        return None
    up_to_text = match.group(4)
    target_count_max = counter_count_from_text(up_to_text) if up_to_text else 1
    if target_count_max is None or target_count_max <= 0:
        return None
    phrase = str(match.group(5) or "").strip().lower()
    excluded_keywords: list[str] = []
    if phrase.endswith(" without flying"):
        excluded_keywords.append("flying")
        phrase = phrase.removesuffix(" without flying").strip()
    exclude_source = phrase.startswith("another target ") or phrase.startswith("other target ")
    normalized_phrase = phrase
    for prefix in ("another target ", "other target ", "target "):
        if normalized_phrase.startswith(prefix):
            normalized_phrase = normalized_phrase[len(prefix) :]
            break
    target_controller = "self" if normalized_phrase.endswith(" you control") else "any"
    if target_controller == "self":
        normalized_phrase = normalized_phrase.removesuffix(" you control").strip()
    if normalized_phrase in {"creature", "creatures"}:
        required_subtypes: list[str] = []
    else:
        subtype_match = re.fullmatch(r"([a-z][a-z '\\-]+?)s?", normalized_phrase)
        if not subtype_match:
            return None
        required_subtypes = [subtype_match.group(1).strip()]
    return etb_counter_target_spec(
        counter_type=match.group(2),
        counter_count=count,
        target_controller=target_controller,
        target_count_max=target_count_max,
        up_to_count=bool(up_to_text),
        exclude_source=exclude_source,
        required_subtypes=required_subtypes,
        excluded_keywords=excluded_keywords,
    )


def fixed_boost_target_from_source(source: str) -> tuple[int, int] | None:
    matches = re.findall(
        r"new\s+BoostTargetEffect\s*\(\s*([+-]?\d+)\s*,\s*([+-]?\d+)\s*"
        r"(?:,\s*Duration\.EndOfTurn\s*)?\)",
        source or "",
    )
    if len(matches) != 1:
        return None
    if len(re.findall(r"new\s+TargetCreaturePermanent\s*\(", source or "")) != 1:
        return None
    if not re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", source or ""):
        return None
    if "TargetPointer" in (source or "") or ".setTargetPointer" in (source or ""):
        return None
    return int(matches[0][0]), int(matches[0][1])


def target_creature_permanent_count_from_source(source: str) -> dict[str, Any] | str:
    matches = re.findall(r"new\s+TargetCreaturePermanent\s*\(\s*([^()]*)\)", source or "", re.S)
    if len(matches) != 1:
        return "target_creature_permanent_count_not_single"
    args = [arg.strip() for arg in matches[0].split(",") if arg.strip()]
    if not args:
        return {
            "target_count": 1,
            "target_count_min": 1,
            "target_count_max": 1,
            "up_to_count": False,
        }
    if len(args) == 1 and re.fullmatch(r"\d+", args[0]):
        count = int(args[0])
        if count <= 0:
            return "target_creature_permanent_count_invalid"
        return {
            "target_count": count,
            "target_count_min": count,
            "target_count_max": count,
            "up_to_count": False,
        }
    if len(args) == 2 and all(re.fullmatch(r"\d+", arg) for arg in args):
        minimum = int(args[0])
        maximum = int(args[1])
        if maximum <= 0 or minimum < 0 or minimum > maximum:
            return "target_creature_permanent_count_invalid"
        return {
            "target_count": maximum,
            "target_count_min": minimum,
            "target_count_max": maximum,
            "up_to_count": minimum < maximum,
        }
    return "target_creature_permanent_count_dynamic_or_unsupported"


def fixed_boost_untap_target_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if re.search(r"new\s+TargetPermanent\s*\(", text) and not re.search(
        r"new\s+TargetCreaturePermanent\s*\(",
        text,
    ):
        return "boost_untap_source_target_filter_not_supported"
    if len(re.findall(r"new\s+UntapTargetEffect\s*\(", text)) != 1:
        return "boost_untap_source_untap_not_single"
    matches = re.findall(
        r"new\s+BoostTargetEffect\s*\(\s*([+-]?\d+)\s*,\s*([+-]?\d+)\s*"
        r"(?:,\s*Duration\.EndOfTurn\s*)?\)",
        text,
        re.S,
    )
    if len(matches) != 1:
        return "boost_untap_source_boost_not_single_fixed"
    if "TargetPointer" in text or ".setTargetPointer" in text:
        return "boost_untap_source_target_pointer_not_supported"
    target_count = target_creature_permanent_count_from_source(text)
    if isinstance(target_count, str):
        return target_count
    return {
        "power_delta": int(matches[0][0]),
        "toughness_delta": int(matches[0][1]),
        **target_count,
    }


def gain_control_target_spec_from_phrase(phrase: str) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    if text in {"artifact or creature", "artifact or target creature"}:
        return {
            "target": "artifact_or_creature",
            "target_constraints": {"card_types": ["artifact", "creature"]},
        }
    if text == "artifact":
        return {
            "target": "artifact",
            "target_constraints": {"card_types": ["artifact"]},
        }
    if text == "nonlegendary creature":
        return {
            "target": "creature",
            "target_constraints": {
                "card_types": ["creature"],
                "exclude_supertypes": ["legendary"],
            },
        }
    match = re.fullmatch(
        r"creature with (?:mana value|converted mana cost) (?P<value>\d+) or less",
        text,
    )
    if match:
        return {
            "target": "creature",
            "target_constraints": {
                "card_types": ["creature"],
                "mana_value_max": int(match.group("value")),
            },
        }
    match = re.fullmatch(r"creature with power (?P<value>\d+) or less", text)
    if match:
        return {
            "target": "creature",
            "target_constraints": {
                "card_types": ["creature"],
                "power_max": int(match.group("value")),
            },
        }
    if text == "creature":
        return {
            "target": "creature",
            "target_constraints": {"card_types": ["creature"]},
        }
    return "gain_control_untap_haste_target_phrase_not_supported"


def gain_control_untap_haste_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if "TemporaryInsanityPredicate" in text or "number of cards in your graveyard" in text:
        return "gain_control_untap_haste_source_dynamic_filter_not_supported"
    if len(re.findall(r"new\s+GainControlTargetEffect\s*\(\s*Duration\.EndOfTurn\s*\)", text)) != 1:
        return "gain_control_untap_haste_source_control_not_single_eot"
    if len(re.findall(r"new\s+UntapTargetEffect\s*\(", text)) != 1:
        return "gain_control_untap_haste_source_untap_not_single"
    haste_effects = re.findall(
        r"new\s+GainAbilityTargetEffect\s*\(\s*HasteAbility\.getInstance\(\)\s*,\s*Duration\.EndOfTurn",
        text,
        re.S,
    )
    if len(haste_effects) != 1:
        return "gain_control_untap_haste_source_haste_not_single_eot"
    all_gain_ability_effects = re.findall(r"new\s+GainAbilityTargetEffect\s*\(", text)
    if len(all_gain_ability_effects) != 1:
        return "gain_control_untap_haste_source_extra_granted_ability_not_supported"

    if re.search(r"new\s+TargetArtifactPermanent\s*\(", text):
        phrase = "artifact"
    elif "FILTER_PERMANENT_ARTIFACT_OR_CREATURE" in text:
        phrase = "artifact or creature"
    elif "PowerPredicate(ComparisonType.FEWER_THAN, 5)" in text:
        phrase = "creature with power 4 or less"
    elif "ManaValuePredicate(ComparisonType.FEWER_THAN, 4)" in text:
        phrase = "creature with mana value 3 or less"
    elif "SuperType.LEGENDARY.getPredicate" in text or "nonlegendary creature" in text.lower():
        phrase = "nonlegendary creature"
    elif re.search(r"new\s+TargetCreaturePermanent\s*\(", text) or "FilterCreaturePermanent" in text:
        phrase = "creature"
    else:
        return "gain_control_untap_haste_source_target_not_supported"

    spec = gain_control_target_spec_from_phrase(phrase)
    if isinstance(spec, str):
        return spec
    return spec


def graveyard_count_boost_target_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str | None:
    text = strip_leading_parenthetical_reminders(oracle_text(metadata))
    match = re.match(
        r"^target creature gets (?P<power>[+-])x/(?P<toughness>[+-])(?P<toughness_value>x|0) "
        r"until end of turn, where x is the number of (?P<filter>cards|creature cards) "
        r"in your graveyard\.?$",
        text,
    )
    if not match:
        return None
    power_per = -1 if match.group("power") == "-" else 1
    toughness_token = match.group("toughness_value")
    toughness_per = 0 if toughness_token == "0" else (-1 if match.group("toughness") == "-" else 1)
    filter_text = match.group("filter")
    card_types = ["creature"] if filter_text == "creature cards" else ["card"]
    return {
        "graveyard_count_scope": "controller_graveyard",
        "graveyard_count_card_types": card_types,
        "power_base_delta": 0,
        "toughness_base_delta": 0,
        "power_delta_per_graveyard_count": power_per,
        "toughness_delta_per_graveyard_count": toughness_per,
    }


def graveyard_count_boost_target_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    if "getSpellAbility().addCost" in text or "addCost(" in text:
        return "graveyard_count_boost_additional_cost_not_supported"
    boost_matches = re.findall(r"new\s+BoostTargetEffect\s*\((.*?)\)", text, re.S)
    if len(boost_matches) != 1:
        return "graveyard_count_boost_source_not_single"
    if len(re.findall(r"new\s+TargetCreaturePermanent\s*\(", text)) != 1:
        return "graveyard_count_boost_target_not_supported"
    if not re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", text):
        return "graveyard_count_boost_target_not_supported"
    filter_match = re.search(
        r"CardsInControllerGraveyardCount\s*\(\s*StaticFilters\.(FILTER_CARD_CARDS|FILTER_CARD_CREATURES)\s*,",
        text,
    )
    if not filter_match:
        return "graveyard_count_boost_source_filter_not_supported"
    card_types = ["creature"] if filter_match.group(1) == "FILTER_CARD_CREATURES" else ["card"]
    match = re.search(
        r"new\s+BoostTargetEffect\s*\(\s*(?P<power>[^,]+?)\s*,\s*(?P<toughness>.+?)\s*,\s*Duration\.EndOfTurn\s*\)",
        text,
        re.S,
    )
    if not match:
        return "graveyard_count_boost_source_not_single"

    def per_count(expr: str) -> int | str:
        expr = re.sub(r"\s+", " ", expr).strip()
        if re.fullmatch(r"StaticValue\.get\s*\(\s*0\s*\)", expr):
            return 0
        if "xValue" in expr:
            return -1 if "xValue = new SignInversionDynamicValue" in text else 1
        return "graveyard_count_boost_source_delta_not_supported"

    power_per = per_count(match.group("power"))
    toughness_per = per_count(match.group("toughness"))
    if isinstance(power_per, str):
        return power_per
    if isinstance(toughness_per, str):
        return toughness_per
    return {
        "graveyard_count_scope": "controller_graveyard",
        "graveyard_count_card_types": card_types,
        "power_base_delta": 0,
        "toughness_base_delta": 0,
        "power_delta_per_graveyard_count": power_per,
        "toughness_delta_per_graveyard_count": toughness_per,
    }


def _dynamic_boost_sign(sign_token: str) -> int:
    return -1 if str(sign_token or "").strip().startswith("-") else 1


def _dynamic_count_boost_dict(
    amount_source: str,
    *,
    power_per: int,
    toughness_per: int,
    power_base: int = 0,
    toughness_base: int = 0,
    **count_fields: Any,
) -> dict[str, Any]:
    return {
        "stat_modifier_amount_source": amount_source,
        "power_base_delta": power_base,
        "toughness_base_delta": toughness_base,
        "power_delta_per_graveyard_count": power_per,
        "toughness_delta_per_graveyard_count": toughness_per,
        **count_fields,
    }


def _controlled_battlefield_count_fields(filter_text: str) -> dict[str, Any] | None:
    token = str(filter_text or "").strip().lower()
    basic_land_subtypes = {"plains", "island", "swamp", "mountain", "forest", "desert"}
    if token in basic_land_subtypes:
        return {
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["land"],
            "battlefield_count_subtypes": [token],
        }
    if token == "equipment":
        return {
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["artifact"],
            "battlefield_count_subtypes": ["equipment"],
        }
    if token == "artifact":
        return {
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["artifact"],
        }
    if token == "creature":
        return {
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["creature"],
        }
    if token == "land":
        return {
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["land"],
        }
    if token == "goblin":
        return {
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_subtypes": ["goblin"],
        }
    if re.fullmatch(r"[a-z][a-z_ -]*", token):
        subtype = token.replace(" ", "_").replace("-", "_")
        return {
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_subtypes": [subtype],
        }
    return None


def _battlefield_subtype_count_fields(plural_subtype: str) -> dict[str, Any]:
    subtype = str(plural_subtype or "").strip().lower()
    if subtype == "elves":
        subtype = "elf"
    elif subtype == "zombies":
        subtype = "zombie"
    elif subtype.endswith("ies"):
        subtype = subtype[:-3] + "y"
    elif subtype.endswith("s"):
        subtype = subtype[:-1]
    return {
        "battlefield_count_scope": "all_battlefields",
        "battlefield_count_subtypes": [subtype],
    }


def dynamic_count_boost_target_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    domain_match = re.match(
        r"^(?:domain — )?target creature gets (?P<power>[+-])1/(?P<toughness>[+-])1 "
        r"until end of turn for each basic land type among lands you control\.?$",
        text,
    )
    if domain_match:
        return _dynamic_count_boost_dict(
            "domain_basic_land_types",
            power_per=_dynamic_boost_sign(domain_match.group("power")),
            toughness_per=_dynamic_boost_sign(domain_match.group("toughness")),
        )
    hand_match = re.match(
        r"^target creature gets (?P<power>[+-])x/(?P<toughness>[+-])x until end of turn, "
        r"where x is the number of cards in your hand\.?$",
        text,
    )
    if hand_match:
        return _dynamic_count_boost_dict(
            "controller_hand_count",
            power_per=_dynamic_boost_sign(hand_match.group("power")),
            toughness_per=_dynamic_boost_sign(hand_match.group("toughness")),
        )
    controlled_match = re.match(
        r"^target creature gets (?P<power>[+-])1/(?P<toughness>[+-])(?P<toughness_value>1|0) "
        r"until end of turn for each (?P<filter>swamp|island|mountain|forest|plains|desert|artifact|creature|land) "
        r"you control\.?$",
        text,
    )
    if controlled_match:
        count_fields = _controlled_battlefield_count_fields(controlled_match.group("filter"))
        if count_fields is None:
            return "dynamic_count_boost_oracle_filter_not_supported"
        toughness_per = 0 if controlled_match.group("toughness_value") == "0" else _dynamic_boost_sign(controlled_match.group("toughness"))
        return _dynamic_count_boost_dict(
            "battlefield_permanent_count",
            power_per=_dynamic_boost_sign(controlled_match.group("power")),
            toughness_per=toughness_per,
            **count_fields,
        )
    lands_match = re.match(
        r"^target creature gets (?P<power>[+-])x/(?P<toughness>[+-])x until end of turn, "
        r"where x is the number of lands you control\.?$",
        text,
    )
    if lands_match:
        return _dynamic_count_boost_dict(
            "battlefield_permanent_count",
            power_per=_dynamic_boost_sign(lands_match.group("power")),
            toughness_per=_dynamic_boost_sign(lands_match.group("toughness")),
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["land"],
        )
    battlefield_subtype_match = re.match(
        r"^target creature gets (?P<power>[+-])x/(?P<toughness>[+-])x until end of turn, "
        r"where x is the number of (?P<subtype>[a-z]+) on the battlefield\.?$",
        text,
    )
    if battlefield_subtype_match:
        return _dynamic_count_boost_dict(
            "battlefield_permanent_count",
            power_per=_dynamic_boost_sign(battlefield_subtype_match.group("power")),
            toughness_per=_dynamic_boost_sign(battlefield_subtype_match.group("toughness")),
            **_battlefield_subtype_count_fields(battlefield_subtype_match.group("subtype")),
        )
    desert_due_match = re.match(
        r"^target creature gets -2/-2 until end of turn\. it gets an additional -1/-1 "
        r"until end of turn for each desert you control\.?$",
        text,
    )
    if desert_due_match:
        return _dynamic_count_boost_dict(
            "battlefield_permanent_count",
            power_per=-1,
            toughness_per=-1,
            power_base=-2,
            toughness_base=-2,
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["land"],
            battlefield_count_subtypes=["desert"],
        )
    return None


def _dynamic_count_source_spec_from_expr(source: str, expr: str) -> dict[str, Any] | str | None:
    text = source or ""
    token = re.sub(r"\s+", " ", str(expr or "")).strip()
    if re.fullmatch(r"StaticValue\.get\s*\(\s*0\s*\)", token):
        return {"static_value": 0, "per": 0}
    sign = -1 if (
        "SignInversionDynamicValue" in token
        or (token == "xValue" and "xValue = new SignInversionDynamicValue" in text)
        or (token == "xValue" and "xValue = new PermanentsOnBattlefieldCount" in text and re.search(r"PermanentsOnBattlefieldCount\s*\([^;]+,\s*-1\s*\)", text, re.S))
    ) else 1
    if token == "xValue" and "AdditiveDynamicValue" in text and "StaticValue.get(-2)" in text:
        return {
            **_dynamic_count_boost_dict(
                "battlefield_permanent_count",
                power_per=-1,
                toughness_per=-1,
                power_base=-2,
                toughness_base=-2,
                battlefield_count_scope="controller_battlefield",
                battlefield_count_card_types=["land"],
                battlefield_count_subtypes=["desert"],
            ),
            "_full_spec": True,
        }
    if "DomainValue.REGULAR" in token or (token == "xValue" and "DomainValue.REGULAR" in text):
        return {"stat_modifier_amount_source": "domain_basic_land_types", "per": sign}
    if "CardsInControllerHandCount.ANY" in token or (token == "xValue" and "CardsInControllerHandCount.ANY" in text):
        return {"stat_modifier_amount_source": "controller_hand_count", "per": sign}
    if "ArtifactYouControlCount.instance" in token:
        return {
            "stat_modifier_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["artifact"],
            "per": sign,
        }
    if token != "xValue":
        return "dynamic_count_boost_source_delta_not_supported"
    if "FILTER_CONTROLLED_CREATURE" in text:
        return {
            "stat_modifier_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["creature"],
            "per": sign,
        }
    if "FILTER_CONTROLLED_PERMANENT_LANDS" in text:
        return {
            "stat_modifier_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["land"],
            "per": sign,
        }
    subtype_match = re.search(r"FilterControlledPermanent\s*\(\s*SubType\.(SWAMP|ISLAND|MOUNTAIN|FOREST|PLAINS|DESERT)", text)
    if subtype_match:
        return {
            "stat_modifier_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["land"],
            "battlefield_count_subtypes": [subtype_match.group(1).lower()],
            "per": sign,
        }
    if "FilterControlledArtifactPermanent" in text:
        return {
            "stat_modifier_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["artifact"],
            "per": sign,
        }
    any_subtype_match = re.search(r"FilterPermanent\s*\(\s*SubType\.(ZOMBIE|ELF)", text)
    if any_subtype_match:
        return {
            "stat_modifier_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "all_battlefields",
            "battlefield_count_subtypes": [any_subtype_match.group(1).lower()],
            "per": sign,
        }
    return "dynamic_count_boost_source_filter_not_supported"


def dynamic_count_boost_target_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    if "getSpellAbility().addCost" in text or "addCost(" in text:
        return "dynamic_count_boost_additional_cost_not_supported"
    if len(re.findall(r"new\s+TargetCreaturePermanent\s*\(", text)) != 1:
        return "dynamic_count_boost_target_not_supported"
    if not re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", text):
        return "dynamic_count_boost_target_not_supported"
    if "TargetPointer" in text or ".setTargetPointer" in text:
        return "dynamic_count_boost_target_not_supported"
    constructor_args = extract_constructor_args(text, "BoostTargetEffect")
    if constructor_args is None:
        return None
    args = split_top_level_args(constructor_args)
    if len(args) < 2:
        return "dynamic_count_boost_source_not_single"
    power_spec = _dynamic_count_source_spec_from_expr(text, args[0])
    toughness_spec = _dynamic_count_source_spec_from_expr(text, args[1])
    if isinstance(power_spec, str):
        return power_spec
    if isinstance(toughness_spec, str):
        return toughness_spec
    if power_spec is None or toughness_spec is None:
        return "dynamic_count_boost_source_delta_not_supported"
    if power_spec.get("_full_spec") and toughness_spec.get("_full_spec"):
        return {key: value for key, value in power_spec.items() if key != "_full_spec"}
    count_spec = toughness_spec if power_spec.get("static_value") is not None else power_spec
    for spec in (power_spec, toughness_spec):
        if spec.get("static_value") is None:
            for key in (
                "stat_modifier_amount_source",
                "battlefield_count_scope",
                "battlefield_count_card_types",
                "battlefield_count_subtypes",
            ):
                if spec.get(key) != count_spec.get(key):
                    return "dynamic_count_boost_source_mixed_counts_not_supported"
    return _dynamic_count_boost_dict(
        str(count_spec.get("stat_modifier_amount_source")),
        power_per=int(power_spec.get("per") or 0),
        toughness_per=int(toughness_spec.get("per") or 0),
        **{
            key: value
            for key, value in count_spec.items()
            if key not in {"stat_modifier_amount_source", "per", "static_value"}
        },
    )


def fixed_boost_draw_from_oracle(metadata: dict[str, Any]) -> tuple[int, int, int] | None:
    text = strip_leading_parenthetical_reminders(oracle_text(metadata))
    match = re.match(
        r"^target creature gets ([+-]?\d+)/([+-]?\d+) until end of turn\. draw a card\.?$",
        text,
    )
    if not match:
        return None
    power = signed_int_from_oracle(match.group(1))
    toughness = signed_int_from_oracle(match.group(2))
    if power is None or toughness is None:
        return None
    return power, toughness, 1


def fixed_boost_draw_from_source(source: str) -> tuple[int, int, int] | None:
    text = source or ""
    boost = fixed_boost_target_from_source(text)
    if boost is None:
        return None
    draw_matches = re.findall(r"new\s+DrawCardSourceControllerEffect\s*\(\s*(\d+)\s*\)", text)
    if len(draw_matches) != 1:
        return None
    boost_match = re.search(r"new\s+BoostTargetEffect\s*\(", text)
    draw_match = re.search(r"new\s+DrawCardSourceControllerEffect\s*\(", text)
    if not boost_match or not draw_match or boost_match.start() > draw_match.start():
        return None
    return boost[0], boost[1], int(draw_matches[0])


def fixed_boost_scry_from_oracle(metadata: dict[str, Any]) -> tuple[int, int, int] | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    text = re.sub(r"\s+", " ", text).strip()
    match = re.match(
        r"^target creature gets ([+-]?\d+)/([+-]?\d+) until end of turn\. scry (\d+)\.?$",
        text,
    )
    if not match:
        return None
    power = signed_int_from_oracle(match.group(1))
    toughness = signed_int_from_oracle(match.group(2))
    if power is None or toughness is None:
        return None
    scry_count = int(match.group(3))
    if scry_count <= 0:
        return None
    return power, toughness, scry_count


def fixed_boost_scry_from_source(source: str) -> tuple[int, int, int] | None:
    text = source or ""
    boost = fixed_boost_target_from_source(text)
    if boost is None:
        return None
    scry_match = fixed_scry_count_match_from_source(text)
    if scry_match is None:
        return None
    boost_match = re.search(r"new\s+BoostTargetEffect\s*\(", text)
    if boost_match is None or boost_match.start() > scry_match[1]:
        return None
    return boost[0], boost[1], scry_match[0]


def fixed_boost_keyword_target_from_source(
    source: str,
    keyword_ability_class: str,
) -> tuple[int, int, str] | None:
    text = source or ""
    boost_matches = re.findall(
        r"new\s+BoostTargetEffect\s*\(\s*([+-]?\d+)\s*,\s*([+-]?\d+)\s*"
        r"(?:,\s*Duration\.EndOfTurn\s*)?\)",
        text,
        re.S,
    )
    if len(boost_matches) != 1:
        return None
    gain_matches = re.findall(r"new\s+GainAbilityTargetEffect\s*\(", text)
    if len(gain_matches) != 1:
        return None
    ability_expr = (
        rf"(?:{re.escape(keyword_ability_class)}\.getInstance\s*\(\s*\)"
        rf"|new\s+{re.escape(keyword_ability_class)}\s*\([^)]*\))"
    )
    if not re.search(
        rf"new\s+GainAbilityTargetEffect\s*\(\s*{ability_expr}"
        rf"\s*(?:,\s*Duration\.EndOfTurn\s*)?\)",
        text,
        re.S,
    ):
        return None
    any_target = re.findall(r"new\s+TargetCreaturePermanent\s*\(", text)
    controlled_target = re.findall(r"new\s+TargetControlledCreaturePermanent\s*\(", text)
    if len(any_target) + len(controlled_target) != 1:
        return None
    if controlled_target:
        if not re.search(r"new\s+TargetControlledCreaturePermanent\s*\(\s*\)", text):
            return None
        target_controller = "self"
    else:
        if not re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", text):
            return None
        target_controller = "any"
    if "TargetPointer" in text or ".setTargetPointer" in text:
        return None
    return int(boost_matches[0][0]), int(boost_matches[0][1]), target_controller


def fixed_target_keyword_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    text = re.sub(r"\s+", " ", text).strip().lower()
    keyword_words = "|".join(
        re.escape(word)
        for word in sorted(TARGET_GRANT_KEYWORD_ORACLE_WORDS, key=len, reverse=True)
    )
    match = re.fullmatch(
        rf"(?P<target>target .+?) gains (?P<keywords>(?:{keyword_words})(?:,? (?:and |or )?(?:{keyword_words}))*) until end of turn\.?",
        text,
    )
    if not match:
        return "target_keyword_spell_oracle_not_exact"
    if " or " in match.group("keywords"):
        return "target_keyword_spell_oracle_choice_not_supported"
    keyword_parts = [
        part.strip()
        for part in re.split(r",?\s+and\s+|,\s*", match.group("keywords"))
        if part.strip()
    ]
    keywords = [TARGET_GRANT_KEYWORD_ORACLE_WORDS.get(part) for part in keyword_parts]
    if not keywords or any(keyword is None for keyword in keywords):
        return "target_keyword_spell_oracle_keyword_not_supported"
    target_phrase = match.group("target")
    if target_phrase.startswith("target "):
        target_phrase = target_phrase[len("target ") :].strip()
    target_data = activated_target_keyword_target_phrase_data(target_phrase)
    if isinstance(target_data, str):
        return target_data.replace("activated_target_keyword", "target_keyword_spell")
    return {
        "keywords": list(dict.fromkeys(str(keyword) for keyword in keywords if keyword)),
        **target_data,
    }


def fixed_target_keyword_from_source(
    source: str,
    keyword_ability_classes: set[str],
) -> dict[str, Any] | str:
    text = source or ""
    if not keyword_ability_classes:
        return "target_keyword_spell_source_keyword_missing"
    if "TargetPointer" in text or ".setTargetPointer" in text or "EachTargetPointer" in text:
        return "target_keyword_spell_source_target_not_supported"
    if "BoostTargetEffect" in text:
        return "target_keyword_spell_source_boost_not_supported"
    gain_matches = re.findall(r"new\s+GainAbilityTargetEffect\s*\(", text)
    if len(gain_matches) != len(keyword_ability_classes):
        return "target_keyword_spell_source_effect_count_mismatch"
    keywords: list[str] = []
    for ability_class in sorted(keyword_ability_classes):
        ability_expr = (
            rf"(?:{re.escape(ability_class)}\.getInstance\s*\(\s*\)"
            rf"|new\s+{re.escape(ability_class)}\s*\([^)]*\))"
        )
        if not re.search(
            rf"new\s+GainAbilityTargetEffect\s*\(\s*{ability_expr}"
            rf"\s*(?:,\s*Duration\.EndOfTurn\s*)?\)",
            text,
            re.S,
        ):
            return "target_keyword_spell_source_keyword_not_supported"
        keyword = TARGET_GRANT_KEYWORD_ABILITY_CLASSES.get(ability_class)
        if not keyword:
            return "target_keyword_spell_source_keyword_not_supported"
        keywords.append(keyword)
    any_target = re.findall(r"new\s+TargetCreaturePermanent\s*\(", text)
    controlled_target = re.findall(r"new\s+TargetControlledCreaturePermanent\s*\(", text)
    if len(any_target) + len(controlled_target) != 1:
        return "target_keyword_spell_source_target_not_supported"
    if controlled_target:
        if not re.search(r"new\s+TargetControlledCreaturePermanent\s*\(\s*\)", text, re.S):
            return "target_keyword_spell_source_target_not_supported"
        target_controller = "self"
    else:
        if not re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", text, re.S):
            return "target_keyword_spell_source_target_not_supported"
        target_controller = "any"
    return {
        "keywords": list(dict.fromkeys(keywords)),
        "target": "creature",
        "target_controller": target_controller,
        "exclude_source": False,
        "target_constraints": {"card_types": ["creature"]},
    }


def fixed_keyword_draw_target_from_source(
    source: str,
    keyword_ability_class: str,
) -> tuple[str, int] | None:
    text = source or ""
    gain_matches = re.findall(r"new\s+GainAbilityTargetEffect\s*\(", text)
    if len(gain_matches) != 1:
        return None
    ability_expr = (
        rf"(?:{re.escape(keyword_ability_class)}\.getInstance\s*\(\s*\)"
        rf"|new\s+{re.escape(keyword_ability_class)}\s*\([^)]*\))"
    )
    gain_match = re.search(
        rf"new\s+GainAbilityTargetEffect\s*\(\s*{ability_expr}\s*,\s*Duration\.EndOfTurn",
        text,
        re.S,
    )
    if not gain_match:
        return None
    draw_matches = re.findall(r"new\s+DrawCardSourceControllerEffect\s*\(\s*(\d+)\s*\)", text)
    if len(draw_matches) != 1:
        return None
    draw_match = re.search(r"new\s+DrawCardSourceControllerEffect\s*\(", text)
    if not draw_match or gain_match.start() > draw_match.start():
        return None
    any_target = re.findall(r"new\s+TargetCreaturePermanent\s*\(", text)
    controlled_target = re.findall(r"new\s+TargetControlledCreaturePermanent\s*\(", text)
    if len(any_target) + len(controlled_target) != 1:
        return None
    if controlled_target:
        if not re.search(r"new\s+TargetControlledCreaturePermanent\s*\(\s*\)", text):
            return None
        target_controller = "self"
    else:
        if not re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", text):
            return None
        target_controller = "any"
    if "TargetPointer" in text or ".setTargetPointer" in text:
        return None
    return target_controller, int(draw_matches[0])


def fixed_boost_keyword_draw_target_from_source(
    source: str,
    keyword_ability_class: str,
) -> tuple[int, int, str, int] | None:
    text = source or ""
    boost = fixed_boost_target_from_source(text)
    if boost is None:
        return None
    gain_matches = re.findall(r"new\s+GainAbilityTargetEffect\s*\(", text)
    if len(gain_matches) != 1:
        return None
    ability_expr = (
        rf"(?:{re.escape(keyword_ability_class)}\.getInstance\s*\(\s*\)"
        rf"|new\s+{re.escape(keyword_ability_class)}\s*\([^)]*\))"
    )
    gain_match = re.search(
        rf"new\s+GainAbilityTargetEffect\s*\(\s*{ability_expr}"
        rf"\s*(?:,\s*Duration\.EndOfTurn\s*)?\)",
        text,
        re.S,
    )
    if not gain_match:
        return None
    draw_matches = re.findall(r"new\s+DrawCardSourceControllerEffect\s*\(\s*(\d+)\s*\)", text)
    if len(draw_matches) != 1:
        return None
    boost_match = re.search(r"new\s+BoostTargetEffect\s*\(", text)
    draw_match = re.search(r"new\s+DrawCardSourceControllerEffect\s*\(", text)
    if not boost_match or not draw_match:
        return None
    if not (boost_match.start() < gain_match.start() < draw_match.start()):
        return None
    if len(re.findall(r"new\s+TargetCreaturePermanent\s*\(", text)) != 1:
        return None
    if not re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", text):
        return None
    return boost[0], boost[1], "any", int(draw_matches[0])


STATIC_CONTROLLED_PT_BLOCKED_ORACLE_WORDS = {
    "blocking",
    "blocked",
    "enchanted",
    "equipped",
    "modified",
    "tapped",
}

STATIC_CONTROLLED_PT_BLOCKED_SOURCE_MARKERS = (
    "Predicates.or",
    "Predicates.and",
    "EnchantedPredicate",
    "EquippedPredicate",
    "BlockingPredicate",
    "ControlledByControllerPredicate",
)
STATIC_CONTROLLED_PT_COLOR_WORDS = {
    "white": "W",
    "blue": "U",
    "black": "B",
    "red": "R",
    "green": "G",
}

STATIC_CONTROLLED_PT_IRREGULAR_SUBTYPES = {
    "elves": "elf",
    "dwarves": "dwarf",
    "thallids": "thallid",
    "zombies": "zombie",
    "kithkin": "kithkin",
}


def canonical_static_subtype(value: str) -> str:
    token = re.sub(r"[^a-z0-9]+", " ", str(value or "").strip().lower()).strip()
    if not token:
        return ""
    if token in STATIC_CONTROLLED_PT_IRREGULAR_SUBTYPES:
        return STATIC_CONTROLLED_PT_IRREGULAR_SUBTYPES[token]
    if token.endswith("ies") and len(token) > 3:
        return f"{token[:-3]}y"
    if token.endswith("ves") and len(token) > 3:
        return f"{token[:-3]}f"
    if token.endswith("s") and not token.endswith("ss"):
        return token[:-1]
    return token


def static_controlled_pt_constraints_from_subject(subject: str) -> dict[str, Any] | str:
    phrase = re.sub(r"\s+", " ", str(subject or "").strip().lower())
    if not phrase or phrase == "creatures":
        return {}
    if phrase.endswith(" creatures"):
        phrase = phrase[: -len(" creatures")].strip()
    if not phrase:
        return {}
    words = phrase.split()
    if any(word in STATIC_CONTROLLED_PT_BLOCKED_ORACLE_WORDS for word in words):
        return "static_controlled_pt_oracle_filter_not_supported"
    constraints: dict[str, Any] = {}
    colors: list[str] = []
    subtypes: list[str] = []
    for word in words:
        if word in STATIC_CONTROLLED_PT_COLOR_WORDS:
            colors.append(STATIC_CONTROLLED_PT_COLOR_WORDS[word])
            continue
        if word == "attacking":
            constraints["static_required_combat_state"] = "attacking"
            continue
        if word == "untapped":
            constraints["static_required_tapped_state"] = "untapped"
            continue
        if word == "artifact":
            constraints["static_artifact_creature"] = True
            continue
        if word == "legendary":
            constraints["static_required_supertypes"] = ["legendary"]
            continue
        subtype = canonical_static_subtype(word)
        if subtype:
            subtypes.append(subtype)
    if colors:
        constraints["static_required_colors"] = ordered_color_symbols(colors)
    if subtypes:
        constraints["static_required_subtypes"] = sorted(set(subtypes))
    return constraints


def static_controlled_pt_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str | None:
    text = strip_leading_parenthetical_reminders(oracle_text(metadata))
    match = re.match(
        r"^(?:each )?(?P<other>other )?(?P<subject>[a-z0-9' -]+?) "
        r"you control get (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+)\.?$",
        text,
    )
    if not match:
        return None
    subject = match.group("subject").strip()
    constraints = static_controlled_pt_constraints_from_subject(subject)
    if isinstance(constraints, str):
        return constraints
    power = signed_int_from_oracle(match.group("power"))
    toughness = signed_int_from_oracle(match.group("toughness"))
    if power is None or toughness is None:
        return None
    return {
        "static_power_bonus": power,
        "static_toughness_bonus": toughness,
        "static_exclude_source": bool(match.group("other")),
        **constraints,
    }


def static_controlled_pt_filter_constraints_from_source(source: str, filter_name: str | None) -> dict[str, Any] | str:
    text = source or ""
    if any(marker in text for marker in STATIC_CONTROLLED_PT_BLOCKED_SOURCE_MARKERS):
        return "static_controlled_pt_source_filter_not_supported"
    if not filter_name:
        return {}
    if filter_name == "StaticFilters.FILTER_PERMANENT_CREATURES":
        return {}
    if filter_name == "StaticFilters.FILTER_ATTACKING_CREATURES":
        return {"static_required_combat_state": "attacking"}
    if filter_name == "StaticFilters.FILTER_PERMANENT_SLIVERS":
        return {"static_required_subtypes": ["sliver"]}
    if filter_name == "StaticFilters.FILTER_PERMANENTS_ARTIFACT_CREATURE":
        return {"static_artifact_creature": True}
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", filter_name):
        return "static_controlled_pt_source_filter_not_supported"
    constraints: dict[str, Any] = {}
    color_tokens = re.findall(
        rf"{re.escape(filter_name)}\.add\s*\(\s*new\s+ColorPredicate\s*\(\s*ObjectColor\.([A-Z]+)\s*\)\s*\)",
        text,
    )
    if color_tokens:
        colors = [
            OBJECT_COLOR_TO_SYMBOL[token]
            for token in color_tokens
            if token in OBJECT_COLOR_TO_SYMBOL
        ]
        if colors:
            constraints["static_required_colors"] = ordered_color_symbols(colors)
    subtype_tokens = re.findall(
        rf"{re.escape(filter_name)}\s*=\s*new\s+Filter(?:Creature)?Permanent\s*\(\s*SubType\.([A-Z0-9_]+)",
        text,
    )
    subtype_tokens += re.findall(rf"{re.escape(filter_name)}\.add\s*\(\s*SubType\.([A-Z0-9_]+)\.getPredicate\s*\(\s*\)\s*\)", text)
    if subtype_tokens:
        constraints["static_required_subtypes"] = sorted(
            {canonical_static_subtype(token.replace("_", " ")) for token in subtype_tokens}
        )
    if re.search(rf"{re.escape(filter_name)}\.add\s*\(\s*CardType\.ARTIFACT\.getPredicate\s*\(\s*\)\s*\)", text):
        constraints["static_artifact_creature"] = True
    if re.search(rf"{re.escape(filter_name)}\.add\s*\(\s*SuperType\.LEGENDARY\.getPredicate\s*\(\s*\)\s*\)", text):
        constraints["static_required_supertypes"] = ["legendary"]
    if re.search(rf"{re.escape(filter_name)}\.add\s*\(\s*TappedPredicate\.UNTAPPED\s*\)", text):
        constraints["static_required_tapped_state"] = "untapped"
    if "TappedPredicate.TAPPED" in text:
        return "static_controlled_pt_source_filter_not_supported"
    if re.search(rf"{re.escape(filter_name)}\.add\s*\(\s*AttackingPredicate\.instance\s*\)", text):
        constraints["static_required_combat_state"] = "attacking"
    if "AttackingPredicate" in text and constraints.get("static_required_combat_state") != "attacking":
        return "static_controlled_pt_source_filter_not_supported"
    safe_get_predicates = re.findall(rf"{re.escape(filter_name)}\.add\s*\(\s*([A-Za-z]+)\.([A-Z0-9_]+)\.getPredicate", text)
    for owner, value in safe_get_predicates:
        if owner == "SubType":
            continue
        if owner == "CardType" and value == "ARTIFACT":
            continue
        if owner == "SuperType" and value == "LEGENDARY":
            continue
        return "static_controlled_pt_source_filter_not_supported"
    if "ColorPredicate" in text and not constraints.get("static_required_colors"):
        return "static_controlled_pt_source_filter_not_supported"
    if not constraints and filter_name != "filter":
        return "static_controlled_pt_source_filter_not_supported"
    return constraints


def static_controlled_pt_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    matches = re.findall(
        r"new\s+BoostControlledEffect\s*\(\s*([+-]?\d+)\s*,\s*([+-]?\d+)\s*,\s*"
        r"Duration\.WhileOnBattlefield(?P<rest>[^)]*)\)",
        text,
        re.S,
    )
    if len(matches) != 1:
        return None
    power_raw, toughness_raw, rest = matches[0]
    rest_text = str(rest or "")
    bool_args = re.findall(r"\b(true|false)\b", rest_text)
    exclude_source = bool_args[-1] == "true" if bool_args else False
    filter_name: str | None = None
    static_filter_match = re.search(r"(StaticFilters\.FILTER_[A-Z0-9_]+)", rest_text)
    if static_filter_match:
        filter_name = static_filter_match.group(1)
    else:
        filter_match = re.search(r",\s*([A-Za-z_][A-Za-z0-9_]*)\s*(?:,\s*(?:true|false))?\s*$", rest_text.strip())
        if filter_match:
            candidate = filter_match.group(1)
            if candidate not in {"true", "false"}:
                filter_name = candidate
    constraints = static_controlled_pt_filter_constraints_from_source(text, filter_name)
    if isinstance(constraints, str):
        return constraints
    return {
        "static_power_bonus": int(power_raw),
        "static_toughness_bonus": int(toughness_raw),
        "static_exclude_source": exclude_source,
        **constraints,
    }


STATIC_CONTROLLED_KEYWORD_COLOR_WORDS = {
    "white": "W",
    "blue": "U",
    "black": "B",
    "red": "R",
    "green": "G",
}


def static_controlled_keyword_constraints_from_subject(
    subject: str,
) -> dict[str, Any] | str:
    phrase = re.sub(r"\s+", " ", str(subject or "").strip().lower())
    if not phrase or phrase in {"creature", "creatures"}:
        return {}
    if phrase.endswith(" creatures"):
        phrase = phrase[: -len(" creatures")].strip()
    elif phrase.endswith(" creature"):
        phrase = phrase[: -len(" creature")].strip()
    if not phrase:
        return {}
    blocked_words = STATIC_CONTROLLED_PT_BLOCKED_ORACLE_WORDS - set(
        STATIC_CONTROLLED_KEYWORD_COLOR_WORDS
    )
    words = phrase.split()
    if any(word in blocked_words for word in words):
        return "static_controlled_keyword_oracle_filter_not_supported"
    constraints: dict[str, Any] = {}
    colors = [
        STATIC_CONTROLLED_KEYWORD_COLOR_WORDS[word]
        for word in words
        if word in STATIC_CONTROLLED_KEYWORD_COLOR_WORDS
    ]
    subtypes: list[str] = []
    for word in words:
        if word in STATIC_CONTROLLED_KEYWORD_COLOR_WORDS:
            continue
        if word == "artifact":
            constraints["static_artifact_creature"] = True
            continue
        if word == "legendary":
            constraints["static_required_supertypes"] = ["legendary"]
            continue
        subtype = canonical_static_subtype(word)
        if subtype:
            subtypes.append(subtype)
    if colors:
        constraints["static_required_colors"] = ordered_color_symbols(colors)
    if subtypes:
        constraints["static_required_subtypes"] = sorted(set(subtypes))
    return constraints


def static_controlled_keyword_from_oracle(
    metadata: dict[str, Any],
    keyword: str,
) -> dict[str, Any] | str | None:
    text = strip_parenthetical_reminders(oracle_text_after_leading_static_keywords(metadata))
    text = re.sub(r"\s+", " ", text).strip().lower()
    text = re.sub(r"^[a-z0-9' -]+\s+[—-]\s+", "", text)
    keyword_text = str(keyword or "").replace("_", " ").strip().lower()
    if not keyword_text:
        return None
    match = re.match(
        rf"^(?:each )?(?P<other>other )?(?P<subject>[a-z0-9' -]+?) "
        rf"you control (?:have|has) {re.escape(keyword_text)}\.?$",
        text,
    )
    if not match:
        return None
    constraints = static_controlled_keyword_constraints_from_subject(
        match.group("subject").strip()
    )
    if isinstance(constraints, str):
        return constraints
    return {
        "static_granted_keywords": [keyword],
        "static_exclude_source": bool(match.group("other")),
        **constraints,
    }


def static_controlled_keyword_filter_constraints_from_source(
    source: str,
    filter_name: str | None,
) -> dict[str, Any] | str:
    text = source or ""
    unsupported_markers = set(STATIC_CONTROLLED_PT_BLOCKED_SOURCE_MARKERS) - {
        "ColorPredicate"
    }
    if any(marker in text for marker in unsupported_markers):
        return "static_controlled_keyword_source_filter_not_supported"
    if not filter_name:
        return {}
    if filter_name in {
        "StaticFilters.FILTER_PERMANENT_CREATURE",
        "StaticFilters.FILTER_PERMANENT_CREATURES",
        "StaticFilters.FILTER_CONTROLLED_CREATURES",
    }:
        return {}
    if filter_name == "StaticFilters.FILTER_PERMANENT_SLIVERS":
        return {"static_required_subtypes": ["sliver"]}
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", filter_name):
        return "static_controlled_keyword_source_filter_not_supported"
    constraints: dict[str, Any] = {}
    color_tokens = re.findall(
        rf"{re.escape(filter_name)}\.add\s*\(\s*new\s+ColorPredicate\s*\(\s*ObjectColor\.([A-Z]+)\s*\)\s*\)",
        text,
    )
    if color_tokens:
        colors = [
            OBJECT_COLOR_TO_SYMBOL[token]
            for token in color_tokens
            if token in OBJECT_COLOR_TO_SYMBOL
        ]
        if colors:
            constraints["static_required_colors"] = ordered_color_symbols(colors)
    subtype_tokens = re.findall(
        rf"{re.escape(filter_name)}\s*=\s*new\s+Filter(?:Creature)?Permanent\s*\(\s*SubType\.([A-Z0-9_]+)",
        text,
    )
    subtype_tokens += re.findall(
        rf"{re.escape(filter_name)}\.add\s*\(\s*SubType\.([A-Z0-9_]+)\.getPredicate\s*\(\s*\)\s*\)",
        text,
    )
    if subtype_tokens:
        constraints["static_required_subtypes"] = sorted(
            {canonical_static_subtype(token.replace("_", " ")) for token in subtype_tokens}
        )
    if re.search(rf"{re.escape(filter_name)}\.add\s*\(\s*CardType\.ARTIFACT\.getPredicate\s*\(\s*\)\s*\)", text):
        constraints["static_artifact_creature"] = True
    if re.search(rf"{re.escape(filter_name)}\.add\s*\(\s*SuperType\.LEGENDARY\.getPredicate\s*\(\s*\)\s*\)", text):
        constraints["static_required_supertypes"] = ["legendary"]
    safe_get_predicates = re.findall(
        rf"{re.escape(filter_name)}\.add\s*\(\s*([A-Za-z]+)\.([A-Z0-9_]+)\.getPredicate",
        text,
    )
    for owner, value in safe_get_predicates:
        if owner == "SubType":
            continue
        if owner == "CardType" and value == "ARTIFACT":
            continue
        if owner == "SuperType" and value == "LEGENDARY":
            continue
        return "static_controlled_keyword_source_filter_not_supported"
    if "ColorPredicate" in text and not constraints.get("static_required_colors"):
        return "static_controlled_keyword_source_filter_not_supported"
    if not constraints and filter_name != "filter":
        return "static_controlled_keyword_source_filter_not_supported"
    return constraints


def static_controlled_keyword_from_source(
    source: str,
) -> dict[str, Any] | str | None:
    text = source or ""
    if len(re.findall(r"new\s+GainAbilityControlledEffect\s*\(", text)) != 1:
        return None
    gain_match = re.search(r"new\s+GainAbilityControlledEffect\s*\(", text)
    window = text[gain_match.start() : gain_match.start() + 1600] if gain_match else text
    if "Duration.WhileOnBattlefield" not in window or "Duration.EndOfTurn" in window:
        return None
    keyword_matches = re.findall(
        r"(?:new\s+GainAbilityControlledEffect\s*\(\s*)"
        r"(?:([A-Za-z0-9_]+Ability)\.getInstance\s*\(\s*\)|new\s+([A-Za-z0-9_]+Ability)\s*\()",
        window,
        re.S,
    )
    keywords = [
        STATIC_SELF_KEYWORD_ABILITY_CLASSES.get(match[0] or match[1])
        for match in keyword_matches
        if STATIC_SELF_KEYWORD_ABILITY_CLASSES.get(match[0] or match[1])
    ]
    if len(keywords) != 1:
        return None
    after_duration = window.split("Duration.WhileOnBattlefield", 1)[1]
    bool_args = re.findall(r"\b(true|false)\b", after_duration)
    exclude_source = bool_args[-1] == "true" if bool_args else False
    filter_name: str | None = None
    static_filter_match = re.search(r"(StaticFilters\.FILTER_[A-Z0-9_]+)", after_duration)
    if static_filter_match:
        filter_name = static_filter_match.group(1)
    elif re.search(r"new\s+FilterControlledCreaturePermanent\s*\(", after_duration):
        filter_name = None
    else:
        filter_match = re.search(
            r",\s*([A-Za-z_][A-Za-z0-9_]*)\s*(?:,\s*(?:true|false))?\s*\)",
            after_duration,
            re.S,
        )
        if filter_match:
            candidate = filter_match.group(1)
            if candidate not in {"true", "false"}:
                filter_name = candidate
    constraints = static_controlled_keyword_filter_constraints_from_source(
        text,
        filter_name,
    )
    if isinstance(constraints, str):
        return constraints
    return {
        "static_granted_keywords": [keywords[0]],
        "static_exclude_source": exclude_source,
        **constraints,
    }


STATIC_GLOBAL_PT_BLOCKED_SOURCE_MARKERS = {
    "Duration.EndOfTurn",
    "DynamicValue",
    "CardsDrawnThisTurnDynamicValue",
    "CardsInControllerHandCount",
    "PermanentsOnBattlefieldCount",
    "FilterBlockingCreature",
    "FILTER_ATTACKING_CREATURES",
    "FILTER_BLOCKING_CREATURES",
    "filterNoAbilities",
    "ObjectHasNoAbilitiesPredicate",
}


def static_global_pt_filter_label(creature_filter: dict[str, Any] | None) -> str:
    if not creature_filter:
        return "creatures"
    if creature_filter.get("token"):
        return "creature_tokens"
    if creature_filter.get("card_types"):
        return "_".join(str(value).lower() for value in creature_filter["card_types"]) + "_creatures"
    if creature_filter.get("colors"):
        return "_".join(str(value).lower() for value in creature_filter["colors"]) + "_creatures"
    if creature_filter.get("subtypes"):
        return "_".join(str(value).lower() for value in creature_filter["subtypes"]) + "_creatures"
    return boost_all_filter_label(creature_filter)


def static_global_pt_filter_from_oracle_subject(subject: str) -> dict[str, Any] | str | None:
    phrase = re.sub(r"\s+", " ", str(subject or "").strip().lower())
    if not phrase or phrase in {"creature", "creatures", "all creatures"}:
        return None
    if phrase == "creature tokens":
        return {"token": True}
    if phrase in {"land", "lands", "each land"}:
        return {"card_types": ["land"]}
    if phrase.startswith("all "):
        phrase = phrase[4:].strip()
    if phrase.endswith(" creatures"):
        phrase = phrase[: -len(" creatures")].strip()
    elif phrase.endswith(" creature"):
        phrase = phrase[: -len(" creature")].strip()
    if not phrase:
        return None
    words = phrase.split()
    blocked_words = STATIC_CONTROLLED_PT_BLOCKED_ORACLE_WORDS - set(BOOST_ALL_FILTER_COLOR_WORDS)
    if any(word in blocked_words for word in words):
        return "static_global_pt_oracle_filter_not_supported"
    colors = [BOOST_ALL_FILTER_COLOR_WORDS[word] for word in words if word in BOOST_ALL_FILTER_COLOR_WORDS]
    subtypes = [
        canonical_static_subtype(word)
        for word in words
        if word not in BOOST_ALL_FILTER_COLOR_WORDS
    ]
    result: dict[str, Any] = {}
    if colors:
        result["colors"] = ordered_color_symbols(colors)
    if subtypes:
        result["subtypes"] = sorted({subtype for subtype in subtypes if subtype})
    return result or None


def static_global_pt_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str | None:
    text = strip_leading_parenthetical_reminders(oracle_text(metadata))
    lowered = text.lower()
    if any(token in lowered for token in ("+x/", "/+x", "-x/", "/-x", "where x", "for each")):
        return "static_global_pt_oracle_dynamic_not_supported"
    land_match = re.match(
        r"^each land gets (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+) as long as it's a creature\.?$",
        text,
        re.I,
    )
    if land_match:
        power = signed_int_from_oracle(land_match.group("power"))
        toughness = signed_int_from_oracle(land_match.group("toughness"))
        if power is None or toughness is None:
            return None
        return {
            "static_power_bonus": power,
            "static_toughness_bonus": toughness,
            "static_controller_scope": "all",
            "static_exclude_source": False,
            "creature_filter": {"card_types": ["land"]},
        }
    opponents_match = re.match(
        r"^creatures your opponents control get (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+)\.?$",
        text,
        re.I,
    )
    if opponents_match:
        power = signed_int_from_oracle(opponents_match.group("power"))
        toughness = signed_int_from_oracle(opponents_match.group("toughness"))
        if power is None or toughness is None:
            return None
        return {
            "static_power_bonus": power,
            "static_toughness_bonus": toughness,
            "static_controller_scope": "opponents",
            "static_exclude_source": False,
            "creature_filter": None,
        }
    match = re.match(
        r"^(?P<other>other )?(?P<subject>[a-z0-9' -]+?) "
        r"get (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+)\.?$",
        text,
        re.I,
    )
    if not match:
        return None
    subject = match.group("subject").strip()
    creature_filter = static_global_pt_filter_from_oracle_subject(subject)
    if isinstance(creature_filter, str):
        return creature_filter
    power = signed_int_from_oracle(match.group("power"))
    toughness = signed_int_from_oracle(match.group("toughness"))
    if power is None or toughness is None:
        return None
    return {
        "static_power_bonus": power,
        "static_toughness_bonus": toughness,
        "static_controller_scope": "all",
        "static_exclude_source": bool(match.group("other")),
        "creature_filter": creature_filter,
    }


def static_global_pt_filter_from_source(source: str, args: list[str]) -> dict[str, Any] | str | None:
    text = source or ""
    if len(args) <= 3:
        return None
    filter_args = [arg.strip() for arg in args[3:] if arg.strip() not in {"true", "false"}]
    if not filter_args:
        return None
    filter_text = ", ".join(filter_args)
    if "StaticFilters.FILTER_OPPONENTS_PERMANENT_CREATURES" in filter_text:
        return None
    if "StaticFilters.FILTER_PERMANENT_CREATURE" in filter_text:
        return None
    if "StaticFilters.FILTER_PERMANENT_ALL_SLIVERS" in filter_text:
        return {"subtypes": ["sliver"]}
    inline_subtypes = re.findall(r"SubType\.([A-Z0-9_]+)", filter_text)
    if inline_subtypes:
        return {
            "subtypes": sorted(
                {canonical_static_subtype(token.replace("_", " ")) for token in inline_subtypes}
            )
        }
    filter_name = filter_args[0] if len(filter_args) == 1 else ""
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", filter_name):
        return "static_global_pt_source_filter_not_supported"
    if re.search(rf"\b{re.escape(filter_name)}\.add\s*\(\s*TokenPredicate\.TRUE\s*\)", text):
        return {"token": True}
    if re.search(rf"\b{re.escape(filter_name)}\.add\s*\(\s*CardType\.LAND\.getPredicate\s*\(\s*\)\s*\)", text):
        return {"card_types": ["land"]}
    color_tokens = re.findall(
        rf"\b{re.escape(filter_name)}\.add\s*\(\s*new\s+ColorPredicate\s*\(\s*ObjectColor\.([A-Z]+)\s*\)\s*\)",
        text,
    )
    if color_tokens:
        colors = [
            OBJECT_COLOR_TO_SYMBOL[token]
            for token in color_tokens
            if token in OBJECT_COLOR_TO_SYMBOL
        ]
        if colors:
            return {"colors": ordered_color_symbols(colors)}
    subtype_tokens = re.findall(
        rf"\b{re.escape(filter_name)}\.add\s*\(\s*SubType\.([A-Z0-9_]+)\.getPredicate\s*\(\s*\)\s*\)",
        text,
    )
    subtype_tokens += re.findall(
        rf"\b{re.escape(filter_name)}\s*=\s*new\s+Filter(?:Creature)?Permanent\s*\(\s*SubType\.([A-Z0-9_]+)",
        text,
    )
    if subtype_tokens:
        return {
            "subtypes": sorted(
                {canonical_static_subtype(token.replace("_", " ")) for token in subtype_tokens}
            )
        }
    return "static_global_pt_source_filter_not_supported"


def static_global_pt_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    if any(marker in text for marker in STATIC_GLOBAL_PT_BLOCKED_SOURCE_MARKERS):
        return "static_global_pt_source_dynamic_or_phase_not_supported"
    if len(re.findall(r"\bBoostAllEffect\s*\(", text)) != 1:
        return "static_global_pt_source_not_single_fixed"
    args_text = extract_java_call_args(text, "BoostAllEffect")
    if args_text is None:
        return "static_global_pt_source_not_single_fixed"
    args = split_java_args(args_text)
    if len(args) < 3:
        return "static_global_pt_source_not_single_fixed"
    if not re.fullmatch(r"[+-]?\d+", args[0].strip()) or not re.fullmatch(r"[+-]?\d+", args[1].strip()):
        return "static_global_pt_source_dynamic_or_phase_not_supported"
    if args[2].strip() != "Duration.WhileOnBattlefield":
        return "static_global_pt_source_dynamic_or_phase_not_supported"
    controller_scope = "all"
    if any("StaticFilters.FILTER_OPPONENTS_PERMANENT_CREATURES" in arg for arg in args[3:]):
        controller_scope = "opponents"
    bool_args = [arg.strip() for arg in args[3:] if arg.strip() in {"true", "false"}]
    exclude_source = bool_args[-1] == "true" if bool_args else False
    creature_filter = static_global_pt_filter_from_source(text, args)
    if isinstance(creature_filter, str):
        return creature_filter
    return {
        "static_power_bonus": int(args[0].strip()),
        "static_toughness_bonus": int(args[1].strip()),
        "static_controller_scope": controller_scope,
        "static_exclude_source": exclude_source,
        "creature_filter": creature_filter,
    }


def static_global_pt_source_can_match_filter(metadata: dict[str, Any], creature_filter: dict[str, Any] | None) -> bool:
    type_line = str(metadata.get("type_line") or "").lower()
    if "creature" not in type_line:
        return False
    if not creature_filter:
        return True
    if creature_filter.get("token"):
        return False
    for card_type in creature_filter.get("card_types") or []:
        if str(card_type).lower() not in type_line.replace("—", " ").replace("-", " ").split():
            return False
    for subtype in creature_filter.get("subtypes") or []:
        if canonical_static_subtype(str(subtype)) not in {
            canonical_static_subtype(part)
            for part in re.split(r"[\s—-]+", type_line)
            if part
        }:
            return False
    source_colors = set(ordered_color_symbols(metadata.get("colors") or metadata.get("color_identity") or []))
    required_colors = set(ordered_color_symbols(creature_filter.get("colors") or []))
    if required_colors and not source_colors.intersection(required_colors):
        return False
    return True


def static_global_pt_specs_match(
    source_static: dict[str, Any],
    oracle_static: dict[str, Any],
    metadata: dict[str, Any],
) -> bool:
    if source_static == oracle_static:
        return True
    normalized_source = dict(source_static)
    normalized_oracle = dict(oracle_static)
    if (
        bool(normalized_source.get("static_exclude_source"))
        and not bool(normalized_oracle.get("static_exclude_source"))
        and normalized_source.get("creature_filter") == normalized_oracle.get("creature_filter")
        and not static_global_pt_source_can_match_filter(metadata, normalized_source.get("creature_filter"))
    ):
        normalized_source["static_exclude_source"] = False
    return normalized_source == normalized_oracle


STATIC_GRAVEYARD_COUNT_PT_FILTERS = {
    "StaticFilters.FILTER_CARD_ARTIFACTS": ["artifact"],
    "StaticFilters.FILTER_CARD_CREATURES": ["creature"],
    "StaticFilters.FILTER_CARD_ENCHANTMENTS": ["enchantment"],
    "StaticFilters.FILTER_CARD_INSTANTS": ["instant"],
    "StaticFilters.FILTER_CARD_LANDS": ["land"],
    "StaticFilters.FILTER_CARD_SORCERIES": ["sorcery"],
}


def static_graveyard_count_pt_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text_after_leading_static_keywords(metadata)
    match = re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of "
        r"(?P<card_type>artifact|creature|enchantment|instant|land|sorcery) cards in "
        r"(?P<scope>your graveyard|all graveyards)\.?$",
        text,
    )
    if match:
        return {
            "graveyard_count_scope": (
                "controller_graveyard"
                if match.group("scope") == "your graveyard"
                else "all_graveyards"
            ),
            "graveyard_count_card_types": [match.group("card_type")],
        }
    if re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of cards in all graveyards\.?$",
        text,
    ):
        return {
            "graveyard_count_scope": "all_graveyards",
            "graveyard_count_card_types": ["card"],
        }
    return None


def static_graveyard_count_filter_types_from_source(source: str, filter_name: str | None) -> list[str] | str:
    text = source or ""
    if not filter_name:
        return ["card"]
    if filter_name in STATIC_GRAVEYARD_COUNT_PT_FILTERS:
        return list(STATIC_GRAVEYARD_COUNT_PT_FILTERS[filter_name])
    if filter_name == "new FilterLandCard":
        return ["land"]
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", filter_name):
        return "static_graveyard_count_pt_source_filter_not_supported"
    type_tokens = re.findall(
        rf"{re.escape(filter_name)}\.add\s*\(\s*CardType\.([A-Z0-9_]+)\.getPredicate\s*\(\s*\)\s*\)",
        text,
    )
    if len(type_tokens) == 1:
        return [type_tokens[0].lower().replace("_", " ")]
    return "static_graveyard_count_pt_source_filter_not_supported"


def static_graveyard_count_pt_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    if (
        "AdditiveDynamicValue" in text
        or "PermanentsOnBattlefieldCount" in text
        or "game.getBattlefield().count" in text
    ):
        return "static_graveyard_count_pt_source_not_direct_graveyard_count"
    if len(re.findall(r"new\s+SetBasePowerToughnessSourceEffect\s*\(", text)) != 1:
        return None
    if "CardsInControllerGraveyardCount" in text:
        scope = "controller_graveyard"
        match = re.search(r"new\s+CardsInControllerGraveyardCount\s*\(\s*([^)]+?)\s*\)", text, re.S)
        filter_name = match.group(1).strip() if match else None
    elif "CardsInAllGraveyardsCount" in text:
        scope = "all_graveyards"
        match = re.search(r"new\s+CardsInAllGraveyardsCount\s*\(\s*(?:new\s+)?([^)]+?)\s*\)", text, re.S)
        filter_name = match.group(1).strip() if match else None
        if filter_name and filter_name.startswith("FilterLandCard"):
            filter_name = "new FilterLandCard"
    elif re.search(r"getMessage\s*\(\s*\).*?cards in all graveyards", text, re.S):
        scope = "all_graveyards"
        filter_name = None
    else:
        return None
    card_types = static_graveyard_count_filter_types_from_source(text, filter_name)
    if isinstance(card_types, str):
        return card_types
    return {
        "graveyard_count_scope": scope,
        "graveyard_count_card_types": card_types or ["card"],
    }


STATIC_COUNT_PT_BASIC_LAND_SUBTYPES = {
    "plains": "plains",
    "islands": "island",
    "island": "island",
    "swamps": "swamp",
    "swamp": "swamp",
    "mountains": "mountain",
    "mountain": "mountain",
    "forests": "forest",
    "forest": "forest",
}
STATIC_COUNT_PT_IRREGULAR_SUBTYPES = {
    "elves": "elf",
}
STATIC_COUNT_PT_COLOR_WORDS = {
    "white": "W",
    "blue": "U",
    "black": "B",
    "red": "R",
    "green": "G",
}
STATIC_COUNT_PT_OBJECT_COLOR_SYMBOLS = {
    "WHITE": "W",
    "BLUE": "U",
    "BLACK": "B",
    "RED": "R",
    "GREEN": "G",
}


def static_count_pt_subtype_token(value: str) -> str:
    token = re.sub(r"[^a-z0-9]+", " ", str(value or "").lower()).strip()
    token = re.sub(r"\s+", " ", token)
    if token in STATIC_COUNT_PT_IRREGULAR_SUBTYPES:
        return STATIC_COUNT_PT_IRREGULAR_SUBTYPES[token]
    if token.endswith("ies") and len(token) > 3:
        return f"{token[:-3]}y"
    if token.endswith("s") and len(token) > 1:
        return token[:-1]
    return token


def static_count_pt_result(**fields: Any) -> dict[str, Any]:
    return {
        "static_power_toughness_source": "battlefield_permanent_count",
        "stat_modifier_amount_source": "battlefield_permanent_count",
        "static_power_toughness_base": 0,
        "static_power_toughness_count_multiplier": 1,
        **fields,
    }


def static_count_pt_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text_after_leading_static_keywords(metadata)
    text = re.sub(r"\b(domain|chroma)\s+[\u2014-]\s+", "", text)
    if re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of creatures you control\.?$",
        text,
    ):
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["creature"],
        )
    if re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of creatures on the battlefield\.?$",
        text,
    ):
        return static_count_pt_result(
            battlefield_count_scope="all_battlefields",
            battlefield_count_card_types=["creature"],
        )
    if re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of lands you control\.?$",
        text,
    ):
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["land"],
        )
    domain_match = re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to "
        r"(?P<twice>twice )?the number of basic land types among lands you control\.?$",
        text,
    )
    if domain_match:
        return static_count_pt_result(
            static_power_toughness_source="domain_basic_land_types",
            stat_modifier_amount_source="domain_basic_land_types",
            static_power_toughness_count_multiplier=2 if domain_match.group("twice") else 1,
        )
    color_match = re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of "
        r"(?P<color>white|blue|black|red|green) permanents you control\.?$",
        text,
    )
    if color_match:
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["permanent"],
            battlefield_count_required_colors=[
                STATIC_COUNT_PT_COLOR_WORDS[color_match.group("color")]
            ],
        )
    if re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of nonland permanents you control\.?$",
        text,
    ):
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["permanent"],
            battlefield_count_excluded_card_types=["land"],
        )
    non_wall_match = re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of non-wall creatures you control\.?$",
        text,
    )
    if non_wall_match:
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["creature"],
            battlefield_count_excluded_subtypes=["wall"],
        )
    if re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of untapped artifacts, creatures, and lands you control\.?$",
        text,
    ):
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["artifact", "creature", "land"],
            battlefield_count_tapped_state="untapped",
        )
    named_match = re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of creatures named (?P<name>[a-z0-9' ,./-]+) on the battlefield\.?$",
        text,
    )
    if named_match:
        return static_count_pt_result(
            battlefield_count_scope="all_battlefields",
            battlefield_count_card_types=["creature"],
            battlefield_count_card_names=[named_match.group("name").strip()],
        )
    basic_land_match = re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of "
        r"(?P<subtype>plains|islands|swamps|mountains|forests) you control\.?$",
        text,
    )
    if basic_land_match:
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_subtypes=[
                STATIC_COUNT_PT_BASIC_LAND_SUBTYPES[basic_land_match.group("subtype")]
            ],
        )
    if re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of cards in your hand\.?$",
        text,
    ):
        return static_count_pt_result(
            static_power_toughness_source="controller_hand_count",
            stat_modifier_amount_source="controller_hand_count",
        )
    if re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to twice the number of cards in your hand\.?$",
        text,
    ):
        return static_count_pt_result(
            static_power_toughness_source="controller_hand_count",
            stat_modifier_amount_source="controller_hand_count",
            static_power_toughness_count_multiplier=2,
        )
    if re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of cards in the hand of the opponent with the most cards in hand\.?$",
        text,
    ):
        return static_count_pt_result(
            static_power_toughness_source="opponent_max_hand_count",
            stat_modifier_amount_source="opponent_max_hand_count",
        )
    if re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the total number of cards in all players' hands\.?$",
        text,
    ):
        return static_count_pt_result(
            static_power_toughness_source="all_players_hand_count",
            stat_modifier_amount_source="all_players_hand_count",
        )
    subtype_battlefield_match = re.match(
        r"^[a-z0-9' ,./-]+ power and toughness are each equal to the number of "
        r"(?P<subtype>[a-z][a-z -]+) on the battlefield\.?$",
        text,
    )
    if subtype_battlefield_match:
        subtype = static_count_pt_subtype_token(subtype_battlefield_match.group("subtype"))
        if subtype and " " not in subtype:
            return static_count_pt_result(
                battlefield_count_scope="all_battlefields",
                battlefield_count_subtypes=[subtype],
            )
    return None


def static_count_pt_source_subtypes(source: str) -> list[str]:
    return [
        token.lower().replace("_", " ")
        for token in re.findall(r"\.add\s*\(\s*SubType\.([A-Z0-9_]+)\.getPredicate\s*\(\s*\)\s*\)", source or "")
    ]


def static_count_pt_source_color_symbols(source: str) -> list[str]:
    return [
        STATIC_COUNT_PT_OBJECT_COLOR_SYMBOLS[token]
        for token in re.findall(r"ColorPredicate\s*\(\s*ObjectColor\.([A-Z]+)\s*\)", source or "")
        if token in STATIC_COUNT_PT_OBJECT_COLOR_SYMBOLS
    ]


def static_count_pt_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    if len(re.findall(r"new\s+SetBasePowerToughnessSourceEffect\s*\(", text)) != 1:
        return None
    if "DomainValue.REGULAR" in text:
        multiplier = 1
        if re.search(
            r"new\s+MultipliedValue\s*\(\s*DomainValue\.REGULAR\s*,\s*([0-9]+)\s*\)",
            text,
        ):
            multiplier = int(
                re.search(
                    r"new\s+MultipliedValue\s*\(\s*DomainValue\.REGULAR\s*,\s*([0-9]+)\s*\)",
                    text,
                ).group(1)
            )
        elif "MultipliedValue" in text:
            return "static_count_pt_source_count_not_supported"
        return static_count_pt_result(
            static_power_toughness_source="domain_basic_land_types",
            stat_modifier_amount_source="domain_basic_land_types",
            static_power_toughness_count_multiplier=multiplier,
        )
    if "MostCardsInOpponentsHandCount" in text:
        return static_count_pt_result(
            static_power_toughness_source="opponent_max_hand_count",
            stat_modifier_amount_source="opponent_max_hand_count",
        )
    if "CardsInAllHandsCount.instance" in text:
        return static_count_pt_result(
            static_power_toughness_source="all_players_hand_count",
            stat_modifier_amount_source="all_players_hand_count",
        )
    if "CardsInControllerHandCount.ANY" in text:
        multiplier = 1
        multiplied = re.search(
            r"new\s+MultipliedValue\s*\(\s*CardsInControllerHandCount\.ANY\s*,\s*([0-9]+)\s*\)",
            text,
        )
        if multiplied:
            multiplier = int(multiplied.group(1))
        elif "MultipliedValue" in text:
            return "static_count_pt_source_count_not_supported"
        return static_count_pt_result(
            static_power_toughness_source="controller_hand_count",
            stat_modifier_amount_source="controller_hand_count",
            static_power_toughness_count_multiplier=multiplier,
        )
    blocked_markers = (
        "AdditiveDynamicValue",
        "IntPlusDynamicValue",
        "MultipliedValue",
        "CardsInControllerHandCount",
        "MostCardsInOpponentsHandCount",
        "DevotionCount",
        "ManaSymbolsCount",
        "ColorsAmongControlledPermanentsCount",
        "getHand().size()",
    )
    if any(marker in text for marker in blocked_markers):
        return "static_count_pt_source_count_not_supported"
    if "CreaturesYouControlCount" in text or "StaticFilters.FILTER_CONTROLLED_CREATURES" in text:
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["creature"],
        )
    if "new FilterCreaturePermanent" in text and "creatures on the battlefield" in text:
        return static_count_pt_result(
            battlefield_count_scope="all_battlefields",
            battlefield_count_card_types=["creature"],
        )
    if "FilterControlledLandPermanent" in text or "StaticFilters.FILTER_CONTROLLED_PERMANENT_LAND" in text:
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["land"],
        )
    colors = static_count_pt_source_color_symbols(text)
    if colors and "PermanentsOnBattlefieldCount" in text and "FilterControlledPermanent" in text:
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["permanent"],
            battlefield_count_required_colors=colors,
        )
    if "PermanentsOnBattlefieldCount" in text and "Predicates.not(CardType.LAND.getPredicate())" in text:
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["permanent"],
            battlefield_count_excluded_card_types=["land"],
        )
    if "PermanentsOnBattlefieldCount" in text and "Predicates.not(SubType.WALL.getPredicate())" in text:
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["creature"],
            battlefield_count_excluded_subtypes=["wall"],
        )
    if "PermanentsOnBattlefieldCount" in text and "TappedPredicate.UNTAPPED" in text:
        card_types = [
            card_type.lower()
            for card_type in re.findall(r"CardType\.([A-Z]+)\.getPredicate\s*\(\s*\)", text)
        ]
        if card_types:
            return static_count_pt_result(
                battlefield_count_scope="controller_battlefield",
                battlefield_count_card_types=card_types,
                battlefield_count_tapped_state="untapped",
            )
    name_match = re.search(r"new\s+NamePredicate\s*\(\s*\"([^\"]+)\"\s*\)", text)
    if "PermanentsOnBattlefieldCount" in text and name_match:
        return static_count_pt_result(
            battlefield_count_scope="all_battlefields",
            battlefield_count_card_types=["creature"],
            battlefield_count_card_names=[name_match.group(1).strip().lower()],
        )
    subtypes = static_count_pt_source_subtypes(text)
    if subtypes:
        controlled = (
            "FilterControlledPermanent" in text
            or "FilterControlledLandPermanent" in text
            or "you control" in text
        )
        return static_count_pt_result(
            battlefield_count_scope="controller_battlefield" if controlled else "all_battlefields",
            battlefield_count_subtypes=subtypes,
        )
    return None


STATIC_GRAVEYARD_THRESHOLD_WORDS = {
    "one": 1,
    "two": 2,
    "three": 3,
    "four": 4,
    "five": 5,
    "six": 6,
    "seven": 7,
    "eight": 8,
    "nine": 9,
    "ten": 10,
}


def static_graveyard_threshold_int(value: str) -> int | None:
    token = str(value or "").strip().lower()
    if token.isdigit():
        return int(token)
    return STATIC_GRAVEYARD_THRESHOLD_WORDS.get(token)


def static_graveyard_threshold_boost_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text_after_leading_static_keywords(metadata)
    text = re.sub(r"^(?:threshold|delirium|descend\s+\d+)\s*[—-]\s*", "", text).strip()
    delirium_match = re.match(
        r"^(?:this creature|[a-z0-9' ,./-]+) gets (?P<power>[+-]\d+)/(?P<toughness>[+-]\d+) "
        r"as long as there are four or more card types among cards in your graveyard\.?$",
        text,
    )
    if delirium_match:
        power_bonus = signed_int_from_oracle(delirium_match.group("power"))
        toughness_bonus = signed_int_from_oracle(delirium_match.group("toughness"))
        if power_bonus is None or toughness_bonus is None:
            return None
        return {
            "graveyard_count_scope": "controller_graveyard",
            "graveyard_count_card_types": ["card_type"],
            "graveyard_count_mode": "distinct_card_types",
            "graveyard_count_threshold": 4,
            "static_power_bonus": power_bonus,
            "static_toughness_bonus": toughness_bonus,
        }
    match = re.match(
        r"^this creature gets (?P<power>[+-]\d+)/(?P<toughness>[+-]\d+) as long as "
        r"(?:there are (?P<threshold_a>\d+|one|two|three|four|five|six|seven|eight|nine|ten) "
        r"or more (?P<permanent_a>permanent )?cards in your graveyard|"
        r"(?P<threshold_b>\d+|one|two|three|four|five|six|seven|eight|nine|ten) "
        r"or more (?P<permanent_b>permanent )?cards are in your graveyard)\.?$",
        text,
    )
    if not match:
        return None
    threshold = static_graveyard_threshold_int(match.group("threshold_a") or match.group("threshold_b"))
    power_bonus = signed_int_from_oracle(match.group("power"))
    toughness_bonus = signed_int_from_oracle(match.group("toughness"))
    if threshold is None or power_bonus is None or toughness_bonus is None:
        return None
    return {
        "graveyard_count_scope": "controller_graveyard",
        "graveyard_count_card_types": [
            "permanent" if (match.group("permanent_a") or match.group("permanent_b")) else "card"
        ],
        "graveyard_count_threshold": threshold,
        "static_power_bonus": power_bonus,
        "static_toughness_bonus": toughness_bonus,
    }


def static_graveyard_threshold_boost_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    if len(re.findall(r"new\s+ConditionalContinuousEffect\s*\(", text)) != 1:
        return None
    boost_match = re.search(
        r"new\s+BoostSourceEffect\s*\(\s*([+-]?\d+)\s*,\s*([+-]?\d+)\s*,\s*Duration\.WhileOnBattlefield\s*\)",
        text,
        re.S,
    )
    if not boost_match:
        return "static_graveyard_threshold_boost_source_not_fixed_boost"
    if "ThresholdCondition.instance" in text:
        threshold = 7
        card_types = ["card"]
    elif "DescendCondition.FOUR" in text:
        threshold = 4
        card_types = ["permanent"]
    elif "DeliriumCondition" in text:
        threshold = 4
        card_types = ["card_type"]
        count_mode = "distinct_card_types"
    elif (
        "LessonsInGraveCondition" in text
        or "CardsInOpponentGraveyardCondition" in text
        or "DifferentManaValuesInGraveCondition" in text
    ):
        return "static_graveyard_threshold_boost_source_condition_not_supported"
    else:
        return "static_graveyard_threshold_boost_source_condition_not_supported"
    return {
        "graveyard_count_scope": "controller_graveyard",
        "graveyard_count_card_types": card_types,
        **({"graveyard_count_mode": count_mode} if "count_mode" in locals() else {}),
        "graveyard_count_threshold": threshold,
        "static_power_bonus": int(boost_match.group(1)),
        "static_toughness_bonus": int(boost_match.group(2)),
    }


def static_graveyard_count_boost_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text_after_leading_static_keywords(metadata)
    match = re.match(
        r"^(?:this creature|[a-z0-9' ,./-]+) gets (?P<power>[+-]\d+)/(?P<toughness>[+-]\d+) for each "
        r"(?P<card_type>artifact|creature|artifact and/or enchantment|noncreature, nonland) card in "
        r"(?P<scope>your graveyard|your opponents' graveyards)\.?$",
        text,
    )
    if not match:
        return None
    power_bonus = signed_int_from_oracle(match.group("power"))
    toughness_bonus = signed_int_from_oracle(match.group("toughness"))
    if power_bonus is None or toughness_bonus is None:
        return None
    return {
        "graveyard_count_scope": (
            "controller_graveyard"
            if match.group("scope") == "your graveyard"
            else "opponents_graveyards"
        ),
        "graveyard_count_card_types": {
            "artifact and/or enchantment": ["artifact", "enchantment"],
            "noncreature, nonland": ["noncreature_nonland"],
        }.get(match.group("card_type"), [match.group("card_type")]),
        "static_power_bonus_per_graveyard_count": power_bonus,
        "static_toughness_bonus_per_graveyard_count": toughness_bonus,
    }


def static_graveyard_count_boost_source_filter_types(source: str, expr: str) -> list[str] | str:
    text = source or ""
    value = str(expr or "").strip()
    if "FilterArtifactCard" in value:
        return ["artifact"]
    if "FilterArtifactOrEnchantmentCard" in value:
        return ["artifact", "enchantment"]
    if "FILTER_CARD_CREATURE" in value or "FilterCreatureCard" in value:
        return ["creature"]
    if (
        "noncreature, nonland card" in value
        and re.search(
            r"\.add\s*\(\s*Predicates\.not\s*\(\s*CardType\.CREATURE\.getPredicate\s*\(\s*\)\s*\)\s*\)",
            text,
        )
        and re.search(
            r"\.add\s*\(\s*Predicates\.not\s*\(\s*CardType\.LAND\.getPredicate\s*\(\s*\)\s*\)\s*\)",
            text,
        )
    ):
        return ["noncreature_nonland"]
    if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", value):
        assignment = re.search(
            rf"(?:FilterCard|FilterCreatureCard|FilterArtifactCard)\s+{re.escape(value)}\s*=([^;]+);",
            text,
            re.S,
        )
        if assignment:
            return static_graveyard_count_boost_source_filter_types(text, assignment.group(1))
    return "static_graveyard_count_boost_source_filter_not_supported"


def static_graveyard_count_boost_source_dynamic_spec(source: str, expr: str) -> dict[str, Any] | str | None:
    text = source or ""
    value = str(expr or "").strip()
    if value == "StaticValue.get(0)":
        return {"static_value": 0}
    if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", value):
        assignment = re.search(
            rf"(?:private\s+static\s+final\s+)?(?:DynamicValue\s+)?{re.escape(value)}\s*=\s*new\s+"
            r"(CardsInControllerGraveyardCount|CardsInOpponentGraveyardsCount)\s*\((.*?)\)\s*;",
            text,
            re.S,
        )
        if assignment:
            scope = (
                "controller_graveyard"
                if assignment.group(1) == "CardsInControllerGraveyardCount"
                else "opponents_graveyards"
            )
            card_types = static_graveyard_count_boost_source_filter_types(text, assignment.group(2))
            if isinstance(card_types, str):
                return card_types
            return {
                "graveyard_count_scope": scope,
                "graveyard_count_card_types": card_types,
            }
    direct = re.match(r"^new\s+CardsInControllerGraveyardCount\s*\((.*)\)$", value, re.S)
    if direct:
        card_types = static_graveyard_count_boost_source_filter_types(text, direct.group(1))
        if isinstance(card_types, str):
            return card_types
        return {
            "graveyard_count_scope": "controller_graveyard",
            "graveyard_count_card_types": card_types,
        }
    return "static_graveyard_count_boost_source_dynamic_not_supported"


def split_top_level_args(arg_text: str) -> list[str]:
    args: list[str] = []
    current: list[str] = []
    depth = 0
    for char in str(arg_text or ""):
        if char == "," and depth == 0:
            args.append("".join(current).strip())
            current = []
            continue
        current.append(char)
        if char == "(":
            depth += 1
        elif char == ")" and depth > 0:
            depth -= 1
    if current:
        args.append("".join(current).strip())
    return args


def extract_constructor_args(source: str, constructor: str) -> str | None:
    needle = f"new {constructor}"
    start = str(source or "").find(needle)
    if start < 0:
        return None
    open_index = str(source or "").find("(", start + len(needle))
    if open_index < 0:
        return None
    depth = 0
    for index in range(open_index, len(source)):
        char = source[index]
        if char == "(":
            depth += 1
        elif char == ")":
            depth -= 1
            if depth == 0:
                return source[open_index + 1 : index]
    return None


def static_graveyard_count_boost_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    constructor_args = extract_constructor_args(text, "BoostSourceEffect")
    if constructor_args is None:
        return None
    args = split_top_level_args(constructor_args)
    if len(args) < 3 or args[2] != "Duration.WhileOnBattlefield":
        return "static_graveyard_count_boost_source_not_while_on_battlefield"
    power_spec = static_graveyard_count_boost_source_dynamic_spec(text, args[0])
    toughness_spec = static_graveyard_count_boost_source_dynamic_spec(text, args[1])
    if isinstance(power_spec, str):
        return power_spec
    if isinstance(toughness_spec, str):
        return toughness_spec
    if power_spec is None or toughness_spec is None:
        return "static_graveyard_count_boost_source_dynamic_not_supported"
    count_spec = power_spec if power_spec.get("static_value") is None else toughness_spec
    if count_spec.get("static_value") is not None:
        return "static_graveyard_count_boost_source_dynamic_not_supported"
    for spec in (power_spec, toughness_spec):
        if spec.get("static_value") is None and (
            spec.get("graveyard_count_scope") != count_spec.get("graveyard_count_scope")
            or spec.get("graveyard_count_card_types") != count_spec.get("graveyard_count_card_types")
        ):
            return "static_graveyard_count_boost_source_mixed_counts_not_supported"
    return {
        "graveyard_count_scope": count_spec["graveyard_count_scope"],
        "graveyard_count_card_types": count_spec["graveyard_count_card_types"],
        "static_power_bonus_per_graveyard_count": 0 if power_spec.get("static_value") == 0 else 1,
        "static_toughness_bonus_per_graveyard_count": 0 if toughness_spec.get("static_value") == 0 else 1,
    }


def strip_leading_parenthetical_reminders(text: str) -> str:
    cleaned = str(text or "").strip()
    while True:
        match = re.match(r"^\([^)]*\)\s*", cleaned)
        if not match:
            return cleaned
        cleaned = cleaned[match.end() :].strip()


def strip_parenthetical_reminders(text: str) -> str:
    cleaned = strip_leading_parenthetical_reminders(text)
    return re.sub(r"\s*\([^)]*\)", "", cleaned).strip()


def signed_int_from_oracle(value: str) -> int | None:
    token = str(value or "").strip()
    if not re.fullmatch(r"[+-]?\d+", token):
        return None
    return int(token)


def fixed_boost_target_from_oracle(metadata: dict[str, Any]) -> tuple[int, int] | None:
    text = strip_leading_parenthetical_reminders(oracle_text(metadata))
    match = re.match(
        r"^target creature gets ([+-]?\d+)/([+-]?\d+) until end of turn\.?$",
        text,
    )
    if not match:
        return None
    power = signed_int_from_oracle(match.group(1))
    toughness = signed_int_from_oracle(match.group(2))
    if power is None or toughness is None:
        return None
    return power, toughness


def fixed_boost_untap_target_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_leading_parenthetical_reminders(oracle_text(metadata))
    text = re.sub(r"\s+", " ", text).strip().lower()
    if "nonattacking" in text:
        return "boost_untap_oracle_target_filter_not_supported"
    if "+x/" in text or "/+x" in text or "where x" in text:
        return "boost_untap_dynamic_boost_not_supported"

    patterns = [
        (
            r"^untap target creature\. it gets (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+) until end of turn\.?$",
            1,
            1,
            False,
        ),
        (
            r"^target creature gets (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+) until end of turn\. "
            r"untap (?:it|that creature)\.?$",
            1,
            1,
            False,
        ),
        (
            r"^untap up to two target creatures\. they each get (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+) "
            r"until end of turn\.?$",
            0,
            2,
            True,
        ),
        (
            r"^untap one or two target creatures\. they each get (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+) "
            r"until end of turn\.?$",
            1,
            2,
            True,
        ),
        (
            r"^untap two target creatures\. each of them gets (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+) "
            r"until end of turn\.?$",
            2,
            2,
            False,
        ),
    ]
    for pattern, minimum, maximum, up_to in patterns:
        match = re.fullmatch(pattern, text)
        if not match:
            continue
        power = signed_int_from_oracle(match.group("power"))
        toughness = signed_int_from_oracle(match.group("toughness"))
        if power is None or toughness is None:
            return "boost_untap_oracle_not_exact_fixed"
        return {
            "power_delta": power,
            "toughness_delta": toughness,
            "target_count": maximum,
            "target_count_min": minimum,
            "target_count_max": maximum,
            "up_to_count": up_to,
        }
    return "boost_untap_oracle_not_exact_fixed"


def gain_control_untap_haste_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    text = re.sub(r"\s+", " ", text).strip().lower()
    patterns = [
        (
            r"^gain control of target (?P<target>artifact or creature|artifact|nonlegendary creature|"
            r"creature with (?:mana value|converted mana cost) \d+ or less|"
            r"creature with power \d+ or less|creature) until end of turn\. "
            r"untap (?:it|that creature|that artifact)\. "
            r"(?:it|that creature|that artifact) gains haste until end of turn\.?$"
        ),
        (
            r"^untap target (?P<target>artifact or creature|artifact|nonlegendary creature|"
            r"creature with (?:mana value|converted mana cost) \d+ or less|"
            r"creature with power \d+ or less|creature) and gain control of it until end of turn\. "
            r"(?:it|that creature|that artifact) gains haste until end of turn\.?$"
        ),
    ]
    for pattern in patterns:
        match = re.fullmatch(pattern, text)
        if not match:
            continue
        spec = gain_control_target_spec_from_phrase(match.group("target"))
        if isinstance(spec, str):
            return spec
        return spec
    return "gain_control_untap_haste_oracle_not_exact"


def etb_fixed_boost_target_from_oracle(metadata: dict[str, Any]) -> tuple[int, int] | str:
    text = strip_parenthetical_reminders(oracle_text_after_leading_static_keywords(metadata))
    text = re.sub(r"\s+", " ", text).strip().lower()
    if "choose one" in text or "+x/" in text or "/+x" in text or "-x/" in text or "/-x" in text:
        return "etb_target_boost_oracle_not_exact_fixed"
    match = re.fullmatch(
        r"(?:when|whenever) (?:this creature|[^.]+?) enters(?: the battlefield)?[, ]+"
        r"target creature gets ([+-]?\d+)/([+-]?\d+) until end of turn\.?",
        text,
    )
    if not match:
        return "etb_target_boost_oracle_not_exact_fixed"
    power = signed_int_from_oracle(match.group(1))
    toughness = signed_int_from_oracle(match.group(2))
    if power is None or toughness is None:
        return "etb_target_boost_oracle_not_exact_fixed"
    return power, toughness


def fixed_boost_controlled_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str | None:
    text = strip_leading_parenthetical_reminders(oracle_text(metadata))
    if "choose one" in text.lower() or "+x/" in text.lower() or "/+x" in text.lower():
        return "boost_controlled_oracle_not_simple"
    match = re.match(
        r"^(?:(?P<color>white|blue|black|red|green)\s+)?creatures you control get ([+-]?\d+)/([+-]?\d+) until end of turn\.?$",
        text,
        re.I,
    )
    if not match:
        return None
    power = signed_int_from_oracle(match.group(2))
    toughness = signed_int_from_oracle(match.group(3))
    if power is None or toughness is None:
        return None
    creature_filter: dict[str, Any] = {}
    color_word = str(match.group("color") or "").lower()
    if color_word:
        creature_filter["colors"] = [BOOST_ALL_FILTER_COLOR_WORDS[color_word]]
    return {"power": power, "toughness": toughness, "creature_filter": creature_filter}


def boost_controlled_filter_from_source(source: str, filter_name: str | None) -> dict[str, Any] | str:
    text = source or ""
    if not filter_name or filter_name == "StaticFilters.FILTER_PERMANENT_CREATURES":
        return {}
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", filter_name):
        return "boost_controlled_source_filter_not_supported"
    if any(marker in text for marker in STATIC_CONTROLLED_PT_BLOCKED_SOURCE_MARKERS):
        return "boost_controlled_source_filter_not_supported"
    color_tokens = re.findall(
        rf"\b{re.escape(filter_name)}\.add\s*\(\s*new\s+ColorPredicate\s*\(\s*ObjectColor\.([A-Z]+)\s*\)\s*\)",
        text,
    )
    if color_tokens:
        colors = [
            OBJECT_COLOR_TO_SYMBOL[token]
            for token in color_tokens
            if token in OBJECT_COLOR_TO_SYMBOL
        ]
        if colors:
            return {"colors": ordered_color_symbols(colors)}
    if "ColorPredicate" in text:
        return "boost_controlled_source_filter_not_supported"
    return "boost_controlled_source_filter_not_supported"


def fixed_boost_controlled_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    matches = re.findall(
        r"new\s+BoostControlledEffect\s*\(\s*([+-]?\d+)\s*,\s*([+-]?\d+)\s*,\s*"
        r"Duration\.EndOfTurn(?P<rest>[^)]*)\)",
        text,
        re.S,
    )
    if len(matches) != 1:
        return None
    power_raw, toughness_raw, rest = matches[0]
    rest_text = str(rest or "")
    creature_filter: dict[str, Any] = {}
    if rest_text.strip():
        args = [part.strip() for part in rest_text.lstrip(",").split(",") if part.strip()]
        filter_name = args[0] if args else ""
        source_filter = boost_controlled_filter_from_source(text, filter_name)
        if isinstance(source_filter, str):
            return source_filter
        creature_filter = source_filter
    return {"power": int(power_raw), "toughness": int(toughness_raw), "creature_filter": creature_filter}


BOOST_ALL_FILTER_COLOR_WORDS = {
    "white": "W",
    "blue": "U",
    "black": "B",
    "red": "R",
    "green": "G",
}


def boost_all_filter_label(creature_filter: dict[str, Any] | None) -> str:
    if not creature_filter:
        return "creatures"
    if creature_filter.get("combat_state"):
        return f"{creature_filter['combat_state']}_creatures"
    if creature_filter.get("no_counters"):
        return "creatures_with_no_counters"
    if creature_filter.get("colors"):
        return "_".join(str(color).lower() for color in creature_filter["colors"]) + "_creatures"
    if creature_filter.get("exclude_colors"):
        return "non_" + "_".join(str(color).lower() for color in creature_filter["exclude_colors"]) + "_creatures"
    if creature_filter.get("exclude_subtypes"):
        return "non_" + "_".join(
            str(subtype).lower() for subtype in creature_filter["exclude_subtypes"]
        ) + "_creatures"
    if creature_filter.get("exclude_card_types"):
        return "non_" + "_".join(
            str(card_type).lower() for card_type in creature_filter["exclude_card_types"]
        ) + "_creatures"
    return "filtered_creatures"


def _boost_all_filter_from_oracle_prefix(prefix: str) -> dict[str, Any] | None:
    normalized = re.sub(r"\s+", " ", str(prefix or "").strip().lower())
    if not normalized:
        return None
    if normalized == "attacking":
        return {"combat_state": "attacking"}
    if normalized == "blocking":
        return {"combat_state": "blocking"}
    if normalized == "creatures with no counters on them":
        return {"no_counters": True}
    non_match = re.match(r"^non[- ]?([a-z]+)$", normalized)
    if non_match:
        value = non_match.group(1)
        if value in BOOST_ALL_FILTER_COLOR_WORDS:
            return {"exclude_colors": [BOOST_ALL_FILTER_COLOR_WORDS[value]]}
        if value == "artifact":
            return {"exclude_card_types": ["artifact"]}
        return {"exclude_subtypes": [value.capitalize()]}
    if normalized in BOOST_ALL_FILTER_COLOR_WORDS:
        return {"colors": [BOOST_ALL_FILTER_COLOR_WORDS[normalized]]}
    return None


def fixed_boost_all_from_oracle(metadata: dict[str, Any]) -> tuple[int, int, str, dict[str, Any] | None] | str | None:
    text = strip_leading_parenthetical_reminders(oracle_text(metadata))
    lowered = text.lower()
    if (
        "choose one" in lowered
        or "+x/" in lowered
        or "/+x" in lowered
        or "-x/" in lowered
        or "/-x" in lowered
        or "additional cost" in lowered
    ):
        return "boost_all_oracle_not_simple"
    no_counters_match = re.match(
        r"^creatures with no counters on them get (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+) until end of turn\.?$",
        text,
        re.I,
    )
    if no_counters_match:
        power = signed_int_from_oracle(no_counters_match.group("power"))
        toughness = signed_int_from_oracle(no_counters_match.group("toughness"))
        if power is None or toughness is None:
            return None
        return power, toughness, "all", {"no_counters": True}
    filtered_match = re.match(
        r"^(?P<prefix>attacking|blocking|non[- ]?[a-z]+|white|blue|black|red|green) "
        r"creatures get (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+) until end of turn\.?$",
        text,
        re.I,
    )
    if filtered_match:
        creature_filter = _boost_all_filter_from_oracle_prefix(filtered_match.group("prefix"))
        if creature_filter is None:
            return "boost_all_oracle_filter_not_supported"
        power = signed_int_from_oracle(filtered_match.group("power"))
        toughness = signed_int_from_oracle(filtered_match.group("toughness"))
        if power is None or toughness is None:
            return None
        return power, toughness, "all", creature_filter
    patterns = [
        (
            r"^all creatures get ([+-]?\d+)/([+-]?\d+) until end of turn\.?$",
            "all",
            None,
        ),
        (
            r"^creatures your opponents control get ([+-]?\d+)/([+-]?\d+) until end of turn\.?$",
            "opponents",
            None,
        ),
    ]
    for pattern, controller_scope, creature_filter in patterns:
        match = re.match(pattern, text, re.I)
        if not match:
            continue
        power = signed_int_from_oracle(match.group(1))
        toughness = signed_int_from_oracle(match.group(2))
        if power is None or toughness is None:
            return None
        return power, toughness, controller_scope, creature_filter
    return None


def _boost_all_filter_from_source(source: str, rest_text: str) -> dict[str, Any] | str:
    if "StaticFilters.FILTER_ATTACKING_CREATURES" in rest_text:
        return {"combat_state": "attacking"}
    if "StaticFilters.FILTER_BLOCKING_CREATURES" in rest_text:
        return {"combat_state": "blocking"}
    if "Predicates.not(SubType.ELF.getPredicate())" in source:
        return {"exclude_subtypes": ["Elf"]}
    if "Predicates.not(new ColorPredicate(ObjectColor.BLACK))" in source:
        return {"exclude_colors": ["B"]}
    if "Predicates.not(new ColorPredicate(ObjectColor.WHITE))" in source:
        return {"exclude_colors": ["W"]}
    if re.search(r"filter\.add\s*\(\s*new\s+ColorPredicate\s*\(\s*ObjectColor\.BLACK\s*\)\s*\)", source):
        return {"colors": ["B"]}
    if re.search(r"filter\.add\s*\(\s*new\s+ColorPredicate\s*\(\s*ObjectColor\.WHITE\s*\)\s*\)", source):
        return {"colors": ["W"]}
    if "Predicates.not(CardType.ARTIFACT.getPredicate())" in source:
        return {"exclude_card_types": ["artifact"]}
    if "Predicates.not(CounterAnyPredicate.instance)" in source:
        return {"no_counters": True}
    return "boost_all_source_filter_not_supported"


def fixed_boost_all_from_source(source: str) -> tuple[int, int, str, dict[str, Any] | None] | str | None:
    text = source or ""
    matches = re.findall(
        r"new\s+BoostAllEffect\s*\(\s*([+-]?\d+)\s*,\s*([+-]?\d+)\s*,\s*"
        r"Duration\.EndOfTurn(?P<rest>[^)]*)\)",
        text,
        re.S,
    )
    if len(matches) != 1:
        return None
    power_raw, toughness_raw, rest = matches[0]
    rest_text = str(rest or "")
    if not rest_text.strip():
        controller_scope = "all"
        creature_filter = None
    elif "StaticFilters.FILTER_PERMANENT_ALL_CREATURES" in rest_text:
        controller_scope = "all"
        creature_filter = None
    elif "StaticFilters.FILTER_OPPONENTS_PERMANENT_CREATURES" in rest_text:
        controller_scope = "opponents"
        creature_filter = None
    else:
        controller_scope = "all"
        creature_filter = _boost_all_filter_from_source(text, rest_text)
        if isinstance(creature_filter, str):
            return creature_filter
    return int(power_raw), int(toughness_raw), controller_scope, creature_filter


def fixed_draw_count_from_oracle_sentence(sentence: str) -> int | None:
    text = strip_parenthetical_reminders(str(sentence or ""))
    text = re.sub(r"\s+", " ", text).strip().lower()
    match = re.fullmatch(r"draw (?P<count>a|an|one|two|three|four|five|six|seven|eight|nine|ten|\d+) cards?\.?", text)
    if not match:
        return None
    count_token = match.group("count")
    if count_token in {"a", "an"}:
        return 1
    count = COUNT_WORDS.get(count_token) or (int(count_token) if count_token.isdigit() else 0)
    return count if count > 0 else None


def simple_oracle_sentences(text: str) -> list[str]:
    normalized = strip_parenthetical_reminders(str(text or ""))
    sentences: list[str] = []
    for paragraph in re.split(r"\n+", normalized):
        paragraph = re.sub(r"\s+", " ", paragraph).strip()
        if not paragraph:
            continue
        sentences.extend(part.strip() for part in re.split(r"(?<=\.)\s+", paragraph) if part.strip())
    return sentences


def fixed_boost_all_draw_from_oracle(
    metadata: dict[str, Any],
) -> tuple[int, int, str, dict[str, Any] | None, int, str] | None:
    sentences = simple_oracle_sentences(oracle_text(metadata))
    if len(sentences) != 2:
        return None
    boost: tuple[int, int, str, dict[str, Any] | None] | None = None
    draw_count: int | None = None
    order: list[str] = []
    for sentence in sentences:
        draw = fixed_draw_count_from_oracle_sentence(sentence)
        if draw is not None:
            if draw_count is not None:
                return None
            draw_count = draw
            order.append("draw")
            continue
        boost_result = fixed_boost_all_from_oracle({**metadata, "oracle_text": sentence})
        if isinstance(boost_result, str) or boost_result is None:
            return None
        if boost is not None:
            return None
        boost = boost_result
        order.append("boost")
    if boost is None or draw_count is None or len(order) != 2:
        return None
    resolution_order = "draw_then_boost" if order == ["draw", "boost"] else "boost_then_draw"
    return (*boost, draw_count, resolution_order)


def fixed_boost_all_draw_from_source(
    source: str,
) -> tuple[int, int, str, dict[str, Any] | None, int, str] | str | None:
    text = source or ""
    if len(re.findall(r"new\s+DrawCardSourceControllerEffect\s*\(", text)) != 1:
        return None
    boost = fixed_boost_all_from_source(text)
    if isinstance(boost, str) or boost is None:
        return boost
    draw_count = java_constructor_int_or_noarg_default(
        text,
        "DrawCardSourceControllerEffect",
        noarg_default=1,
    )
    if draw_count is None or draw_count <= 0:
        return None
    boost_match = re.search(r"new\s+BoostAllEffect\s*\(", text)
    draw_match = re.search(r"new\s+DrawCardSourceControllerEffect\s*\(", text)
    if not boost_match or not draw_match:
        return None
    order = "draw_then_boost" if draw_match.start() < boost_match.start() else "boost_then_draw"
    return (*boost, draw_count, order)


def fixed_proliferate_draw_from_oracle(metadata: dict[str, Any]) -> tuple[int, str] | None:
    sentences = simple_oracle_sentences(oracle_text(metadata))
    if len(sentences) == 1:
        text = strip_parenthetical_reminders(sentences[0])
        text = re.sub(r"\s+", " ", text).strip().lower()
        match = re.fullmatch(
            r"draw (?P<count>a|an|one|two|three|four|five|six|seven|eight|nine|ten|\d+) cards?, then proliferate\.?",
            text,
        )
        if not match:
            return None
        token = match.group("count")
        if token in {"a", "an"}:
            return 1, "draw_then_proliferate"
        count = COUNT_WORDS.get(token) or (int(token) if token.isdigit() else 0)
        return (count, "draw_then_proliferate") if count > 0 else None
    if len(sentences) != 2:
        return None
    draw_count: int | None = None
    order: list[str] = []
    for sentence in sentences:
        text = strip_parenthetical_reminders(sentence)
        text = re.sub(r"\s+", " ", text).strip().lower()
        if re.fullmatch(r"proliferate\.?", text):
            order.append("proliferate")
            continue
        draw = fixed_draw_count_from_oracle_sentence(sentence)
        if draw is not None:
            if draw_count is not None:
                return None
            draw_count = draw
            order.append("draw")
            continue
        return None
    if draw_count is None or len(order) != 2 or set(order) != {"draw", "proliferate"}:
        return None
    resolution_order = "draw_then_proliferate" if order == ["draw", "proliferate"] else "proliferate_then_draw"
    return draw_count, resolution_order


def fixed_proliferate_draw_from_source(source: str) -> tuple[int, str] | None:
    text = source or ""
    if len(re.findall(r"new\s+ProliferateEffect\s*\(", text)) != 1:
        return None
    if len(re.findall(r"new\s+DrawCardSourceControllerEffect\s*\(", text)) != 1:
        return None
    draw_count = java_constructor_int_or_noarg_default(
        text,
        "DrawCardSourceControllerEffect",
        noarg_default=1,
    )
    if draw_count is None or draw_count <= 0:
        return None
    proliferate_match = re.search(r"new\s+ProliferateEffect\s*\(", text)
    draw_match = re.search(r"new\s+DrawCardSourceControllerEffect\s*\(", text)
    if not proliferate_match or not draw_match:
        return None
    order = (
        "draw_then_proliferate"
        if draw_match.start() < proliferate_match.start()
        else "proliferate_then_draw"
    )
    return draw_count, order


def fixed_boost_keyword_target_from_oracle(metadata: dict[str, Any]) -> tuple[int, int, str, str] | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    keyword_words = "|".join(re.escape(word) for word in sorted(TARGET_GRANT_KEYWORD_ORACLE_WORDS, key=len, reverse=True))
    match = None
    for pattern in (
        rf"^target creature( you control)? gets ([+-]?\d+)/([+-]?\d+) "
        rf"and gains ({keyword_words}) until end of turn\.?$",
        rf"^until end of turn, target creature( you control)? gets ([+-]?\d+)/([+-]?\d+) "
        rf"and gains ({keyword_words})\.?$",
    ):
        match = re.match(pattern, text)
        if match:
            break
    if not match:
        return None
    power = signed_int_from_oracle(match.group(2))
    toughness = signed_int_from_oracle(match.group(3))
    if power is None or toughness is None:
        return None
    target_controller = "self" if match.group(1) else "any"
    keyword = TARGET_GRANT_KEYWORD_ORACLE_WORDS[match.group(4)]
    return power, toughness, keyword, target_controller


def fixed_keyword_draw_target_from_oracle(metadata: dict[str, Any]) -> tuple[str, str, int] | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    keyword_words = "|".join(
        re.escape(word)
        for word in sorted(TARGET_GRANT_KEYWORD_ORACLE_WORDS, key=len, reverse=True)
    )
    match = re.match(
        rf"^target creature( you control)? gains ({keyword_words}) until end of turn\. draw a card\.?$",
        text,
    )
    if not match:
        return None
    target_controller = "self" if match.group(1) else "any"
    keyword = TARGET_GRANT_KEYWORD_ORACLE_WORDS[match.group(2)]
    return keyword, target_controller, 1


def fixed_boost_keyword_draw_target_from_oracle(
    metadata: dict[str, Any],
) -> tuple[int, int, str, str, int] | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    keyword_words = "|".join(
        re.escape(word)
        for word in sorted(TARGET_GRANT_KEYWORD_ORACLE_WORDS, key=len, reverse=True)
    )
    match = re.match(
        rf"^target creature( you control)? gets ([+-]?\d+)/([+-]?\d+) "
        rf"and gains ({keyword_words}) until end of turn\. draw a card\.?$",
        text,
    )
    if not match:
        return None
    power = signed_int_from_oracle(match.group(2))
    toughness = signed_int_from_oracle(match.group(3))
    if power is None or toughness is None:
        return None
    target_controller = "self" if match.group(1) else "any"
    keyword = TARGET_GRANT_KEYWORD_ORACLE_WORDS[match.group(4)]
    return power, toughness, keyword, target_controller, 1


