COLOR_WORD_TO_SYMBOL = {
    "white": "W",
    "blue": "U",
    "black": "B",
    "red": "R",
    "green": "G",
}
COLOR_SYMBOL_ORDER = ["W", "U", "B", "R", "G"]
OBJECT_COLOR_TO_SYMBOL = {
    "WHITE": "W",
    "BLUE": "U",
    "BLACK": "B",
    "RED": "R",
    "GREEN": "G",
}


def ordered_color_symbols(symbols: list[str]) -> list[str]:
    normalized = {str(symbol or "").strip().upper() for symbol in symbols if str(symbol or "").strip()}
    return [symbol for symbol in COLOR_SYMBOL_ORDER if symbol in normalized]


def evasion_filter_from_phrase(phrase: str) -> list[dict[str, Any]] | None:
    normalized = re.sub(r"\s+", " ", phrase or "").strip().lower().rstrip(".")
    if not normalized:
        return None
    power_match = re.fullmatch(r"creatures with power (\d+) or greater", normalized)
    if power_match:
        return [{"kind": "power", "operator": "gte", "value": int(power_match.group(1))}]
    power_match = re.fullmatch(r"creatures with power (\d+) or less", normalized)
    if power_match:
        return [{"kind": "power", "operator": "lte", "value": int(power_match.group(1))}]
    if normalized == "creature tokens":
        return [{"kind": "token"}]
    subtype_phrases = {
        "walls": ["wall"],
        "wall creatures": ["wall"],
        "rogues": ["rogue"],
        "rogue creatures": ["rogue"],
        "dinosaurs": ["dinosaur"],
        "dinosaur creatures": ["dinosaur"],
        "eldrazi scions": ["eldrazi", "scion"],
        "eldrazi scion creatures": ["eldrazi", "scion"],
    }
    if normalized in subtype_phrases:
        return [{"kind": "subtype_all", "subtypes": subtype_phrases[normalized]}]
    if normalized in {"artifact creatures", "artifact creature"}:
        return [{"kind": "artifact"}]
    artifact_color_match = re.fullmatch(
        r"artifact creatures and/or (white|blue|black|red|green) creatures",
        normalized,
    )
    if artifact_color_match:
        return [
            {"kind": "artifact"},
            {"kind": "color", "colors": [COLOR_WORD_TO_SYMBOL[artifact_color_match.group(1)]]},
        ]
    colors = re.findall(r"\b(white|blue|black|red|green)\b", normalized)
    if colors and "creature" in normalized:
        return [{"kind": "color", "colors": ordered_color_symbols([COLOR_WORD_TO_SYMBOL[color] for color in colors])}]
    return None


def filtered_evasion_spec_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = strip_parenthetical_reminders(str(metadata.get("oracle_text") or ""))
    text = re.sub(r"\s+", " ", text).strip().lower().rstrip(".")
    if not text:
        return None
    source_name = re.sub(r"\s+", " ", str(metadata.get("name") or "").strip().lower())
    subjects = ["this creature"]
    if source_name:
        subjects.append(re.escape(source_name))
    for subject in subjects:
        except_match = re.fullmatch(rf"{subject} can't be blocked except by (.+)", text)
        if except_match:
            filters = evasion_filter_from_phrase(except_match.group(1))
            if filters:
                return {"mode": "can_be_blocked_only_by", "filters": filters}
        by_match = re.fullmatch(rf"{subject} can't be blocked by (.+)", text)
        if by_match:
            filters = evasion_filter_from_phrase(by_match.group(1))
            if filters:
                return {"mode": "cant_be_blocked_by", "filters": filters}
    return None


def source_filter_add_chunks(source: str) -> list[str]:
    chunks: list[str] = []
    lines = (source or "").splitlines()
    idx = 0
    while idx < len(lines):
        line = lines[idx]
        if ".add(" not in line or "this.subtype.add" in line:
            idx += 1
            continue
        chunk = line
        idx += 1
        while ";" not in chunk and idx < len(lines):
            chunk += "\n" + lines[idx]
            idx += 1
        chunks.append(chunk)
    return chunks


def filtered_evasion_spec_from_source(source: str) -> dict[str, Any] | None:
    text = source or ""
    if (
        "CantBeBlockedByCreaturesSourceEffect" not in text
        or "SimpleEvasionAbility" not in text
        or "Duration.WhileOnBattlefield" not in text
    ):
        return None
    chunks = "\n".join(source_filter_add_chunks(text))
    direct_constructor_subtypes = re.findall(
        r"new\s+FilterCreaturePermanent\s*\(\s*SubType\.([A-Z_]+)\s*,",
        text,
    )
    mode = "can_be_blocked_only_by" if "Predicates.not" in chunks else "cant_be_blocked_by"
    filters: list[dict[str, Any]] = []
    power_match = re.search(r"PowerPredicate\s*\(\s*ComparisonType\.([A-Z_]+)\s*,\s*(\d+)\s*\)", chunks)
    if power_match:
        comparison = power_match.group(1)
        value = int(power_match.group(2))
        if comparison == "MORE_THAN":
            filters.append({"kind": "power", "operator": "gte", "value": value + 1})
        elif comparison == "OR_GREATER":
            filters.append({"kind": "power", "operator": "gte", "value": value})
        elif comparison == "FEWER_THAN":
            filters.append({"kind": "power", "operator": "lte", "value": value - 1})
        else:
            return None
    colors = ordered_color_symbols(
        [
            OBJECT_COLOR_TO_SYMBOL[color]
            for color in re.findall(r"ObjectColor\.([A-Z]+)", chunks)
            if color in OBJECT_COLOR_TO_SYMBOL
        ]
    )
    subtypes = [
        subtype.strip().lower().replace("_", " ")
        for subtype in re.findall(r"SubType\.([A-Z_]+)\.getPredicate\(\)", chunks)
    ]
    subtypes.extend(
        subtype.strip().lower().replace("_", " ")
        for subtype in direct_constructor_subtypes
    )
    subtypes = list(dict.fromkeys(subtypes))
    has_artifact_filter = "CardType.ARTIFACT.getPredicate()" in chunks
    has_token_filter = "TokenPredicate.TRUE" in chunks
    if mode == "can_be_blocked_only_by":
        if has_artifact_filter:
            filters.append({"kind": "artifact"})
        if colors:
            filters.append({"kind": "color", "colors": colors})
        if subtypes:
            filters.append({"kind": "subtype_all", "subtypes": subtypes})
        if has_token_filter or power_match:
            return None
    else:
        if colors:
            filters.append({"kind": "color", "colors": colors})
        if subtypes:
            filters.append({"kind": "subtype_all", "subtypes": subtypes})
        if has_artifact_filter:
            filters.append({"kind": "artifact"})
        if has_token_filter:
            filters.append({"kind": "token"})
    if not filters:
        return None
    return {"mode": mode, "filters": filters}


def canonical_evasion_filter(value: dict[str, Any]) -> str:
    normalized = dict(value)
    if isinstance(normalized.get("colors"), list):
        normalized["colors"] = ordered_color_symbols([str(color) for color in normalized["colors"]])
    if isinstance(normalized.get("subtypes"), list):
        normalized["subtypes"] = sorted({str(subtype).strip().lower() for subtype in normalized["subtypes"]})
    return json.dumps(normalized, sort_keys=True, separators=(",", ":"))


def evasion_specs_match(left: dict[str, Any], right: dict[str, Any]) -> bool:
    if left.get("mode") != right.get("mode"):
        return False
    left_filters = {canonical_evasion_filter(filter_spec) for filter_spec in left.get("filters") or []}
    right_filters = {canonical_evasion_filter(filter_spec) for filter_spec in right.get("filters") or []}
    return bool(left_filters) and left_filters == right_filters


def damage_target_from_oracle(metadata: dict[str, Any]) -> str | None:
    text = oracle_text(metadata)
    restricted = restricted_battlefield_target_from_oracle(metadata, "damage")
    if restricted is not None:
        return restricted
    if "any target" in text:
        return "any_target"
    if re.search(r"target opponent\b", text):
        return "opponent"
    if re.search(r"target player\b", text):
        return "player"
    if re.search(r"target creature or planeswalker\b", text):
        return "creature_or_planeswalker"
    if re.search(r"target (?:white (?:and/or|or) blue|blue (?:and/or|or) white) creatures?\b", text):
        return "white_or_blue_creature"
    if re.search(r"target creature\b", text):
        return "creature"
    return None


def multi_target_damage_count_from_phrase(phrase: str, amount: int) -> tuple[int, int] | None:
    normalized = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    if normalized == "any number of":
        return 0, max(1, int(amount))
    if normalized == "one or two":
        return 1, 2
    if normalized == "one, two, or three":
        return 1, 3
    exact_count = word_count_value(normalized)
    if exact_count is not None and exact_count > 0:
        return int(exact_count), int(exact_count)
    up_to_match = re.fullmatch(r"up to (?P<count>one|two|three|four|five|six|seven|eight|nine|ten|\d+)", normalized)
    if up_to_match:
        count = word_count_value(up_to_match.group("count"))
        if count is None or count <= 0:
            return None
        return 0, int(count)
    return None


def multi_target_damage_target_from_phrase(phrase: str) -> tuple[str, str | None] | None:
    normalized = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    normalized = normalized.removesuffix(".")
    target_controller: str | None = None
    if normalized.endswith(" your opponents control"):
        target_controller = "opponent"
        normalized = normalized.removesuffix(" your opponents control").strip()
    mapping = {
        "targets": "any_target",
        "target": "any_target",
        "target creatures": "creature",
        "target creature": "creature",
        "target creatures with flying": "flying_creature",
        "target attacking creatures": "attacking_creature",
        "target attacking creature": "attacking_creature",
        "target attacking or blocking creatures": "attacking_or_blocking_creature",
        "target attacking or blocking creature": "attacking_or_blocking_creature",
        "target creatures and/or planeswalkers": "creature_or_planeswalker",
        "target creature or planeswalker": "creature_or_planeswalker",
        "target white and/or blue creatures": "white_or_blue_creature",
        "target white and/or blue creature": "white_or_blue_creature",
    }
    target = mapping.get(normalized)
    if target is None:
        return None
    return target, target_controller


def fixed_multi_target_damage_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    text = re.sub(r"\s+", " ", text.strip().lower())
    if " x damage " in text or "where x is" in text:
        return "multi_target_damage_oracle_x_not_supported"
    match = re.fullmatch(
        r".+ deals (?P<amount>\d+) damage divided as you choose among (?P<body>.+?)\.?",
        text,
    )
    if not match:
        return "multi_target_damage_oracle_not_exact_fixed"
    amount = int(match.group("amount"))
    if amount <= 0:
        return "multi_target_damage_oracle_amount_not_fixed"
    body = match.group("body").strip()
    count_prefixes = [
        "one, two, or three",
        "one or two",
        "any number of",
        "up to ten",
        "up to nine",
        "up to eight",
        "up to seven",
        "up to six",
        "up to five",
        "up to four",
        "up to three",
        "up to two",
        "up to one",
    ]
    count_phrase = None
    target_phrase = None
    for prefix in count_prefixes:
        if body == prefix or body.startswith(prefix + " "):
            count_phrase = prefix
            target_phrase = body[len(prefix) :].strip()
            break
    if not count_phrase or not target_phrase:
        return "multi_target_damage_oracle_count_not_supported"
    count_range = multi_target_damage_count_from_phrase(count_phrase, amount)
    if count_range is None:
        return "multi_target_damage_oracle_count_not_supported"
    target_spec = multi_target_damage_target_from_phrase(target_phrase)
    if target_spec is None:
        return "multi_target_damage_oracle_target_not_supported"
    target, target_controller = target_spec
    target_count_min, target_count_max = count_range
    if target_count_max <= 1:
        return "multi_target_damage_oracle_count_not_supported"
    return {
        "amount": amount,
        "damage": amount,
        "target": target,
        "target_controller": target_controller,
        "target_count_min": int(target_count_min),
        "target_count_max": int(target_count_max),
        "up_to_count": int(target_count_min) == 0,
    }


def fixed_multi_target_damage_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    if has_additional_cost(text) or "AlternativeCostSourceAbility" in text:
        return "multi_target_damage_additional_cost_not_supported"
    if any(token in text for token in ("GetXValue", "ManacostVariableValue", "XValue", "xValue")):
        return "multi_target_damage_source_x_not_supported"
    if "TargetPointer" in text or ".setTargetPointer" in text:
        return "multi_target_damage_source_target_pointer_not_supported"
    if len(re.findall(r"new\s+DamageMultiEffect\s*\(", text)) != 1:
        return "multi_target_damage_source_not_single"
    target_matches = list(
        re.finditer(
            r"new\s+(?P<class>TargetAnyTargetAmount|TargetCreaturePermanentAmount|TargetCreatureOrPlaneswalkerAmount)\s*\(",
            text,
        )
    )
    if len(target_matches) != 1:
        return "multi_target_damage_source_target_constructor_not_single"
    target_class = target_matches[0].group("class")
    args = extract_constructor_args(text[target_matches[0].start() :], target_class)
    if args is None:
        return "multi_target_damage_source_target_constructor_not_supported"
    parts = split_top_level_args(args)
    if not parts or not re.fullmatch(r"\d+", str(parts[0] or "").strip()):
        return "multi_target_damage_source_amount_not_fixed"
    amount = int(str(parts[0]).strip())
    if amount <= 0:
        return "multi_target_damage_source_amount_not_fixed"
    numeric_tail = [int(str(part).strip()) for part in parts[1:3] if re.fullmatch(r"\d+", str(part or "").strip())]
    if len(numeric_tail) >= 2:
        target_count_min, target_count_max = numeric_tail[0], numeric_tail[1]
    else:
        target_count_min = 0 if amount > 3 else 1
        target_count_max = amount
    target_map = {
        "TargetAnyTargetAmount": "any_target",
        "TargetCreaturePermanentAmount": "creature",
        "TargetCreatureOrPlaneswalkerAmount": "creature_or_planeswalker",
    }
    target = target_map[target_class]
    target_controller = None
    if target_class == "TargetCreaturePermanentAmount":
        if "FILTER_ATTACKING_OR_BLOCKING_CREATURES" in text:
            target = "attacking_or_blocking_creature"
        elif "FILTER_ATTACKING_CREATURES" in text:
            target = "attacking_creature"
        elif "FlyingAbility.class" in text or "creatures with flying" in text:
            target = "flying_creature"
        elif "ObjectColor.WHITE" in text and "ObjectColor.BLUE" in text:
            target = "white_or_blue_creature"
    if "TargetController.OPPONENT" in text:
        target_controller = "opponent"
    return {
        "amount": amount,
        "damage": amount,
        "target": target,
        "target_controller": target_controller,
        "target_count_min": int(target_count_min),
        "target_count_max": int(target_count_max),
        "up_to_count": int(target_count_min) == 0,
    }


