def activated_target_boost_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if "Zone.GRAVEYARD" in text:
        return "activated_target_boost_source_not_battlefield"
    if "TargetPointer" in text or ".setTargetPointer" in text or "EachTargetPointer" in text:
        return "activated_target_boost_source_target_not_supported"
    target_constructors = re.findall(r"new\s+(Target\w+)\s*\(", text)
    if len(target_constructors) != 1:
        return "activated_target_boost_source_target_not_supported"
    if not re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", text, re.S):
        return "activated_target_boost_source_target_not_supported"
    boost_matches = re.findall(
        r"new\s+BoostTargetEffect\s*\(\s*([+-]?\d+)\s*,\s*([+-]?\d+)\s*"
        r"(?:,\s*Duration\.EndOfTurn\s*)?\)",
        text,
        re.S,
    )
    if len(boost_matches) != 1:
        return "activated_target_boost_source_not_single_fixed"
    boost_index = text.find("BoostTargetEffect")
    window = text[max(0, boost_index - 500) : boost_index + 2000]
    if "SimpleActivatedAbility" not in window:
        return "activated_target_boost_source_not_simple_activated"
    activation = activated_target_boost_cost_from_source(window)
    if isinstance(activation, str):
        return activation
    return {
        "power_delta": int(boost_matches[0][0]),
        "toughness_delta": int(boost_matches[0][1]),
        "target": "creature",
        "target_controller": "any",
        **activation,
    }


def activated_target_keyword_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(
        oracle_text_after_leading_static_keywords(metadata)
    )
    text = re.sub(r"\s+", " ", text).strip().lower()
    if text.count(":") != 1:
        return "activated_target_keyword_oracle_not_simple"
    cost_text, effect_text = [part.strip() for part in text.split(":", 1)]
    keyword_words = "|".join(
        re.escape(word)
        for word in sorted(TARGET_GRANT_KEYWORD_ORACLE_WORDS, key=len, reverse=True)
    )
    match = re.match(
        rf"^(another\s+)?target\s+(.+?)\s+gains\s+({keyword_words}) until end of turn\.?$",
        effect_text,
    )
    if not match:
        return "activated_target_keyword_oracle_not_simple"
    target_data = activated_target_keyword_target_phrase_data(match.group(2))
    if isinstance(target_data, str):
        return target_data.replace("source", "oracle")
    if match.group(1):
        target_data["exclude_source"] = True
        target_data.setdefault("target_constraints", {})["exclude_source"] = True
    activation = activated_target_keyword_activation_cost_from_oracle(cost_text)
    if isinstance(activation, str):
        return str(activation).replace("activated_self_boost", "activated_target_keyword")
    return {
        "keyword": TARGET_GRANT_KEYWORD_ORACLE_WORDS[match.group(3)],
        **target_data,
        **activation,
    }


TARGET_KEYWORD_TARGET_COLOR_WORDS = {
    "white": "W",
    "blue": "U",
    "black": "B",
    "red": "R",
    "green": "G",
}

TARGET_KEYWORD_IMPLICIT_CREATURE_SUBTYPES = {
    "dinosaur",
    "knight",
}


def ordered_color_symbols(colors: list[str]) -> list[str]:
    order = {"W": 0, "U": 1, "B": 2, "R": 3, "G": 4}
    unique = list(dict.fromkeys(colors))
    return sorted(unique, key=lambda color: order.get(color, 99))


def target_keyword_subtypes_from_phrase(phrase: str) -> list[str]:
    return [
        token.lower()
        for token in re.split(r"[^A-Za-z0-9']+", str(phrase or ""))
        if token
    ]


def activated_target_keyword_target_phrase_data(phrase: str) -> dict[str, Any] | str:
    target_phrase = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    exclude_source = False
    for prefix in ("another target ", "another "):
        if target_phrase.startswith(prefix):
            exclude_source = True
            target_phrase = target_phrase[len(prefix) :].strip()
            break
    if target_phrase.startswith("target "):
        target_phrase = target_phrase[len("target ") :].strip()
    target_controller = "any"
    if target_phrase.endswith(" you control"):
        target_controller = "self"
        target_phrase = target_phrase[: -len(" you control")].strip()
    combat_state = None
    for prefix, state in (
        ("attacking or blocking ", "attacking_or_blocking"),
        ("attacking ", "attacking"),
        ("blocking ", "blocking"),
    ):
        if target_phrase.startswith(prefix):
            combat_state = state
            target_phrase = target_phrase[len(prefix) :].strip()
            break
    constraints: dict[str, Any] = {"card_types": ["creature"]}
    if exclude_source:
        constraints["exclude_source"] = True
    if combat_state:
        constraints["combat_state"] = combat_state
    without_match = re.search(
        r"\s+without\s+(?P<keyword>deathtouch|double strike|first strike|flying|haste|hexproof|indestructible|lifelink|menace|reach|trample|vigilance)$",
        target_phrase,
    )
    if without_match:
        keyword = TARGET_GRANT_KEYWORD_ORACLE_WORDS.get(without_match.group("keyword"))
        if keyword is None:
            return "activated_target_keyword_source_target_not_supported"
        constraints["excluded_keywords"] = [keyword]
        target_phrase = target_phrase[: without_match.start()].strip()
    power_match = re.fullmatch(r"creature with power (\d+) or greater", target_phrase)
    if power_match:
        constraints["power_min"] = int(power_match.group(1))
        return {
            "target": "creature",
            "target_controller": target_controller,
            "exclude_source": exclude_source,
            "target_constraints": constraints,
        }
    power_match = re.fullmatch(r"creature with power (\d+) or less", target_phrase)
    if power_match:
        constraints["power_max"] = int(power_match.group(1))
        return {
            "target": "creature",
            "target_controller": target_controller,
            "exclude_source": exclude_source,
            "target_constraints": constraints,
        }
    if target_phrase == "creature":
        return {
            "target": "creature",
            "target_controller": target_controller,
            "exclude_source": exclude_source,
            "target_constraints": constraints,
        }
    if target_phrase in {"artifact", "enchantment", "land", "permanent"}:
        return {
            "target": target_phrase,
            "target_controller": target_controller,
            "exclude_source": exclude_source,
            "target_constraints": {
                "card_types": [target_phrase],
                **({"exclude_source": True} if exclude_source else {}),
            },
        }
    if target_phrase.endswith(" creature"):
        modifier = target_phrase[: -len(" creature")].strip()
        if not modifier:
            return "activated_target_keyword_source_target_not_supported"
        color_parts = [part.strip() for part in re.split(r"\s+or\s+", modifier) if part.strip()]
        color_symbols = [TARGET_KEYWORD_TARGET_COLOR_WORDS.get(part) for part in color_parts]
        if color_symbols and all(color_symbols):
            constraints["target_colors"] = ordered_color_symbols([str(symbol) for symbol in color_symbols])
        elif modifier == "snow":
            constraints["required_supertypes"] = ["snow"]
        else:
            subtypes = target_keyword_subtypes_from_phrase(modifier)
            if not subtypes:
                return "activated_target_keyword_source_target_not_supported"
            constraints["target_subtypes"] = subtypes
        return {
            "target": "creature",
            "target_controller": target_controller,
            "exclude_source": exclude_source,
            "target_constraints": constraints,
        }
    subtypes = target_keyword_subtypes_from_phrase(target_phrase)
    if not subtypes:
        return "activated_target_keyword_source_target_not_supported"
    if combat_state or all(subtype in TARGET_KEYWORD_IMPLICIT_CREATURE_SUBTYPES for subtype in subtypes):
        constraints["target_subtypes"] = subtypes
        return {
            "target": "creature",
            "target_controller": target_controller,
            "exclude_source": exclude_source,
            "target_constraints": constraints,
        }
    return {
        "target": "permanent",
        "target_controller": target_controller,
        "exclude_source": exclude_source,
        "target_constraints": {
            "card_types": ["permanent"],
            "target_subtypes": subtypes,
            **({"exclude_source": True} if exclude_source else {}),
        },
    }


def activated_target_keyword_activation_cost_from_oracle(cost_text: str) -> dict[str, Any] | str:
    normalized_cost = re.sub(r"\s+", " ", str(cost_text or "").strip().lower())
    sacrifice_target = None
    sacrifice_pattern = (
        r"(?:^|,\s*)sacrifice (?P<phrase>"
        r"(?:a|an|another) (?:artifact|creature|enchantment|land|permanent)"
        r")(?:\s*,?|$)"
    )
    sacrifice_matches = list(re.finditer(sacrifice_pattern, normalized_cost))
    if len(sacrifice_matches) > 1:
        return "activated_target_keyword_oracle_cost_not_supported"
    if sacrifice_matches:
        sacrifice_target = activation_sacrifice_target_from_phrase(
            sacrifice_matches[0].group("phrase")
        )
        if sacrifice_target is None:
            return "activated_target_keyword_oracle_cost_not_supported"
        normalized_cost = re.sub(sacrifice_pattern, ",", normalized_cost).strip(" ,")
    activation = activation_cost_from_oracle_prefix(
        normalized_cost,
        allow_source_sacrifice=True,
    )
    if isinstance(activation, str):
        return str(activation).replace("activated_self_boost", "activated_target_keyword")
    if activation.get("activation_requires_sacrifice") and sacrifice_target:
        return "activated_target_keyword_oracle_cost_not_supported"
    if sacrifice_target:
        activation["activation_sacrifice_target"] = sacrifice_target
        activation["activation_requires_sacrifice_target"] = True
    return activation


def activated_target_keyword_cost_from_source(source: str, window: str) -> dict[str, Any] | str:
    risky_cost_classes = {
        "CompositeCost",
        "DiscardCardCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "OrCost",
        "PayLifeCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "TapTargetCost",
        "UntapSourceCost",
    }
    present_risky = sorted(cost for cost in risky_cost_classes if cost in window)
    if present_risky:
        return "activated_target_keyword_source_cost_not_supported"
    mana_matches = re.findall(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window, re.S)
    generic_matches = re.findall(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window, re.S)
    colored_matches = re.findall(r"ColoredManaCost\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)", window, re.S)
    cost_kinds = sum(1 for matches in (mana_matches, generic_matches, colored_matches) if matches)
    if cost_kinds > 1:
        return "activated_target_keyword_source_cost_not_supported"
    if len(mana_matches) > 1 or len(generic_matches) > 1 or len(colored_matches) > 1:
        return "activated_target_keyword_source_cost_not_supported"
    if mana_matches:
        cost_text = mana_matches[0]
    elif generic_matches:
        cost_text = "{" + generic_matches[0] + "}"
    elif colored_matches:
        cost_text = "{" + colored_matches[0] + "}"
    else:
        cost_text = "{0}"
    parsed = parse_mana_cost_text(cost_text)
    if parsed is None:
        return "activated_target_keyword_source_mana_cost_not_supported"
    generic, colors = parsed
    source_sacrifice_count = len(re.findall(r"new\s+SacrificeSourceCost\s*\(", window))
    target_sacrifice_count = len(re.findall(r"new\s+SacrificeTargetCost\s*\(", window))
    if source_sacrifice_count > 1 or target_sacrifice_count > 1:
        return "activated_target_keyword_source_cost_not_supported"
    if source_sacrifice_count and target_sacrifice_count:
        return "activated_target_keyword_source_cost_not_supported"
    result = {
        "activation_cost_mana": cost_text,
        "activation_cost_generic": generic,
        "activation_cost_colors": colors,
        "activation_requires_tap": "TapSourceCost" in window,
        "activation_requires_sacrifice": bool(source_sacrifice_count),
    }
    if target_sacrifice_count:
        sacrifice_target = activation_sacrifice_target_from_source(source, window)
        if sacrifice_target is None:
            return "activated_target_keyword_source_cost_not_supported"
        result["activation_sacrifice_target"] = sacrifice_target
        result["activation_requires_sacrifice_target"] = True
    return result


def activated_target_keyword_target_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if "TargetPointer" in text or ".setTargetPointer" in text or "EachTargetPointer" in text:
        return "activated_target_keyword_source_target_not_supported"
    target_constructors = re.findall(r"new\s+(Target\w+)\s*\(", text)
    if len(target_constructors) != 1:
        return "activated_target_keyword_source_target_not_supported"
    if re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", text, re.S):
        return {
            "target": "creature",
            "target_controller": "any",
            "exclude_source": False,
            "target_constraints": {"card_types": ["creature"]},
        }
    if re.search(r"new\s+TargetControlledCreaturePermanent\s*\(\s*\)", text, re.S):
        return {
            "target": "creature",
            "target_controller": "self",
            "exclude_source": False,
            "target_constraints": {"card_types": ["creature"]},
        }
    if "FILTER_ANOTHER_TARGET_CREATURE_YOU_CONTROL" in text:
        return {
            "target": "creature",
            "target_controller": "self",
            "exclude_source": True,
            "target_constraints": {"card_types": ["creature"], "exclude_source": True},
        }
    if "FILTER_ANOTHER_TARGET_CREATURE" in text:
        return {
            "target": "creature",
            "target_controller": "any",
            "exclude_source": True,
            "target_constraints": {"card_types": ["creature"], "exclude_source": True},
        }
    if re.search(r"FILTER_CONTROLLED_CREATURE|FILTER_TARGET_CREATURE_YOU_CONTROL", text, re.S):
        return {
            "target": "creature",
            "target_controller": "self",
            "exclude_source": False,
            "target_constraints": {"card_types": ["creature"]},
        }
    controlled_subtype_match = re.search(
        r"new\s+FilterControlledPermanent\s*\(\s*SubType\.([A-Z0-9_]+)(?:\s*,\s*\"([^\"]+)\")?\s*\)",
        text,
        re.S,
    )
    if controlled_subtype_match and re.search(r"new\s+TargetPermanent\s*\(", text, re.S):
        if controlled_subtype_match.group(2):
            return activated_target_keyword_target_phrase_data(controlled_subtype_match.group(2))
        subtype = controlled_subtype_match.group(1).lower()
        return {
            "target": "creature",
            "target_controller": "self",
            "exclude_source": False,
            "target_constraints": {"card_types": ["creature"], "target_subtypes": [subtype]},
        }
    phrase_match = re.search(
        r"new\s+Filter(?:Attacking)?Creature(?:Permanent)?\s*\(\s*\"([^\"]+)\"\s*\)",
        text,
        re.S,
    )
    if phrase_match and re.search(r"new\s+TargetPermanent\s*\(", text, re.S):
        return activated_target_keyword_target_phrase_data(phrase_match.group(1))
    phrase_match = re.search(
        r"new\s+FilterPermanent\s*\(\s*\"([^\"]+)\"\s*\)",
        text,
        re.S,
    )
    if phrase_match and re.search(r"new\s+TargetPermanent\s*\(", text, re.S):
        return activated_target_keyword_target_phrase_data(phrase_match.group(1))
    subtype_match = re.search(
        r"new\s+Filter(Creature)?Permanent\s*\(\s*SubType\.([A-Z0-9_]+)\s*,\s*\"([^\"]+)\"\s*\)",
        text,
        re.S,
    )
    if subtype_match and re.search(r"new\s+TargetPermanent\s*\(", text, re.S):
        return activated_target_keyword_target_phrase_data(subtype_match.group(3))
    return "activated_target_keyword_source_target_not_supported"


def activated_target_keyword_from_source(source: str, keyword_ability_class: str) -> dict[str, Any] | str:
    text = source or ""
    if "Zone.GRAVEYARD" in text:
        return "activated_target_keyword_source_not_battlefield"
    gain_matches = re.findall(r"new\s+GainAbilityTargetEffect\s*\(", text)
    if len(gain_matches) != 1:
        return "activated_target_keyword_source_not_single_effect"
    ability_expr = (
        rf"(?:{re.escape(keyword_ability_class)}\.getInstance\s*\(\s*\)"
        rf"|new\s+{re.escape(keyword_ability_class)}\s*\([^)]*\))"
    )
    if not re.search(
        rf"new\s+GainAbilityTargetEffect\s*\(\s*{ability_expr}"
        rf"(?:\s*,\s*Duration\.EndOfTurn\s*)?\)",
        text,
        re.S,
    ):
        return "activated_target_keyword_source_keyword_not_supported"
    gain_index = text.find("GainAbilityTargetEffect")
    window = text[max(0, gain_index - 500) : gain_index + 2000]
    if "SimpleActivatedAbility" not in window:
        return "activated_target_keyword_source_not_simple_activated"
    activation = activated_target_keyword_cost_from_source(text, window)
    if isinstance(activation, str):
        return activation
    target_data = activated_target_keyword_target_from_source(text)
    if isinstance(target_data, str):
        return target_data
    return {
        "keyword": TARGET_GRANT_KEYWORD_ABILITY_CLASSES[keyword_ability_class],
        **target_data,
        **activation,
    }


def activated_self_keyword_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(
        oracle_text_after_leading_static_keywords(metadata)
    )
    text = re.sub(r"\s+", " ", text).strip().lower()
    if text.count(":") != 1:
        return "activated_self_keyword_oracle_not_simple"
    cost_text, effect_text = [part.strip() for part in text.split(":", 1)]
    keyword_words = "|".join(
        re.escape(word)
        for word in sorted(TARGET_GRANT_KEYWORD_ORACLE_WORDS, key=len, reverse=True)
    )
    match = re.match(
        rf"^(?!target\b)(?P<subject>.+?)\s+gains\s+(?P<keyword>{keyword_words}) until end of turn\.?$",
        effect_text,
    )
    if not match:
        return "activated_self_keyword_oracle_not_simple"
    normalized_cost = cost_text
    discard_cost = activation_discard_cost_from_oracle(text)
    if discard_cost:
        discard_pattern = r"(?:^|,\s*)discard a card(?: at random)?(?:\s*,?|$)"
        normalized_cost = re.sub(discard_pattern, ",", normalized_cost).strip(" ,")
    life_cost = 0
    life_pattern = r"(?:^|,\s*)pay (?P<life>\d+) life(?:\s*,?|$)"
    life_matches = list(re.finditer(life_pattern, normalized_cost))
    if len(life_matches) > 1:
        return "activated_self_keyword_oracle_cost_not_supported"
    if life_matches:
        life_cost = int(life_matches[0].group("life"))
        normalized_cost = re.sub(life_pattern, ",", normalized_cost).strip(" ,")
    activation = activation_cost_from_oracle_prefix(normalized_cost)
    if isinstance(activation, str):
        return str(activation).replace("activated_self_boost", "activated_self_keyword")
    result = {
        "keyword": TARGET_GRANT_KEYWORD_ORACLE_WORDS[match.group("keyword")],
        **activation,
    }
    if discard_cost:
        result.update(discard_cost)
    if life_cost:
        result["activation_life_cost"] = life_cost
    return result


def activated_self_keyword_cost_from_source(window: str) -> dict[str, Any] | str:
    risky_cost_classes = {
        "CompositeCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "OrCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "SacrificeSourceCost",
        "SacrificeTargetCost",
        "TapTargetCost",
        "UntapSourceCost",
    }
    present_risky = sorted(cost for cost in risky_cost_classes if cost in window)
    if present_risky:
        return "activated_self_keyword_source_cost_not_supported"
    discard_cost = activation_discard_cost_from_source(window)
    if isinstance(discard_cost, str):
        return discard_cost.replace("activated_damage", "activated_self_keyword")
    life_matches = re.findall(r"PayLifeCost\s*\(\s*(\d+)\s*\)", window or "", re.S)
    if len(life_matches) > 1:
        return "activated_self_keyword_source_cost_not_supported"
    mana_matches = re.findall(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window, re.S)
    generic_matches = re.findall(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window, re.S)
    colored_matches = re.findall(r"ColoredManaCost\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)", window, re.S)
    cost_kinds = sum(1 for matches in (mana_matches, generic_matches, colored_matches) if matches)
    if cost_kinds > 1:
        return "activated_self_keyword_source_cost_not_supported"
    if len(mana_matches) > 1 or len(generic_matches) > 1 or len(colored_matches) > 1:
        return "activated_self_keyword_source_cost_not_supported"
    if mana_matches:
        cost_text = mana_matches[0]
    elif generic_matches:
        cost_text = "{" + generic_matches[0] + "}"
    elif colored_matches:
        cost_text = "{" + colored_matches[0] + "}"
    else:
        cost_text = "{0}"
    parsed = parse_mana_cost_text(cost_text)
    if parsed is None:
        return "activated_self_keyword_source_mana_cost_not_supported"
    generic, colors = parsed
    result = {
        "activation_cost_mana": cost_text,
        "activation_cost_generic": generic,
        "activation_cost_colors": colors,
        "activation_requires_tap": "TapSourceCost" in window,
        "activation_requires_sacrifice": False,
    }
    if discard_cost:
        result.update(discard_cost)
    if life_matches:
        result["activation_life_cost"] = int(life_matches[0])
    return result


def activated_self_keyword_from_source(source: str, keyword_ability_class: str) -> dict[str, Any] | str:
    text = source or ""
    if "Zone.GRAVEYARD" in text:
        return "activated_self_keyword_source_not_battlefield"
    gain_matches = re.findall(r"new\s+GainAbilitySourceEffect\s*\(", text)
    if len(gain_matches) != 1:
        return "activated_self_keyword_source_not_single_effect"
    ability_expr = (
        rf"(?:{re.escape(keyword_ability_class)}\.getInstance\s*\(\s*\)"
        rf"|new\s+{re.escape(keyword_ability_class)}\s*\([^)]*\))"
    )
    if not re.search(
        rf"new\s+GainAbilitySourceEffect\s*\(\s*{ability_expr}"
        rf"(?:\s*,\s*Duration\.EndOfTurn\s*)?\)",
        text,
        re.S,
    ):
        return "activated_self_keyword_source_keyword_not_supported"
    gain_index = text.find("GainAbilitySourceEffect")
    window = text[max(0, gain_index - 500) : gain_index + 2000]
    if "SimpleActivatedAbility" not in window:
        return "activated_self_keyword_source_not_simple_activated"
    activation = activated_self_keyword_cost_from_source(window)
    if isinstance(activation, str):
        return (
            activation.replace("activated_target_keyword", "activated_self_keyword")
            .replace("activated_self_boost", "activated_self_keyword")
        )
    return {
        "keyword": TARGET_GRANT_KEYWORD_ABILITY_CLASSES[keyword_ability_class],
        **activation,
    }


def attack_target_keyword_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(
        oracle_text_after_leading_static_keywords(metadata)
    )
    text = re.sub(r"\s+", " ", text).strip().lower()
    keyword_words = "|".join(
        re.escape(word)
        for word in sorted(TARGET_GRANT_KEYWORD_ORACLE_WORDS, key=len, reverse=True)
    )
    match = re.match(
        rf"^whenever (?:this creature|[^,.]+) attacks, "
        rf"(?P<optional>you may have )?(?P<another>another\s+)?target\s+"
        rf"(?P<target>.+?)\s+gains?\s+(?P<keyword>{keyword_words}) until end of turn\.?$",
        text,
    )
    if not match:
        return "attack_target_keyword_oracle_not_simple"
    target_phrase = match.group("target")
    target_data = activated_target_keyword_target_phrase_data(target_phrase)
    if isinstance(target_data, str):
        return target_data.replace("activated_target_keyword", "attack_target_keyword")
    if match.group("another"):
        target_data["exclude_source"] = True
        target_data.setdefault("target_constraints", {})["exclude_source"] = True
    return {
        "keyword": TARGET_GRANT_KEYWORD_ORACLE_WORDS[match.group("keyword")],
        "optional_trigger": bool(match.group("optional")),
        **target_data,
    }


def attack_target_keyword_from_source(source: str, keyword_ability_class: str) -> dict[str, Any] | str:
    text = source or ""
    if "AttacksTriggeredAbility" not in text:
        return "attack_target_keyword_source_not_attack_trigger"
    if "Zone.GRAVEYARD" in text:
        return "attack_target_keyword_source_not_battlefield"
    gain_matches = re.findall(r"new\s+GainAbilityTargetEffect\s*\(", text)
    if len(gain_matches) != 1:
        return "attack_target_keyword_source_not_single_effect"
    ability_expr = (
        rf"(?:{re.escape(keyword_ability_class)}\.getInstance\s*\(\s*\)"
        rf"|new\s+{re.escape(keyword_ability_class)}\s*\([^)]*\))"
    )
    if not re.search(
        rf"new\s+GainAbilityTargetEffect\s*\(\s*{ability_expr}"
        rf"\s*,\s*Duration\.EndOfTurn\s*\)",
        text,
        re.S,
    ):
        return "attack_target_keyword_source_keyword_not_supported"
    target_data = activated_target_keyword_target_from_source(text)
    if isinstance(target_data, str):
        return target_data.replace("activated_target_keyword", "attack_target_keyword")
    optional_trigger = bool(
        re.search(r"new\s+AttacksTriggeredAbility\s*\([^;]*,\s*true\s*\)", text, re.S)
    )
    return {
        "keyword": TARGET_GRANT_KEYWORD_ABILITY_CLASSES[keyword_ability_class],
        "optional_trigger": optional_trigger,
        **target_data,
    }


def attack_self_boost_from_oracle(metadata: dict[str, Any]) -> dict[str, int] | str:
    text = strip_parenthetical_reminders(
        oracle_text_after_leading_static_keywords(metadata)
    )
    text = re.sub(r"\s+", " ", text).strip().lower()
    match = re.search(
        r"whenever (?:this creature|[^,.]+?) attacks, it gets "
        r"(?P<power>[+-]\d+)/(?P<toughness>[+-]\d+) until end of turn\.?$",
        text,
    )
    if not match:
        return "attack_self_boost_oracle_not_fixed"
    return {
        "power_delta": int(match.group("power")),
        "toughness_delta": int(match.group("toughness")),
    }


def attack_self_boost_from_source(source: str) -> dict[str, int] | str:
    text = source or ""
    if "AttacksTriggeredAbility" not in text:
        return "attack_self_boost_source_not_attack_trigger"
    constructor_args = extract_constructor_args(text, "BoostSourceEffect")
    if constructor_args is None:
        return "attack_self_boost_source_not_single_fixed"
    args = split_top_level_args(constructor_args)
    if len(args) < 3:
        return "attack_self_boost_source_not_single_fixed"
    if args[2].strip() != "Duration.EndOfTurn":
        return "attack_self_boost_source_not_end_of_turn"
    if not re.fullmatch(r"[+-]?\d+", args[0].strip()) or not re.fullmatch(
        r"[+-]?\d+",
        args[1].strip(),
    ):
        return "attack_self_boost_source_not_single_fixed"
    if len(re.findall(r"new\s+BoostSourceEffect\s*\(", text)) != 1:
        return "attack_self_boost_source_not_single_fixed"
    return {
        "power_delta": int(args[0].strip()),
        "toughness_delta": int(args[1].strip()),
    }


def becomes_blocked_self_boost_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(
        oracle_text_after_leading_static_keywords(metadata)
    )
    text = re.sub(r"\s+", " ", text).strip().lower()
    match = re.search(
        r"whenever (?:this creature|[^,.]+?) becomes blocked, it gets "
        r"(?P<power>[+-]\d+)/(?P<toughness>[+-]\d+) until end of turn"
        r"(?: for (?P<mode>each creature blocking it|each creature blocking it beyond the first))?\.?$",
        text,
    )
    if not match:
        return "becomes_blocked_self_boost_oracle_not_supported"
    mode_text = match.group("mode") or ""
    blocker_count_mode = "fixed"
    if mode_text == "each creature blocking it":
        blocker_count_mode = "per_blocker"
    elif mode_text == "each creature blocking it beyond the first":
        blocker_count_mode = "beyond_first"
    return {
        "power_delta": int(match.group("power")),
        "toughness_delta": int(match.group("toughness")),
        "blocker_count_mode": blocker_count_mode,
    }


def _java_int_assignment_value(source: str, variable_name: str) -> int | None:
    match = re.search(
        rf"(?:private\s+static\s+final\s+)?DynamicValue\s+{re.escape(variable_name)}\s*="
        r"\s*new\s+MultipliedValue\s*\(\s*BlockingCreatureCount\.(?:SOURCE|BEYOND_FIRST)\s*,\s*([+-]?\d+)\s*\)",
        source,
        re.S,
    )
    if match:
        return int(match.group(1))
    match = re.search(
        rf"(?:private\s+static\s+final\s+)?DynamicValue\s+{re.escape(variable_name)}\s*="
        r"\s*new\s+SignInversionDynamicValue\s*\(\s*BlockingCreatureCount\.BEYOND_FIRST\s*\)",
        source,
        re.S,
    )
    if match:
        return -1
    return None


def _parse_blocking_count_boost_arg(arg: str, source: str) -> tuple[int, str] | str:
    cleaned = str(arg or "").strip()
    if re.fullmatch(r"[+-]?\d+", cleaned):
        return int(cleaned), "fixed"
    if cleaned == "BlockingCreatureCount.SOURCE":
        return 1, "per_blocker"
    if cleaned == "BlockingCreatureCount.BEYOND_FIRST":
        return 1, "beyond_first"
    multiplied = re.fullmatch(
        r"new\s+MultipliedValue\s*\(\s*BlockingCreatureCount\.(SOURCE|BEYOND_FIRST)\s*,\s*([+-]?\d+)\s*\)",
        cleaned,
        re.S,
    )
    if multiplied:
        return int(multiplied.group(2)), "per_blocker" if multiplied.group(1) == "SOURCE" else "beyond_first"
    inverted = re.fullmatch(
        r"new\s+SignInversionDynamicValue\s*\(\s*BlockingCreatureCount\.BEYOND_FIRST\s*\)",
        cleaned,
        re.S,
    )
    if inverted:
        return -1, "beyond_first"
    assigned = _java_int_assignment_value(source, cleaned)
    if assigned is not None:
        if re.search(
            rf"{re.escape(cleaned)}\s*=\s*new\s+MultipliedValue\s*\(\s*BlockingCreatureCount\.SOURCE",
            source,
            re.S,
        ):
            return assigned, "per_blocker"
        return assigned, "beyond_first"
    return "becomes_blocked_self_boost_source_not_supported_dynamic_value"


def becomes_blocked_self_boost_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if "BecomesBlockedSourceTriggeredAbility" not in text:
        return "becomes_blocked_self_boost_source_not_trigger"
    constructor_args = extract_constructor_args(text, "BoostSourceEffect")
    if constructor_args is None:
        return "becomes_blocked_self_boost_source_not_single_effect"
    if len(re.findall(r"new\s+BoostSourceEffect\s*\(", text)) != 1:
        return "becomes_blocked_self_boost_source_not_single_effect"
    args = split_top_level_args(constructor_args)
    if len(args) < 3:
        return "becomes_blocked_self_boost_source_not_single_effect"
    if args[2].strip() != "Duration.EndOfTurn":
        return "becomes_blocked_self_boost_source_not_end_of_turn"
    power = _parse_blocking_count_boost_arg(args[0], text)
    toughness = _parse_blocking_count_boost_arg(args[1], text)
    if isinstance(power, str):
        return power
    if isinstance(toughness, str):
        return toughness
    power_delta, power_mode = power
    toughness_delta, toughness_mode = toughness
    if power_mode != toughness_mode:
        return "becomes_blocked_self_boost_source_mixed_count_modes"
    return {
        "power_delta": int(power_delta),
        "toughness_delta": int(toughness_delta),
        "blocker_count_mode": power_mode,
    }


def normalized_activation_sacrifice_cost(cost: dict[str, Any] | None) -> dict[str, Any] | None:
    if not isinstance(cost, dict):
        return None
    constraints = dict(cost.get("constraints") or {})
    for key in ("card_types", "exclude_card_types", "target_subtypes", "required_subtypes"):
        if key in constraints:
            constraints[key] = sorted(
                {
                    str(value or "").strip().lower()
                    for value in as_list(constraints.get(key))
                    if str(value or "").strip()
                }
            )
    return {
        "count": int(cost.get("count") or 1),
        "target_controller": str(cost.get("target_controller") or "self"),
        "constraints": constraints,
    }


def normalized_activation_tap_cost(cost: dict[str, Any] | None) -> dict[str, Any] | None:
    if not isinstance(cost, dict):
        return None
    constraints = dict(cost.get("constraints") or {})
    for key in ("card_types", "exclude_card_types", "target_subtypes", "required_subtypes"):
        if key in constraints:
            constraints[key] = sorted(
                {
                    str(value or "").strip().lower()
                    for value in as_list(constraints.get(key))
                    if str(value or "").strip()
                }
            )
    if "target_colors" in constraints:
        constraints["target_colors"] = sorted(
            {
                str(value or "").strip().upper()
                for value in as_list(constraints.get("target_colors"))
                if str(value or "").strip()
            }
        )
    if "tapped_state" in constraints:
        constraints["tapped_state"] = str(constraints.get("tapped_state") or "").strip().lower()
    return {
        "count": int(cost.get("count") or 1),
        "target_controller": str(cost.get("target_controller") or "self"),
        "constraints": constraints,
    }


def activation_sacrifice_cost_from_phrase(phrase: str) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    count = 1
    count_match = re.match(
        r"(?P<count>one|two|three|four|five|six|seven|eight|nine|ten|\d+)\s+(?P<object>.+)$",
        text,
    )
    if count_match:
        count = number_word_to_int(count_match.group("count"))
        text = count_match.group("object").strip()
    if count <= 0:
        return "activated_damage_sacrifice_cost_not_supported"
    text = re.sub(r"^(?:a|an)\s+", "", text).strip()
    exclude_source = False
    if text.startswith("another "):
        exclude_source = True
        text = text[len("another ") :].strip()
    if count > 1 and " and " in text:
        text = text.split(" and ", 1)[0].strip()
    constraints: dict[str, Any] = {}
    if text in {"creature", "creatures"}:
        constraints["card_types"] = ["creature"]
    elif text in {"artifact", "artifacts"}:
        constraints["card_types"] = ["artifact"]
    elif text in {"land", "lands"}:
        constraints["card_types"] = ["land"]
    elif text in {"nonland permanent", "nonland permanents"}:
        constraints["card_types"] = ["permanent"]
        constraints["exclude_card_types"] = ["land"]
    elif text in {"goblin", "goblins"}:
        constraints["target_subtypes"] = ["goblin"]
    elif text in {"goblin creature", "goblin creatures"}:
        constraints["card_types"] = ["creature"]
        constraints["target_subtypes"] = ["goblin"]
    elif text in {"forest", "forests"}:
        constraints["target_subtypes"] = ["forest"]
    elif text in {"creature or enchantment", "creature or an enchantment"}:
        constraints["card_types"] = ["creature", "enchantment"]
    elif text in {"creature or artifact", "creature or an artifact", "artifact or creature"}:
        constraints["card_types"] = ["artifact", "creature"]
    else:
        return "activated_damage_sacrifice_cost_not_supported"
    if exclude_source:
        constraints["exclude_source"] = True
    return normalized_activation_sacrifice_cost(
        {"count": count, "target_controller": "self", "constraints": constraints}
    )


def activation_sacrifice_cost_from_oracle(text: str) -> dict[str, Any] | str | None:
    cost_text = str(text or "").lower().rsplit(":", 1)[0]
    matches = list(
        re.finditer(
            r"(?:^|,\s*)sacrifice\s+(?P<object>(?:another|an?|one|two|three|four|five|six|seven|eight|nine|ten|\d+)\s+[^,]+?)(?:,|$)",
            cost_text,
        )
    )
    if not matches:
        return None
    if len(matches) != 1:
        return "activated_damage_sacrifice_cost_not_supported"
    return activation_sacrifice_cost_from_phrase(matches[0].group("object"))


def activation_sacrifice_cost_from_source(text: str, window: str) -> dict[str, Any] | str | None:
    cost_matches = re.findall(r"new\s+SacrificeTargetCost\s*\((.*?)\)", window or "", re.S)
    if not cost_matches:
        return None
    if len(cost_matches) != 1:
        return "activated_damage_source_sacrifice_cost_not_supported"
    cost_arg = re.sub(r"\s+", " ", cost_matches[0]).strip()
    count = 1
    count_match = re.match(r"(?P<count>\d+)\s*,\s*(?P<rest>.+)$", cost_arg, re.S)
    if count_match:
        count = int(count_match.group("count"))
        cost_arg = count_match.group("rest").strip()
    if count <= 0:
        return "activated_damage_source_sacrifice_cost_not_supported"
    constraints: dict[str, Any] = {}
    if "FILTER_PERMANENT_CREATURE_OR_ENCHANTMENT" in cost_arg:
        constraints["card_types"] = ["creature", "enchantment"]
    elif "FILTER_CONTROLLED_ARTIFACT_OR_OTHER_CREATURE" in cost_arg:
        constraints["card_types"] = ["artifact", "creature"]
        constraints["exclude_source"] = True
    elif "FILTER_CONTROLLED_ANOTHER_CREATURE" in cost_arg or "FILTER_PERMANENT_ANOTHER_CREATURE" in cost_arg:
        constraints["card_types"] = ["creature"]
        constraints["exclude_source"] = True
    elif "FILTER_PERMANENT_CREATURE" in cost_arg:
        constraints["card_types"] = ["creature"]
    elif "FILTER_CONTROLLED_PERMANENT_ARTIFACT" in cost_arg or "FILTER_PERMANENT_ARTIFACT" in cost_arg:
        constraints["card_types"] = ["artifact"]
    elif "FILTER_LANDS" in cost_arg or "FILTER_LAND" in cost_arg or "FilterControlledLandPermanent" in cost_arg:
        constraints["card_types"] = ["land"]
    elif "filter" in cost_arg:
        filter_match = re.search(
            r"FilterControlledPermanent\s+filter\s*=\s*new\s+FilterControlledPermanent\s*\((.*?)\)\s*;",
            text or "",
            re.S,
        )
        filter_body = filter_match.group(1) if filter_match else ""
        filter_window = ""
        if filter_match:
            filter_window = (text or "")[filter_match.start() : filter_match.start() + 700]
        if "SubType.GOBLIN" in filter_body or "SubType.GOBLIN" in filter_window:
            constraints["target_subtypes"] = ["goblin"]
        elif "SubType.FOREST" in filter_body or "SubType.FOREST" in filter_window:
            constraints["target_subtypes"] = ["forest"]
        elif "CardType.ARTIFACT" in filter_window:
            constraints["card_types"] = ["artifact"]
        elif "Predicates.not(CardType.LAND.getPredicate())" in filter_window:
            constraints["card_types"] = ["permanent"]
            constraints["exclude_card_types"] = ["land"]
        else:
            return "activated_damage_source_sacrifice_cost_not_supported"
    else:
        return "activated_damage_source_sacrifice_cost_not_supported"
    return normalized_activation_sacrifice_cost(
        {"count": count, "target_controller": "self", "constraints": constraints}
    )


def activation_sacrifice_target_from_cost(cost: dict[str, Any] | None) -> str | None:
    normalized = normalized_activation_sacrifice_cost(cost)
    if not normalized or int(normalized.get("count") or 1) != 1:
        return None
    constraints = dict(normalized.get("constraints") or {})
    subtypes = [
        str(value or "").strip().lower()
        for value in as_list(constraints.get("target_subtypes") or constraints.get("required_subtypes"))
        if str(value or "").strip()
    ]
    if len(subtypes) == 1:
        return subtypes[0]
    card_types = sorted(
        {
            str(value or "").strip().lower()
            for value in as_list(constraints.get("card_types"))
            if str(value or "").strip()
        }
    )
    if card_types == ["artifact", "creature"]:
        return "artifact_or_creature"
    if card_types == ["creature", "enchantment"]:
        return "creature_or_enchantment"
    if len(card_types) == 1:
        return card_types[0]
    return None


def symbol_name_from_symbol(symbol: str) -> str:
    return {
        "W": "WHITE",
        "U": "BLUE",
        "B": "BLACK",
        "R": "RED",
        "G": "GREEN",
    }.get(str(symbol or "").upper(), "")


def activation_tap_cost_from_phrase(phrase: str) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    count = 1
    count_match = re.match(
        r"(?P<count>an?|one|two|three|four|five|six|seven|eight|nine|ten|\d+)\s+(?P<object>.+)$",
        text,
    )
    if count_match:
        count_word = count_match.group("count")
        count = 1 if count_word in {"a", "an"} else number_word_to_int(count_word)
        text = count_match.group("object").strip()
    if count <= 0 or not text.startswith("untapped "):
        return "activation_tap_cost_not_supported"
    text = text[len("untapped ") :].strip()
    text = re.sub(r"\s+you control$", "", text).strip()
    words = text.split()
    target_colors = []
    while words and words[0] in TOKEN_COLOR_WORDS:
        target_colors.append(TOKEN_COLOR_WORDS[words.pop(0)])
    object_text = " ".join(words).strip()
    constraints: dict[str, Any] = {"tapped_state": "untapped"}
    if target_colors:
        constraints["target_colors"] = target_colors
    if object_text in {"creature", "creatures"}:
        constraints["card_types"] = ["creature"]
    elif object_text in {"artifact", "artifacts"}:
        constraints["card_types"] = ["artifact"]
    elif object_text in {"permanent", "permanents"}:
        constraints["card_types"] = ["permanent"]
    elif object_text in {"soldier", "soldiers"}:
        constraints["card_types"] = ["creature"]
        constraints["required_subtypes"] = ["soldier"]
    else:
        return "activation_tap_cost_not_supported"
    return normalized_activation_tap_cost(
        {"count": count, "target_controller": "self", "constraints": constraints}
    )


def activation_tap_cost_from_oracle(text: str) -> dict[str, Any] | str | None:
    cost_text = str(text or "").lower().rsplit(":", 1)[0]
    matches = list(
        re.finditer(
            r"(?:^|,\s*)tap\s+(?P<object>(?:an?|one|two|three|four|five|six|seven|eight|nine|ten|\d+)\s+[^,]+?)(?:,|$)",
            cost_text,
        )
    )
    if not matches:
        return None
    if len(matches) != 1:
        return "activation_tap_cost_not_supported"
    return activation_tap_cost_from_phrase(matches[0].group("object"))


def source_filter_window(text: str, filter_name: str) -> str:
    name = str(filter_name or "").strip()
    if not re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", name):
        return ""
    pattern = (
        r"(?:private\s+static\s+final\s+)?"
        r"(?:Filter\w+|FilterControlledPermanent|FilterPermanent|FilterCreaturePermanent|FilterControlledCreaturePermanent)"
        rf"\s+{re.escape(name)}\s*=.*?;"
    )
    match = re.search(pattern, text or "", re.S)
    if not match:
        return ""
    return (text or "")[match.start() : match.start() + 1400]


def source_effect_target_window(text: str, effect_index: int) -> str:
    source = text or ""
    search_area = source[max(0, effect_index) :]
    add_target_match = re.search(r"\.addTarget\s*\(", search_area)
    if add_target_match:
        target_window = search_area[add_target_match.start() : add_target_match.start() + 1400]
    else:
        target_window = search_area[:1400]
    filter_refs = re.findall(r"\b(?:TargetPermanent|TargetCreaturePermanent|TargetArtifactPermanent)\s*\(\s*([A-Za-z_][A-Za-z0-9_]*)\s*\)", target_window)
    for filter_name in filter_refs:
        filter_window = source_filter_window(source, filter_name)
        if not filter_window:
            filter_window = source[max(0, effect_index - 900) : max(0, effect_index)]
        target_window += "\n" + filter_window
    return target_window


def activation_tap_cost_source_constraints(search_text: str) -> dict[str, Any] | None:
    text = search_text or ""
    constraints: dict[str, Any] = {"tapped_state": "untapped"}
    if (
        "FILTER_CONTROLLED_UNTAPPED_PERMANENT" in text
        or re.search(r"\buntapped permanents?\b", text, re.I)
    ):
        constraints["card_types"] = ["permanent"]
    if (
        "FILTER_CONTROLLED_UNTAPPED_CREATURE" in text
        or "FilterControlledCreaturePermanent" in text
        or re.search(r"\buntapped creatures?\b", text, re.I)
    ):
        constraints["card_types"] = ["creature"]
    if "SubType.SOLDIER" in text or re.search(r"\buntapped soldiers?\b", text, re.I):
        constraints["card_types"] = ["creature"]
        constraints["required_subtypes"] = ["soldier"]
    if "CardType.ARTIFACT" in text or re.search(r"\buntapped artifacts?\b", text, re.I):
        constraints["card_types"] = ["artifact"]
    color_matches = [
        symbol
        for color_word, symbol in TOKEN_COLOR_WORDS.items()
        if (
            re.search(rf"\buntapped\s+{re.escape(color_word)}\s+creatures?\b", text, re.I)
            or f"ObjectColor.{symbol_name_from_symbol(symbol)}" in text
        )
    ]
    if color_matches:
        constraints["target_colors"] = sorted(set(color_matches))
        constraints.setdefault("card_types", ["creature"])
    if "card_types" not in constraints and "required_subtypes" not in constraints:
        return None
    return constraints


def activation_tap_cost_from_source(text: str, window: str) -> dict[str, Any] | str | None:
    if "TapTargetCost" not in (window or ""):
        return None
    if len(re.findall(r"new\s+TapTargetCost\s*\(", window or "")) != 1:
        return "activation_tap_source_cost_not_supported"
    tap_args_text = extract_constructor_args(window or "", "TapTargetCost")
    if tap_args_text is None:
        return "activation_tap_source_cost_not_supported"
    tap_args = split_top_level_args(tap_args_text)
    count = 1
    filter_arg = ""
    if len(tap_args) >= 2 and re.fullmatch(r"\d+", tap_args[0].strip()):
        count = int(tap_args[0].strip())
        filter_arg = tap_args[1].strip()
    elif len(tap_args) == 1 and tap_args[0].strip().startswith("new TargetControlledPermanent"):
        target_args_text = extract_constructor_args(tap_args[0], "TargetControlledPermanent")
        target_args = split_top_level_args(target_args_text or "")
        if target_args and re.fullmatch(r"\d+", target_args[0].strip()):
            count = int(target_args[0].strip())
            filter_arg = (
                target_args[2].strip()
                if len(target_args) >= 3
                else (target_args[1].strip() if len(target_args) >= 2 else "")
            )
        elif target_args:
            filter_arg = target_args[0].strip()
    elif len(tap_args) == 1:
        filter_arg = tap_args[0].strip()
    else:
        return "activation_tap_source_cost_not_supported"
    if count <= 0:
        return "activation_tap_source_cost_not_supported"
    search_text = filter_arg
    if re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", filter_arg):
        search_text = f"{filter_arg}\n{source_filter_window(text, filter_arg)}"
    constraints = activation_tap_cost_source_constraints(search_text)
    if constraints is None:
        return "activation_tap_source_cost_not_supported"
    return normalized_activation_tap_cost(
        {"count": count, "target_controller": "self", "constraints": constraints}
    )


def activation_discard_cost_from_oracle(text: str) -> dict[str, Any] | None:
    cost_text = str(text or "").lower().rsplit(":", 1)[0]
    random_count_match = re.search(r"(?:^|,)\s*discard (?P<count>two|three|\d+) cards at random\s*$", cost_text)
    if random_count_match:
        count = number_word_to_int(random_count_match.group("count"))
        if count > 1:
            return {
                "activation_discard_count": count,
                "activation_discard_target": "any_card",
                "activation_requires_discard_card": True,
                "activation_discard_random": True,
            }
    if re.search(r"(?:^|,)\s*discard a card at random\s*$", cost_text):
        return {
            "activation_discard_count": 1,
            "activation_discard_target": "any_card",
            "activation_requires_discard_card": True,
            "activation_discard_random": True,
        }
    if re.search(r"(?:^|,)\s*discard a land card\s*$", cost_text):
        return {
            "activation_discard_count": 1,
            "activation_discard_target": "land_card",
            "activation_requires_discard_card": True,
        }
    if re.search(r"(?:^|,)\s*discard a card\s*$", cost_text):
        return {
            "activation_discard_count": 1,
            "activation_discard_target": "any_card",
            "activation_requires_discard_card": True,
        }
    return None


def activation_discard_cost_from_source(window: str) -> dict[str, Any] | str | None:
    if "DiscardCardCost" not in (window or "") and "DiscardTargetCost" not in (window or ""):
        return None
    random_target_matches = re.findall(
        r"new\s+DiscardTargetCost\s*\(\s*new\s+TargetCardInHand\s*\(\s*(?P<count>\d+)\s*,\s*new\s+FilterCard\s*\(\s*\"cards at random\"\s*\)\s*\)\s*,\s*true\s*\)",
        window or "",
        re.S,
    )
    random_matches = re.findall(r"new\s+DiscardCardCost\s*\(\s*true\s*\)", window or "")
    plain_matches = re.findall(r"new\s+DiscardCardCost\s*\(\s*\)", window or "")
    land_matches = re.findall(
        r"new\s+DiscardTargetCost\s*\(\s*new\s+TargetCardInHand\s*\(\s*StaticFilters\.FILTER_CARD_LAND_A\s*\)\s*\)",
        window or "",
    )
    supported_count = len(random_target_matches) + len(random_matches) + len(plain_matches) + len(land_matches)
    if supported_count != 1:
        return "activated_damage_source_discard_cost_not_supported"
    if random_target_matches:
        count = int(random_target_matches[0])
        if count <= 0:
            return "activated_damage_source_discard_cost_not_supported"
        return {
            "activation_discard_count": count,
            "activation_discard_target": "any_card",
            "activation_requires_discard_card": True,
            "activation_discard_random": True,
        }
    if random_matches:
        return {
            "activation_discard_count": 1,
            "activation_discard_target": "any_card",
            "activation_requires_discard_card": True,
            "activation_discard_random": True,
        }
    if land_matches:
        return {
            "activation_discard_count": 1,
            "activation_discard_target": "land_card",
            "activation_requires_discard_card": True,
        }
    return {
        "activation_discard_count": 1,
        "activation_discard_target": "any_card",
        "activation_requires_discard_card": True,
    }


def activation_life_cost_from_oracle(text: str) -> int | None:
    cost_text = str(text or "").lower().rsplit(":", 1)[0]
    if "life" not in cost_text:
        return 0
    pay_life_mentions = re.findall(r"pay [^,:]*life", cost_text)
    life_matches = re.findall(r"(?:^|,)\s*pay (?P<life>\d+) life(?:\s*,?|$)", cost_text)
    if len(pay_life_mentions) != 1 or len(life_matches) != 1:
        return None
    life_cost = int(life_matches[0])
    if life_cost <= 0:
        return None
    return life_cost


def activated_damage_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = re.sub(r"\s+", " ", oracle_text(metadata)).strip().lower()
    if text.count(":") != 1:
        return None
    discard_cost = activation_discard_cost_from_oracle(text)
    life_cost = activation_life_cost_from_oracle(text)
    if life_cost is None:
        return None
    tap_cost = activation_tap_cost_from_oracle(text)
    if isinstance(tap_cost, str):
        return None
    effect_text = text.rsplit(":", 1)[1].strip()
    restricted = restricted_battlefield_target_from_oracle({"oracle_text": effect_text}, "damage")
    if restricted is not None:
        match = re.match(
            r"^(?:it|this (?:artifact|creature|enchantment)|[^.]+?) deals (\d+) damage to ",
            effect_text,
        )
        if not match:
            return None
        sacrifice_cost = activation_sacrifice_cost_from_oracle(text)
        if isinstance(sacrifice_cost, str):
            return None
        return {
            "amount": int(match.group(1)),
            "target": restricted,
            "activation_sacrifice_cost": sacrifice_cost,
            "activation_tap_cost": tap_cost,
            "activation_life_cost": life_cost,
            **(discard_cost or {}),
        }
    match = re.match(
        r"^(?:it|this (?:artifact|creature|enchantment)|[^.]+?) deals (\d+) damage to "
        r"(any target|target creature|target player|target opponent|target player or planeswalker|target opponent or planeswalker|target creature or planeswalker)\.?$",
        effect_text,
    )
    if not match:
        return None
    target_map = {
        "any target": "any_target",
        "target creature": "creature",
        "target player": "player",
        "target opponent": "opponent",
        "target player or planeswalker": "player_or_planeswalker",
        "target opponent or planeswalker": "opponent_or_planeswalker",
        "target creature or planeswalker": "creature_or_planeswalker",
    }
    sacrifice_cost = activation_sacrifice_cost_from_oracle(text)
    if isinstance(sacrifice_cost, str):
        return None
    return {
        "amount": int(match.group(1)),
        "target": target_map[match.group(2)],
        "activation_sacrifice_cost": sacrifice_cost,
        "activation_tap_cost": tap_cost,
        "activation_life_cost": life_cost,
        **(discard_cost or {}),
    }


def activated_damage_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    risky_cost_classes = {
        "ExileFrom",
        "ExileFromTopOfLibraryCost",
        "ExileSourceFromGraveCost",
        "MillCardsCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "RevealTargetFromHandCost",
    }
    if "Zone.GRAVEYARD" in text:
        return "activated_damage_source_not_battlefield"
    damage_matches = re.findall(r"DamageTargetEffect\s*\(\s*(\d*)\s*(?:,|\))", text)
    if len(damage_matches) != 1:
        return "activated_damage_source_count_not_fixed"
    count = int(damage_matches[0] or "0")
    if count <= 0:
        return "activated_damage_source_count_not_fixed"
    damage_index = text.find("DamageTargetEffect")
    target_text = source_effect_target_window(text, damage_index)
    restricted = restricted_battlefield_target_from_source(target_text)
    if restricted is not None:
        target = restricted
    elif "new TargetAnyTarget(" in target_text:
        target = "any_target"
    elif "new TargetPlayerOrPlaneswalker(" in target_text:
        target = "player_or_planeswalker"
    elif "new TargetOpponentOrPlaneswalker(" in target_text:
        target = "opponent_or_planeswalker"
    elif "new TargetCreatureOrPlaneswalker(" in target_text:
        target = "creature_or_planeswalker"
    elif "new TargetOpponent(" in target_text:
        target = "opponent"
    elif "new TargetPlayer(" in target_text:
        target = "player"
    elif "new TargetCreaturePermanent(" in target_text:
        target = "creature"
    else:
        return "activated_damage_source_target_not_supported"
    window = text[max(0, damage_index - 300) : damage_index + 1600]
    if "SimpleActivatedAbility" not in window:
        return "activated_damage_source_not_simple_activated"
    present_risky = sorted(cost for cost in risky_cost_classes if cost in window)
    if present_risky:
        return "activated_damage_source_cost_not_supported"
    life_matches = re.findall(r"PayLifeCost\s*\(\s*(\d+)\s*\)", window)
    if "PayLifeCost" in window and len(life_matches) != 1:
        return "activated_damage_source_cost_not_supported"
    activation_life_cost = int(life_matches[0]) if life_matches else 0
    if activation_life_cost < 0:
        return "activated_damage_source_cost_not_supported"
    discard_cost = activation_discard_cost_from_source(window)
    if isinstance(discard_cost, str):
        return discard_cost
    sacrifice_cost = activation_sacrifice_cost_from_source(text, window)
    if isinstance(sacrifice_cost, str):
        return sacrifice_cost
    tap_cost = activation_tap_cost_from_source(text, window)
    if isinstance(tap_cost, str):
        return tap_cost.replace("activation_tap", "activated_damage")
    cost_text = "{0}"
    mana_match = re.search(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_match = re.search(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    colored_match = re.search(r"ColoredManaCost\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)", window)
    if mana_match:
        cost_text = mana_match.group(1)
    elif generic_match:
        cost_text = "{" + generic_match.group(1) + "}"
    elif colored_match:
        cost_text = "{" + colored_match.group(1) + "}"
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_damage_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    requires_tap = "TapSourceCost" in window
    requires_sacrifice = "SacrificeSourceCost" in window
    return {
        "amount": count,
        "damage": count,
        "target": target,
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": requires_tap,
        "activation_requires_sacrifice": requires_sacrifice,
        "activation_sacrifice_cost": sacrifice_cost,
        "activation_tap_cost": tap_cost,
        **({"activation_requires_tap_target": True} if tap_cost is not None else {}),
        "activation_life_cost": activation_life_cost,
        **(discard_cost or {}),
    }


def activated_destroy_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = re.sub(r"\s+", " ", oracle_text(metadata)).strip().lower()
    if text.count(":") != 1:
        return None
    discard_cost = activation_discard_cost_from_oracle(text)
    sacrifice_cost = activation_sacrifice_cost_from_oracle(text)
    if isinstance(sacrifice_cost, str):
        return None
    tap_cost = activation_tap_cost_from_oracle(text)
    if isinstance(tap_cost, str):
        return None
    effect_text = text.rsplit(":", 1)[1].strip()
    extra_sentences = [
        sentence.strip()
        for sentence in re.split(r"(?<=\.)\s+", effect_text)
        if sentence.strip()
    ]
    if len(extra_sentences) > 1 and extra_sentences[1:] != ["it can't be regenerated."]:
        return None
    effect_metadata = dict(metadata)
    effect_metadata["oracle_text"] = effect_text
    target = destroy_target_from_oracle(effect_metadata)
    if target is None:
        return None
    effect, target_type = target
    return {
        "effect": effect,
        "target": target_type,
        "activation_sacrifice_cost": sacrifice_cost,
        "activation_tap_cost": tap_cost,
        **(discard_cost or {}),
    }


def activated_destroy_sacrifice_target_from_oracle(metadata: dict[str, Any]) -> str | None:
    text = re.sub(r"\s+", " ", oracle_text(metadata)).strip().lower()
    if text.count(":") != 1:
        return None
    cost_text = text.split(":", 1)[0].strip()
    sacrifice_pattern = (
        r"(?:^|,\s*)sacrifice (?P<phrase>"
        r"(?:an?|another) (?:creature|artifact|enchantment|land|forest|beast|permanent|swamp)"
        r")(?:\s*,?|$)"
    )
    sacrifice_matches = list(re.finditer(sacrifice_pattern, cost_text))
    if len(sacrifice_matches) != 1:
        return None
    return activation_sacrifice_target_from_phrase(sacrifice_matches[0].group("phrase"))


def activated_destroy_target_from_source(text: str) -> str | None:
    if "TargetPointer" in text or ".setTargetPointer" in text or "EachTargetPointer" in text:
        return None
    restricted = restricted_battlefield_target_from_source(text)
    if restricted is not None:
        return restricted
    target_classes = list(dict.fromkeys(re.findall(r"new\s+(Target\w+)\s*\(", text)))
    if len(target_classes) != 1:
        return None
    target_patterns = [
        (
            "artifact_or_enchantment",
            r"TargetPermanent\s*\(\s*StaticFilters\.FILTER_PERMANENT_ARTIFACT_OR_ENCHANTMENT\s*\)",
        ),
        (
            "artifact_or_enchantment",
            r"FILTER_PERMANENT_ARTIFACT_OR_ENCHANTMENT",
        ),
        (
            "creature_enchantment_or_planeswalker",
            r"FILTER_PERMANENT_CREATURE_ENCHANTMENT_OR_PLANESWALKER",
        ),
        (
            "nonland_permanent",
            r"FILTER_PERMANENT_NON_LAND|FilterNonlandPermanent",
        ),
        (
            "artifact_creature",
            r'FilterCreaturePermanent\s*\(\s*"artifact creature"\s*\)|\bartifact creature\b',
        ),
        (
            "artifact",
            r'FilterPermanent\s*\(\s*"artifact"\s*\)',
        ),
        ("nonbasic_land", r"TargetNonBasicLandPermanent\s*\("),
        ("creature_or_planeswalker", r"TargetCreatureOrPlaneswalker\s*\("),
        ("artifact", r"TargetArtifactPermanent\s*\("),
        ("enchantment", r"TargetEnchantmentPermanent\s*\("),
        ("land", r"TargetLandPermanent\s*\("),
        ("creature", r"TargetCreaturePermanent\s*\("),
        ("permanent", r"TargetPermanent\s*\(\s*\)"),
    ]
    matched = [
        target
        for target, pattern in target_patterns
        if re.search(pattern, text, re.S)
    ]
    matched = list(dict.fromkeys(matched))
    if len(matched) != 1:
        return None
    return matched[0]


def activated_destroy_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    risky_cost_classes = {
        "CompositeCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "MillCardsCost",
        "OrCost",
        "PayLifeCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "RevealTargetFromHandCost",
    }
    if "Zone.GRAVEYARD" in text:
        return "activated_destroy_source_not_battlefield"
    present_risky = sorted(cost for cost in risky_cost_classes if cost in text)
    if present_risky:
        return "activated_destroy_source_cost_not_supported"
    if len(re.findall(r"new\s+DestroyTargetEffect\s*\(\s*(?:true|false)?\s*\)", text, re.S)) != 1:
        return "activated_destroy_source_not_simple_destroy_effect"
    destroy_index = text.find("DestroyTargetEffect")
    window = text[max(0, destroy_index - 500) : destroy_index + 2000]
    if "SimpleActivatedAbility" not in window:
        return "activated_destroy_source_not_simple_activated"
    discard_cost = activation_discard_cost_from_source(window)
    if isinstance(discard_cost, str):
        return discard_cost.replace("activated_damage", "activated_destroy")
    sacrifice_cost = None
    sacrifice_target = None
    if "SacrificeTargetCost" in window:
        sacrifice_cost = activation_sacrifice_cost_from_source(text, window)
        if isinstance(sacrifice_cost, str):
            return sacrifice_cost.replace("activated_damage", "activated_destroy")
        if sacrifice_cost is None:
            return "activated_destroy_source_cost_not_supported"
        sacrifice_target = activation_sacrifice_target_from_cost(sacrifice_cost)
    tap_cost = activation_tap_cost_from_source(text, window)
    if isinstance(tap_cost, str):
        return tap_cost.replace("activation_tap", "activated_destroy")
    target_text = source_effect_target_window(text, destroy_index)
    target = activated_destroy_target_from_source(target_text)
    if target is None:
        return "activated_destroy_source_target_not_supported"
    cost_text = "{0}"
    mana_match = re.search(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_match = re.search(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    colored_match = re.search(r"ColoredManaCost\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)", window)
    cost_kinds = sum(1 for match in (mana_match, generic_match, colored_match) if match)
    if cost_kinds > 1:
        return "activated_destroy_source_mana_cost_not_supported"
    if mana_match:
        cost_text = canonical_mana_cost_text(mana_match.group(1))
    elif generic_match:
        cost_text = "{" + generic_match.group(1) + "}"
    elif colored_match:
        cost_text = "{" + colored_match.group(1) + "}"
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_destroy_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    return {
        "target": target,
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": "TapSourceCost" in window,
        "activation_requires_sacrifice": "SacrificeSourceCost" in window,
        **(
            {
                "activation_sacrifice_cost": sacrifice_cost,
                "activation_requires_sacrifice_target": True,
            }
            if sacrifice_cost is not None
            else {}
        ),
        **(
            {
                "activation_sacrifice_target": sacrifice_target,
                "activation_requires_sacrifice_target": True,
            }
            if sacrifice_target is not None
            else {}
        ),
        **(
            {
                "activation_tap_cost": tap_cost,
                "activation_requires_tap_target": True,
            }
            if tap_cost is not None
            else {}
        ),
        **(discard_cost or {}),
    }


def activated_tap_target_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    text = re.sub(r"\s+", " ", text).strip().lower()
    if text.count(":") != 1:
        return "activated_tap_target_oracle_not_simple"
    cost_text, effect_text = [part.strip() for part in text.split(":", 1)]
    target_patterns = [
        (r"tap target wall\.?", "wall_creature"),
        (r"tap target spirit\.?", "spirit_creature"),
        (r"tap target nonenchantment creature\.?", "nonenchantment_creature"),
        (
            r"tap target creature with (?:converted mana cost|mana value) 2 or greater\.?",
            "creature_mana_value_2_or_greater",
        ),
        (r"tap target non-human creature\.?", "non_human_creature"),
        (r"tap target non-mount creature\.?", "non_mount_creature"),
        (r"tap target creature with flying\.?", "flying_creature"),
        (r"tap target creature\.?", "creature"),
        (r"tap target artifact\.?", "artifact"),
        (r"tap target artifact or creature\.?", "artifact_or_creature"),
        (r"tap target artifact, creature, or land\.?", "artifact_creature_or_land"),
        (r"tap target permanent\.?", "permanent"),
    ]
    target = None
    for pattern, candidate in target_patterns:
        if re.fullmatch(pattern, effect_text):
            target = candidate
            break
    if target is None:
        return "activated_tap_target_oracle_not_simple"
    activation = activation_cost_from_oracle_prefix(cost_text)
    if isinstance(activation, str):
        return activation.replace("activated_self_boost", "activated_tap_target")
    return {
        "target": target,
        "target_constraints": target_constraints_for(target),
        **activation,
    }


def activated_tap_target_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    risky_cost_classes = {
        "CompositeCost",
        "DiscardCardCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "MillCardsCost",
        "OrCost",
        "PayLifeCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "RevealTargetFromHandCost",
        "SacrificeSourceCost",
        "SacrificeTargetCost",
        "TapTargetCost",
    }
    if "Zone.GRAVEYARD" in text:
        return "activated_tap_target_source_not_battlefield"
    present_risky = sorted(cost for cost in risky_cost_classes if cost in text)
    if present_risky:
        return "activated_tap_target_source_cost_not_supported"
    if len(re.findall(r"new\s+TapTargetEffect\s*\(\s*\)", text, re.S)) != 1:
        return "activated_tap_target_source_not_simple_tap_effect"
    tap_index = text.find("TapTargetEffect")
    window = text[max(0, tap_index - 500) : tap_index + 2000]
    if "SimpleActivatedAbility" not in window:
        return "activated_tap_target_source_not_simple_activated"
    target = None
    mana_value_target = mana_value_restricted_target_from_source(text)
    if mana_value_target:
        target = mana_value_target
    elif "FILTER_CREATURE_FLYING" in text:
        target = "flying_creature"
    elif "SubType.WALL" in text:
        target = "wall_creature"
    elif "SubType.SPIRIT" in text:
        target = "spirit_creature"
    elif (
        "FilterCreaturePermanent" in text
        and "Predicates.not" in text
        and "CardType.ENCHANTMENT.getPredicate()" in text
    ):
        target = "nonenchantment_creature"
    elif "FilterCreaturePermanent" in text and "Predicates.not" in text and "SubType.HUMAN.getPredicate()" in text:
        target = "non_human_creature"
    elif "FilterCreaturePermanent" in text and "Predicates.not" in text and "SubType.MOUNT.getPredicate()" in text:
        target = "non_mount_creature"
    elif re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", text, re.S):
        target = "creature"
    elif "FILTER_PERMANENT_ARTIFACT_OR_CREATURE" in text:
        target = "artifact_or_creature"
    elif re.search(r'FilterPermanent\s*\(\s*"artifact"\s*\)', text) and "CardType.ARTIFACT" in text:
        target = "artifact"
    elif re.search(r'FilterPermanent\s*\(\s*"artifact,\s*creature,\s*or\s*land"\s*\)', text) and all(
        marker in text for marker in ("CardType.ARTIFACT", "CardType.CREATURE", "CardType.LAND")
    ):
        target = "artifact_creature_or_land"
    elif re.search(r"new\s+TargetPermanent\s*\(\s*\)", text, re.S):
        target = "permanent"
    if target is None:
        return "activated_tap_target_source_target_not_supported"
    cost_text = "{0}"
    mana_match = re.search(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_match = re.search(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    colored_match = re.search(r"ColoredManaCost\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)", window)
    cost_kinds = sum(1 for match in (mana_match, generic_match, colored_match) if match)
    if cost_kinds > 1:
        return "activated_tap_target_source_mana_cost_not_supported"
    if mana_match:
        cost_text = canonical_mana_cost_text(mana_match.group(1))
    elif generic_match:
        cost_text = "{" + generic_match.group(1) + "}"
    elif colored_match:
        cost_text = "{" + colored_match.group(1) + "}"
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_tap_target_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    return {
        "target": target,
        "target_constraints": target_constraints_for(target),
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": "TapSourceCost" in window,
        "activation_requires_sacrifice": False,
    }


def untap_target_constraints_for(target: str, *, another: bool = False) -> dict[str, Any]:
    constraints = dict(target_constraints_for(target))
    if another:
        constraints["exclude_source"] = True
    return constraints


def activated_untap_target_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    text = re.sub(r"\s+", " ", text).strip().lower()
    if text.count(":") != 1:
        return "activated_untap_target_oracle_not_simple"
    cost_text, effect_text = [part.strip() for part in text.split(":", 1)]
    target_patterns = [
        (r"untap target forest\.?", "forest_land", 1, False),
        (r"untap target gate\.?", "gate_land", 1, False),
        (r"untap target land\.?", "land", 1, False),
        (r"untap two target lands\.?", "land", 2, False),
        (r"untap target snow land\.?", "snow_land", 1, False),
        (r"untap target artifact\.?", "artifact", 1, False),
        (r"untap target artifact creature\.?", "artifact_creature", 1, False),
        (r"untap target creature\.?", "creature", 1, False),
        (
            r"untap target creature that has an activated ability with \{t\} in its cost\.?",
            "creature_with_tap_ability",
            1,
            False,
        ),
        (r"untap another target permanent\.?", "permanent", 1, True),
        (r"untap another target snow permanent\.?", "snow_permanent", 1, True),
    ]
    target = None
    target_count = 1
    another = False
    for pattern, candidate, count, is_another in target_patterns:
        if re.fullmatch(pattern, effect_text):
            target = candidate
            target_count = count
            another = is_another
            break
    if target is None:
        return "activated_untap_target_oracle_not_simple"
    activation = activation_cost_from_oracle_prefix(cost_text)
    if isinstance(activation, str):
        return activation.replace("activated_self_boost", "activated_untap_target")
    return {
        "target": target,
        "target_constraints": untap_target_constraints_for(target, another=another),
        "target_count": int(target_count),
        "target_count_min": int(target_count),
        "target_count_max": int(target_count),
        "activated_untap_another": bool(another),
        **activation,
    }


def _activated_untap_target_from_source_target(text: str, window: str) -> tuple[str, dict[str, Any], int] | str:
    target_count = 1
    target = None
    constraints: dict[str, Any] | None = None
    land_count_match = re.search(r"new\s+TargetLandPermanent\s*\(\s*(\d+)?\s*\)", window, re.S)
    if land_count_match:
        target = "land"
        target_count = int(land_count_match.group(1) or 1)
        constraints = target_constraints_for("land")
    elif re.search(r"new\s+TargetLandPermanent\s*\(\s*\)", window, re.S):
        target = "land"
        constraints = target_constraints_for("land")
    elif re.search(r"new\s+TargetCreaturePermanent\s*\(\s*\)", window, re.S):
        target = "creature"
        constraints = target_constraints_for("creature")
    elif "SubType.FOREST" in text:
        target = "forest_land"
        constraints = target_constraints_for(target)
    elif "SubType.GATE" in text:
        target = "gate_land"
        constraints = target_constraints_for(target)
    elif "FilterLandPermanent" in text and "SuperType.SNOW" in text:
        target = "snow_land"
        constraints = target_constraints_for(target)
    elif "HasAbilityWithTapSymbolPredicate" in text:
        target = "creature_with_tap_ability"
        constraints = target_constraints_for(target)
    elif "FilterCreaturePermanent" in text and "CardType.ARTIFACT" in text:
        target = "artifact_creature"
        constraints = target_constraints_for(target)
    elif "FilterPermanent" in text and "CardType.ARTIFACT" in text:
        target = "artifact"
        constraints = target_constraints_for(target)
    elif "SuperType.SNOW" in text and "AnotherPredicate" in text:
        target = "snow_permanent"
        constraints = untap_target_constraints_for(target, another=True)
    elif "AnotherPredicate" in text:
        target = "permanent"
        constraints = untap_target_constraints_for(target, another=True)
    elif re.search(r"new\s+TargetPermanent\s*\(\s*\)", window, re.S):
        target = "permanent"
        constraints = target_constraints_for("permanent")
    if target is None or constraints is None:
        return "activated_untap_target_source_target_not_supported"
    return target, constraints, target_count


def activated_untap_target_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    risky_cost_classes = {
        "CompositeCost",
        "DiscardCardCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "MillCardsCost",
        "OrCost",
        "PayLifeCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "RevealTargetFromHandCost",
        "SacrificeSourceCost",
        "SacrificeTargetCost",
        "TapTargetCost",
        "ExertSourceCost",
    }
    if "Zone.GRAVEYARD" in text:
        return "activated_untap_target_source_not_battlefield"
    present_risky = sorted(cost for cost in risky_cost_classes if cost in text)
    if present_risky:
        return "activated_untap_target_source_cost_not_supported"
    if len(re.findall(r"new\s+UntapTargetEffect\s*\(\s*\)", text, re.S)) != 1:
        return "activated_untap_target_source_not_single_untap_effect"
    if len(re.findall(r"new\s+SimpleActivatedAbility\s*\(", text, re.S)) != 1:
        return "activated_untap_target_source_not_single_simple_activated"
    untap_index = text.find("UntapTargetEffect")
    window = text[max(0, untap_index - 500) : untap_index + 2000]
    if "SimpleActivatedAbility" not in window:
        return "activated_untap_target_source_not_simple_activated"
    parsed_target = _activated_untap_target_from_source_target(text, window)
    if isinstance(parsed_target, str):
        return parsed_target
    target, constraints, target_count = parsed_target
    cost_text = "{0}"
    mana_match = re.search(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_match = re.search(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    colored_match = re.search(r"ColoredManaCost\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)", window)
    cost_kinds = sum(1 for match in (mana_match, generic_match, colored_match) if match)
    if cost_kinds > 1:
        return "activated_untap_target_source_mana_cost_not_supported"
    if mana_match:
        cost_text = canonical_mana_cost_text(mana_match.group(1))
    elif generic_match:
        cost_text = "{" + generic_match.group(1) + "}"
    elif colored_match:
        cost_text = "{" + colored_match.group(1) + "}"
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_untap_target_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    return {
        "target": target,
        "target_constraints": constraints,
        "target_count": int(target_count),
        "target_count_min": int(target_count),
        "target_count_max": int(target_count),
        "activated_untap_another": bool(constraints.get("exclude_source")),
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": "TapSourceCost" in window,
        "activation_requires_sacrifice": False,
    }


def tap_target_count_value(raw: str) -> int | str | None:
    value = str(raw or "").strip().lower()
    if value == "x":
        return "x"
    if value.isdigit():
        return int(value)
    return NUMBER_WORDS.get(value)


def tap_target_spell_target_from_text(raw_target: str) -> str | None:
    target = re.sub(r"\s+", " ", str(raw_target or "").strip().lower())
    return {
        "creature": "creature",
        "creatures": "creature",
        "land": "land",
        "lands": "land",
        "nonland permanent": "nonland_permanent",
        "nonland permanents": "nonland_permanent",
        "permanent": "permanent",
        "permanents": "permanent",
    }.get(target)


def tap_target_spell_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    lines = [
        re.sub(r"\s+", " ", line).strip().lower().rstrip(".")
        for line in oracle_effect_lines_without_neutral_auxiliary(metadata)
        if line.strip()
    ]
    if len(lines) != 1:
        return "tap_target_spell_oracle_not_simple"
    text = strip_parenthetical_reminders(lines[0])
    match = re.fullmatch(
        r"tap (?:(?P<up_to>up to) )?(?P<count>x|\d+|one|two|three|four|five|six|seven|eight|nine|ten) "
        r"target (?P<target>creatures?|lands?|nonland permanents?|permanents?)",
        text,
    )
    if not match:
        return "tap_target_spell_oracle_not_simple"
    target = tap_target_spell_target_from_text(match.group("target") or "")
    if target is None:
        return "tap_target_spell_oracle_target_not_supported"
    count = tap_target_count_value(match.group("count") or "")
    if count is None:
        return "tap_target_spell_oracle_count_not_supported"
    spec: dict[str, Any] = {
        "target": target,
        "target_constraints": target_constraints_for(target),
        "up_to_count": bool(match.group("up_to")),
    }
    if count == "x":
        spec["target_count_from_x"] = True
        spec["target_count_source"] = "x_value"
    else:
        spec["target_count"] = int(count)
        spec["target_count_max"] = int(count)
    return spec


def tap_target_spell_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if has_additional_cost(text):
        return "tap_target_spell_additional_cost_not_supported"
    if len(re.findall(r"new\s+TapTargetEffect\s*\(", text, re.S)) != 1:
        return "tap_target_spell_source_not_simple_tap_effect"
    target = None
    if re.search(r"new\s+TargetCreaturePermanent\s*\(", text, re.S):
        target = "creature"
    elif re.search(r"new\s+TargetLandPermanent\s*\(", text, re.S):
        target = "land"
    elif re.search(r"new\s+TargetNonlandPermanent\s*\(", text, re.S):
        target = "nonland_permanent"
    elif re.search(r"new\s+TargetPermanent\s*\(", text, re.S):
        target = "permanent"
    if target is None:
        return "tap_target_spell_source_target_not_supported"
    spec: dict[str, Any] = {
        "target": target,
        "target_constraints": target_constraints_for(target),
        "up_to_count": False,
    }
    if "XTargetsCountAdjuster" in text:
        spec["target_count_from_x"] = True
        spec["target_count_source"] = "x_value"
        return spec
    target_class = {
        "creature": "TargetCreaturePermanent",
        "land": "TargetLandPermanent",
        "nonland_permanent": "TargetNonlandPermanent",
        "permanent": "TargetPermanent",
    }[target]
    args = extract_constructor_args(text, target_class)
    if args is None:
        return "tap_target_spell_source_target_count_not_supported"
    parts = split_java_args(args)
    if len(parts) == 2 and parts[0].strip() == "0" and re.fullmatch(r"\d+", parts[1].strip()):
        count = int(parts[1].strip())
        spec["target_count"] = count
        spec["target_count_max"] = count
        spec["up_to_count"] = True
        return spec
    if len(parts) == 0 or args.strip() == "":
        spec["target_count"] = 1
        spec["target_count_max"] = 1
        return spec
    return "tap_target_spell_source_target_count_not_supported"


def activated_draw_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if "Zone.GRAVEYARD" in text:
        return "activated_draw_source_not_battlefield"
    draw_matches = re.findall(
        r"SimpleActivatedAbility\s*\(\s*new\s+DrawCardSourceControllerEffect\s*\(\s*(\d*)\s*\)",
        text,
        flags=re.DOTALL,
    )
    if len(draw_matches) != 1:
        return "activated_draw_source_count_not_fixed"
    count = int(draw_matches[0] or "1")
    if count <= 0:
        return "activated_draw_source_count_not_fixed"
    draw_index = text.find("SimpleActivatedAbility")
    window = text[max(0, draw_index - 500) : draw_index + 1800]
    risky_cost_classes = {
        "ExileFrom",
        "ExileSourceFromGraveCost",
        "MillCardsCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "RevealTargetFromHandCost",
        "TapTargetCost",
    }
    present_risky = sorted(cost for cost in risky_cost_classes if cost in window)
    if present_risky:
        return "activated_draw_source_cost_not_supported"
    discard_count = 0
    if re.search(r"new\s+DiscardCardCost\s*\(\s*\)", window):
        discard_count = 1
    elif re.search(
        r"new\s+DiscardTargetCost\s*\(\s*new\s+TargetCardInHand\s*\(\s*(?:1\s*,\s*StaticFilters\.FILTER_CARD_A)?\s*\)\s*\)",
        window,
        flags=re.DOTALL,
    ):
        discard_count = 1
    elif "DiscardCardCost" in window or "DiscardTargetCost" in window:
        return "activated_draw_source_cost_not_supported"
    if "SimpleActivatedAbility" not in window:
        return "activated_draw_source_not_simple_activated"
    cost_text = "{0}"
    mana_match = re.search(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_match = re.search(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    if mana_match:
        cost_text = mana_match.group(1)
    elif generic_match:
        cost_text = "{" + generic_match.group(1) + "}"
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_draw_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    requires_tap = "TapSourceCost" in window
    requires_sacrifice = "SacrificeSourceCost" in window
    life_cost = None
    life_matches = re.findall(r"PayLifeCost\s*\(\s*(\d+)\s*\)", window)
    if len(life_matches) > 1:
        return "activated_draw_source_cost_not_supported"
    if life_matches:
        life_cost = int(life_matches[0])
    sacrifice_target = None
    if "SacrificeTargetCost" in window:
        sacrifice_cost_constructors = re.findall(r"new\s+SacrificeTargetCost\s*\(", window)
        if len(sacrifice_cost_constructors) > 1:
            return "activated_draw_source_cost_not_supported"
        sacrifice_target = activation_sacrifice_target_from_source(text, window)
        if sacrifice_target is None:
            return "activated_draw_source_cost_not_supported"
    if requires_sacrifice and sacrifice_target:
        return "activated_draw_source_cost_not_supported"
    return {
        "count": count,
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": requires_tap,
        "activation_requires_sacrifice": requires_sacrifice,
        **(
            {
                "activation_discard_count": discard_count,
                "activation_discard_target": "any_card",
                "activation_requires_discard_card": True,
            }
            if discard_count
            else {}
        ),
        **({"activation_life_cost": life_cost} if life_cost else {}),
        **(
            {
                "activation_sacrifice_target": sacrifice_target,
                "activation_requires_sacrifice_target": True,
            }
            if sacrifice_target
            else {}
        ),
    }


def draw_discard_counts_from_source(source: str) -> tuple[int, int] | str:
    matches = re.findall(r"DrawDiscardControllerEffect\s*\(([^)]*)\)", source or "")
    if len(matches) != 1:
        return "activated_draw_discard_source_count_not_fixed"
    raw_args = [part.strip() for part in matches[0].split(",") if part.strip()]
    if not raw_args:
        return 1, 1
    if len(raw_args) == 1:
        if raw_args[0].lower() == "false":
            return 1, 1
        return "activated_draw_discard_source_optional_not_supported"
    if len(raw_args) == 2 and all(arg.isdigit() for arg in raw_args):
        draw_count = int(raw_args[0])
        discard_count = int(raw_args[1])
    elif (
        len(raw_args) == 3
        and raw_args[0].isdigit()
        and raw_args[1].isdigit()
        and raw_args[2].lower() in {"true", "false"}
    ):
        if raw_args[2].lower() == "true":
            return "activated_draw_discard_source_optional_not_supported"
        draw_count = int(raw_args[0])
        discard_count = int(raw_args[1])
    else:
        return "activated_draw_discard_source_count_not_fixed"
    if draw_count <= 0 or discard_count <= 0:
        return "activated_draw_discard_source_count_not_fixed"
    return draw_count, discard_count


def discard_controller_spell_count_from_source(source: str) -> tuple[int, bool] | str:
    matches = re.findall(r"DiscardControllerEffect\s*\(([^)]*)\)", source or "")
    if len(matches) != 1:
        return "draw_discard_spell_source_count_not_fixed"
    raw_args = [part.strip() for part in matches[0].split(",") if part.strip()]
    if not raw_args:
        return 1, False
    if not raw_args[0].isdigit():
        return "draw_discard_spell_source_count_not_fixed"
    discard_count = int(raw_args[0])
    if discard_count <= 0:
        return "draw_discard_spell_source_count_not_fixed"
    random_discard = False
    if len(raw_args) >= 2:
        if raw_args[1].lower() not in {"true", "false"}:
            return "draw_discard_spell_source_count_not_fixed"
        random_discard = raw_args[1].lower() == "true"
    if len(raw_args) > 2:
        return "draw_discard_spell_source_count_not_fixed"
    return discard_count, random_discard


def fixed_draw_discard_spell_from_source(source: str, classes: set[str]) -> dict[str, Any] | str:
    text = source or ""
    if has_additional_cost(text):
        return "draw_discard_spell_source_additional_cost_not_supported"
    unsupported_markers = {
        "ConditionalOneShotEffect",
        "DoIfCostPaid",
        "Mode",
        "Modes",
        "TargetPointer",
        ".setTargetPointer",
    }
    if any(marker in text for marker in unsupported_markers):
        return "draw_discard_spell_source_not_simple"
    if classes == {"DrawDiscardControllerEffect"}:
        counts = draw_discard_counts_from_source(text)
        if isinstance(counts, str):
            return counts.replace("activated_draw_discard", "draw_discard_spell")
        draw_count, discard_count = counts
        return {
            "draw_count": draw_count,
            "discard_count": discard_count,
            "draw_discard_order": "draw_then_discard",
            "discard_random": False,
            "xmage_effect_classes": ["DrawDiscardControllerEffect"],
        }
    if classes == {"DrawCardSourceControllerEffect", "DiscardControllerEffect"}:
        draw_count = java_constructor_int_or_noarg_default(
            text,
            "DrawCardSourceControllerEffect",
            noarg_default=1,
        )
        if draw_count is None or draw_count <= 0:
            return "draw_discard_spell_source_count_not_fixed"
        discard_detail = discard_controller_spell_count_from_source(text)
        if isinstance(discard_detail, str):
            return discard_detail
        discard_count, random_discard = discard_detail
        draw_match = re.search(r"DrawCardSourceControllerEffect\s*\(", text)
        discard_match = re.search(r"DiscardControllerEffect\s*\(", text)
        if not draw_match or not discard_match:
            return "draw_discard_spell_source_not_simple"
        order = "draw_then_discard" if draw_match.start() < discard_match.start() else "discard_then_draw"
        return {
            "draw_count": draw_count,
            "discard_count": discard_count,
            "draw_discard_order": order,
            "discard_random": random_discard,
            "xmage_effect_classes": ["DrawCardSourceControllerEffect", "DiscardControllerEffect"],
        }
    return "draw_discard_spell_source_effect_class_not_supported"


def fixed_draw_lose_life_spell_from_source(source: str, classes: set[str]) -> dict[str, Any] | str:
    text = source or ""
    if has_additional_cost(text):
        return "draw_lose_life_spell_source_additional_cost_not_supported"
    unsupported_markers = {
        "ConditionalOneShotEffect",
        "DoIfCostPaid",
        "Mode",
        "Modes",
        "TargetPointer",
        ".setTargetPointer",
    }
    if any(marker in text for marker in unsupported_markers):
        return "draw_lose_life_spell_source_not_simple"
    if classes == {"DrawCardSourceControllerEffect", "LoseLifeSourceControllerEffect"}:
        draw_count = java_constructor_int_or_noarg_default(
            text,
            "DrawCardSourceControllerEffect",
            noarg_default=1,
        )
        life_loss = java_constructor_int(text, "LoseLifeSourceControllerEffect")
        target_controller = "self"
        effect_classes = ["DrawCardSourceControllerEffect", "LoseLifeSourceControllerEffect"]
    elif classes == {"DrawCardTargetEffect", "LoseLifeTargetEffect"}:
        if "TargetPlayer" not in text:
            return "draw_lose_life_spell_source_target_not_supported"
        draw_count = java_constructor_int_or_noarg_default(
            text,
            "DrawCardTargetEffect",
            noarg_default=1,
        )
        life_loss = java_constructor_int(text, "LoseLifeTargetEffect")
        target_controller = "target_player"
        effect_classes = ["DrawCardTargetEffect", "LoseLifeTargetEffect"]
    else:
        return "draw_lose_life_spell_source_effect_class_not_supported"
    if draw_count is None or life_loss is None or draw_count <= 0 or life_loss <= 0:
        return "draw_lose_life_spell_source_count_not_fixed"
    return {
        "draw_count": int(draw_count),
        "life_loss": int(life_loss),
        "target_controller": target_controller,
        "xmage_effect_classes": effect_classes,
    }


def fixed_target_player_draw_spell_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if has_additional_cost(text):
        return "target_player_draw_spell_source_additional_cost_not_supported"
    unsupported_markers = {
        "ConditionalOneShotEffect",
        "DoIfCostPaid",
        "Mode",
        "Modes",
        "TargetPointer",
        ".setTargetPointer",
    }
    if any(marker in text for marker in unsupported_markers):
        return "target_player_draw_spell_source_not_simple"
    if "TargetPlayer" not in text:
        return "target_player_draw_spell_source_target_not_supported"
    if len(re.findall(r"\bDrawCardTargetEffect\s*\(", text)) != 1:
        return "target_player_draw_spell_source_not_simple"
    draw_count = java_constructor_int_or_noarg_default(
        text,
        "DrawCardTargetEffect",
        noarg_default=1,
    )
    if draw_count is None or draw_count <= 0:
        return "target_player_draw_spell_source_count_not_fixed"
    return {
        "draw_count": int(draw_count),
        "xmage_effect_class": "DrawCardTargetEffect",
    }


def fixed_target_player_discard_spell_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if has_additional_cost(text):
        return "target_player_discard_spell_source_additional_cost_not_supported"
    unsupported_markers = {
        "ConditionalOneShotEffect",
        "DoIfCostPaid",
        "Mode",
        "Modes",
        "TargetPointer",
        ".setTargetPointer",
        "GetXValue",
        "DomainValue",
        "ColorsOfManaSpentToCastCount",
        "GreatestAmongPermanentsValue",
    }
    if any(marker in text for marker in unsupported_markers):
        return "target_player_discard_spell_source_not_simple"
    if len(re.findall(r"new\s+TargetPlayer\s*\(\s*\)", text)) != 1:
        return "target_player_discard_spell_source_target_not_supported"
    matches = re.findall(
        r"\bDiscardTargetEffect\s*\(\s*(\d+)(?:\s*,\s*(true|false))?\s*\)",
        text,
        re.S,
    )
    if len(matches) != 1:
        return "target_player_discard_spell_source_not_simple"
    count_raw, random_raw = matches[0]
    discard_count = int(count_raw)
    if discard_count <= 0:
        return "target_player_discard_spell_source_count_not_fixed"
    return {
        "discard_count": discard_count,
        "discard_random": random_raw == "true",
        "xmage_effect_class": "DiscardTargetEffect",
    }


def _discard_count_phrase_to_int(value: str) -> int:
    token = str(value or "").strip().lower()
    if token in {"a", "an"}:
        return 1
    if token.isdigit():
        return int(token)
    return number_word_to_int(token)


def triggered_target_player_discard_from_source(
    source: str,
    *,
    trigger_class: str,
    damaged_player_target: bool = False,
) -> dict[str, Any] | str:
    text = source or ""
    unsupported_markers = {
        "DoIfCostPaid",
        "ConditionalOneShotEffect",
        "MultikickerAbility",
        "KickerAbility",
        "DevourAbility",
        "RaidCondition",
        "ManaWasSpentCondition",
        "GetXValue",
        "DynamicValue",
        "ZuberasDiedDynamicValue",
    }
    if any(marker in text for marker in unsupported_markers):
        return "target_player_discard_trigger_source_not_simple"
    if trigger_class not in text:
        return "target_player_discard_trigger_source_trigger_mismatch"
    matches = re.findall(
        r"\bDiscardTargetEffect\s*\(\s*(\d+)(?:\s*,\s*(true|false))?\s*\)",
        text,
        re.S,
    )
    if len(matches) != 1:
        return "target_player_discard_trigger_source_not_simple"
    count_raw, random_raw = matches[0]
    discard_count = int(count_raw)
    if discard_count <= 0:
        return "target_player_discard_trigger_source_count_not_fixed"
    target_controller = "damaged_player"
    if not damaged_player_target:
        has_target_opponent = bool(re.search(r"new\s+TargetOpponent\s*\(", text))
        has_target_player = bool(re.search(r"new\s+TargetPlayer\s*\(", text))
        if has_target_opponent == has_target_player:
            return "target_player_discard_trigger_source_target_not_supported"
        target_controller = "target_opponent" if has_target_opponent else "target_player"
    return {
        "discard_count": discard_count,
        "discard_random": random_raw == "true",
        "target_controller": target_controller,
        "target_preference": "opponent",
        "xmage_effect_class": "DiscardTargetEffect",
    }


def etb_target_player_discard_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    prefix = r"when this creature enters(?: the battlefield)?"
    patterns = [
        (
            rf"^{prefix}, you may have target (?P<target>opponent|player) discard "
            rf"(?P<count>a|an|one|two|three|four|five|\d+) cards?(?P<random> at random)?\.?$",
            True,
        ),
        (
            rf"^{prefix}, target (?P<target>opponent|player) discards "
            rf"(?P<count>a|an|one|two|three|four|five|\d+) cards?(?P<random> at random)?\.?$",
            False,
        ),
    ]
    for pattern, optional in patterns:
        match = re.fullmatch(pattern, text)
        if not match:
            continue
        count = _discard_count_phrase_to_int(match.group("count"))
        if count <= 0:
            return "etb_target_player_discard_oracle_count_not_fixed"
        target = match.group("target")
        return {
            "discard_count": count,
            "discard_random": bool(match.group("random")),
            "target_controller": "target_opponent" if target == "opponent" else "target_player",
            "target_preference": "opponent",
            "optional": optional,
        }
    return "etb_target_player_discard_oracle_not_simple"


def dies_target_player_discard_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    match = re.fullmatch(
        r"when this creature dies, target (?P<target>opponent|player) discards "
        r"(?P<count>a|an|one|two|three|four|five|\d+) cards?(?P<random> at random)?\.?",
        text,
    )
    if not match:
        return "dies_target_player_discard_oracle_not_simple"
    count = _discard_count_phrase_to_int(match.group("count"))
    if count <= 0:
        return "dies_target_player_discard_oracle_count_not_fixed"
    target = match.group("target")
    return {
        "discard_count": count,
        "discard_random": bool(match.group("random")),
        "target_controller": "target_opponent" if target == "opponent" else "target_player",
        "target_preference": "opponent",
    }


def combat_damage_target_player_discard_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    match = re.fullmatch(
        r"whenever this creature deals combat damage to a player, that player discards "
        r"(?P<count>a|an|one|two|three|four|five|\d+) cards?(?P<random> at random)?\.?",
        text,
    )
    if not match:
        return "combat_damage_target_player_discard_oracle_not_simple"
    count = _discard_count_phrase_to_int(match.group("count"))
    if count <= 0:
        return "combat_damage_target_player_discard_oracle_count_not_fixed"
    return {
        "discard_count": count,
        "discard_random": bool(match.group("random")),
        "target_controller": "damaged_player",
        "target_preference": "damaged_player",
    }


def activated_draw_discard_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if "Zone.GRAVEYARD" in text:
        return "activated_draw_discard_source_not_battlefield"
    counts = draw_discard_counts_from_source(text)
    if isinstance(counts, str):
        return counts
    draw_count, discard_count = counts
    effect_index = text.find("DrawDiscardControllerEffect")
    window = text[max(0, effect_index - 500) : effect_index + 1800]
    risky_cost_classes = {
        "DiscardCardCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileSourceFromGraveCost",
        "MillCardsCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "RevealTargetFromHandCost",
        "TapTargetCost",
    }
    present_risky = sorted(cost for cost in risky_cost_classes if cost in window)
    if present_risky:
        return "activated_draw_discard_source_cost_not_supported"
    if "SimpleActivatedAbility" not in window:
        return "activated_draw_discard_source_not_simple_activated"
    cost_text = "{0}"
    mana_match = re.search(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_match = re.search(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    if mana_match:
        cost_text = mana_match.group(1)
    elif generic_match:
        cost_text = "{" + generic_match.group(1) + "}"
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_draw_discard_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    requires_tap = "TapSourceCost" in window
    requires_sacrifice = "SacrificeSourceCost" in window
    life_cost = None
    life_matches = re.findall(r"PayLifeCost\s*\(\s*(\d+)\s*\)", window)
    if len(life_matches) > 1:
        return "activated_draw_discard_source_cost_not_supported"
    if life_matches:
        life_cost = int(life_matches[0])
    sacrifice_target = None
    if "SacrificeTargetCost" in window:
        sacrifice_cost_constructors = re.findall(r"new\s+SacrificeTargetCost\s*\(", window)
        if len(sacrifice_cost_constructors) > 1:
            return "activated_draw_discard_source_cost_not_supported"
        sacrifice_target = activation_sacrifice_target_from_source(text, window)
        if sacrifice_target is None:
            return "activated_draw_discard_source_cost_not_supported"
    if requires_sacrifice and sacrifice_target:
        return "activated_draw_discard_source_cost_not_supported"
    return {
        "draw_count": draw_count,
        "discard_count": discard_count,
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": requires_tap,
        "activation_requires_sacrifice": requires_sacrifice,
        **({"activation_life_cost": life_cost} if life_cost else {}),
        **(
            {
                "activation_sacrifice_target": sacrifice_target,
                "activation_requires_sacrifice_target": True,
            }
            if sacrifice_target
            else {}
        ),
    }


def activation_sacrifice_target_from_source(source: str, window: str) -> str | None:
    text = source or ""
    relevant = (window or "") + "\n" + text
    cost_var_match = re.search(r"new\s+SacrificeTargetCost\s*\(\s*([A-Za-z_][A-Za-z0-9_]*)\s*\)", window or "")
    if cost_var_match:
        var_name = cost_var_match.group(1)
        var_filter_match = re.search(
            rf"FilterControlledPermanent\s+{re.escape(var_name)}\s*=\s*"
            r"new\s+FilterControlledPermanent\s*\(\s*\"([^\"]+)\"\s*\)",
            text,
            re.S,
        )
        if var_filter_match:
            named_target = activation_sacrifice_target_from_phrase(var_filter_match.group(1))
            if named_target is not None:
                return named_target
        var_pattern = re.compile(
            rf"\b{re.escape(var_name)}\.add\s*\(\s*SubType\.([A-Z_]+)\.getPredicate\s*\(\s*\)\s*\)",
            re.S,
        )
        var_subtypes = [match.group(1).lower() for match in var_pattern.finditer(text)]
        if len(var_subtypes) == 1:
            subtype_target = activation_sacrifice_target_from_phrase(var_subtypes[0])
            if subtype_target is not None:
                return subtype_target
    subtype_constructor_match = re.search(
        r"new\s+FilterControlledPermanent\s*\(\s*SubType\.([A-Z_]+)\s*,",
        relevant,
    )
    if subtype_constructor_match:
        subtype_target = activation_sacrifice_target_from_phrase(subtype_constructor_match.group(1).lower())
        if subtype_target is not None:
            return subtype_target
    if "FILTER_PERMANENT_CREATURE_OR_ENCHANTMENT" in relevant:
        return "creature_or_enchantment"
    if (
        "CardType.CREATURE.getPredicate()" in relevant
        and "CardType.PLANESWALKER.getPredicate()" in relevant
    ):
        return "creature_or_planeswalker"
    if "FILTER_PERMANENT_ARTIFACT_OR_CREATURE" in relevant:
        return "artifact_or_creature"
    if "FILTER_CONTROLLED_ANOTHER_CREATURE_OR_ARTIFACT" in relevant:
        return "artifact_or_creature"
    if "FilterControlledEnchantmentPermanent" in relevant:
        return "enchantment"
    if "SubType.SWAMP.getPredicate" in relevant:
        return "swamp"
    if "FILTER_PERMANENT_CREATURE" in relevant or "TargetControlledCreaturePermanent" in relevant:
        return "creature"
    if (
        "FILTER_PERMANENT_ARTIFACT" in relevant
        or "FILTER_CONTROLLED_PERMANENT_ARTIFACT" in relevant
        or "FilterControlledArtifactPermanent" in relevant
    ):
        return "artifact"
    if (
        "FILTER_CONTROLLED_LAND" in relevant
        or "FILTER_LANDS" in relevant
        or "FILTER_LAND" in relevant
        or "FilterControlledLandPermanent" in relevant
    ):
        return "land"
    if "FILTER_PERMANENT" in relevant:
        return "permanent"
    if "SubType.FOREST" in relevant:
        return "forest"
    if "SubType.MOUNTAIN" in relevant:
        return "mountain"
    if "SubType.GOBLIN" in relevant:
        return "goblin"
    if "SubType.BEAST" in relevant:
        return "beast"
    if "TokenPredicate.TRUE" in relevant:
        return "token"
    if "TokenPredicate.FALSE" in relevant:
        return "nontoken_permanent"
    if "CardType.ARTIFACT.getPredicate()" in relevant and "CardType.LAND.getPredicate()" in relevant:
        return "artifact_or_land"
    if "CardType.CREATURE.getPredicate()" in relevant and "CardType.LAND.getPredicate()" in relevant:
        return "creature_or_land"
    filter_match = re.search(r'new\s+FilterControlledPermanent\s*\(\s*"([^"]+)"\s*\)', relevant)
    if filter_match:
        return activation_sacrifice_target_from_phrase(filter_match.group(1))
    filter_match = re.search(r'new\s+FilterPermanent\s*\(\s*"([^"]+)"\s*\)', relevant)
    if filter_match:
        return activation_sacrifice_target_from_phrase(filter_match.group(1))
    return None


def fixed_spell_additional_cost_fields_from_source(
    source: str,
    metadata: dict[str, Any],
    unsupported_reason: str,
) -> tuple[dict[str, Any] | None, str | None]:
    text = source or ""
    has_cost = has_additional_cost(text) or "additional cost" in oracle_text(metadata).lower()
    if not has_cost:
        return {}, None
    cost_count = len(re.findall(r"\.addCost\s*\(", text))
    if cost_count != 1:
        return None, unsupported_reason
    if "OrCost" in text or "GenericManaCost" in text or "PayLifeCost" in text:
        return None, unsupported_reason
    lowered_oracle = oracle_text(metadata).lower()
    if "DiscardCardCost" in text and re.search(r"additional cost.*discard a card", lowered_oracle):
        return {
            "additional_cost": "discard_card",
            "requires_discard_card": True,
            "xmage_additional_cost_class": "DiscardCardCost",
            "xmage_additional_cost_target": "card",
        }, None
    if (
        "DiscardTargetCost" in text
        and "FilterLandCard" in text
        and re.search(r"additional cost.*discard a land card", lowered_oracle)
    ):
        return {
            "additional_cost": "discard_land",
            "requires_discard_land": True,
            "xmage_additional_cost_class": "DiscardTargetCost",
            "xmage_additional_cost_target": "land",
        }, None
    if "SacrificeTargetCost" in text and re.search(
        r"additional cost.*sacrifice (?:a|one) creature", lowered_oracle
    ):
        if re.search(r"SacrificeTargetCost\s*\(\s*2\b", text):
            return None, unsupported_reason
        sacrifice_target = activation_sacrifice_target_from_source(text, text)
        if sacrifice_target == "creature":
            return {
                "additional_cost": "sacrifice_creature",
                "requires_sacrifice_creature": True,
                "xmage_additional_cost_class": "SacrificeTargetCost",
                "xmage_additional_cost_target": "creature",
            }, None
    if "SacrificeTargetCost" in text and re.search(
        r"additional cost.*sacrifice (?:an?|one) artifact or creature", lowered_oracle
    ):
        sacrifice_target = activation_sacrifice_target_from_source(text, text)
        if sacrifice_target == "artifact_or_creature":
            return {
                "additional_cost": "sacrifice_artifact_or_creature",
                "requires_sacrifice_artifact_or_creature": True,
                "xmage_additional_cost_class": "SacrificeTargetCost",
                "xmage_additional_cost_target": "artifact_or_creature",
            }, None
    if "SacrificeTargetCost" in text and re.search(
        r"additional cost.*sacrifice (?:an?|one) artifact", lowered_oracle
    ):
        sacrifice_target = activation_sacrifice_target_from_source(text, text)
        if sacrifice_target == "artifact":
            return {
                "additional_cost": "sacrifice_artifact",
                "requires_sacrifice_artifact": True,
                "xmage_additional_cost_class": "SacrificeTargetCost",
                "xmage_additional_cost_target": "artifact",
            }, None
    if "SacrificeTargetCost" in text and re.search(
        r"additional cost.*sacrifice (?:a|one) goblin", lowered_oracle
    ):
        sacrifice_target = activation_sacrifice_target_from_source(text, text)
        if sacrifice_target == "goblin":
            return {
                "additional_cost": "sacrifice_goblin",
                "requires_sacrifice_goblin": True,
                "xmage_additional_cost_class": "SacrificeTargetCost",
                "xmage_additional_cost_target": "goblin",
            }, None
    if "SacrificeTargetCost" in text and re.search(
        r"additional cost.*sacrifice (?:a|one) land", lowered_oracle
    ):
        sacrifice_target = activation_sacrifice_target_from_source(text, text)
        if sacrifice_target == "land":
            return {
                "additional_cost": "sacrifice_land",
                "requires_sacrifice_land": True,
                "xmage_additional_cost_class": "SacrificeTargetCost",
                "xmage_additional_cost_target": "land",
            }, None
    return None, unsupported_reason


