def spell_cast_draw_filter_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text(metadata)).strip().lower()
    text = re.sub(r"\s*\([^)]*historic[^)]*\)\s*", " ", text).strip()
    match = re.search(
        r"whenever you cast (?P<filter>.+?), (?:you )?(?P<may>may )?draw (?P<count>a|one|two|three|\d+) cards?\.?",
        text,
    )
    if not match:
        return "spell_cast_draw_oracle_not_simple"
    value = match.group("count")
    words = {"a": 1, "one": 1, "two": 2, "three": 3}
    count = words.get(value, int(value) if value.isdigit() else 0)
    if count <= 0:
        return "spell_cast_draw_oracle_count_not_supported"
    filter_text = re.sub(r"\s+", " ", match.group("filter").strip())
    if filter_text.endswith(" spell"):
        filter_text = filter_text[: -len(" spell")].strip()
    result: dict[str, Any] = {
        "spell_cast_draw_count": count,
        "spell_cast_draw_optional": bool(match.group("may")),
        "trigger": "spell_cast",
    }
    filter_specs: list[tuple[str, dict[str, Any]]] = [
        ("a creature", {"spell_cast_draw_card_types": ["creature"]}),
        ("an enchantment", {"spell_cast_draw_card_types": ["enchantment"]}),
        ("an artifact", {"spell_cast_draw_card_types": ["artifact"]}),
        ("a noncreature", {"trigger": "noncreature_spell_cast"}),
        ("a legendary", {"spell_cast_draw_required_supertypes": ["legendary"]}),
        ("a historic", {"spell_cast_draw_requires_historic": True}),
        (
            "an aura, equipment, or vehicle",
            {"spell_cast_draw_required_subtypes": ["aura", "equipment", "vehicle"]},
        ),
        ("a spell from your graveyard", {"spell_cast_draw_source_zone": "graveyard"}),
    ]
    for prefix, spec in filter_specs:
        if filter_text == prefix:
            result.update(spec)
            return result
    match_mv = re.fullmatch(r"a spell with mana value (?P<mv>\d+) or greater", filter_text)
    if match_mv:
        result["spell_cast_draw_mana_value_min"] = int(match_mv.group("mv"))
        return result
    match_eldrazi = re.fullmatch(
        r"an eldrazi creature spell with mana value (?P<mv>\d+) or greater",
        filter_text,
    )
    if match_eldrazi:
        result["spell_cast_draw_card_types"] = ["creature"]
        result["spell_cast_draw_required_subtypes"] = ["eldrazi"]
        result["spell_cast_draw_mana_value_min"] = int(match_eldrazi.group("mv"))
        return result
    return "spell_cast_draw_oracle_filter_not_supported"


def spell_cast_draw_filter_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if len(re.findall(r"new\s+SpellCastControllerTriggeredAbility\s*\(", text)) != 1:
        return "spell_cast_draw_source_not_single_trigger"
    if "DoIfCostPaid" in text or "SacrificeSourceCost" in text or "PayLifeCost" in text:
        return "spell_cast_draw_source_optional_cost_not_supported"
    if "AdventurePredicate" in text:
        return "spell_cast_draw_source_filter_not_supported"
    draw_count = java_constructor_int(text, "DrawCardSourceControllerEffect")
    if draw_count is None or draw_count <= 0:
        return "spell_cast_draw_source_count_not_fixed"
    result: dict[str, Any] = {
        "spell_cast_draw_count": draw_count,
        "trigger": "spell_cast",
    }
    if "FILTER_SPELL_A_NON_CREATURE" in text:
        result["trigger"] = "noncreature_spell_cast"
        return result
    if "FILTER_SPELL_A_CREATURE" in text:
        result["spell_cast_draw_card_types"] = ["creature"]
        return result
    if "FILTER_SPELL_AN_ENCHANTMENT" in text:
        result["spell_cast_draw_card_types"] = ["enchantment"]
        return result
    if "FILTER_SPELL_AN_ARTIFACT" in text:
        result["spell_cast_draw_card_types"] = ["artifact"]
        return result
    if "FILTER_SPELL_HISTORIC" in text:
        result["spell_cast_draw_requires_historic"] = True
        return result
    if "FILTER_SPELL_MV_4_OR_GREATER" in text:
        result["spell_cast_draw_mana_value_min"] = 4
        return result
    if "SpellZonePredicate(Zone.GRAVEYARD)" in text:
        result["spell_cast_draw_source_zone"] = "graveyard"
        return result
    subtype_matches = [
        value.lower()
        for value in re.findall(r"SubType\.([A-Z_]+)\.getPredicate\s*\(\s*\)", text)
    ]
    if subtype_matches:
        result["spell_cast_draw_required_subtypes"] = subtype_matches
    if "SuperType.LEGENDARY.getPredicate()" in text:
        result["spell_cast_draw_required_supertypes"] = ["legendary"]
    mv_match = re.search(
        r"ManaValuePredicate\s*\(\s*ComparisonType\.MORE_THAN\s*,\s*(\d+)\s*\)",
        text,
    )
    if mv_match:
        result["spell_cast_draw_mana_value_min"] = int(mv_match.group(1)) + 1
    if "Predicates.or" in text:
        subtype_matches = [
            value.lower()
            for value in re.findall(r"SubType\.([A-Z_]+)\.getPredicate\s*\(\s*\)", text)
        ]
        if subtype_matches:
            result["spell_cast_draw_required_subtypes"] = subtype_matches
    supported_filter = any(
        key in result
        for key in (
            "spell_cast_draw_card_types",
            "spell_cast_draw_required_subtypes",
            "spell_cast_draw_required_supertypes",
            "spell_cast_draw_requires_historic",
            "spell_cast_draw_source_zone",
            "spell_cast_draw_mana_value_min",
        )
    )
    if not supported_filter:
        return "spell_cast_draw_source_filter_not_supported"
    return result


def spell_cast_draw_specs_match(oracle_spec: dict[str, Any], source_spec: dict[str, Any]) -> bool:
    comparable_keys = {
        "trigger",
        "spell_cast_draw_count",
        "spell_cast_draw_card_types",
        "spell_cast_draw_required_subtypes",
        "spell_cast_draw_required_supertypes",
        "spell_cast_draw_requires_historic",
        "spell_cast_draw_source_zone",
        "spell_cast_draw_mana_value_min",
    }
    for key in comparable_keys:
        oracle_value = oracle_spec.get(key)
        source_value = source_spec.get(key)
        if isinstance(oracle_value, list):
            oracle_value = sorted(str(value) for value in oracle_value)
        if isinstance(source_value, list):
            source_value = sorted(str(value) for value in source_value)
        if oracle_value != source_value:
            return False
    return True


def _spell_cast_self_alias_pattern(metadata: dict[str, Any]) -> str:
    normalized_card_name = normalize_name(str(metadata.get("name") or ""))
    aliases = {
        alias
        for alias in {
            normalized_card_name,
            normalize_name(normalized_card_name.split(",", 1)[0]),
        }
        if alias
    }
    return "|".join(re.escape(alias) for alias in sorted(aliases, key=len, reverse=True))


def spell_cast_add_counters_filter_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(
        r"\s+",
        " ",
        oracle_text_after_leading_static_keywords(metadata),
    ).strip().lower()
    self_alias_pattern = _spell_cast_self_alias_pattern(metadata)
    match = re.search(
        r"whenever you cast (?P<filter>.+?), put (?P<count>a|an|one|two|three|four|five|six|seven|eight|nine|ten|\d+) "
        r"(?P<counter>\+1/\+1|-1/-1) counters? on "
        rf"(?P<target>this (?:creature|artifact|permanent)|it|{self_alias_pattern})\.?",
        text,
    )
    if not match:
        return "spell_cast_add_counters_oracle_not_simple"
    count = counter_count_from_text(match.group("count"))
    if count is None or count <= 0:
        return "spell_cast_add_counters_oracle_count_not_supported"
    filter_text = re.sub(r"\s+", " ", match.group("filter").strip())
    result: dict[str, Any] = {
        "spell_cast_add_counters_count": count,
        "spell_cast_add_counters_counter_type": match.group("counter"),
        "counter_count": count,
        "counter_type": match.group("counter"),
        "trigger": "spell_cast",
    }
    simple_filter_text = re.sub(r"\s+spell$", "", filter_text)
    filter_specs: list[tuple[str, dict[str, Any]]] = [
        ("an enchantment", {"spell_cast_add_counters_card_types": ["enchantment"]}),
        ("an artifact", {"spell_cast_add_counters_card_types": ["artifact"]}),
        ("a noncreature", {"trigger": "noncreature_spell_cast"}),
        ("an instant or sorcery", {"spell_cast_add_counters_card_types": ["instant", "sorcery"]}),
        ("a multicolored", {"spell_cast_add_counters_requires_multicolored": True}),
    ]
    for prefix, spec in filter_specs:
        if simple_filter_text == prefix:
            result.update(spec)
            return result
    match_mv = re.fullmatch(r"a spell with mana value (?P<mv>\d+) or greater", filter_text)
    if match_mv:
        result["spell_cast_add_counters_mana_value_min"] = int(match_mv.group("mv"))
        return result
    match_creature_mv = re.fullmatch(
        r"a creature spell with mana value (?P<mv>\d+) or greater",
        filter_text,
    )
    if match_creature_mv:
        result["spell_cast_add_counters_card_types"] = ["creature"]
        result["spell_cast_add_counters_mana_value_min"] = int(match_creature_mv.group("mv"))
        return result
    color_filter_text = re.sub(
        r"^(?:a|an)\s+spell\s+that(?:'s| is)\s+",
        "",
        simple_filter_text,
    )
    color_filter_text = re.sub(r"^(?:a|an)\s+", "", color_filter_text)
    color_parts = [
        part.strip()
        for part in re.split(r",| or ", color_filter_text)
        if part.strip()
    ]
    color_symbols = [TOKEN_COLOR_WORDS.get(part) for part in color_parts]
    if color_parts and all(color_symbols):
        result["spell_cast_add_counters_required_colors"] = color_symbols
        return result
    return "spell_cast_add_counters_oracle_filter_not_supported"


def spell_cast_add_counters_filter_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if len(re.findall(r"new\s+SpellCastControllerTriggeredAbility\s*\(", text)) != 1:
        return "spell_cast_add_counters_source_not_single_trigger"
    if "AdventurePredicate" in text:
        return "spell_cast_add_counters_source_filter_not_supported"
    if "withTriggerCondition" in text or "OpponentsTurnCondition" in text:
        return "spell_cast_add_counters_source_condition_not_supported"
    counter = fixed_counter_source_from_source(text)
    if counter is None:
        return "spell_cast_add_counters_source_counter_not_fixed"
    counter_type, count = counter
    result: dict[str, Any] = {
        "spell_cast_add_counters_count": count,
        "spell_cast_add_counters_counter_type": counter_type,
        "counter_count": count,
        "counter_type": counter_type,
        "trigger": "spell_cast",
    }
    if "FILTER_SPELL_A_NON_CREATURE" in text:
        result["trigger"] = "noncreature_spell_cast"
        return result
    if "FILTER_SPELL_AN_ENCHANTMENT" in text:
        result["spell_cast_add_counters_card_types"] = ["enchantment"]
        return result
    if "FILTER_SPELL_AN_ARTIFACT" in text:
        result["spell_cast_add_counters_card_types"] = ["artifact"]
        return result
    if "FILTER_SPELL_AN_INSTANT_OR_SORCERY" in text or "FilterInstantOrSorcerySpell" in text:
        result["spell_cast_add_counters_card_types"] = ["instant", "sorcery"]
        return result
    if "FILTER_SPELL_A_MULTICOLORED" in text:
        result["spell_cast_add_counters_requires_multicolored"] = True
        return result
    if "FILTER_SPELL_MV_4_OR_GREATER" in text:
        result["spell_cast_add_counters_mana_value_min"] = 4
        return result
    if "CardType.CREATURE.getPredicate()" in text:
        result["spell_cast_add_counters_card_types"] = ["creature"]
    color_symbols = [
        TOKEN_COLOR_WORDS.get(match.lower())
        for match in re.findall(r"ObjectColor\.(WHITE|BLUE|BLACK|RED|GREEN)\b", text)
    ]
    if color_symbols:
        result["spell_cast_add_counters_required_colors"] = color_symbols
    mv_match = re.search(
        r"ManaValuePredicate\s*\(\s*ComparisonType\.MORE_THAN\s*,\s*(\d+)\s*\)",
        text,
    )
    if mv_match:
        result["spell_cast_add_counters_mana_value_min"] = int(mv_match.group(1)) + 1
    supported_filter = any(
        key in result
        for key in (
            "spell_cast_add_counters_card_types",
            "spell_cast_add_counters_required_colors",
            "spell_cast_add_counters_requires_multicolored",
            "spell_cast_add_counters_mana_value_min",
        )
    )
    if not supported_filter:
        return "spell_cast_add_counters_source_filter_not_supported"
    return result


def spell_cast_add_counters_specs_match(
    oracle_spec: dict[str, Any],
    source_spec: dict[str, Any],
) -> bool:
    comparable_keys = {
        "trigger",
        "spell_cast_add_counters_count",
        "spell_cast_add_counters_counter_type",
        "spell_cast_add_counters_card_types",
        "spell_cast_add_counters_required_colors",
        "spell_cast_add_counters_requires_multicolored",
        "spell_cast_add_counters_mana_value_min",
    }
    for key in comparable_keys:
        oracle_value = oracle_spec.get(key)
        source_value = source_spec.get(key)
        if isinstance(oracle_value, list):
            oracle_value = sorted(str(value) for value in oracle_value)
        if isinstance(source_value, list):
            source_value = sorted(str(value) for value in source_value)
        if oracle_value != source_value:
            return False
    return True


def spell_cast_gain_life_filter_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip().lower()
    match = re.search(
        r"whenever you cast (?P<filter>.+?), you (?P<may>may )?gain "
        r"(?P<count>a|an|one|two|three|four|five|six|seven|eight|nine|ten|\d+) life\.?",
        text,
    )
    if not match:
        return "spell_cast_gain_life_oracle_not_simple"
    amount = counter_count_from_text(match.group("count"))
    if amount is None or amount <= 0:
        return "spell_cast_gain_life_oracle_amount_not_supported"
    filter_text = re.sub(r"\s+", " ", match.group("filter").strip())
    simple_filter_text = re.sub(r"\s+spell$", "", filter_text)
    result: dict[str, Any] = {
        "spell_cast_gain_life_amount": amount,
        "spell_cast_gain_life_optional": bool(match.group("may")),
        "trigger": "spell_cast",
    }
    filter_specs: list[tuple[str, dict[str, Any]]] = [
        ("a", {}),
        ("an enchantment", {"spell_cast_gain_life_card_types": ["enchantment"]}),
        ("a noncreature", {"trigger": "noncreature_spell_cast"}),
    ]
    for prefix, spec in filter_specs:
        if simple_filter_text == prefix:
            result.update(spec)
            return result
    color_filter_text = re.sub(
        r"^(?:a|an)\s+spell\s+that(?:'s| is)\s+",
        "",
        simple_filter_text,
    )
    color_filter_text = re.sub(r"^(?:a|an)\s+", "", color_filter_text)
    color_parts = [
        part.strip()
        for part in re.split(r",| or ", color_filter_text)
        if part.strip()
    ]
    color_symbols = [TOKEN_COLOR_WORDS.get(part) for part in color_parts]
    if color_parts and all(color_symbols):
        result["spell_cast_gain_life_required_colors"] = color_symbols
        return result
    return "spell_cast_gain_life_oracle_filter_not_supported"


def spell_cast_gain_life_filter_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    if len(re.findall(r"new\s+SpellCastControllerTriggeredAbility\s*\(", text)) != 1:
        return "spell_cast_gain_life_source_not_single_trigger"
    if "DoIfCostPaid" in text or "SacrificeSourceCost" in text or "PayLifeCost" in text:
        return "spell_cast_gain_life_source_optional_cost_not_supported"
    if "SpellCastAllTriggeredAbility" in text or "OrTriggeredAbility" in text:
        return "spell_cast_gain_life_source_trigger_not_supported"
    amount = java_constructor_int(text, "GainLifeEffect")
    if amount is None or amount <= 0:
        return "spell_cast_gain_life_source_amount_not_fixed"
    result: dict[str, Any] = {
        "spell_cast_gain_life_amount": amount,
        "trigger": "spell_cast",
    }
    if "FILTER_SPELL_A_NON_CREATURE" in text:
        result["trigger"] = "noncreature_spell_cast"
        return result
    if "FILTER_SPELL_AN_ENCHANTMENT" in text:
        result["spell_cast_gain_life_card_types"] = ["enchantment"]
        return result
    color_symbols = [
        TOKEN_COLOR_WORDS.get(match.lower())
        for match in re.findall(r"ObjectColor\.(WHITE|BLUE|BLACK|RED|GREEN)\b", text)
    ]
    if color_symbols:
        result["spell_cast_gain_life_required_colors"] = color_symbols
        return result
    if re.search(r"SpellCastControllerTriggeredAbility\s*\(\s*new\s+GainLifeEffect\s*\(\s*\d+\s*\)\s*,\s*false\s*\)", text):
        return result
    return "spell_cast_gain_life_source_filter_not_supported"


def spell_cast_gain_life_specs_match(
    oracle_spec: dict[str, Any],
    source_spec: dict[str, Any],
) -> bool:
    comparable_keys = {
        "trigger",
        "spell_cast_gain_life_amount",
        "spell_cast_gain_life_card_types",
        "spell_cast_gain_life_required_colors",
    }
    for key in comparable_keys:
        oracle_value = oracle_spec.get(key)
        source_value = source_spec.get(key)
        if isinstance(oracle_value, list):
            oracle_value = sorted(str(value) for value in oracle_value)
        if isinstance(source_value, list):
            source_value = sorted(str(value) for value in source_value)
        if oracle_value != source_value:
            return False
    return True


def activated_recursion_to_hand_target_from_source(text: str) -> tuple[str, int, bool] | str:
    lowered = str(text or "").lower()
    if "arcane card" in lowered or "SubType.ARCANE.getPredicate()" in text:
        target = "arcane_card"
    elif "basic land card" in lowered or "FILTER_CARD_BASIC_LAND" in text:
        target = "basic_land"
    elif "instant or sorcery card" in lowered or "FilterInstantOrSorceryCard" in text:
        target = "instant_or_sorcery"
    elif (
        "artifact or enchantment card" in lowered
        or "FILTER_CARD_ARTIFACT_OR_ENCHANTMENT" in text
    ):
        target = "artifact_or_enchantment"
    elif "artifact creature card" in lowered:
        target = "artifact_creature"
    elif "creature card" in lowered or "FILTER_CARD_CREATURE_YOUR_GRAVEYARD" in text or "FILTER_CARD_CREATURES_YOUR_GRAVEYARD" in text:
        target = "creature"
    elif "artifact card" in lowered or "FILTER_CARD_ARTIFACT_FROM_YOUR_GRAVEYARD" in text:
        target = "artifact"
    elif "enchantment card" in lowered or "FilterEnchantmentCard" in text:
        target = "enchantment"
    elif "permanent card" in lowered or "FilterPermanentCard" in text:
        target = "permanent"
    else:
        return "activated_recursion_source_target_not_supported"

    count = 1
    up_to = False
    count_match = re.search(r"TargetCardInYourGraveyard\s*\(\s*0\s*,\s*(\d+)\s*,", text, re.S)
    if count_match:
        count = int(count_match.group(1))
        up_to = True
    return target, count, up_to


def activated_recursion_to_hand_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    risky_cost_classes = {
        "CompositeCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "MillCardsCost",
        "OrCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "RevealTargetFromHandCost",
        "TapTargetCost",
    }
    if "Zone.GRAVEYARD" in text:
        return "activated_recursion_source_not_battlefield"
    present_risky = sorted(cost for cost in risky_cost_classes if cost in text)
    if present_risky:
        return "activated_recursion_source_cost_not_supported"
    if len(re.findall(r"TargetCardInYourGraveyard\s*\(", text)) != 1:
        return "activated_recursion_source_target_not_supported"
    if "EachTargetPointer" in text:
        return "activated_recursion_source_target_not_supported"
    if "put there from the battlefield this turn" in text.lower() or "that was put there" in text.lower():
        return "activated_recursion_source_target_not_supported"
    effect_matches = re.findall(r"ReturnFromGraveyardToHandTargetEffect\s*\(", text)
    if len(effect_matches) != 1:
        return "activated_recursion_source_count_not_fixed"
    effect_index = text.find("ReturnFromGraveyardToHandTargetEffect")
    window = text[max(0, effect_index - 500) : effect_index + 1800]
    ability_match = re.search(r"\b(SimpleActivatedAbility|ActivateAsSorceryActivatedAbility)\b", window)
    if not ability_match:
        return "activated_recursion_source_not_simple_activated"
    activation_timing = "sorcery" if ability_match.group(1) == "ActivateAsSorceryActivatedAbility" else None
    parsed_target = activated_recursion_to_hand_target_from_source(text)
    if isinstance(parsed_target, str):
        return parsed_target
    target, count, up_to = parsed_target
    discard_count = 0
    discard_target = None
    discard_matches = re.findall(r"new\s+DiscardCardCost\s*\(([^)]*)\)", window, re.S)
    if discard_matches:
        if len(discard_matches) != 1:
            return "activated_recursion_source_cost_not_supported"
        discard_arg = re.sub(r"\s+", " ", discard_matches[0]).strip()
        discard_count = 1
        if not discard_arg:
            discard_target = "any_card"
        elif "FILTER_CARD_CREATURE_A" in discard_arg:
            discard_target = "creature_card"
        else:
            return "activated_recursion_source_cost_not_supported"
    cost_text = "{0}"
    mana_match = re.search(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_match = re.search(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    if mana_match:
        cost_text = mana_match.group(1)
    elif generic_match:
        cost_text = "{" + generic_match.group(1) + "}"
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_recursion_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    requires_tap = "TapSourceCost" in window
    requires_sacrifice = "SacrificeSourceCost" in window
    life_cost = None
    life_matches = re.findall(r"PayLifeCost\s*\(\s*(\d+)\s*\)", window)
    if len(life_matches) > 1:
        return "activated_recursion_source_cost_not_supported"
    if life_matches:
        life_cost = int(life_matches[0])
    sacrifice_target = None
    if "SacrificeTargetCost" in window:
        if re.search(r"new\s+SacrificeTargetCost\s*\(\s*\d+\s*,", window):
            return "activated_recursion_source_cost_not_supported"
        sacrifice_cost_constructors = re.findall(r"new\s+SacrificeTargetCost\s*\(", window)
        if len(sacrifice_cost_constructors) > 1:
            return "activated_recursion_source_cost_not_supported"
        sacrifice_target = activation_sacrifice_target_from_source(text, window)
        if sacrifice_target is None:
            return "activated_recursion_source_cost_not_supported"
    if requires_sacrifice and sacrifice_target:
        return "activated_recursion_source_cost_not_supported"
    result = {
        "target": target,
        "count": count,
        "up_to": up_to,
        "xmage_ability_class": ability_match.group(1),
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": requires_tap,
        "activation_requires_sacrifice": requires_sacrifice,
        "activation_discard_count": discard_count,
        "activation_discard_target": discard_target,
        **({"activation_life_cost": life_cost} if life_cost else {}),
        **(
            {
                "activation_sacrifice_target": sacrifice_target,
                "activation_requires_sacrifice_target": True,
            }
            if sacrifice_target
            else {}
        ),
    }
    if activation_timing:
        result["activation_timing"] = activation_timing
    return result


def activated_recursion_to_battlefield_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text(metadata)).strip().lower()
    if text.count(":") != 1:
        return "activated_recursion_battlefield_oracle_not_simple"
    cost_text, effect_text = [part.strip() for part in text.split(":", 1)]
    effect_text = re.split(r"\s+partner[—-]", effect_text, maxsplit=1)[0].strip()
    activation_timing = None
    timing_suffix = re.search(
        r"\s*activate (?:only )?as a sorcery\.?$",
        effect_text,
    )
    if timing_suffix:
        activation_timing = "sorcery"
        effect_text = effect_text[: timing_suffix.start()].strip()
        if not effect_text.endswith("."):
            effect_text += "."
    normalized_cost = cost_text
    life_cost = 0
    life_pattern = r"(?:^|,\s*)pay (?P<life>\d+) life(?:\s*,?|$)"
    life_matches = list(re.finditer(life_pattern, normalized_cost))
    if len(life_matches) > 1:
        return "activated_recursion_battlefield_oracle_cost_not_supported"
    if life_matches:
        life_cost = int(life_matches[0].group("life"))
        normalized_cost = re.sub(life_pattern, ",", normalized_cost).strip(" ,")

    sacrifice_target = None
    sacrifice_pattern = (
        r"(?:^|,\s*)sacrifice (?P<phrase>"
        r"(?:an?|another) (?:artifact or creature|artifact or land|creature or land|"
        r"nontoken permanent|non-token permanent|token|creature|artifact|enchantment|land|swamp|permanent)"
        r")(?:\s*,?|$)"
    )
    sacrifice_matches = list(re.finditer(sacrifice_pattern, normalized_cost))
    if len(sacrifice_matches) > 1:
        return "activated_recursion_battlefield_oracle_cost_not_supported"
    if sacrifice_matches:
        sacrifice_target = activation_sacrifice_target_from_phrase(sacrifice_matches[0].group("phrase"))
        if sacrifice_target is None:
            return "activated_recursion_battlefield_oracle_cost_not_supported"
        normalized_cost = re.sub(sacrifice_pattern, ",", normalized_cost).strip(" ,")

    activation = activation_cost_from_oracle_prefix(normalized_cost, allow_source_sacrifice=True)
    if isinstance(activation, str):
        return str(activation).replace("activated_self_boost", "activated_recursion_battlefield")
    if activation.get("activation_requires_sacrifice") and sacrifice_target:
        return "activated_recursion_battlefield_oracle_cost_not_supported"
    target = recursion_to_battlefield_from_oracle({**metadata, "oracle_text": effect_text})
    if target is None:
        return "activated_recursion_battlefield_target_not_supported"
    result = {**target, **activation}
    if activation_timing:
        result["activation_timing"] = activation_timing
    if life_cost:
        result["activation_life_cost"] = life_cost
    if sacrifice_target:
        result["activation_sacrifice_target"] = sacrifice_target
        result["activation_requires_sacrifice_target"] = True
    return result


def activated_recursion_to_battlefield_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    risky_cost_classes = {
        "CompositeCost",
        "DiscardCardCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "MillCardsCost",
        "OrCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "RevealTargetFromHandCost",
        "TapTargetCost",
        "UntapSourceCost",
    }
    if "Zone.GRAVEYARD" in text:
        return "activated_recursion_battlefield_source_not_battlefield"
    present_risky = sorted(cost for cost in risky_cost_classes if cost in text)
    if present_risky:
        return "activated_recursion_battlefield_source_cost_not_supported"
    if len(re.findall(r"TargetCardInYourGraveyard\s*\(", text)) != 1:
        return "activated_recursion_battlefield_source_target_not_supported"
    if "EachTargetPointer" in text:
        return "activated_recursion_battlefield_source_target_not_supported"
    effect_matches = re.findall(r"ReturnFromGraveyardToBattlefieldTargetEffect\s*\(", text)
    if len(effect_matches) != 1:
        return "activated_recursion_battlefield_source_count_not_fixed"
    effect_index = text.find("ReturnFromGraveyardToBattlefieldTargetEffect")
    window = text[max(0, effect_index - 500) : effect_index + 1800]
    ability_match = re.search(r"\b(SimpleActivatedAbility|ActivateAsSorceryActivatedAbility)\b", window)
    if not ability_match:
        return "activated_recursion_battlefield_source_not_simple_activated"
    activation_timing = "sorcery" if ability_match.group(1) == "ActivateAsSorceryActivatedAbility" else None

    if "FilterPermanentCard" in text and "SubType.REBEL.getPredicate" in text:
        target = "rebel_permanent"
    elif "FILTER_CARD_CREATURE" in text or "FilterCreatureCard" in text or "creature card" in text.lower():
        target = "creature"
    elif "FILTER_CARD_ARTIFACT_FROM_YOUR_GRAVEYARD" in text or "FilterArtifactCard" in text or "artifact card" in text.lower():
        target = "artifact"
    elif "FilterEnchantmentCard" in text or "enchantment card" in text.lower():
        target = "enchantment"
    elif "FilterPermanentCard" in text or "permanent card" in text.lower():
        target = "permanent"
    else:
        return "activated_recursion_battlefield_source_target_not_supported"

    mana_matches = re.findall(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_matches = re.findall(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    colored_matches = re.findall(r"ColoredManaCost\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)", window)
    cost_kinds = sum(1 for matches in (mana_matches, generic_matches, colored_matches) if matches)
    if cost_kinds > 1:
        return "activated_recursion_battlefield_source_cost_not_supported"
    if len(mana_matches) > 1 or len(generic_matches) > 1 or len(colored_matches) > 1:
        return "activated_recursion_battlefield_source_cost_not_supported"
    if mana_matches:
        cost_text = mana_matches[0]
    elif generic_matches:
        cost_text = "{" + generic_matches[0] + "}"
    elif colored_matches:
        cost_text = "{" + colored_matches[0] + "}"
    else:
        cost_text = "{0}"
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_recursion_battlefield_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    requires_tap = "TapSourceCost" in window
    requires_sacrifice = "SacrificeSourceCost" in window
    life_cost = None
    life_matches = re.findall(r"PayLifeCost\s*\(\s*(\d+)\s*\)", window)
    if len(life_matches) > 1:
        return "activated_recursion_battlefield_source_cost_not_supported"
    if life_matches:
        life_cost = int(life_matches[0])
    sacrifice_target = None
    if "SacrificeTargetCost" in window:
        if re.search(r"new\s+SacrificeTargetCost\s*\(\s*\d+\s*,", window):
            return "activated_recursion_battlefield_source_cost_not_supported"
        sacrifice_cost_constructors = re.findall(r"new\s+SacrificeTargetCost\s*\(", window)
        if len(sacrifice_cost_constructors) > 1:
            return "activated_recursion_battlefield_source_cost_not_supported"
        sacrifice_target = activation_sacrifice_target_from_source(text, window)
        if sacrifice_target is None:
            return "activated_recursion_battlefield_source_cost_not_supported"
    if requires_sacrifice and sacrifice_target:
        return "activated_recursion_battlefield_source_cost_not_supported"
    result = {
        "target": target,
        "count": 1,
        "target_graveyard_controller": "self",
        "battlefield_controller": "self",
        "enters_tapped": bool(
            re.search(r"ReturnFromGraveyardToBattlefieldTargetEffect\s*\(\s*true\b", text)
        ),
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": requires_tap,
        "activation_requires_sacrifice": requires_sacrifice,
    }
    if activation_timing:
        result["activation_timing"] = activation_timing
    if life_cost:
        result["activation_life_cost"] = life_cost
    if sacrifice_target:
        result["activation_sacrifice_target"] = sacrifice_target
        result["activation_requires_sacrifice_target"] = True
    if "PutIntoGraveFromBattlefieldThisTurnPredicate" in text:
        result["graveyard_from_battlefield_this_turn"] = True
    mana_value_match = re.search(
        r"ManaValuePredicate\s*\(\s*ComparisonType\.FEWER_THAN\s*,\s*(\d+)\s*\)",
        text,
    )
    if mana_value_match:
        result["mana_value_max"] = int(mana_value_match.group(1)) - 1
    return result


def activated_graveyard_exile_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text(metadata)).strip().lower()
    if text.count(":") != 1:
        return "activated_graveyard_exile_oracle_not_simple"
    effect_text = text.rsplit(":", 1)[1].strip()
    patterns: list[tuple[str, str, bool, bool]] = [
        (r"^exile target card from a graveyard\.?$", "any_card", False, False),
        (r"^exile target creature card from a graveyard\.?$", "creature", False, False),
        (
            r"^exile up to (one|two|three|\d+) target cards from a single graveyard\.?$",
            "any_card",
            True,
            True,
        ),
        (
            r"^exile up to (one|two|three|\d+) target creature cards from a single graveyard\.?$",
            "creature",
            True,
            True,
        ),
    ]
    words = {"one": 1, "two": 2, "three": 3}
    for pattern, target, up_to, single_graveyard in patterns:
        match = re.match(pattern, effect_text)
        if not match:
            continue
        count = 1
        if match.groups():
            value = match.group(1)
            count = words.get(value, int(value) if value.isdigit() else 0)
        if count <= 0:
            return "activated_graveyard_exile_oracle_count_not_supported"
        return {
            "target": target,
            "count": count,
            "up_to": up_to,
            "single_graveyard": single_graveyard,
        }
    return "activated_graveyard_exile_oracle_not_simple"


def activated_graveyard_exile_target_from_source(text: str) -> dict[str, Any] | str:
    target_card_count = len(re.findall(r"\bTargetCardInGraveyard\s*\(", text))
    target_single_count = len(re.findall(r"\bTargetCardInASingleGraveyard\s*\(", text))
    if target_card_count + target_single_count != 1:
        return "activated_graveyard_exile_source_target_not_supported"
    if target_card_count:
        target = (
            "creature"
            if (
                "FILTER_CARD_CREATURE_A_GRAVEYARD" in text
                or "FilterCreatureCard" in text
            )
            else "any_card"
        )
        return {
            "target": target,
            "count": 1,
            "up_to": False,
            "single_graveyard": False,
        }
    match = re.search(r"TargetCardInASingleGraveyard\s*\(\s*0\s*,\s*(\d+)\s*,", text, re.S)
    if not match:
        return "activated_graveyard_exile_source_target_not_supported"
    target = (
        "creature"
        if (
            "FILTER_CARD_CREATURE_A_GRAVEYARD" in text
            or "FilterCreatureCard" in text
        )
        else "any_card"
    )
    return {
        "target": target,
        "count": int(match.group(1)),
        "up_to": True,
        "single_graveyard": True,
    }


def activated_graveyard_exile_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    risky_cost_classes = {
        "CompositeCost",
        "DiscardCardCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileSourceFromGraveCost",
        "MillCardsCost",
        "OrCost",
        "PayLifeCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "RevealTargetFromHandCost",
        "RevealVariableBlackCardsFromHandCost",
        "SacrificeTargetCost",
        "TapTargetCost",
        "VariableCost",
        "XTargetsCountAdjuster",
    }
    if "Zone.GRAVEYARD" in text:
        return "activated_graveyard_exile_source_not_battlefield"
    present_risky = sorted(cost for cost in risky_cost_classes if cost in text)
    if present_risky:
        return "activated_graveyard_exile_source_cost_not_supported"
    effect_matches = re.findall(r"ExileTargetEffect\s*\(", text)
    if len(effect_matches) != 1:
        return "activated_graveyard_exile_source_multiple_abilities_not_supported"
    effect_index = text.find("ExileTargetEffect")
    window = text[max(0, effect_index - 500) : effect_index + 1800]
    if "SimpleActivatedAbility" not in window:
        return "activated_graveyard_exile_source_not_simple_activated"
    parsed_target = activated_graveyard_exile_target_from_source(text)
    if isinstance(parsed_target, str):
        return parsed_target
    cost_text = "{0}"
    mana_match = re.search(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_matches = re.findall(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    if mana_match:
        cost_text = mana_match.group(1)
    elif generic_matches:
        cost_text = "{" + str(sum(int(value) for value in generic_matches)) + "}"
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_graveyard_exile_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    return {
        **parsed_target,
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": "TapSourceCost" in window,
        "activation_requires_sacrifice": "SacrificeSourceCost" in window,
    }


def graveyard_exile_target_constraints_for(target: str, *, controller: str = "any") -> dict[str, Any]:
    constraints: dict[str, Any] = {"zone": "graveyard", "controller": controller}
    if target == "creature":
        constraints["card_types"] = ["creature"]
    elif target in {"any_card", "card"}:
        constraints["card_types"] = ["card"]
    else:
        constraints["target"] = target
    return constraints


def life_gain_amount_from_oracle(metadata: dict[str, Any]) -> int | None:
    match = re.match(r"^you gain (\d+) life\.?$", oracle_text(metadata))
    if not match:
        return None
    return int(match.group(1))


def _dynamic_life_gain_dict(
    amount_source: str,
    *,
    base: int = 0,
    per: int = 1,
    **count_fields: Any,
) -> dict[str, Any]:
    return {
        "life_gain_amount_source": amount_source,
        "life_gain_base_amount": int(base),
        "life_gain_per_count": int(per),
        **count_fields,
    }


def _life_gain_count_fields_from_filter(filter_text: str) -> dict[str, Any] | str | None:
    token = re.sub(r"\s+", " ", str(filter_text or "").strip().lower())
    if token in {"card in your graveyard", "cards in your graveyard"}:
        return {
            "life_gain_amount_source": "graveyard_card_count",
            "graveyard_count_scope": "controller_graveyard",
            "graveyard_count_card_types": ["card"],
        }
    if token in {"creature card in your graveyard", "creature cards in your graveyard"}:
        return {
            "life_gain_amount_source": "graveyard_card_count",
            "graveyard_count_scope": "controller_graveyard",
            "graveyard_count_card_types": ["creature"],
        }
    if token == "creature attacking you":
        return {
            "life_gain_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "opponents_battlefield",
            "battlefield_count_card_types": ["creature"],
            "battlefield_count_combat_state": "attacking",
        }
    if token in {"land you control", "lands you control"}:
        return {
            "life_gain_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["land"],
        }
    if token in {"creature you control", "creatures you control"}:
        return {
            "life_gain_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["creature"],
        }
    if token in {"other creature you control", "other creatures you control"}:
        return {
            "life_gain_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["creature"],
            "battlefield_count_exclude_source": True,
        }
    if token in {"creature you control with flying", "creatures you control with flying"}:
        return {
            "life_gain_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["creature"],
            "battlefield_count_keywords": ["flying"],
        }
    if token in {"gate you control", "gates you control"}:
        return {
            "life_gain_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["permanent"],
            "battlefield_count_subtypes": ["gate"],
        }
    if token in {"creature in your party", "creatures in your party"}:
        return {"life_gain_amount_source": "party_count"}
    if token == "colors among permanents you control":
        return {"life_gain_amount_source": "colors_among_permanents_you_control"}
    if token == "your devotion to green":
        return {
            "life_gain_amount_source": "controlled_permanents_mana_symbol_count",
            "mana_symbol_count_color": "G",
        }
    if token == "greatest toughness among other creatures you control":
        return {"life_gain_amount_source": "greatest_toughness_among_other_controlled_creatures"}
    if token in {"forest on the battlefield", "forests on the battlefield"}:
        return {
            "life_gain_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "all_battlefields",
            "battlefield_count_card_types": ["land"],
            "battlefield_count_subtypes": ["forest"],
        }
    if token in {"plains you control", "plains land you control"}:
        return {
            "life_gain_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["land"],
            "battlefield_count_subtypes": ["plains"],
        }
    if token in {"card in your hand", "cards in your hand"}:
        return {"life_gain_amount_source": "controller_hand_count"}
    if token == "creature cards in all graveyards":
        return {
            "life_gain_amount_source": "graveyard_card_count",
            "graveyard_count_scope": "all_graveyards",
            "graveyard_count_card_types": ["creature"],
        }
    if token == "tapped artifact, creature, and land you control":
        return {
            "life_gain_amount_source": "battlefield_permanent_count",
            "battlefield_count_scope": "controller_battlefield",
            "battlefield_count_card_types": ["artifact", "creature", "land"],
            "battlefield_count_tapped_state": "tapped",
        }
    if token == "basic land type among lands you control":
        return {"life_gain_amount_source": "domain_basic_land_types"}
    if "target opponent controls" in token:
        return "dynamic_life_gain_target_opponent_count_not_supported"
    if "that creature's power plus its toughness" in token:
        return "dynamic_life_gain_target_power_toughness_not_supported"
    return None


def dynamic_life_gain_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    normalized = re.sub(r"\s+", " ", text).strip().lower()
    if "colors of mana spent to cast this spell" in normalized:
        return "dynamic_life_gain_mana_spent_colors_not_supported"
    if "damage dealt to you so far this turn" in normalized:
        return "dynamic_life_gain_damage_dealt_to_you_not_supported"
    if re.match(r"^you gain x plus \d+ life\.?$", normalized):
        return "dynamic_life_gain_x_value_not_supported"
    if "target opponent controls" in normalized:
        return "dynamic_life_gain_target_opponent_count_not_supported"
    if "that creature's power plus its toughness" in normalized:
        return "dynamic_life_gain_target_power_toughness_not_supported"

    each_match = re.match(
        r"^(?:domain — )?you gain (?P<per>\d+) life for each (?P<filter>.+?)\.?$",
        normalized,
    )
    if each_match:
        count_fields = _life_gain_count_fields_from_filter(each_match.group("filter"))
        if isinstance(count_fields, str):
            return count_fields
        if count_fields is None:
            return "dynamic_life_gain_oracle_filter_not_supported"
        amount_source = str(count_fields.pop("life_gain_amount_source"))
        return _dynamic_life_gain_dict(
            amount_source,
            per=int(each_match.group("per")),
            **count_fields,
        )

    equal_match = re.match(
        r"^you gain life equal to the number of (?P<filter>.+?)\.?$",
        normalized,
    )
    if equal_match:
        count_fields = _life_gain_count_fields_from_filter(equal_match.group("filter"))
        if isinstance(count_fields, str):
            return count_fields
        if count_fields is None:
            return "dynamic_life_gain_oracle_filter_not_supported"
        amount_source = str(count_fields.pop("life_gain_amount_source"))
        return _dynamic_life_gain_dict(amount_source, **count_fields)

    devotion_match = re.match(r"^you gain life equal to (?P<filter>your devotion to green)\.?$", normalized)
    if devotion_match:
        count_fields = _life_gain_count_fields_from_filter(devotion_match.group("filter"))
        if isinstance(count_fields, str):
            return count_fields
        if count_fields is None:
            return "dynamic_life_gain_oracle_filter_not_supported"
        amount_source = str(count_fields.pop("life_gain_amount_source"))
        return _dynamic_life_gain_dict(amount_source, **count_fields)

    greatest_match = re.match(
        r"^you gain life equal to the (?P<filter>greatest toughness among other creatures you control)\.?$",
        normalized,
    )
    if greatest_match:
        count_fields = _life_gain_count_fields_from_filter(greatest_match.group("filter"))
        if isinstance(count_fields, str):
            return count_fields
        if count_fields is None:
            return "dynamic_life_gain_oracle_filter_not_supported"
        amount_source = str(count_fields.pop("life_gain_amount_source"))
        return _dynamic_life_gain_dict(amount_source, **count_fields)

    return None


def etb_dynamic_life_gain_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str | None:
    text = strip_parenthetical_reminders(oracle_text_after_leading_static_keywords(metadata))
    normalized = re.sub(r"\s+", " ", text).strip().lower()
    match = re.search(
        r"(?:^|[. ]+)(?:undergrowth — |vivid — )?(?:when|whenever) "
        r"(?:this creature|[^.]+?) enters(?: the battlefield)?[, ]+"
        r"(?P<body>you gain .+?)\.?$",
        normalized,
    )
    if not match:
        return None
    return dynamic_life_gain_from_oracle({"oracle_text": match.group("body")})


def _dynamic_life_gain_source_spec_from_expr(source: str, expr: str) -> dict[str, Any] | str | None:
    text = source or ""
    token = re.sub(r"\s+", " ", str(expr or "")).strip()
    parts = split_top_level_args(token)
    if len(parts) > 1 and any(part.strip().startswith('"') for part in parts[1:]):
        token = parts[0].strip()
    multiplied_args = extract_constructor_args(token, "MultipliedValue")
    if multiplied_args is None and token in {"amount", "xValue"}:
        multiplied_args = extract_constructor_args(text, "MultipliedValue")
    if multiplied_args is not None:
        multiplied_parts = split_top_level_args(multiplied_args)
        if len(multiplied_parts) < 2 or not multiplied_parts[1].strip().isdigit():
            return "dynamic_life_gain_multiplier_not_supported"
        nested = _dynamic_life_gain_source_spec_from_expr(text, multiplied_parts[0])
        if isinstance(nested, str) or nested is None:
            return nested
        return {
            **nested,
            "life_gain_per_count": int(nested.get("life_gain_per_count") or 1)
            * int(multiplied_parts[1].strip()),
        }
    if "GetXValue" in token or "IntPlusDynamicValue" in token:
        return "dynamic_life_gain_x_value_not_supported"
    if "ColorsOfManaSpentToCastCount" in token or (
        token in {"amount", "xValue"} and "ColorsOfManaSpentToCastCount" in text
    ):
        return "dynamic_life_gain_mana_spent_colors_not_supported"
    if "ReversePolarityAmount" in token or (
        token in {"amount", "xValue"} and "ReversePolarityAmount" in text
    ):
        return "dynamic_life_gain_damage_dealt_to_you_not_supported"
    if "TargetPermanentPowerPlusToughnessCount" in token or (
        token in {"amount", "xValue"} and "TargetPermanentPowerPlusToughnessCount" in text
    ):
        return "dynamic_life_gain_target_power_toughness_not_supported"
    if "PermanentsTargetOpponentControlsCount" in token or (
        token in {"amount", "xValue"} and "PermanentsTargetOpponentControlsCount" in text
    ):
        return "dynamic_life_gain_target_opponent_count_not_supported"

    search_text = text if token in {"amount", "xValue"} else token
    if "CreaturesAttackingYouCount.instance" in search_text:
        return _dynamic_life_gain_dict(
            "battlefield_permanent_count",
            battlefield_count_scope="opponents_battlefield",
            battlefield_count_card_types=["creature"],
            battlefield_count_combat_state="attacking",
        )
    if "CardsInAllGraveyardsCount" in search_text and "FILTER_CARD_CREATURE" in text:
        return _dynamic_life_gain_dict(
            "graveyard_card_count",
            graveyard_count_scope="all_graveyards",
            graveyard_count_card_types=["creature"],
        )
    if "CardsInControllerGraveyardCount" in search_text:
        card_types = ["creature"] if "FILTER_CARD_CREATURE" in text else ["card"]
        return _dynamic_life_gain_dict(
            "graveyard_card_count",
            graveyard_count_scope="controller_graveyard",
            graveyard_count_card_types=card_types,
        )
    if "DomainValue.REGULAR" in search_text:
        return _dynamic_life_gain_dict("domain_basic_land_types")
    if "CardsInControllerHandCount.ANY" in search_text:
        return _dynamic_life_gain_dict("controller_hand_count")
    if "CreaturesYouControlCount" in search_text:
        return _dynamic_life_gain_dict(
            "battlefield_permanent_count",
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["creature"],
        )
    if "PartyCount" in search_text:
        return _dynamic_life_gain_dict("party_count")
    if "ColorsAmongControlledPermanentsCount" in search_text:
        return _dynamic_life_gain_dict("colors_among_permanents_you_control")
    if "DevotionCount.G" in search_text:
        return _dynamic_life_gain_dict(
            "controlled_permanents_mana_symbol_count",
            mana_symbol_count_color="G",
        )
    if "GreatestAmongPermanentsValue.TOUGHNESS_OTHER_CONTROLLED_CREATURES" in search_text:
        return _dynamic_life_gain_dict("greatest_toughness_among_other_controlled_creatures")
    if "LandsYouControlCount.instance" in search_text:
        return _dynamic_life_gain_dict(
            "battlefield_permanent_count",
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["land"],
        )
    if "TappedPredicate.TAPPED" in text and "Predicates.or" in text and "PermanentsOnBattlefieldCount" in search_text:
        return _dynamic_life_gain_dict(
            "battlefield_permanent_count",
            battlefield_count_scope="controller_battlefield",
            battlefield_count_card_types=["artifact", "creature", "land"],
            battlefield_count_tapped_state="tapped",
        )
    if "PermanentsOnBattlefieldCount" in search_text:
        per = 1
        count_args = extract_constructor_args(search_text, "PermanentsOnBattlefieldCount") or ""
        count_parts = split_top_level_args(count_args)
        if len(count_parts) >= 2 and count_parts[1].strip().lstrip("-").isdigit():
            per = int(count_parts[1].strip())
        if (
            "FilterControlledCreaturePermanent" in search_text
            or "FILTER_CONTROLLED_CREATURE" in text
            or "FILTER_OTHER_CONTROLLED_CREATURE" in text
        ):
            fields = _dynamic_life_gain_dict(
                "battlefield_permanent_count",
                per=per,
                battlefield_count_scope="controller_battlefield",
                battlefield_count_card_types=["creature"],
            )
            if "FILTER_OTHER_CONTROLLED_CREATURE" in text:
                fields["battlefield_count_exclude_source"] = True
            if "AbilityPredicate(FlyingAbility.class)" in text:
                fields["battlefield_count_keywords"] = ["flying"]
            return fields
        if "SubType.GATE" in text:
            return _dynamic_life_gain_dict(
                "battlefield_permanent_count",
                per=per,
                battlefield_count_scope="controller_battlefield",
                battlefield_count_card_types=["permanent"],
                battlefield_count_subtypes=["gate"],
            )
        if "FilterControlledLandPermanent" in text:
            return _dynamic_life_gain_dict(
                "battlefield_permanent_count",
                per=per,
                battlefield_count_scope="controller_battlefield",
                battlefield_count_card_types=["land"],
            )
        if "SubType.PLAINS" in text and "TargetController.YOU" in text:
            return _dynamic_life_gain_dict(
                "battlefield_permanent_count",
                per=per,
                battlefield_count_scope="controller_battlefield",
                battlefield_count_card_types=["land"],
                battlefield_count_subtypes=["plains"],
            )
        if "SubType.FOREST" in text:
            return _dynamic_life_gain_dict(
                "battlefield_permanent_count",
                per=per,
                battlefield_count_scope="all_battlefields",
                battlefield_count_card_types=["land"],
                battlefield_count_subtypes=["forest"],
            )
    return "dynamic_life_gain_source_filter_not_supported"


def dynamic_life_gain_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    if "getSpellAbility().addCost" in text or "addCost(" in text:
        return "dynamic_life_gain_additional_cost_not_supported"
    if len(re.findall(r"new\s+GainLifeEffect\s*\(", text)) != 1:
        return "dynamic_life_gain_source_not_single"
    constructor_args = extract_constructor_args(text, "GainLifeEffect")
    if constructor_args is None:
        return None
    spec = _dynamic_life_gain_source_spec_from_expr(text, constructor_args)
    if isinstance(spec, str) or spec is None:
        return spec
    return {
        "life_gain_base_amount": int(spec.get("life_gain_base_amount") or 0),
        "life_gain_per_count": int(spec.get("life_gain_per_count") or 1),
        **{
            key: value
            for key, value in spec.items()
            if key not in {"life_gain_base_amount", "life_gain_per_count"}
        },
    }


def fixed_life_gain_draw_from_oracle(metadata: dict[str, Any]) -> tuple[int, int] | None:
    match = re.match(r"^you gain (\d+) life\. draw a card\.?$", oracle_text(metadata))
    if not match:
        return None
    return int(match.group(1)), 1


def fixed_life_gain_draw_from_source(source_text: str) -> tuple[int, int] | None:
    text = str(source_text or "")
    gain_matches = list(re.finditer(r"new\s+GainLifeEffect\s*\(", text))
    if len(gain_matches) != 1:
        return None
    draw_matches = list(re.finditer(r"new\s+DrawCardSourceControllerEffect\s*\(", text))
    if len(draw_matches) != 1:
        return None
    life_gain = java_constructor_int(text, "GainLifeEffect")
    draw_count = java_constructor_int_or_noarg_default(
        text,
        "DrawCardSourceControllerEffect",
        noarg_default=1,
    )
    if life_gain is None or life_gain <= 0 or draw_count != 1:
        return None
    if gain_matches[0].start() > draw_matches[0].start():
        return None
    return life_gain, draw_count


def etb_life_gain_amount_from_oracle(metadata: dict[str, Any]) -> int | None:
    text = re.sub(r"\s+", " ", oracle_text(metadata)).strip()
    match = re.search(
        r"(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+you gain (\d+) life(?:\.|$)",
        text,
    )
    if not match:
        return None
    return int(match.group(1))


def creature_enters_life_gain_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip().lower()
    number_pattern = r"(a|one|two|three|four|five|\d+)"
    patterns: list[tuple[str, str, bool]] = [
        (
            rf"whenever another creature you control enters(?: the battlefield)?[, ]+you (may )?gain {number_pattern} life\.?",
            "self",
            True,
        ),
        (
            rf"whenever another creature enters(?: the battlefield)?[, ]+you (may )?gain {number_pattern} life\.?",
            "any",
            True,
        ),
        (
            rf"whenever a creature you control enters(?: the battlefield)?[, ]+you (may )?gain {number_pattern} life\.?",
            "self",
            False,
        ),
        (
            rf"whenever this creature or another creature you control enters(?: the battlefield)?[, ]+you (may )?gain {number_pattern} life\.?",
            "self",
            False,
        ),
    ]
    for pattern, controller_scope, another_only in patterns:
        match = re.fullmatch(pattern, text)
        if not match:
            continue
        amount = number_word_to_int(match.group(2))
        if amount <= 0:
            return "creature_enters_life_gain_oracle_amount_not_fixed"
        trigger = "creature_enters" if controller_scope == "any" else "creature_you_control_enters"
        return {
            "trigger": trigger,
            "trigger_effect": "gain_life",
            "trigger_controller_scope": controller_scope,
            "trigger_gain_life": amount,
            "trigger_another_creature_enters": another_only,
            "trigger_optional": bool(match.group(1)),
            "trigger_entering_card_types": ["creature"],
        }
    return "creature_enters_life_gain_oracle_not_exact_creature"


def creature_enters_life_gain_from_source(source_text: str, ability_names: set[str]) -> dict[str, Any] | str:
    text = str(source_text or "")
    amount = java_constructor_int(text, "GainLifeEffect")
    if amount is None or amount <= 0:
        return "creature_enters_life_gain_source_amount_not_fixed"
    if "TokenPredicate" in text:
        return "creature_enters_life_gain_source_token_filter_not_supported"
    if "FILTER_PERMANENT_ARTIFACT" in text or "FILTER_LAND" in text or "FilterLandPermanent" in text:
        return "creature_enters_life_gain_source_noncreature_filter_not_supported"
    if re.search(r"\bfilter\.add\s*\(\s*SubType\.", text):
        return "creature_enters_life_gain_source_subtype_filter_not_supported"

    optional = False
    another_only = bool(
        "AnotherPredicate.instance" in text
        or "FILTER_ANOTHER_CREATURE" in text
        or "FILTER_ANOTHER_CREATURE_YOU_CONTROL" in text
    )
    if ability_names == {"EntersBattlefieldAllTriggeredAbility"}:
        optional = bool(
            re.search(
                r"EntersBattlefieldAllTriggeredAbility\s*\([^;]*,\s*true\s*\)",
                text,
                flags=re.DOTALL,
            )
        )
        if (
            "FilterCreaturePermanent" not in text
            and "FILTER_ANOTHER_CREATURE" not in text
            and "FILTER_ANOTHER_CREATURE_YOU_CONTROL" not in text
        ):
            return "creature_enters_life_gain_source_creature_filter_not_supported"
        controller_scope = "self" if "FILTER_ANOTHER_CREATURE_YOU_CONTROL" in text else "any"
        trigger = "creature_you_control_enters" if controller_scope == "self" else "creature_enters"
    elif ability_names == {"EntersBattlefieldControlledTriggeredAbility"}:
        optional = bool(
            re.search(
                r"EntersBattlefieldControlledTriggeredAbility\s*\([^;]*,\s*true\s*\)",
                text,
                flags=re.DOTALL,
            )
        )
        if (
            "FILTER_PERMANENT_A_CREATURE" not in text
            and "FILTER_ANOTHER_CREATURE" not in text
            and "FilterControlledCreaturePermanent" not in text
        ):
            return "creature_enters_life_gain_source_creature_filter_not_supported"
        controller_scope = "self"
        trigger = "creature_you_control_enters"
    elif ability_names == {"EntersBattlefieldThisOrAnotherTriggeredAbility"}:
        if "FILTER_PERMANENT_CREATURE" not in text:
            return "creature_enters_life_gain_source_creature_filter_not_supported"
        controller_scope = "self"
        trigger = "creature_you_control_enters"
        another_only = False
    else:
        return "creature_enters_life_gain_source_ability_not_supported"

    return {
        "trigger": trigger,
        "trigger_effect": "gain_life",
        "trigger_controller_scope": controller_scope,
        "trigger_gain_life": amount,
        "trigger_another_creature_enters": another_only,
        "trigger_optional": optional,
        "trigger_entering_card_types": ["creature"],
    }


def _creature_enters_draw_filter_from_text(
    filter_text: str,
    *,
    controller_scope: str,
) -> dict[str, Any] | str:
    normalized = re.sub(r"\s+", " ", str(filter_text or "").strip().lower())
    result: dict[str, Any] = {
        "trigger_entering_card_types": ["creature"],
        "trigger_controller_scope": controller_scope,
    }
    if normalized.endswith(" you control"):
        normalized = normalized[: -len(" you control")].strip()
    normalized = normalized.replace("creature you control with power", "creature with power")
    power_match = re.fullmatch(
        r"creature with power (?P<power>\d+) or greater",
        normalized,
    )
    if power_match:
        result["trigger_entering_power_min"] = int(power_match.group("power"))
        return result
    subtype_match = re.fullmatch(r"(?P<subtype>[a-z][a-z -]*)(?: you control)?", normalized)
    if subtype_match:
        subtype = subtype_match.group("subtype").strip().replace("-", " ")
        if subtype == "creature":
            return result
        result["trigger_entering_subtypes"] = [subtype]
        return result
    return "creature_enters_draw_oracle_filter_not_supported"


def creature_enters_draw_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip().lower()
    limit_each_turn = False
    limit_suffix = " this ability triggers only once each turn."
    if text.endswith(limit_suffix):
        limit_each_turn = True
        text = text[: -len(limit_suffix)].strip()
    number_pattern = r"(a|one|two|three|four|five|\d+)"
    match = re.fullmatch(
        rf"whenever (?P<another>another )?(?P<filter>.+?) enters(?: the battlefield)?[, ]+(?:you )?(?P<may>may )?draw (?P<count>{number_pattern}) cards?\.?",
        text,
    )
    if not match:
        return "creature_enters_draw_oracle_not_simple"
    count = number_word_to_int(match.group("count"))
    if count <= 0:
        return "creature_enters_draw_oracle_count_not_fixed"
    filter_text = re.sub(r"^(?:a|an)\s+", "", match.group("filter").strip())
    controller_scope = "self" if "you control" in filter_text else "any"
    filter_spec = _creature_enters_draw_filter_from_text(
        filter_text,
        controller_scope=controller_scope,
    )
    if isinstance(filter_spec, str):
        return filter_spec
    trigger = "creature_you_control_enters" if controller_scope == "self" else "creature_enters"
    result: dict[str, Any] = {
        "trigger": trigger,
        "trigger_effect": "draw_cards",
        "trigger_draw_count": count,
        "trigger_another_creature_enters": bool(match.group("another")),
        "trigger_optional": bool(match.group("may")),
        **filter_spec,
    }
    if limit_each_turn:
        result["trigger_limit_each_turn"] = 1
    return result


def _creature_enters_draw_filter_from_source(source_text: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    if "TokenPredicate" in text or "SymmetryMatrixPredicate" in text:
        return "creature_enters_draw_source_filter_not_supported"
    if "FilterControlledCreaturePermanent" in text or "FilterControlledPermanent" in text:
        controller_scope = "self"
    elif "FilterCreaturePermanent" in text or "new FilterPermanent" in text:
        controller_scope = "any"
    else:
        return "creature_enters_draw_source_creature_filter_not_supported"
    result: dict[str, Any] = {
        "trigger_entering_card_types": ["creature"],
        "trigger_controller_scope": controller_scope,
    }
    power_match = re.search(
        r"new\s+PowerPredicate\s*\(\s*ComparisonType\.MORE_THAN\s*,\s*(\d+)\s*\)",
        text,
    )
    if power_match:
        result["trigger_entering_power_min"] = int(power_match.group(1)) + 1
    subtype_matches = [
        value.lower().replace("_", " ")
        for value in re.findall(r"SubType\.([A-Z_]+)(?:\.getPredicate\s*\(\s*\)|\))", text)
    ]
    if subtype_matches:
        # Ignore source card subtype declarations before `this.addAbility`; only
        # filter subtypes matter for the entering permanent.
        ability_index = text.find("addAbility")
        filtered: list[str] = []
        for match in re.finditer(r"SubType\.([A-Z_]+)(?:\.getPredicate\s*\(\s*\)|\))", text):
            prefix = text[max(0, match.start() - 80): match.start()]
            if ability_index >= 0 and match.start() < ability_index and "filter" not in prefix.lower():
                continue
            filtered.append(match.group(1).lower().replace("_", " "))
        if filtered:
            result["trigger_entering_subtypes"] = sorted(set(filtered))
    if not result.get("trigger_entering_power_min") and not result.get("trigger_entering_subtypes"):
        if "FilterControlledCreaturePermanent" not in text and "FilterCreaturePermanent" not in text:
            return "creature_enters_draw_source_filter_not_supported"
    return result


def creature_enters_draw_from_source(source_text: str, ability_names: set[str]) -> dict[str, Any] | str:
    text = str(source_text or "")
    if ability_names != {"EntersBattlefieldAllTriggeredAbility"}:
        return "creature_enters_draw_source_ability_not_supported"
    if "DoIfCostPaid" in text or "ManaCostsImpl" in text or "GenericManaCost" in text:
        return "creature_enters_draw_source_optional_cost_not_supported"
    draw_count = java_constructor_int(text, "DrawCardSourceControllerEffect", default=1)
    if draw_count is None or draw_count <= 0:
        return "creature_enters_draw_source_count_not_fixed"
    optional = bool(
        re.search(
            r"EntersBattlefieldAllTriggeredAbility\s*\([^;]*,\s*true\s*\)",
            text,
            flags=re.DOTALL,
        )
    )
    another_only = bool("AnotherPredicate.instance" in text)
    filter_spec = _creature_enters_draw_filter_from_source(text)
    if isinstance(filter_spec, str):
        return filter_spec
    controller_scope = str(filter_spec.get("trigger_controller_scope") or "self")
    trigger = "creature_you_control_enters" if controller_scope == "self" else "creature_enters"
    result: dict[str, Any] = {
        "trigger": trigger,
        "trigger_effect": "draw_cards",
        "trigger_draw_count": draw_count,
        "trigger_another_creature_enters": another_only,
        "trigger_optional": optional,
        **filter_spec,
    }
    if ".setTriggersLimitEachTurn(1)" in text:
        result["trigger_limit_each_turn"] = 1
    return result


def dies_life_gain_amount_from_oracle(metadata: dict[str, Any]) -> int | None:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    match = re.fullmatch(
        r"(?:when|whenever) (?:this creature|[^,.]+) dies, you gain "
        r"(a|one|two|three|four|five|\d+) life\.?",
        text,
    )
    if not match:
        return None
    amount = number_word_to_int(match.group(1))
    return amount if amount > 0 else None


def etb_draw_count_from_oracle(metadata: dict[str, Any]) -> int | None:
    text = re.sub(r"\s+", " ", oracle_text(metadata)).strip()
    match = re.search(
        r"(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+draw (a|one|two|three|four|five|\d+) cards?(?:\.|$)",
        text,
    )
    if not match:
        return None
    value = match.group(1)
    words = {"a": 1, "one": 1, "two": 2, "three": 3, "four": 4, "five": 5}
    if value in words:
        return words[value]
    return int(value)


def etb_scry_count_from_oracle(metadata: dict[str, Any]) -> int | str:
    text = strip_parenthetical_reminders(oracle_text_after_leading_static_keywords(metadata))
    text = re.sub(r"\s+", " ", text).strip()
    if len(re.findall(r"\bscry\b", text)) != 1:
        return "etb_scry_oracle_not_simple"
    if re.search(r"\bscry\s+x\b", text):
        return "etb_scry_oracle_not_fixed"
    match = re.fullmatch(
        r"(?:when|whenever) (?:this creature|[^.]+?) enters(?: the battlefield)?[, ]+"
        r"scry (one|two|three|four|five|\d+)\.?",
        text,
    )
    if not match:
        return "etb_scry_oracle_not_exact_fixed"
    count = number_word_to_int(match.group(1))
    if count <= 0:
        return "etb_scry_oracle_not_fixed"
    return count


def etb_scry_count_from_source(source_text: str) -> int | str:
    text = str(source_text or "")
    if "TargetPointer" in text or ".setTargetPointer" in text:
        return "etb_scry_source_target_not_supported"
    if "Conditional" in text or "Condition" in text:
        return "etb_scry_source_condition_not_supported"
    scry_match = fixed_scry_count_match_from_source(text)
    if scry_match is None:
        return "etb_scry_source_count_not_fixed"
    if len(re.findall(r"EntersBattlefieldTriggeredAbility\s*\(", text)) != 1:
        return "etb_scry_source_trigger_not_exact"
    return int(scry_match[0])


def etb_optional_discard_draw_from_oracle(metadata: dict[str, Any]) -> dict[str, int] | str:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    if re.fullmatch(
        r"(?:when|whenever) (?:this creature|[^.]+?) enters(?: the battlefield)?[, ]+"
        r"you may discard a card\. if you do, draw a card\.?",
        text,
    ):
        return {"discard_count": 1, "draw_count": 1}
    return "etb_optional_discard_draw_oracle_not_exact"


def etb_optional_discard_draw_from_source(source_text: str) -> dict[str, int] | str:
    text = str(source_text or "")
    if "DoIfCostPaid" not in text or "DiscardCardCost" not in text:
        return "etb_optional_discard_draw_source_not_optional_discard_cost"
    if len(re.findall(r"DrawCardSourceControllerEffect\s*\(", text)) != 1:
        return "etb_optional_discard_draw_source_count_not_fixed"
    draw_count = java_constructor_int_or_noarg_default(
        text,
        "DrawCardSourceControllerEffect",
        noarg_default=1,
    )
    if draw_count != 1:
        return "etb_optional_discard_draw_source_count_not_fixed"
    if re.search(r"new\s+DiscardCardCost\s*\(\s*\)", text) is None:
        return "etb_optional_discard_draw_source_discard_cost_not_simple"
    return {"discard_count": 1, "draw_count": 1}


def etb_draw_discard_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(oracle_text_after_leading_static_keywords(metadata))
    text = re.sub(r"\s+", " ", text).strip().lower()
    number_pattern = r"(a|one|two|three|four|five|\d+)"
    match = re.fullmatch(
        rf"(?:when|whenever) (?:this creature|[^.]+?) enters(?: the battlefield)?[, ]+"
        rf"draw {number_pattern} cards?, then discard {number_pattern} cards?\.?",
        text,
    )
    if not match:
        return "etb_draw_discard_oracle_not_exact"
    draw_count = number_word_to_int(match.group(1))
    discard_count = number_word_to_int(match.group(2))
    if draw_count <= 0 or discard_count <= 0:
        return "etb_draw_discard_oracle_count_not_fixed"
    return {
        "draw_count": draw_count,
        "discard_count": discard_count,
        "draw_discard_order": "draw_then_discard",
    }


def etb_draw_discard_from_source(source_text: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    if "DoIfCostPaid" in text or "DiscardCardCost" in text:
        return "etb_draw_discard_source_optional_not_supported"
    if "Conditional" in text or "Condition" in text:
        return "etb_draw_discard_source_condition_not_supported"
    if len(re.findall(r"EntersBattlefieldTriggeredAbility\s*\(", text)) != 1:
        return "etb_draw_discard_source_trigger_not_exact"
    counts = draw_discard_counts_from_source(text)
    if isinstance(counts, str):
        return counts.replace("activated_draw_discard", "etb_draw_discard")
    return {
        "draw_count": int(counts[0]),
        "discard_count": int(counts[1]),
        "draw_discard_order": "draw_then_discard",
    }


def etb_dynamic_draw_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    if re.fullmatch(
        r"(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+draw a card for each creature "
        r"you control with a \+1/\+1 counter on it\.?",
        text,
    ):
        return {"draw_count_source": "controlled_creatures_with_plus_one_counters"}
    color_match = re.fullmatch(
        r"(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+draw a card for each "
        r"(white|blue|black|red|green) creature you control\.?",
        text,
    )
    if color_match:
        return {
            "draw_count_source": "controlled_creatures_with_color",
            "draw_count_color": color_match.group(1),
        }
    subtype_match = re.fullmatch(
        r"(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+draw a card for each "
        r"(other )?([a-z][a-z -]+?) you control\.?",
        text,
    )
    if subtype_match:
        raw_subtype = subtype_match.group(2).strip()
        if raw_subtype in {"green creature", "creature"}:
            return "etb_dynamic_draw_oracle_not_supported"
        return {
            "draw_count_source": "controlled_creatures_with_subtype",
            "draw_count_subtype": raw_subtype.replace(" creatures", "").replace(" creature", ""),
            "draw_count_exclude_source": bool(subtype_match.group(1)),
        }
    if re.fullmatch(
        r"(?:vivid — )?(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+draw cards equal to "
        r"the number of colors among permanents you control\.?",
        text,
    ):
        return {"draw_count_source": "colors_among_permanents_you_control"}
    zombie_match = re.fullmatch(
        r"(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+draw cards equal to the number of "
        r"([a-z][a-z -]+?)s you control or the number of \1 cards in your graveyard, whichever is greater\.?",
        text,
    )
    if zombie_match:
        return {
            "draw_count_source": "max_controlled_creatures_or_graveyard_cards_with_subtype",
            "draw_count_subtype": zombie_match.group(1),
        }
    return "etb_dynamic_draw_oracle_not_supported"


def etb_dynamic_draw_from_source(source_text: str, oracle_data: dict[str, Any]) -> dict[str, Any] | str:
    text = str(source_text or "")
    source = str(oracle_data.get("draw_count_source") or "")
    subtype = str(oracle_data.get("draw_count_subtype") or "").strip()
    color = str(oracle_data.get("draw_count_color") or "").strip().lower()
    if source == "controlled_creatures_with_plus_one_counters":
        if "PermanentsOnBattlefieldCount(StaticFilters.FILTER_CONTROLLED_CREATURE_P1P1)" not in re.sub(r"\s+", "", text):
            return "etb_dynamic_draw_source_oracle_mismatch"
        return dict(oracle_data)
    if source == "controlled_creatures_with_subtype":
        subtype_constant = subtype.upper().replace(" ", "_").replace("-", "_")
        if f"SubType.{subtype_constant}" not in text or "PermanentsOnBattlefieldCount" not in text:
            return "etb_dynamic_draw_source_oracle_mismatch"
        if bool(oracle_data.get("draw_count_exclude_source")) != ("AnotherPredicate.instance" in text):
            return "etb_dynamic_draw_source_oracle_mismatch"
        return dict(oracle_data)
    if source == "controlled_creatures_with_color":
        color_constant = color.upper()
        if color_constant == "GREEN":
            color_constant = "GREEN"
        if f"ObjectColor.{color_constant}" not in text or "PermanentsOnBattlefieldCount" not in text:
            return "etb_dynamic_draw_source_oracle_mismatch"
        return dict(oracle_data)
    if source == "colors_among_permanents_you_control":
        if "ColorsAmongControlledPermanentsCount.ALL_PERMANENTS" not in text:
            return "etb_dynamic_draw_source_oracle_mismatch"
        return dict(oracle_data)
    if source == "max_controlled_creatures_or_graveyard_cards_with_subtype":
        subtype_constant = subtype.upper().replace(" ", "_").replace("-", "_")
        if (
            "MaximumDynamicValue" not in text
            or "PermanentsOnBattlefieldCount" not in text
            or "CardsInControllerGraveyardCount" not in text
            or f"SubType.{subtype_constant}" not in text
        ):
            return "etb_dynamic_draw_source_oracle_mismatch"
        return dict(oracle_data)
    return "etb_dynamic_draw_source_not_supported"


def etb_draw_lose_life_from_oracle(metadata: dict[str, Any]) -> dict[str, int] | str:
    trigger_complexity_tokens = SPELL_COMPLEXITY_TOKENS - {"when ", "whenever "}
    if has_oracle_complexity(metadata, tokens=trigger_complexity_tokens):
        return "etb_draw_lose_life_oracle_not_simple"
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    number_pattern = r"(a|one|two|three|four|five|\d+)"
    match = re.fullmatch(
        rf"(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+you draw {number_pattern} cards? "
        rf"and (?:you )?lose (?P<life>\d+) life\.?",
        text,
    )
    if not match:
        return "etb_draw_lose_life_oracle_not_exact_fixed"
    draw_count = number_word_to_int(match.group(1))
    life_loss = int(match.group("life"))
    if draw_count <= 0 or life_loss <= 0:
        return "etb_draw_lose_life_count_not_fixed"
    return {"draw_count": draw_count, "life_loss": life_loss}


def dies_draw_from_oracle(metadata: dict[str, Any]) -> tuple[int, bool] | None:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    match = re.match(
        r"^(?:when|whenever) this creature dies, (you may )?draw "
        r"(a|one|two|three|four|five|\d+) cards?\.?$",
        text,
    )
    if not match:
        return None
    value = match.group(2)
    words = {"a": 1, "one": 1, "two": 2, "three": 3, "four": 4, "five": 5}
    count = words.get(value)
    if count is None and value.isdigit():
        count = int(value)
    if count is None:
        count = 0
    if count <= 0:
        return None
    return count, bool(match.group(1))


def combat_damage_draw_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    match = re.fullmatch(
        r"whenever (?:this creature|[^,.]+) deals combat damage to a player, "
        r"(?:you may )?(?:you )?draw (a|one|two|three|four|five|\d+) cards?\.?",
        text,
    )
    if match:
        count = number_word_to_int(match.group(1))
        if count <= 0:
            return None
        return {
            "draw_count": count,
            "optional": "you may" in text,
        }
    discard_match = re.fullmatch(
        r"whenever (?:this creature|[^,.]+) deals combat damage to a player, "
        r"you may discard a card\. if you do, draw "
        r"(a|one|two|three|four|five|\d+) cards?\.?",
        text,
    )
    if discard_match:
        count = number_word_to_int(discard_match.group(1))
        if count <= 0:
            return None
        return {
            "draw_count": count,
            "optional": True,
            "optional_cost": "discard_card",
            "optional_cost_count": 1,
        }
    sacrifice_match = re.fullmatch(
        r"whenever (?:this creature|[^,.]+) deals combat damage to a player, "
        r"you may sacrifice (?:it|this creature|[^,.]+)\. if you do, draw "
        r"(a|one|two|three|four|five|\d+) cards?\.?",
        text,
    )
    if sacrifice_match:
        count = number_word_to_int(sacrifice_match.group(1))
        if count <= 0:
            return None
        return {
            "draw_count": count,
            "optional": True,
            "optional_cost": "sacrifice_source",
            "optional_cost_count": 1,
        }
    return None


def combat_damage_draw_from_source(source_text: str) -> dict[str, Any] | str:
    text = str(source_text or "")
    if len(re.findall(r"new\s+DrawCardSourceControllerEffect\s*\(", text)) != 1:
        return "combat_damage_draw_source_effect_count_not_supported"
    if "DealsCombatDamageToAPlayerTriggeredAbility" not in text:
        return "combat_damage_draw_source_trigger_mismatch"
    count = java_constructor_int_or_noarg_default(
        text,
        "DrawCardSourceControllerEffect",
        noarg_default=1,
    )
    if count is None or count <= 0:
        return "combat_damage_draw_count_source_not_fixed"
    optional_cost = None
    if re.search(r"new\s+DoIfCostPaid\s*\(", text):
        cost_flags = {
            "discard_card": "new DiscardCardCost" in text,
            "sacrifice_source": "new SacrificeSourceCost" in text,
        }
        enabled = [key for key, active in cost_flags.items() if active]
        if len(enabled) != 1:
            return "combat_damage_draw_optional_cost_not_supported"
        optional_cost = enabled[0]
    return {
        "draw_count": count,
        "optional_cost": optional_cost,
        "optional_cost_count": 1 if optional_cost else 0,
    }


def etb_damage_target_from_oracle(metadata: dict[str, Any]) -> tuple[int, str] | None:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    patterns: list[tuple[str, str]] = [
        (
            r"^when this creature enters(?: the battlefield)?, "
            r"(?:it|this creature) deals (\d+) damage to any target\.?$",
            "any_target",
        ),
        (
            r"^when this creature enters(?: the battlefield)?, "
            r"(?:it|this creature) deals (\d+) damage to target player or planeswalker\.?$",
            "player_or_planeswalker",
        ),
        (
            r"^when this creature enters(?: the battlefield)?, "
            r"(?:it|this creature) deals (\d+) damage to target creature or planeswalker\.?$",
            "creature_or_planeswalker",
        ),
        (
            r"^when this creature enters(?: the battlefield)?, "
            r"(?:it|this creature) deals (\d+) damage to target creature you control\.?$",
            "creature_you_control",
        ),
        (
            r"^when this creature enters(?: the battlefield)?, "
            r"(?:you may have )?(?:it|this creature) deal (\d+) damage to target creature with flying\.?$",
            "flying_creature",
        ),
        (
            r"^when this creature enters(?: the battlefield)?, "
            r"(?:it|this creature) deals (\d+) damage to target creature an opponent controls that was dealt damage this turn\.?$",
            "creature_damaged_this_turn_opponent_controls",
        ),
        (
            r"^when this creature enters(?: the battlefield)?, "
            r"(?:it|this creature) deals (\d+) damage to target creature an opponent controls\.?$",
            "creature",
        ),
        (
            r"^when this creature enters(?: the battlefield)?, "
            r"(?:it|this creature) deals (\d+) damage to target creature\.?$",
            "creature",
        ),
    ]
    for pattern, target in patterns:
        match = re.match(pattern, text)
        if match:
            amount = int(match.group(1))
            if amount > 0:
                return amount, target
    return None


def dies_damage_target_from_oracle(metadata: dict[str, Any]) -> tuple[int, str, bool] | None:
    text = re.sub(r"\s+", " ", oracle_text_after_leading_static_keywords(metadata)).strip()
    subject = r"(?:this creature|this card|[^,.]+?)"
    target_patterns: list[tuple[str, str]] = [
        (r"any target", "any_target"),
        (r"target creature or planeswalker an opponent controls", "creature_or_planeswalker"),
        (r"target creature or planeswalker", "creature_or_planeswalker"),
        (r"target creature an opponent controls", "creature"),
        (r"target creature", "creature"),
        (r"target player or planeswalker", "player_or_planeswalker"),
        (r"target player", "player"),
        (r"target opponent", "opponent"),
    ]
    for target_phrase, target in target_patterns:
        patterns = [
            rf"^(?:when|whenever) {subject} dies, "
            rf"(it|this creature|{subject}) deals (\d+) damage to {target_phrase}\.?$",
            rf"^(?:when|whenever) {subject} dies, "
            rf"you may have (it|this creature|{subject}) deal (\d+) damage to {target_phrase}\.?$",
        ]
        for index, pattern in enumerate(patterns):
            match = re.match(pattern, text)
            if not match:
                continue
            amount = int(match.group(2))
            if amount <= 0:
                return None
            return amount, target, index == 1
    return None


def damage_target_from_source(source: str) -> str | None:
    text = source or ""
    restricted = restricted_battlefield_target_from_source(text)
    if restricted is not None:
        return restricted
    if re.search(r"new\s+TargetAnyTarget\s*\(", text):
        return "any_target"
    if re.search(r"new\s+TargetPlayerOrPlaneswalker\s*\(", text):
        return "player_or_planeswalker"
    if re.search(r"new\s+TargetOpponentOrPlaneswalker\s*\(", text):
        return "opponent_or_planeswalker"
    if re.search(r"new\s+TargetOpponent\s*\(", text):
        return "opponent"
    if re.search(r"new\s+TargetPlayer\s*\(", text):
        return "player"
    if re.search(r"new\s+TargetCreatureOrPlaneswalker\w*\s*\(", text):
        return "creature_or_planeswalker"
    if "TargetPermanent" in text and "creature or planeswalker" in text:
        return "creature_or_planeswalker"
    if re.search(r"new\s+TargetControlledCreaturePermanent\s*\(", text):
        return "creature_you_control"
    if re.search(r"new\s+TargetOpponentsCreaturePermanent\s*\(", text):
        return "creature_opponent_controls"
    if (
        re.search(r"new\s+TargetCreaturePermanent\s*\(", text)
        or "FilterCreaturePermanent" in text
        or "FILTER_PERMANENT_CREATURE" in text
        or "FILTER_CREATURE" in text
    ):
        return "creature"
    return None


def dies_source_trigger_is_optional(source: str) -> bool:
    match = re.search(r"DiesSourceTriggeredAbility\s*\((?P<body>[\s\S]{0,500}?)\)\s*;", source or "")
    if not match:
        return False
    return bool(re.search(r",\s*true\b", match.group("body")))


def etb_destroy_target_from_oracle(metadata: dict[str, Any]) -> tuple[str, str] | None:
    text = strip_parenthetical_reminders(oracle_text_after_leading_static_keywords(metadata))
    text = re.sub(r"\s+", " ", text).strip()
    text = re.sub(r"^[a-z0-9' -]+\s+[—-]\s+", "", text)
    etb_subject = r"(?:this creature|.+?)"
    patterns: list[tuple[str, tuple[str, str]]] = [
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target creature with power 1 or less\.?$",
            ("remove_creature", "creature_power_1_or_less"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target creature with toughness 2 or less\.?$",
            ("remove_creature", "creature_toughness_2_or_less"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy up to three target creatures\.?$",
            ("remove_creature", "creature_up_to_three"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target creature that was dealt damage this turn\.?$",
            ("remove_creature", "creature_damaged_this_turn"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target creature with flying\.?$",
            ("remove_creature", "flying_creature"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target creature with defender\.?$",
            ("remove_creature", "creature_with_defender"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target nonblack creature(?:\. it can't be regenerated)?\.?$",
            ("remove_creature", "nonblack_creature"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target nonartifact, nonblack creature(?:\. that creature can't be regenerated)?\.?$",
            ("remove_creature", "nonartifact_nonblack_creature"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target non-elf creature whose power and toughness aren't equal\.?$",
            ("remove_creature", "non_elf_power_toughness_not_equal_creature"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target token an opponent controls\.?$",
            ("remove_permanent", "token_opponent_controls"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target creature an opponent controls that was dealt damage this turn\.?$",
            ("remove_creature", "creature_damaged_this_turn_opponent_controls"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target creature or planeswalker an opponent controls that was dealt damage this turn\.?$",
            ("remove_permanent", "creature_or_planeswalker_damaged_this_turn_opponent_controls"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target island or swamp an opponent controls\.?$",
            ("remove_permanent", "island_or_swamp_opponent_controls"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target nonbasic land\.?$",
            ("remove_permanent", "nonbasic_land"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy up to one target noncreature artifact\.?$",
            ("remove_permanent", "noncreature_artifact"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target equipment\.?$",
            ("remove_permanent", "equipment"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target aura\.?$",
            ("remove_permanent", "aura"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target vampire, werewolf, or zombie\.?$",
            ("remove_creature", "vampire_werewolf_or_zombie_creature"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target artifact\.?$",
            ("remove_permanent", "artifact"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target enchantment\.?$",
            ("remove_permanent", "enchantment"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy (?:up to one )?target artifact or enchantment(?: an opponent controls)?\.?$",
            ("remove_permanent", "artifact_or_enchantment"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target artifact, enchantment, or land\.?$",
            ("remove_permanent", "artifact_or_enchantment_or_land"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target land\.?$",
            ("remove_permanent", "land"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target nonland permanent an opponent controls\.?$",
            ("remove_permanent", "nonland_permanent"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target permanent\.?$",
            ("remove_permanent", "permanent"),
        ),
        (
            rf"^when {etb_subject} enters(?: the battlefield)?, (?:you may )?destroy target creature an opponent controls\.?$",
            ("remove_creature", "creature"),
        ),
    ]
    for pattern, result in patterns:
        if re.match(pattern, text):
            return result
    return None


def etb_destroy_source_supported(source: str, target: str) -> str | None:
    text = source or ""
    if len(re.findall(r"new\s+DestroyTargetEffect\s*\(", text)) != 1:
        return "etb_destroy_source_effect_count_not_supported"
    if "TargetPointer" in text or ".setTargetPointer" in text or "TargetAdjuster" in text:
        return "etb_destroy_source_multi_target_not_supported"
    if ".withInterveningIf" in text or "InterveningIf" in text:
        return "etb_destroy_source_condition_not_supported"
    checks: dict[str, Callable[[str], bool]] = {
        "creature_power_1_or_less": lambda value: "PowerPredicate" in value and "ComparisonType.FEWER_THAN, 2" in value,
        "creature_toughness_2_or_less": lambda value: "ToughnessPredicate" in value and "ComparisonType.FEWER_THAN, 3" in value,
        "creature_up_to_three": lambda value: re.search(r"new\s+TargetCreaturePermanent\s*\(\s*0\s*,\s*3\s*\)", value) is not None,
        "creature_damaged_this_turn": lambda value: "FILTER_CREATURE_DAMAGED_THIS_TURN" in value,
        "flying_creature": lambda value: "FILTER_CREATURE_FLYING" in value or "AbilityPredicate(FlyingAbility.class)" in value,
        "creature_with_defender": lambda value: "AbilityPredicate(DefenderAbility.class)" in value,
        "nonblack_creature": lambda value: "FILTER_PERMANENT_CREATURE_NON_BLACK" in value,
        "nonartifact_nonblack_creature": lambda value: (
            "nonartifact, nonblack creature" in value
            and "CardType.ARTIFACT" in value
            and "ObjectColor.BLACK" in value
        ),
        "non_elf_power_toughness_not_equal_creature": lambda value: (
            "non-Elf creature whose power and toughness aren't equal" in value
            and "SubType.ELF" in value
            and "PowerToughnessNotEqualPredicate" in value
        ),
        "token_opponent_controls": lambda value: "TokenPredicate.TRUE" in value and "TargetController.OPPONENT" in value,
        "creature_damaged_this_turn_opponent_controls": lambda value: "FILTER_OPPONENTS_CREATURE_DAMAGED_THIS_TURN" in value,
        "creature_or_planeswalker_damaged_this_turn_opponent_controls": lambda value: (
            "FilterCreatureOrPlaneswalkerPermanent" in value
            and "WasDealtDamageThisTurnPredicate" in value
            and "TargetController.OPPONENT" in value
        ),
        "island_or_swamp_opponent_controls": lambda value: (
            "SubType.ISLAND" in value
            and "SubType.SWAMP" in value
            and "TargetController.OPPONENT" in value
        ),
        "nonbasic_land": lambda value: "TargetNonBasicLandPermanent" in value,
        "noncreature_artifact": lambda value: "FILTER_ARTIFACT_NON_CREATURE" in value,
        "equipment": lambda value: "FILTER_PERMANENT_EQUIPMENT" in value,
        "aura": lambda value: "SubType.AURA" in value,
        "vampire_werewolf_or_zombie_creature": lambda value: (
            "SubType.VAMPIRE" in value
            and "SubType.WEREWOLF" in value
            and "SubType.ZOMBIE" in value
        ),
        "artifact_or_enchantment": lambda value: "FILTER_PERMANENT_ARTIFACT_OR_ENCHANTMENT" in value,
        "artifact_or_enchantment_or_land": lambda value: (
            "CardType.ARTIFACT" in value
            and "CardType.ENCHANTMENT" in value
            and "CardType.LAND" in value
        ),
        "artifact": lambda value: "TargetArtifactPermanent" in value or "FilterArtifactPermanent" in value,
        "enchantment": lambda value: "TargetEnchantmentPermanent" in value or "FilterEnchantmentPermanent" in value,
        "land": lambda value: "TargetLandPermanent" in value or "FilterLandPermanent" in value,
        "nonland_permanent": lambda value: "TargetNonlandPermanent" in value or "FilterNonlandPermanent" in value,
        "permanent": lambda value: re.search(r"new\s+TargetPermanent\s*\(\s*\)", value) is not None,
        "creature": lambda value: "TargetCreaturePermanent" in value or "FILTER_PERMANENT_CREATURE" in value,
    }
    checker = checks.get(target)
    if checker is None or not checker(text):
        return "etb_destroy_source_target_not_supported"
    return None


def etb_recursion_target_from_phrase(phrase: str) -> str | None:
    normalized = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    target_patterns: list[tuple[str, str]] = [
        ("spirit_instant_or_sorcery", r"spirit, instant, or sorcery"),
        ("vampire_or_wizard_creature", r"vampire or wizard creature"),
        ("instant_or_sorcery", r"instant (?:or|and/or) sorcery"),
        ("artifact_or_enchantment", r"artifact or enchantment"),
        ("artifact_or_creature", r"artifact or creature"),
        ("creature_or_enchantment", r"creature or enchantment"),
        ("creature_or_food", r"creature or food"),
        ("artifact_creature", r"artifact creature"),
        ("noncreature_nonland", r"noncreature, nonland"),
        ("knight_card", r"knight"),
        ("mercenary_card", r"mercenary"),
        ("elf_card", r"elf"),
        ("permanent", r"permanent"),
        ("creature", r"creature"),
        ("artifact", r"artifact"),
        ("enchantment", r"enchantment"),
        ("instant", r"instant"),
        ("sorcery", r"sorcery"),
        ("land", r"land"),
        ("any_card", r"card"),
    ]
    for target_type, pattern in target_patterns:
        if re.fullmatch(pattern, normalized):
            return target_type
    return None


def word_count_value(value: str) -> int | None:
    normalized = str(value or "").strip().lower()
    words = {
        "one": 1,
        "two": 2,
        "three": 3,
        "four": 4,
        "five": 5,
        "six": 6,
        "seven": 7,
        "eight": 8,
        "nine": 9,
        "ten": 10,
    }
    if normalized in words:
        return words[normalized]
    if normalized.isdigit():
        return int(normalized)
    return None


def library_pick_target_from_phrase(phrase: str) -> str | None:
    normalized = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    normalized = normalized.removeprefix("a ").removeprefix("an ")
    normalized = normalized.removesuffix(".")
    normalized = normalized.removesuffix(" cards").removesuffix(" card")
    mapping = {
        "artifact, creature, or land": "artifact_creature_or_land",
        "artifact or pirate": "artifact_or_pirate",
        "colorless": "colorless_card",
        "colorless card": "colorless_card",
        "creature or enchantment": "creature_or_enchantment",
        "creature or land": "creature_or_land",
        "enchantment or land": "enchantment_or_land",
        "goblin, swamp, or mountain": "goblin_swamp_or_mountain",
        "elf, swamp, or forest": "elf_swamp_or_forest",
        "elemental, island, or mountain": "elemental_island_or_mountain",
        "kithkin, forest, or plains": "kithkin_forest_or_plains",
        "merfolk, plains, or island": "merfolk_plains_or_island",
        "green": "green_card",
        "human": "human_card",
        "instant and/or sorcery": "instant_or_sorcery",
        "instant or sorcery": "instant_or_sorcery",
        "land or double-faced": "land_or_double_faced",
        "mount creature or plains": "mount_creature_or_plains",
        "snow permanent": "snow_permanent",
        "enchantment": "enchantment",
        "creature": "creature",
        "land": "land",
        "artifact": "artifact",
        "card": "any_card",
    }
    return mapping.get(normalized)


def library_pick_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = oracle_text(metadata)
    prefix = r"^reveal the top (?P<look>\w+) cards of your library\. "
    up_to_match = re.match(
        prefix
        + r"put up to (?P<count>\w+) (?P<phrase>.+?) cards? from among them into your hand "
        + r"and (?:the )?rest(?: of the revealed cards)? into your graveyard\.?$",
        text,
    )
    may_match = re.match(
        prefix
        + r"you may put (?P<count>a|an|one|two|three|any number of) (?P<phrase>.+?) cards? "
        + r"from among them into your hand\. put the rest into your graveyard\.?$",
        text,
    )
    match = up_to_match or may_match
    if not match:
        return "library_pick_oracle_not_simple"
    look_count = word_count_value(match.group("look"))
    if look_count is None or look_count <= 0:
        return "library_pick_oracle_look_count_not_supported"
    count_token = str(match.group("count") or "").strip().lower()
    pick_all_matching = count_token == "any number of"
    if pick_all_matching:
        pick_count = look_count
    elif count_token in {"a", "an"}:
        pick_count = 1
    else:
        pick_count = word_count_value(count_token)
    if pick_count is None or pick_count <= 0:
        return "library_pick_oracle_pick_count_not_supported"
    target = library_pick_target_from_phrase(match.group("phrase"))
    if target is None:
        return "library_pick_oracle_target_not_supported"
    return {
        "look_count": look_count,
        "pick_count": pick_count,
        "pick_target": target,
        "pick_up_to_count": True,
        "pick_all_matching": pick_all_matching,
        "rest_destination": "graveyard",
    }


def library_pick_target_from_source(source: str, filter_arg: str) -> str | None:
    text = source or ""
    filter_ref = str(filter_arg or "").strip()
    if "FILTER_CARD_INSTANT_OR_SORCERY" in filter_ref or "FILTER_CARD_INSTANT_OR_SORCERY" in text:
        return "instant_or_sorcery"
    if "FILTER_CARD_ARTIFACTS" in filter_ref or "FILTER_CARD_ARTIFACTS" in text:
        return "artifact"
    if "FILTER_CARD_CREATURES" in filter_ref or "FILTER_CARD_CREATURES" in text:
        return "creature"
    if "FILTER_CARD_CREATURE_A" in filter_ref or "FILTER_CARD_CREATURE_A" in text:
        return "creature"
    if "FILTER_CARD_LANDS" in filter_ref or "FILTER_CARD_LANDS" in text:
        return "land"
    if "FILTER_CARD_CREATURE_OR_LAND" in filter_ref or "FILTER_CARD_CREATURE_OR_LAND" in text:
        return "creature_or_land"
    if "FILTER_CARD_ENCHANTMENTS" in filter_ref or "FILTER_CARD_ENCHANTMENTS" in text:
        return "enchantment"
    if "ColorlessPredicate" in text:
        return "colorless_card"
    if "SuperType.SNOW.getPredicate" in text and "FilterPermanentCard" in text:
        return "snow_permanent"
    filter_match = re.search(r'new\s+Filter(?:Permanent)?Card\s*\(\s*"([^"]+)"\s*\)', text)
    if filter_match:
        target = library_pick_target_from_phrase(filter_match.group(1))
        if target is not None:
            return target
    if "ObjectColor.GREEN" in text or "ColorPredicate(ObjectColor.GREEN)" in text:
        return "green_card"
    subtype_names = {
        "SubType.HUMAN": "human_card",
        "SubType.GOBLIN": "goblin_swamp_or_mountain",
        "SubType.ELF": "elf_swamp_or_forest",
        "SubType.ELEMENTAL": "elemental_island_or_mountain",
        "SubType.KITHKIN": "kithkin_forest_or_plains",
        "SubType.MERFOLK": "merfolk_plains_or_island",
        "SubType.MOUNT": "mount_creature_or_plains",
        "SubType.PIRATE": "artifact_or_pirate",
    }
    for source_subtype, target in subtype_names.items():
        if source_subtype in text:
            if target == "artifact_or_pirate" and "CardType.ARTIFACT" not in text:
                continue
            if target == "mount_creature_or_plains" and "SubType.PLAINS" not in text:
                continue
            if target.endswith("_swamp_or_mountain") and not ("SubType.SWAMP" in text and "SubType.MOUNTAIN" in text):
                continue
            if target.endswith("_swamp_or_forest") and not ("SubType.SWAMP" in text and "SubType.FOREST" in text):
                continue
            if target.endswith("_island_or_mountain") and not ("SubType.ISLAND" in text and "SubType.MOUNTAIN" in text):
                continue
            if target.endswith("_forest_or_plains") and not ("SubType.FOREST" in text and "SubType.PLAINS" in text):
                continue
            if target.endswith("_plains_or_island") and not ("SubType.PLAINS" in text and "SubType.ISLAND" in text):
                continue
            return target
    if "DoubleFacedCardPredicate" in text and "CardType.LAND" in text:
        return "land_or_double_faced"
    if (
        "CardType.ARTIFACT.getPredicate()" in text
        and "CardType.CREATURE.getPredicate()" in text
        and "CardType.LAND.getPredicate()" in text
    ):
        return "artifact_creature_or_land"
    if "CardType.CREATURE.getPredicate()" in text and "CardType.ENCHANTMENT.getPredicate()" in text:
        return "creature_or_enchantment"
    if "CardType.ENCHANTMENT.getPredicate()" in text and "CardType.LAND.getPredicate()" in text:
        return "enchantment_or_land"
    if "CardType.INSTANT.getPredicate()" in text and "CardType.SORCERY.getPredicate()" in text:
        return "instant_or_sorcery"
    return None


def library_pick_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    match = re.search(
        r"RevealLibraryPickControllerEffect\s*\(\s*(?P<look>\d+)\s*,\s*"
        r"(?P<pick>\d+|Integer\.MAX_VALUE)\s*,\s*(?P<filter>[^,]+)\s*,\s*"
        r"PutCards\.HAND\s*,\s*PutCards\.GRAVEYARD",
        text,
        re.S,
    )
    if not match:
        return "library_pick_source_effect_not_found"
    look_count = int(match.group("look"))
    pick_raw = match.group("pick")
    pick_all_matching = pick_raw == "Integer.MAX_VALUE"
    pick_count = look_count if pick_all_matching else int(pick_raw)
    target = library_pick_target_from_source(text, match.group("filter"))
    if target is None:
        return "library_pick_source_target_not_supported"
    return {
        "look_count": look_count,
        "pick_count": pick_count,
        "pick_target": target,
        "pick_all_matching": pick_all_matching,
        "rest_destination": "graveyard",
    }


def look_library_pick_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    raw_text = strip_parenthetical_reminders(str(metadata.get("oracle_text") or ""))
    effect_sentences: list[str] = []
    for raw_line in raw_text.splitlines():
        line = re.sub(r"\s+", " ", raw_line.strip()).strip()
        if not line:
            continue
        for sentence in re.split(r"(?<=\.)\s+", line):
            candidate = re.sub(r"\s+", " ", sentence.strip()).strip()
            if candidate and not is_resolution_neutral_auxiliary_oracle_line(candidate):
                effect_sentences.append(candidate)
    text = re.sub(r"\s+", " ", " ".join(effect_sentences).strip().lower())
    prefix = r"^look at the top (?P<look>\w+) cards of your library\. "
    simple_bottom_match = re.match(
        prefix
        + r"put (?P<count>one|two|three|\d+) of (?:them|those cards) into your hand "
        + r"and (?:the rest|the other) on the bottom of your library(?: in (?:any|a random) order)?\.?$",
        text,
    )
    simple_graveyard_match = re.match(
        prefix
        + r"put (?P<count>one|two|three|\d+) of (?:them|those cards) into your hand "
        + r"and (?:the rest|the other) into your graveyard\.?$",
        text,
    )
    may_reveal_bottom_match = re.match(
        prefix
        + r"you may reveal (?P<count>a|an|one|two|three|up to one|up to two|any number of) "
        + r"(?P<phrase>.+?) cards? from among them and put (?:it|the revealed cards?) into your hand\. "
        + r"(?:then )?put the rest on the bottom of your library(?: in (?:any|a random) order)?\.?$",
        text,
    )
    may_reveal_graveyard_match = re.match(
        prefix
        + r"you may reveal (?P<count>a|an|one|two|three|up to one|up to two|any number of) "
        + r"(?P<phrase>.+?) cards? from among them and put (?:it|the revealed cards?) into your hand\. "
        + r"(?:then )?put the rest into your graveyard\.?$",
        text,
    )
    match = (
        simple_bottom_match
        or simple_graveyard_match
        or may_reveal_bottom_match
        or may_reveal_graveyard_match
    )
    if not match:
        return "look_library_pick_oracle_not_simple"
    look_count = word_count_value(match.group("look"))
    if look_count is None or look_count <= 0:
        return "look_library_pick_oracle_look_count_not_supported"

    count_token = str(match.group("count") or "").strip().lower()
    pick_all_matching = count_token == "any number of"
    may_reveal_match = may_reveal_bottom_match or may_reveal_graveyard_match
    pick_up_to_count = bool(may_reveal_match)
    if pick_all_matching:
        pick_count = look_count
    elif count_token in {"a", "an"}:
        pick_count = 1
    elif count_token.startswith("up to "):
        pick_count = word_count_value(count_token.removeprefix("up to "))
    else:
        pick_count = word_count_value(count_token)
    if pick_count is None or pick_count <= 0:
        return "look_library_pick_oracle_pick_count_not_supported"

    pick_target = "any_card"
    if may_reveal_match:
        pick_target = library_pick_target_from_phrase(may_reveal_match.group("phrase"))
        if pick_target is None:
            return "look_library_pick_oracle_target_not_supported"

    return {
        "look_count": int(look_count),
        "pick_count": int(pick_count),
        "pick_target": pick_target,
        "pick_up_to_count": pick_up_to_count,
        "pick_all_matching": pick_all_matching,
        "rest_destination": "graveyard"
        if simple_graveyard_match or may_reveal_graveyard_match
        else "library_bottom",
    }


def look_library_pick_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    filtered_match = re.search(
        r"LookLibraryAndPickControllerEffect\s*\(\s*(?P<look>\d+)\s*,\s*"
        r"(?P<pick>\d+|Integer\.MAX_VALUE)\s*,\s*(?P<filter>[^,]+)\s*,\s*"
        r"PutCards\.HAND\s*,\s*PutCards\.(?P<rest>BOTTOM_ANY|BOTTOM_RANDOM|GRAVEYARD)",
        text,
        re.S,
    )
    unfiltered_match = re.search(
        r"LookLibraryAndPickControllerEffect\s*\(\s*(?P<look>\d+)\s*,\s*"
        r"(?P<pick>\d+|Integer\.MAX_VALUE)\s*,\s*PutCards\.HAND\s*,\s*"
        r"PutCards\.(?P<rest>BOTTOM_ANY|BOTTOM_RANDOM|GRAVEYARD)",
        text,
        re.S,
    )
    match = filtered_match or unfiltered_match
    if not match:
        return "look_library_pick_source_effect_not_supported"
    pick_raw = match.group("pick")
    look_count = int(match.group("look"))
    pick_all_matching = pick_raw == "Integer.MAX_VALUE"
    pick_count = look_count if pick_all_matching else int(pick_raw)
    pick_target = "any_card"
    if filtered_match:
        pick_target = library_pick_target_from_source(text, filtered_match.group("filter"))
        if pick_target is None:
            return "look_library_pick_source_target_not_supported"
    rest = str(match.group("rest"))
    result = {
        "look_count": look_count,
        "pick_count": pick_count,
        "pick_target": pick_target,
        "pick_all_matching": pick_all_matching,
        "rest_destination": "graveyard" if rest == "GRAVEYARD" else "library_bottom",
    }
    if rest != "GRAVEYARD":
        result["library_bottom_order"] = "random" if rest == "BOTTOM_RANDOM" else "any"
    return result


def etb_recursion_to_hand_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text_after_leading_static_keywords(metadata)
    trigger_prefix = r"^when (?:this creature|[^,]+?) enters(?: the battlefield)?, (?:you may )?"
    mana_value_match = re.match(
        trigger_prefix
        + r"return target (?P<phrase>.+?) card with (?:mana value|converted mana cost) "
        r"(?P<mana_value_max>\d+) or less from your graveyard to your hand\.?$",
        text,
    )
    if mana_value_match:
        target_type = etb_recursion_target_from_phrase(mana_value_match.group("phrase"))
        if target_type is None:
            return None
        return {
            "target": target_type,
            "count": 1,
            "up_to_count": False,
            "mana_value_max": int(mana_value_match.group("mana_value_max")),
        }
    single_match = re.match(
        trigger_prefix
        + r"return target (?P<phrase>.+?) card from your graveyard to your hand\.?$",
        text,
    )
    if single_match:
        target_type = etb_recursion_target_from_phrase(single_match.group("phrase"))
        if target_type is not None:
            return {"target": target_type, "count": 1, "up_to_count": False}
    up_to_match = re.match(
        trigger_prefix
        + r"return up to (?P<count>one|two|\d+) target (?P<phrase>.+?) cards? "
        r"from your graveyard to your hand\.?$",
        text,
    )
    if up_to_match:
        target_type = etb_recursion_target_from_phrase(up_to_match.group("phrase"))
        count = word_count_value(up_to_match.group("count"))
        if target_type is not None and count is not None:
            return {"target": target_type, "count": count, "up_to_count": True}
    return None


def etb_recursion_to_battlefield_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text_after_leading_static_keywords(metadata)
