def etb_library_pick_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = oracle_text_after_leading_static_keywords(metadata)
    text = re.sub(
        r"^when (?:this creature|[^,]+?) enters(?: the battlefield)?,\s*",
        "",
        text,
    )
    pseudo_metadata = dict(metadata)
    pseudo_metadata["oracle_text"] = text
    parsed = look_library_pick_from_oracle(pseudo_metadata)
    if isinstance(parsed, dict):
        return parsed
    match = re.match(
        r"^look at the top (?P<look>\w+) cards of your library(?:, then|\.) "
        + r"put one of (?:them|those cards) into your hand and "
        + r"(?:the other|the rest) into your graveyard\.?$",
        text,
    )
    if not match:
        return "etb_library_pick_oracle_not_simple"
    look_count = word_count_value(match.group("look"))
    if look_count is None or look_count <= 0:
        return "etb_library_pick_oracle_look_count_not_supported"
    return {
        "look_count": look_count,
        "pick_count": 1,
        "pick_target": "any_card",
        "rest_destination": "graveyard",
    }


def etb_library_pick_from_source(source: str) -> dict[str, Any] | str:
    parsed = look_library_pick_from_source(source)
    if isinstance(parsed, str):
        return parsed.replace("look_library_pick", "etb_library_pick")
    return parsed


def dies_recursion_to_hand_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = oracle_text_after_leading_static_keywords(metadata)
    match = re.match(
        r"^when [^,]+ dies, return (?P<another>another )?target (?P<phrase>.+?) "
        r"cards? from your graveyard to your hand\.?$",
        text,
    )
    if not match:
        return None
    target_type = etb_recursion_target_from_phrase(match.group("phrase"))
    if target_type is None:
        return None
    return {
        "target": target_type,
        "count": 1,
        "exclude_self": bool(match.group("another")),
    }


UNSUPPORTED_SIMPLE_MANA_ORACLE_TOKENS = {
    "sacrifice",
    "discard",
    "pay ",
    "instead",
    "if ",
    "for each",
    "spend this mana only",
    "tap an untapped",
}


def normalized_oracle_lines(metadata: dict[str, Any]) -> list[str]:
    raw_text = str(metadata.get("oracle_text") or "").strip().lower()
    lines = []
    for raw_line in raw_text.splitlines():
        line = strip_parenthetical_reminders(re.sub(r"\s+", " ", raw_line.strip())).strip()
        if line:
            lines.append(line)
    return lines


def is_resolution_neutral_auxiliary_oracle_line(line: str) -> bool:
    normalized = re.sub(r"\s+", " ", line or "").strip().strip(".").lower()
    if not normalized:
        return False
    return bool(
        re.match(
            r"^(?:"
            r"affinity for artifacts|assist|(?:this spell )?can['’]t be countered|convoke|cycling|devoid|"
            r"flashback|foretell|freerunning|legendary|madness|miracle|retrace|"
            r"spectacle|split second|surge|suspend|undaunted"
            r")\b",
            normalized,
        )
    )


def oracle_effect_lines_without_neutral_auxiliary(metadata: dict[str, Any]) -> list[str]:
    return [
        line
        for line in normalized_oracle_lines(metadata)
        if not is_resolution_neutral_auxiliary_oracle_line(line)
    ]


def _unique_mana_symbols(symbols: list[str]) -> str:
    return "".join(dict.fromkeys(symbols))


def _brace_mana_symbols(text: str) -> list[str]:
    return [symbol.upper() for symbol in re.findall(r"\{([wubrgc])\}", text)]


def mana_detail_from_add_phrase(mana_phrase: str) -> dict[str, Any] | None:
    normalized = re.sub(r"\s+", " ", str(mana_phrase or "").strip().lower()).strip(".")
    any_color_amounts = {
        "one mana of any color": 1,
        "one mana of any one color": 1,
        "two mana of any color": 2,
        "two mana of any one color": 2,
        "two mana in any combination of colors": 2,
        "three mana of any color": 3,
        "three mana of any one color": 3,
        "three mana in any combination of colors": 3,
    }
    if normalized in any_color_amounts:
        return {
            "produces": "WUBRG",
            "mana_produced": any_color_amounts[normalized],
        }
    produced_symbols = _brace_mana_symbols(normalized)
    if not produced_symbols:
        return None
    return {
        "produces": _unique_mana_symbols(produced_symbols),
        "mana_produced": len(produced_symbols),
        "produced_mana_symbols": produced_symbols,
    }


def simple_mana_source_costs_from_phrase(cost_phrase: str) -> dict[str, Any] | None:
    requires_tap = False
    activation_symbols: list[str] = []
    activation_life_cost = 0
    tokens = [
        re.sub(r"\s+", " ", token.strip().lower())
        for token in str(cost_phrase or "").split(",")
        if token.strip()
    ]
    if not tokens:
        return None
    for token in tokens:
        if token == "{t}":
            requires_tap = True
            continue
        life_match = re.fullmatch(r"pay (?P<life>\d+) life", token)
        if life_match:
            activation_life_cost += int(life_match.group("life"))
            continue
        if re.fullmatch(r"(?:\{[0-9wubrgc]+\})+", token):
            activation_symbols.extend(
                symbol.upper()
                for symbol in re.findall(r"\{([0-9wubrgc]+)\}", token)
                if symbol.lower() != "t"
            )
            if "{t}" in token:
                requires_tap = True
            continue
        return None
    detail: dict[str, Any] = {"mana_activation_requires_tap": requires_tap}
    if activation_symbols:
        detail["activation_mana_cost"] = "".join(f"{{{symbol}}}" for symbol in activation_symbols)
    if activation_life_cost:
        detail["activation_life_cost"] = activation_life_cost
    return detail


def simple_mana_detail_from_add_phrase(mana_phrase: str) -> dict[str, Any] | None:
    normalized = re.sub(r"\s+", " ", str(mana_phrase or "").strip().lower()).strip(".")
    choice_match = re.fullmatch(
        r"\{[wubrgc]\}(?:,\s*\{[wubrgc]\})*(?:,?\s*or\s*\{[wubrgc]\})",
        normalized,
    )
    if choice_match:
        symbols = _brace_mana_symbols(normalized)
        if not symbols:
            return None
        return {
            "produces": _unique_mana_symbols(symbols),
            "mana_produced": 1,
        }
    fixed_symbols = _brace_mana_symbols(normalized)
    if fixed_symbols and re.fullmatch(r"(?:\{[wubrgc]\})+", normalized):
        return {
            "produces": _unique_mana_symbols(fixed_symbols),
            "mana_produced": len(fixed_symbols),
            "produced_mana_symbols": fixed_symbols,
        }
    return mana_detail_from_add_phrase(normalized)


def add_simple_mana_source_common_details(
    detail: dict[str, Any],
    *,
    activation_limit_per_turn: int | None = None,
) -> dict[str, Any]:
    if activation_limit_per_turn:
        detail["activation_limit_per_turn"] = activation_limit_per_turn
    return detail


def simple_mana_source_detail_from_generic_line(
    text: str,
    *,
    activation_limit_per_turn: int | None = None,
) -> dict[str, Any] | None:
    match = re.match(r"^(?P<costs>.+?): add (?P<mana>.+?)\.?$", text)
    if not match:
        return None
    cost_detail = simple_mana_source_costs_from_phrase(match.group("costs"))
    mana_detail = simple_mana_detail_from_add_phrase(match.group("mana"))
    if cost_detail is None or mana_detail is None:
        return None
    return add_simple_mana_source_common_details(
        {**mana_detail, **cost_detail},
        activation_limit_per_turn=activation_limit_per_turn,
    )


def simple_mana_source_detail_from_line(text: str) -> dict[str, Any] | None:
    working_text = strip_parenthetical_reminders(
        re.sub(r"\s+", " ", str(text or "").strip().lower())
    ).strip()
    unsupported_tokens = set(UNSUPPORTED_SIMPLE_MANA_ORACLE_TOKENS)
    if re.search(r"(?:^|,\s*)pay \d+ life(?=[:,])", working_text):
        unsupported_tokens.discard("pay ")
    if any(token in working_text for token in unsupported_tokens):
        return None
    activation_limit_per_turn = None
    once_each_turn_suffix = " activate only once each turn."
    if working_text.endswith(once_each_turn_suffix):
        activation_limit_per_turn = 1
        working_text = working_text[: -len(once_each_turn_suffix)].strip().rstrip(".") + "."
    if re.search(r"(?:^|,\s*)pay \d+ life(?=[:,])", working_text):
        generic_detail = simple_mana_source_detail_from_generic_line(
            working_text,
            activation_limit_per_turn=activation_limit_per_turn,
        )
        if generic_detail is not None:
            return generic_detail
    if working_text == "{t}: add one mana of any color.":
        detail = {"produces": "WUBRG", "mana_produced": 1, "mana_activation_requires_tap": True}
        if activation_limit_per_turn:
            detail["activation_limit_per_turn"] = activation_limit_per_turn
        return detail
    match = re.match(r"^\{t\}: add \{([wubrgc])\}\.?$", working_text)
    if match:
        symbol = match.group(1).upper()
        detail = {
            "produces": symbol,
            "mana_produced": 1,
            "produced_mana_symbols": [symbol],
            "mana_activation_requires_tap": True,
        }
        if activation_limit_per_turn:
            detail["activation_limit_per_turn"] = activation_limit_per_turn
        return detail
    match = re.match(r"^\{t\}: add ((?:\{[wubrgc]\}){2,})\.?$", working_text)
    if match:
        symbols = _brace_mana_symbols(match.group(1))
        if len(symbols) >= 2:
            detail = {
                "produces": _unique_mana_symbols(symbols),
                "mana_produced": len(symbols),
                "produced_mana_symbols": symbols,
                "mana_activation_requires_tap": True,
            }
            if activation_limit_per_turn:
                detail["activation_limit_per_turn"] = activation_limit_per_turn
            return detail
    match = re.match(r"^(?P<cost>(?:\{[0-9wubrgc]+\})+), \{t\}: add (?P<mana>(?:\{[wubrgc]\})+)\.?$", working_text)
    if match:
        symbols = _brace_mana_symbols(match.group("mana"))
        if symbols:
            detail = {
                "produces": _unique_mana_symbols(symbols),
                "mana_produced": len(symbols),
                "produced_mana_symbols": symbols,
                "activation_mana_cost": match.group("cost").upper(),
                "mana_activation_requires_tap": True,
            }
            if activation_limit_per_turn:
                detail["activation_limit_per_turn"] = activation_limit_per_turn
            return detail
    match = re.match(r"^(?P<cost>(?:\{[0-9wubrgc]+\})+), \{t\}: add one mana of any color\.?$", working_text)
    if match:
        detail = {
            "produces": "WUBRG",
            "mana_produced": 1,
            "activation_mana_cost": match.group("cost").upper(),
            "mana_activation_requires_tap": True,
        }
        if activation_limit_per_turn:
            detail["activation_limit_per_turn"] = activation_limit_per_turn
        return detail
    match = re.match(r"^(?P<cost>(?:\{[0-9wubrgc]+\})+): add one mana of any color\.?$", working_text)
    if match:
        detail = {
            "produces": "WUBRG",
            "mana_produced": 1,
            "activation_mana_cost": match.group("cost").upper(),
            "mana_activation_requires_tap": False,
        }
        if activation_limit_per_turn:
            detail["activation_limit_per_turn"] = activation_limit_per_turn
        return detail
    match = re.match(r"^(?P<cost>(?:\{[0-9wubrgc]+\})+): add (?P<mana>(?:\{[wubrgc]\})+)\.?$", working_text)
    if match:
        symbols = _brace_mana_symbols(match.group("mana"))
        if symbols:
            detail = {
                "produces": _unique_mana_symbols(symbols),
                "mana_produced": len(symbols),
                "produced_mana_symbols": symbols,
                "activation_mana_cost": match.group("cost").upper(),
                "mana_activation_requires_tap": False,
            }
            if activation_limit_per_turn:
                detail["activation_limit_per_turn"] = activation_limit_per_turn
            return detail
    match = re.match(
        r"^(?P<cost>(?:\{[0-9wubrgc]+\})+): add (?P<choices>\{[wubrgc]\}(?:, \{[wubrgc]\})*(?:,? or \{[wubrgc]\}))\.?$",
        working_text,
    )
    if match:
        detail = {
            "produces": _unique_mana_symbols(_brace_mana_symbols(match.group("choices"))),
            "mana_produced": 1,
            "activation_mana_cost": match.group("cost").upper(),
            "mana_activation_requires_tap": False,
        }
        if activation_limit_per_turn:
            detail["activation_limit_per_turn"] = activation_limit_per_turn
        return detail
    match = re.match(
        r"^\{t\}: add (?P<choices>\{[wubrgc]\}(?:, \{[wubrgc]\})*(?:,? or \{[wubrgc]\}))\.?$",
        working_text,
    )
    if match:
        produced = _unique_mana_symbols(_brace_mana_symbols(match.group("choices")))
        detail = {"produces": produced, "mana_produced": 1, "mana_activation_requires_tap": True}
        if activation_limit_per_turn:
            detail["activation_limit_per_turn"] = activation_limit_per_turn
        return detail
    return None


def sacrifice_mana_source_detail_from_line(text: str) -> dict[str, Any] | None:
    normalized = strip_parenthetical_reminders(re.sub(r"\s+", " ", str(text or "").strip().lower())).strip()
    prefix_match = re.match(
        r"^(?P<costs>(?:\{(?:t|[0-9wubrgc]+)\},\s*)*)sacrifice [^:]+: add (?P<mana>[^.]+)(?P<tail>\..*)?$",
        normalized,
    )
    if not prefix_match:
        return None
    costs = prefix_match.group("costs") or ""
    mana_phrase = prefix_match.group("mana").strip()
    tail = (prefix_match.group("tail") or "").strip()
    requires_tap = "{t}" in costs
    activation_symbols = [
        symbol.upper()
        for symbol in re.findall(r"\{([0-9wubrgc]+)\}", costs)
        if symbol.lower() != "t"
    ]
    activation_mana_cost = "".join(f"{{{symbol}}}" for symbol in activation_symbols)
    detail = mana_detail_from_add_phrase(mana_phrase)
    if detail is None:
        return None
    detail["mana_activation_requires_tap"] = requires_tap
    detail["mana_activation_requires_sacrifice"] = True
    if activation_mana_cost:
        detail["activation_mana_cost"] = activation_mana_cost
    if tail:
        detail["_runtime_partial_sacrifice_mana_tail"] = tail.lstrip(".").strip()
    return detail


def target_sacrifice_mana_source_detail_from_line(text: str) -> dict[str, Any] | None:
    normalized = strip_parenthetical_reminders(re.sub(r"\s+", " ", str(text or "").strip().lower())).strip()
    match = re.match(
        r"^(?P<costs>(?:\{(?:t|[0-9wubrgc]+)\},\s*)*)sacrifice (?P<phrase>[^:]+): (?P<effect>.+?)\.?$",
        normalized,
    )
    if not match:
        return None
    sacrifice_target = activation_sacrifice_target_from_phrase(match.group("phrase"))
    if sacrifice_target is None:
        return None
    effect_text = match.group("effect").strip()
    mana_phrase = None
    add_match = re.match(r"^add (?P<mana>.+?)\.?$", effect_text)
    if add_match:
        mana_phrase = add_match.group("mana")
    else:
        chosen_player_match = re.match(
            r"^choose a player\. that player adds (?P<mana>.+?)\.?$",
            effect_text,
        )
        if chosen_player_match:
            mana_phrase = chosen_player_match.group("mana")
    if mana_phrase is None:
        return None
    detail = mana_detail_from_add_phrase(mana_phrase)
    if detail is None:
        return None
    costs = match.group("costs") or ""
    activation_symbols = [
        symbol.upper()
        for symbol in re.findall(r"\{([0-9wubrgc]+)\}", costs)
        if symbol.lower() != "t"
    ]
    detail["mana_activation_requires_tap"] = "{t}" in costs
    detail["activation_sacrifice_target"] = sacrifice_target
    detail["activation_requires_sacrifice_target"] = True
    if activation_symbols:
        detail["activation_mana_cost"] = "".join(f"{{{symbol}}}" for symbol in activation_symbols)
    return detail


def target_sacrifice_mana_source_detail_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    candidates = []
    for line in normalized_oracle_lines(metadata):
        line_detail = target_sacrifice_mana_source_detail_from_line(line)
        if line_detail is not None:
            candidates.append(line_detail)
            continue
        if "sacrifice " in line and "add " in line:
            return None
    if len(candidates) == 1:
        return candidates[0]
    return None


def sacrifice_mana_source_detail_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    detail = sacrifice_mana_source_detail_from_line(text)
    if detail is not None:
        return detail

    candidates = []
    for line in normalized_oracle_lines(metadata):
        line_detail = sacrifice_mana_source_detail_from_line(line)
        if line_detail is not None:
            candidates.append(line_detail)
            continue
        if "sacrifice " in line and "add " in line:
            return None
    if len(candidates) == 1:
        return candidates[0]
    return None


def fixed_mana_symbols_from_braces(text: str) -> list[str]:
    symbols = re.findall(r"\{([WUBRGC])\}", str(text or "").upper())
    return [symbol for symbol in symbols if symbol in JAVA_MANA_METHOD_SYMBOLS.values()]


def etb_fixed_mana_detail_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    candidates: list[dict[str, Any]] = []
    for line in normalized_oracle_lines(metadata):
        if "whenever " in line or "at the beginning " in line:
            if "enters" in line and "add " in line:
                return None
            continue
        match = re.fullmatch(
            r"when (?:(?:this|that) creature|(?:this|that) permanent|[^,.]+) "
            r"enters(?: the battlefield)?, "
            r"(?:(?P<condition>if you cast it(?: from your hand)?), )?"
            r"add (?P<mana>(?:\{[wubrgc]\})+)\.?",
            line,
        )
        if not match:
            if "enters" in line and "add " in line:
                return None
            continue
        condition_text = str(match.group("condition") or "").strip()
        etb_mana_condition = None
        if condition_text == "if you cast it from your hand":
            etb_mana_condition = "cast_from_hand"
        elif condition_text == "if you cast it":
            etb_mana_condition = "cast"
        elif condition_text:
            return None
        produced_symbols = fixed_mana_symbols_from_braces(match.group("mana"))
        if not produced_symbols:
            return None
        detail = {
            "produces": _unique_mana_symbols(produced_symbols),
            "mana_produced": len(produced_symbols),
            "produced_mana_symbols": produced_symbols,
        }
        if etb_mana_condition:
            detail["etb_mana_condition"] = etb_mana_condition
        candidates.append(detail)
    if len(candidates) == 1:
        return candidates[0]
    return None


def dies_fixed_mana_detail_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    candidates: list[dict[str, Any]] = []
    for line in normalized_oracle_lines(metadata):
        if " if " in line or "whenever " in line or "you may " in line:
            if "dies" in line and "add " in line:
                return None
            continue
        match = re.fullmatch(
            r"when (?:(?:this|that) (?:creature|permanent|artifact creature)|[^,.]+) "
            r"dies, add (?P<mana>(?:\{[wubrgc]\})+)\.?",
            line,
        )
        if not match:
            if "dies" in line and "add " in line:
                return None
            continue
        produced_symbols = fixed_mana_symbols_from_braces(match.group("mana"))
        if not produced_symbols:
            return None
        candidates.append(
            {
                "produces": _unique_mana_symbols(produced_symbols),
                "mana_produced": len(produced_symbols),
                "produced_mana_symbols": produced_symbols,
            }
        )
    if len(candidates) == 1:
        return candidates[0]
    return None


JAVA_MANA_METHOD_SYMBOLS = {
    "White": "W",
    "Blue": "U",
    "Black": "B",
    "Red": "R",
    "Green": "G",
    "Colorless": "C",
}


def java_simple_mana_symbols_from_source(source_text: str) -> list[str] | None:
    text = source_text or ""
    method_match = re.search(
        r"Mana\.(White|Blue|Black|Red|Green|Colorless)Mana\s*\(\s*(\d+)\s*\)",
        text,
    )
    if method_match:
        return [JAVA_MANA_METHOD_SYMBOLS[method_match.group(1)]] * int(method_match.group(2))
    colored_constructor_match = re.search(
        r"new\s+Mana\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)",
        text,
    )
    if colored_constructor_match:
        return [colored_constructor_match.group(1)]
    constructor_match = re.search(r"new\s+Mana\s*\(\s*([0-9,\s]+)\)", text)
    if constructor_match:
        values = [int(value.strip()) for value in constructor_match.group(1).split(",") if value.strip()]
        symbols: list[str] = []
        for symbol, count in zip(["W", "U", "B", "R", "G", "C"], values[:6]):
            symbols.extend([symbol] * max(0, count))
        return symbols or None
    return None


def java_any_color_mana_amount_from_source(source_text: str) -> int | None:
    text = source_text or ""
    amount_match = re.search(r"new\s+AddManaOfAnyColorEffect\s*\(\s*(\d+)\s*\)", text)
    if amount_match:
        return int(amount_match.group(1))
    combination_match = re.search(r"new\s+AddManaInAnyCombinationEffect\s*\(\s*(\d+)\s*\)", text)
    if combination_match:
        return int(combination_match.group(1))
    if re.search(r"new\s+AnyColorManaAbility\s*\(", text):
        return 1
    return None


MANA_TYPE_TO_SYMBOL = {
    "WHITE": "W",
    "BLUE": "U",
    "BLACK": "B",
    "RED": "R",
    "GREEN": "G",
    "COLORLESS": "C",
}


def limited_times_add_any_color_amount_from_source(source_text: str, args_text: str) -> tuple[int, str] | None:
    if "AddManaOfAnyColorEffect" in args_text:
        amount_match = re.search(r"new\s+AddManaOfAnyColorEffect\s*\(\s*(\d*)\s*\)", args_text)
        if amount_match:
            return int(amount_match.group(1) or "1"), "AddManaOfAnyColorEffect"
    custom_match = re.search(r"new\s+([A-Za-z][A-Za-z0-9_]*)\s*\(\s*\)", args_text)
    if not custom_match:
        return None
    class_name = custom_match.group(1)
    class_match = re.search(
        rf"class\s+{re.escape(class_name)}\s+extends\s+AddManaOfAnyColorEffect\s*\{{(?P<body>.*?)\}}",
        source_text or "",
        re.S,
    )
    if not class_match:
        return None
    super_match = re.search(r"super\s*\(\s*(\d*)\s*\)", class_match.group("body"))
    return int((super_match.group(1) if super_match else "") or "1"), class_name


def limited_times_mana_source_detail_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    detail = simple_mana_source_detail_from_oracle(metadata)
    if detail is not None and int(detail.get("activation_limit_per_turn") or 0) == 1:
        return detail
    for line in normalized_oracle_lines(metadata):
        if "activate only once each turn" not in line:
            continue
        working = strip_parenthetical_reminders(line)
        match = re.match(
            r"^(?P<cost>(?:\{[0-9wubrgc]+\})+): add (?P<mana>one mana of any color|(?:\{[wubrgc]\})+)\. "
            r"(?P<tail>.+?) activate only once each turn\.?$",
            working,
        )
        if not match:
            continue
        if match.group("mana") == "one mana of any color":
            parsed = {"produces": "WUBRG", "mana_produced": 1}
        else:
            symbols = _brace_mana_symbols(match.group("mana"))
            if not symbols:
                continue
            parsed = {
                "produces": _unique_mana_symbols(symbols),
                "mana_produced": len(symbols),
                "produced_mana_symbols": symbols,
            }
        parsed["activation_mana_cost"] = match.group("cost").upper()
        parsed["mana_activation_requires_tap"] = False
        parsed["activation_limit_per_turn"] = 1
        parsed["_runtime_partial_mana_tail"] = match.group("tail").strip().rstrip(".")
        return parsed
    return None


def limited_times_color_choice_mana_source_from_source(source_text: str) -> dict[str, Any] | str | None:
    text = source_text or ""
    if "LimitedTimesPerTurnActivatedManaAbility" not in text:
        return None
    if len(re.findall(r"new\s+LimitedTimesPerTurnActivatedManaAbility\s*\(", text)) != 1:
        return "limited_mana_source_not_single"
    args_text = extract_constructor_args(text, "LimitedTimesPerTurnActivatedManaAbility")
    if args_text is None:
        return "limited_mana_source_constructor_not_supported"
    if (
        "ConditionalMana" in args_text
        or "ConditionalColoredManaAbility" in args_text
        or "ConditionalColorlessManaAbility" in args_text
    ):
        return "limited_mana_source_conditional_not_supported"
    cost_match = re.search(r"new\s+GenericManaCost\s*\(\s*(\d+)\s*\)", args_text)
    if not cost_match:
        return "limited_mana_source_cost_not_supported"
    if "AddManaFromColorChoicesEffect" in args_text:
        mana_types = [
            MANA_TYPE_TO_SYMBOL[token]
            for token in re.findall(r"ManaType\.([A-Z]+)", args_text)
            if token in MANA_TYPE_TO_SYMBOL
        ]
        if not mana_types:
            return "limited_mana_source_choices_not_fixed"
        return {
            "produces": _unique_mana_symbols(mana_types),
            "mana_produced": 1,
            "activation_mana_cost": f"{{{int(cost_match.group(1))}}}",
            "mana_activation_requires_tap": False,
            "activation_limit_per_turn": 1,
            "xmage_mana_effect_class": "AddManaFromColorChoicesEffect",
            "xmage_mana_ability_class": "LimitedTimesPerTurnActivatedManaAbility",
        }
    any_color = limited_times_add_any_color_amount_from_source(text, args_text)
    if any_color is not None:
        amount, effect_class = any_color
        return {
            "produces": "WUBRG",
            "mana_produced": amount,
            "activation_mana_cost": f"{{{int(cost_match.group(1))}}}",
            "mana_activation_requires_tap": False,
            "activation_limit_per_turn": 1,
            "xmage_mana_effect_class": effect_class,
            "xmage_mana_ability_class": "LimitedTimesPerTurnActivatedManaAbility",
        }
    if "BasicManaEffect" in args_text:
        symbols = java_simple_mana_symbols_from_source(args_text)
        if not symbols:
            return "limited_mana_source_choices_not_fixed"
        return {
            "produces": _unique_mana_symbols(symbols),
            "mana_produced": len(symbols),
            "produced_mana_symbols": symbols,
            "activation_mana_cost": f"{{{int(cost_match.group(1))}}}",
            "mana_activation_requires_tap": False,
            "activation_limit_per_turn": 1,
            "xmage_mana_effect_class": "BasicManaEffect",
            "xmage_mana_ability_class": "LimitedTimesPerTurnActivatedManaAbility",
        }
    return "limited_mana_source_effect_not_supported"


MANA_ABILITY_CLASS_SYMBOLS = {
    "WhiteManaAbility": "W",
    "BlueManaAbility": "U",
    "BlackManaAbility": "B",
    "RedManaAbility": "R",
    "GreenManaAbility": "G",
    "ColorlessManaAbility": "C",
}


def fixed_mana_symbols_from_ability_classes(ability_class_values: set[str]) -> list[str]:
    return [
        symbol
        for ability_class, symbol in MANA_ABILITY_CLASS_SYMBOLS.items()
        if ability_class in ability_class_values
    ]


def tap_and_self_sacrifice_mana_source_source_blocker(
    source_text: str,
    ability_class_values: set[str],
    tap_detail: dict[str, Any],
    sacrifice_detail: dict[str, Any],
) -> str | None:
    text = source_text or ""
    normal_symbols = fixed_mana_symbols_from_ability_classes(ability_class_values)
    expected_tap_symbols = list(tap_detail.get("produced_mana_symbols") or [])
    if len(normal_symbols) != 1 or len(expected_tap_symbols) != 1:
        return "tap_sacrifice_mana_source_normal_mana_not_single_fixed"
    if Counter(normal_symbols) != Counter(expected_tap_symbols):
        return "tap_sacrifice_mana_source_normal_mana_mismatch"
    if len(re.findall(r"new\s+SimpleManaAbility\s*\(", text)) != 1:
        return "tap_sacrifice_mana_source_sacrifice_not_single_simple_mana"
    if "SacrificeSourceCost" not in text:
        return "tap_sacrifice_mana_source_sacrifice_cost_missing"
    if "TapSourceCost" in text:
        return "tap_sacrifice_mana_source_sacrifice_tap_cost_not_supported"
    if sacrifice_detail.get("activation_mana_cost"):
        return "tap_sacrifice_mana_source_sacrifice_activation_cost_not_supported"
    source_symbols = java_simple_mana_symbols_from_source(text)
    expected_sacrifice_symbols = list(sacrifice_detail.get("produced_mana_symbols") or [])
    if source_symbols is None or not expected_sacrifice_symbols:
        return "tap_sacrifice_mana_source_sacrifice_mana_not_fixed"
    if Counter(source_symbols) != Counter(expected_sacrifice_symbols):
        return "tap_sacrifice_mana_source_sacrifice_mana_mismatch"
    return None


def sacrifice_mana_source_source_blocker(source_text: str, detail: dict[str, Any]) -> str | None:
    text = source_text or ""
    windows = [
        window
        for window in simple_mana_ability_windows(text)
        if "SacrificeSourceCost" in window
    ]
    if len(windows) != 1:
        return "mana_source_sacrifice_source_not_single_simple_mana"
    window = windows[0]
    simple_ability_count = len(re.findall(r"new\s+SimpleManaAbility\s*\(", window))
    any_color_ability_count = len(re.findall(r"new\s+AnyColorManaAbility\s*\(", window))
    if simple_ability_count + any_color_ability_count != 1:
        return "mana_source_sacrifice_source_not_single_simple_mana"
    if "SacrificeSourceCost" not in window:
        return "mana_source_sacrifice_source_cost_missing"
    requires_tap = bool(detail.get("mana_activation_requires_tap"))
    if requires_tap and "TapSourceCost" not in window and simple_ability_count > 0:
        return "mana_source_sacrifice_source_tap_cost_missing"
    if not requires_tap and "TapSourceCost" in window:
        return "mana_source_sacrifice_source_oracle_tap_mismatch"
    activation_mana_cost = str(detail.get("activation_mana_cost") or "")
    if activation_mana_cost:
        generic_match = re.fullmatch(r"\{(\d+)\}", activation_mana_cost)
        if generic_match:
            generic_cost = generic_match.group(1)
            if (
                f"GenericManaCost({generic_cost})" not in window
                and f'ManaCostsImpl<>("{activation_mana_cost}")' not in window
                and f"ManaCostsImpl<>(\"{activation_mana_cost}\")" not in window
            ):
                return "mana_source_sacrifice_source_activation_cost_mismatch"
        elif f'ManaCostsImpl<>("{activation_mana_cost}")' not in window:
            return "mana_source_sacrifice_source_activation_cost_mismatch"
    elif "GenericManaCost" in window or "ManaCostsImpl<>" in window:
        return "mana_source_sacrifice_source_activation_cost_mismatch"
    source_symbols = java_simple_mana_symbols_from_source(window)
    expected_symbols = list(detail.get("produced_mana_symbols") or [])
    if source_symbols is not None and expected_symbols and Counter(source_symbols) != Counter(expected_symbols):
        return "mana_source_sacrifice_source_mana_output_mismatch"
    if str(detail.get("produces") or "") == "WUBRG" and not expected_symbols:
        source_any_color_amount = java_any_color_mana_amount_from_source(window)
        if source_any_color_amount != int(detail.get("mana_produced") or 0):
            return "mana_source_sacrifice_source_mana_output_mismatch"
    return None


def simple_mana_ability_windows(source_text: str) -> list[str]:
    text = source_text or ""
    windows: list[str] = []
    positions = [
        match.start()
        for match in re.finditer(r"new\s+(?:SimpleManaAbility|AnyColorManaAbility)\b", text)
    ]
    for index, position in enumerate(positions):
        next_position = positions[index + 1] if index + 1 < len(positions) else len(text)
        end_candidates = [
            value
            for value in (
                text.find("\n        //", position + 1),
                text.find("\n        Ability ", position + 1),
                text.find("\n        this.addAbility", position + 1),
                next_position,
            )
            if value > position
        ]
        end = min(end_candidates) if end_candidates else min(len(text), position + 1600)
        windows.append(text[position:end])
    return windows


def target_sacrifice_mana_source_source_blocker(source_text: str, detail: dict[str, Any]) -> str | None:
    text = source_text or ""
    windows = [
        window
        for window in simple_mana_ability_windows(text)
        if "SacrificeTargetCost" in window
    ]
    if len(windows) != 1:
        return "target_sacrifice_mana_source_not_single_simple_mana"
    window = windows[0]
    if re.search(r"new\s+SacrificeTargetCost\s*\(\s*[2-9]\d*\s*,", window):
        return "target_sacrifice_mana_source_multi_sacrifice_not_supported"
    if len(re.findall(r"new\s+SacrificeTargetCost\s*\(", window)) != 1:
        return "target_sacrifice_mana_source_not_single_sacrifice_cost"
    source_sacrifice_target = activation_sacrifice_target_from_source(text, window)
    if source_sacrifice_target != detail.get("activation_sacrifice_target"):
        return "target_sacrifice_mana_source_sacrifice_target_mismatch"
    requires_tap = bool(detail.get("mana_activation_requires_tap"))
    if requires_tap and "TapSourceCost" not in window:
        return "target_sacrifice_mana_source_tap_cost_missing"
    if not requires_tap and "TapSourceCost" in window:
        return "target_sacrifice_mana_source_oracle_tap_mismatch"
    activation_mana_cost = str(detail.get("activation_mana_cost") or "")
    if activation_mana_cost:
        generic_match = re.fullmatch(r"\{(\d+)\}", activation_mana_cost)
        if generic_match:
            generic_cost = generic_match.group(1)
            if (
                f"GenericManaCost({generic_cost})" not in window
                and f'ManaCostsImpl<>("{activation_mana_cost}")' not in window
                and f"ManaCostsImpl<>(\"{activation_mana_cost}\")" not in window
            ):
                return "target_sacrifice_mana_source_activation_cost_mismatch"
        elif f'ManaCostsImpl<>("{activation_mana_cost}")' not in window:
            return "target_sacrifice_mana_source_activation_cost_mismatch"
    elif "GenericManaCost" in window or "ManaCostsImpl<>" in window:
        return "target_sacrifice_mana_source_activation_cost_mismatch"
    source_symbols = java_simple_mana_symbols_from_source(window) or java_simple_mana_symbols_from_source(text)
    expected_symbols = list(detail.get("produced_mana_symbols") or [])
    if source_symbols is not None and expected_symbols and Counter(source_symbols) != Counter(expected_symbols):
        return "target_sacrifice_mana_source_mana_output_mismatch"
    if str(detail.get("produces") or "") == "WUBRG" and not expected_symbols:
        source_any_color_amount = java_any_color_mana_amount_from_source(window) or java_any_color_mana_amount_from_source(text)
        if source_any_color_amount != int(detail.get("mana_produced") or 0):
            return "target_sacrifice_mana_source_mana_output_mismatch"
    elif source_symbols is None and expected_symbols:
        return "target_sacrifice_mana_source_mana_output_mismatch"
    return None


def etb_fixed_mana_source_blocker(source_text: str, detail: dict[str, Any]) -> str | None:
    text = source_text or ""
    if len(re.findall(r"new\s+EntersBattlefieldTriggeredAbility\s*\(", text)) != 1:
        return "etb_mana_source_not_single_etb_trigger"
    if len(re.findall(r"new\s+BasicManaEffect\s*\(", text)) != 1:
        return "etb_mana_source_not_single_basic_mana_effect"
    source_conditions = re.findall(
        r"\.withInterveningIf\s*\(\s*([A-Za-z0-9_.]+)\.instance\s*\)",
        text,
    )
    expected_condition = detail.get("etb_mana_condition")
    source_condition = None
    if len(source_conditions) > 1:
        return "etb_mana_source_condition_not_supported"
    if source_conditions:
        condition_class = source_conditions[0].split(".")[-1]
        if condition_class == "CastFromHandSourcePermanentCondition":
            source_condition = "cast_from_hand"
        elif condition_class == "CastFromEverywhereSourceCondition":
            source_condition = "cast"
        else:
            return "etb_mana_source_condition_not_supported"
    if expected_condition != source_condition:
        return "etb_mana_source_condition_mismatch"
    unsupported_markers = {
        "ConditionalManaEffect": "etb_mana_source_condition_not_supported",
        "ConditionalOneShotEffect": "etb_mana_source_condition_not_supported",
        "ConditionalContinuousEffect": "etb_mana_source_condition_not_supported",
        "DynamicManaEffect": "etb_mana_source_dynamic_not_supported",
        "AddConditionalManaEffect": "etb_mana_source_restricted_spend_not_supported",
        "Target": "etb_mana_source_target_not_supported",
    }
    for marker, reason in unsupported_markers.items():
        if marker in text:
            return reason
    source_symbols = java_simple_mana_symbols_from_source(text)
    expected_symbols = list(detail.get("produced_mana_symbols") or [])
    if source_symbols is None:
        return "etb_mana_source_output_not_fixed"
    if Counter(source_symbols) != Counter(expected_symbols):
        return "etb_mana_source_oracle_mismatch"
    return None


def dies_fixed_mana_source_blocker(source_text: str, detail: dict[str, Any]) -> str | None:
    text = source_text or ""
    if len(re.findall(r"new\s+DiesSourceTriggeredAbility\s*\(", text)) != 1:
        return "dies_mana_source_not_single_dies_trigger"
    if len(re.findall(r"new\s+BasicManaEffect\s*\(", text)) != 1:
        return "dies_mana_source_not_single_basic_mana_effect"
    unsupported_markers = {
        ".withInterveningIf": "dies_mana_source_condition_not_supported",
        "Conditional": "dies_mana_source_condition_not_supported",
        "DynamicManaEffect": "dies_mana_source_dynamic_not_supported",
        "Target": "dies_mana_source_target_not_supported",
    }
    for marker, reason in unsupported_markers.items():
        if marker in text:
            return reason
    if dies_source_trigger_is_optional(text):
        return "dies_mana_source_optional_not_supported"
    source_symbols = java_simple_mana_symbols_from_source(text)
    expected_symbols = list(detail.get("produced_mana_symbols") or [])
    if source_symbols is None:
        return "dies_mana_source_output_not_fixed"
    if Counter(source_symbols) != Counter(expected_symbols):
        return "dies_mana_source_oracle_mismatch"
    return None


def simple_mana_source_detail_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | None:
    text = strip_parenthetical_reminders(oracle_text(metadata))
    detail = simple_mana_source_detail_from_line(text)
    if detail is not None:
        return detail

    candidates = []
    for line in normalized_oracle_lines(metadata):
        line_detail = simple_mana_source_detail_from_line(line)
        if line_detail is not None:
            candidates.append(line_detail)
            continue
        if "add " in line and ("{t}" in line or "mana" in line):
            return None
    if len(candidates) == 1:
        return candidates[0]
    return None


def simple_mana_source_from_oracle(metadata: dict[str, Any]) -> tuple[str, int] | None:
    detail = simple_mana_source_detail_from_oracle(metadata)
    if detail is None:
        return None
    return str(detail["produces"]), int(detail["mana_produced"])


DIRECT_SAFE_MANA_ABILITY_CLASSES = SAFE_MANA_ABILITY_CLASSES - {"SimpleManaAbility"}


def has_direct_independent_safe_mana_ability(
    source_text: str,
    ability_class_values: set[str],
) -> bool:
    text = source_text or ""
    for ability_class in sorted(DIRECT_SAFE_MANA_ABILITY_CLASSES & ability_class_values):
        if re.search(rf"this\.addAbility\(new\s+{re.escape(ability_class)}\s*\(", text):
            return True

    if "SimpleManaAbility" not in ability_class_values:
        return False
    for match in re.finditer(r"this\.addAbility\(new\s+SimpleManaAbility\b", text):
        statement = text[match.start() : text.find(";", match.start()) + 1]
        if not statement:
            continue
        if not any(
            marker in statement
            for marker in (
                "SacrificeSourceCost",
                "SacrificeTargetCost",
                "Discard",
                "PayLifeCost",
                "ExileSourceCost",
                "ConditionalMana",
                "spend this mana only",
            )
        ):
            return True
    return False


def simple_mana_source_source_blocker(
    source_text: str,
    ability_class_values: set[str],
    mana_source_detail: dict[str, Any] | None = None,
    *,
    allow_auxiliary_sacrifice_cost_when_independent_mana: bool = False,
) -> str | None:
    text = source_text or ""
    has_independent_mana = (
        allow_auxiliary_sacrifice_cost_when_independent_mana
        and has_direct_independent_safe_mana_ability(text, ability_class_values)
    )
    unsupported_markers = {
        "SacrificeSourceCost": "mana_source_source_sacrifice_cost_not_supported",
        "SacrificeTargetCost": "mana_source_source_sacrifice_target_cost_not_supported",
        "Discard": "mana_source_source_discard_cost_not_supported",
        "ExileSourceCost": "mana_source_source_exile_cost_not_supported",
        "ConditionalMana": "mana_source_source_conditional_mana_not_supported",
        "spend this mana only": "mana_source_source_restricted_spend_not_supported",
    }
    for marker, reason in unsupported_markers.items():
        if marker in text:
            if marker == "SacrificeSourceCost" and has_independent_mana:
                continue
            return reason
    source_life_costs = [
        int(value)
        for value in re.findall(r"PayLifeCost\s*\(\s*(\d+)\s*\)", text)
    ]
    expected_life_cost = (
        int(mana_source_detail.get("activation_life_cost") or 0)
        if mana_source_detail is not None
        else 0
    )
    if source_life_costs:
        if expected_life_cost <= 0:
            return "mana_source_source_pay_life_cost_not_supported"
        if len(source_life_costs) != 1:
            return "mana_source_source_pay_life_cost_not_single"
        if source_life_costs[0] != expected_life_cost:
            return "mana_source_source_pay_life_cost_mismatch"
    elif expected_life_cost:
        return "mana_source_source_pay_life_cost_missing"
    if mana_source_detail is not None:
        requires_tap = bool(mana_source_detail.get("mana_activation_requires_tap", True))
        if "TapSourceCost" in text and not requires_tap:
            return "mana_source_source_oracle_tap_mismatch"
        if "SimpleManaAbility" in ability_class_values and "TapSourceCost" not in text and requires_tap:
            return "mana_source_simple_source_missing_tap_cost"
    return None


COUNT_WORDS = {
    "one": 1,
    "two": 2,
    "three": 3,
    "four": 4,
    "five": 5,
    "six": 6,
    "seven": 7,
    "eight": 8,
    "nine": 9,
    "ten": 10,
}


def _clean_library_tutor_phrase(phrase: str) -> str:
    normalized = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
    normalized = normalized.removesuffix(".")
    for prefix in ("a ", "an "):
        if normalized.startswith(prefix):
            normalized = normalized[len(prefix) :]
            break
    return normalized


def library_tutor_target_from_phrase(phrase: str) -> str | None:
    normalized = _clean_library_tutor_phrase(phrase)
    mapping = {
        "card": "any",
        "cards": "any",
        "basic land card": "basic_land",
        "basic land cards": "basic_land",
        "basic lands": "basic_land",
        "basic plains card": "basic_plains",
        "basic plains cards": "basic_plains",
        "basic land card or gate card": "basic_land_or_gate",
        "basic land card or a gate card": "basic_land_or_gate",
        "basic land cards and/or gate cards": "basic_land_or_gate",
        "basic lands and/or gates": "basic_land_or_gate",
        "basic land card or cave card": "basic_land_or_cave",
        "basic land card or a cave card": "basic_land_or_cave",
        "basic land cards and/or town cards with different names": "basic_land_or_town",
        "forest card": "forest",
        "forest cards": "forest",
        "plains card": "plains",
        "plains cards": "plains",
        "basic forest or island card": "basic_forest_or_island",
        "basic forest or island cards": "basic_forest_or_island",
        "land card": "land",
        "land cards": "land",
        "snow land card": "snow_land",
        "plains, island, swamp, or mountain card": "plains_island_swamp_or_mountain",
        "plains, island, swamp, mountain, or forest card": "basic_land_type",
        "instant card": "instant",
        "sorcery card": "sorcery",
        "instant or sorcery card": "instant_or_sorcery",
        "instant and/or sorcery card": "instant_or_sorcery",
        "creature card": "creature",
        "creature cards": "creature",
        "enchantment card": "enchantment",
        "enchantment cards": "enchantment",
        "planeswalker card": "planeswalker",
        "planeswalker cards": "planeswalker",
        "artifact card": "artifact",
        "artifact cards": "artifact",
    }
    return mapping.get(normalized)


def parse_library_tutor_query(query: str) -> dict[str, Any] | None:
    text = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if "less than or equal to the number of lands you control" in text:
        return None
    if "white card, a blue card, a black card, a red card, and a green card" in text:
        return None
    if " and a " in text and any(marker in text for marker in ("basic forest", "basic plains")):
        return None
    up_to = False
    count = 1
    phrase = text
    match = re.match(r"^up to (?P<count>\w+) (?P<phrase>.+)$", text)
    if match:
        count_text = match.group("count")
        count = COUNT_WORDS.get(count_text) or (int(count_text) if count_text.isdigit() else 0)
        up_to = True
        phrase = match.group("phrase")
    else:
        any_number_match = re.match(r"^any number of (?P<phrase>.+)$", phrase)
        if any_number_match:
            count = 99
            up_to = True
            phrase = any_number_match.group("phrase")
    phrase = _clean_library_tutor_phrase(phrase)
    parsed: dict[str, Any] = {"count": count, "up_to_count": up_to}

    if "targetcardwithdifferentname" in phrase:
        return None
    if " with different names" in phrase or " that each have different names" in phrase:
        parsed["requires_different_names"] = True
        phrase = phrase.replace(" that each have different names", "")
        phrase = phrase.replace(" with different names", "")
    if " not named " in phrase:
        return None

    named_match = re.fullmatch(r"cards? named (?P<name>.+)", phrase)
    if named_match:
        parsed["target"] = "any"
        parsed["target_names"] = [
            name.strip()
            for name in re.split(r"\s+or\s+", named_match.group("name").strip())
            if name.strip()
        ]
        return parsed if count > 0 else None

    mana_value_match = re.fullmatch(
        r"(?P<card_type>artifact|creature|instant|sorcery|enchantment|planeswalker|permanent) cards? "
        r"with mana value (?P<first>\d+)(?: or (?P<second>\d+)| or less)?",
        phrase,
    )
    if mana_value_match:
        parsed["target"] = "any" if mana_value_match.group("card_type") == "permanent" else mana_value_match.group("card_type")
        parsed["target_card_types"] = (
            ["artifact", "creature", "enchantment", "planeswalker", "land", "battle"]
            if mana_value_match.group("card_type") == "permanent"
            else [mana_value_match.group("card_type")]
        )
        first = int(mana_value_match.group("first"))
        second = mana_value_match.group("second")
        if second is not None:
            values = sorted([first, int(second)])
            parsed["target_mana_value_min"] = values[0]
            parsed["target_mana_value_max"] = values[1]
        elif phrase.endswith("or less"):
            parsed["target_mana_value_max"] = first
        else:
            parsed["target_mana_value_min"] = first
            parsed["target_mana_value_max"] = first
        return parsed if count > 0 else None

    exact_specs: dict[str, dict[str, Any]] = {
        "artifact card": {"target": "artifact", "target_card_types": ["artifact"]},
        "artifact cards": {"target": "artifact", "target_card_types": ["artifact"]},
        "creature card": {"target": "creature", "target_card_types": ["creature"]},
        "creature cards": {"target": "creature", "target_card_types": ["creature"]},
        "enchantment card": {"target": "enchantment", "target_card_types": ["enchantment"]},
        "enchantment cards": {"target": "enchantment", "target_card_types": ["enchantment"]},
        "instant card": {"target": "instant", "target_card_types": ["instant"]},
        "instant or sorcery card": {"target": "instant_or_sorcery"},
        "instant and/or sorcery card": {"target": "instant_or_sorcery"},
        "land card": {"target": "land", "target_card_types": ["land"]},
        "land cards": {"target": "land", "target_card_types": ["land"]},
        "planeswalker card": {"target": "planeswalker", "target_card_types": ["planeswalker"]},
        "planeswalker cards": {"target": "planeswalker", "target_card_types": ["planeswalker"]},
        "permanent card": {
            "target": "any",
            "target_card_types": ["artifact", "creature", "enchantment", "planeswalker", "land", "battle"],
        },
        "permanent cards": {
            "target": "any",
            "target_card_types": ["artifact", "creature", "enchantment", "planeswalker", "land", "battle"],
        },
        "sorcery card": {"target": "sorcery", "target_card_types": ["sorcery"]},
        "basic forest card": {"target": "forest", "required_supertypes": ["basic"]},
        "basic forest cards": {"target": "forest", "required_supertypes": ["basic"]},
        "basic land card or cave": {"target": "basic_land_or_cave"},
        "basic land card or cave card": {"target": "basic_land_or_cave"},
        "aura card": {"target": "any", "target_subtypes": ["aura"]},
        "aura cards": {"target": "any", "target_subtypes": ["aura"]},
        "aura or equipment card": {"target": "any", "target_subtypes": ["aura", "equipment"]},
        "equipment or vehicle card": {"target": "any", "target_subtypes": ["equipment", "vehicle"]},
        "forest or plains card": {"target": "land", "target_card_types": ["land"], "target_subtypes": ["forest", "plains"]},
        "dragon card": {"target": "any", "target_subtypes": ["dragon"]},
        "dragon cards": {"target": "any", "target_subtypes": ["dragon"]},
        "dragon creature card": {"target": "creature", "target_card_types": ["creature"], "target_subtypes": ["dragon"]},
        "goblin card": {"target": "any", "target_subtypes": ["goblin"]},
        "goblin cards": {"target": "any", "target_subtypes": ["goblin"]},
        "mercenary card": {"target": "any", "target_card_types": ["creature"], "target_subtypes": ["mercenary"]},
        "arcane card": {"target": "any", "target_subtypes": ["arcane"]},
        "trap card": {"target": "any", "target_subtypes": ["trap"]},
        "legendary card": {"target": "any", "required_supertypes": ["legendary"]},
        "legendary creature card": {
            "target": "creature",
            "target_card_types": ["creature"],
            "required_supertypes": ["legendary"],
        },
        "blue instant card": {"target": "instant", "target_card_types": ["instant"], "target_colors": ["U"]},
    }
    if phrase in exact_specs:
        parsed.update(exact_specs[phrase])
        return parsed if count > 0 else None

    subtype_permanent_match = re.fullmatch(
        r"(?P<subtype>[a-z][a-z' -]+?) permanent cards?(?: with mana value (?P<mv>\d+) or less)?",
        phrase,
    )
    if subtype_permanent_match:
        parsed["target"] = "any"
        parsed["target_card_types"] = ["artifact", "creature", "enchantment", "planeswalker", "land", "battle"]
        parsed["target_subtypes"] = [subtype_permanent_match.group("subtype").strip()]
        if subtype_permanent_match.group("mv") is not None:
            parsed["target_mana_value_max"] = int(subtype_permanent_match.group("mv"))
        return parsed if count > 0 else None

    target = library_tutor_target_from_phrase(phrase)
    if target is not None and count > 0:
        parsed["target"] = target
        return parsed

    subtype_card_match = re.fullmatch(
        r"(?P<subtype>[a-z][a-z' -]+?) cards?",
        phrase,
    )
    if subtype_card_match:
        parsed["target"] = "any"
        parsed["target_subtypes"] = [subtype_card_match.group("subtype").strip()]
        return parsed if count > 0 else None

    return None


def library_tutor_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = oracle_text(metadata)
    if "additional cost" in text:
        return "library_tutor_oracle_additional_cost_not_supported"
    top_match = re.match(
        r"^search your library for (?P<query>.+?), reveal it, then shuffle and put that card on top\.?$",
        text,
    )
    if top_match:
        parsed = parse_library_tutor_query(top_match.group("query"))
        if parsed is None:
            return "library_tutor_oracle_target_not_supported"
        parsed["destination"] = "library_top"
        parsed["enters_tapped"] = False
        return parsed

    hand_match = re.match(
        r"^search your library for (?P<query>.+?)"
        r"(?:, reveal (?:it|that card|them|those cards))?, put "
        r"(?:it|that card|them|those cards) into your hand, "
        r"then shuffle(?: your library)?\.?$",
        text,
    )
    if hand_match:
        parsed = parse_library_tutor_query(hand_match.group("query"))
        if parsed is None:
            return "library_tutor_oracle_target_not_supported"
        parsed["destination"] = "hand"
        parsed["enters_tapped"] = False
        return parsed

    battle_match = re.match(
        r"^search your library for (?P<query>.+?)(?:,| and) put "
        r"(?:it|that card|them|those cards) onto the battlefield(?P<tapped> tapped)?"
        r"(?:, then shuffle|\. then shuffle)\.?$",
        text,
    )
    if battle_match:
        parsed = parse_library_tutor_query(battle_match.group("query"))
        if parsed is None:
            return "library_tutor_oracle_target_not_supported"
        parsed["destination"] = "battlefield"
        parsed["enters_tapped"] = bool(battle_match.group("tapped"))
        return parsed
    return "library_tutor_oracle_not_simple"


def etb_library_tutor_to_battlefield_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(oracle_text_after_leading_static_keywords(metadata))
    text = re.sub(r"\s+", " ", text).strip()
    if " if " in f" {text} " or " additional cost " in f" {text} ":
        return "etb_library_tutor_oracle_not_simple"
    match = re.fullmatch(
        r"(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+"
        r"(?:you may )?search your library for (?P<query>.+?)(?:,| and) put "
        r"(?:it|that card|them|those cards) onto the battlefield(?P<tapped> tapped)?, "
        r"then shuffle(?: your library)?\.?",
        text,
    )
    if not match:
        return "etb_library_tutor_oracle_not_simple"
    parsed = parse_library_tutor_query(match.group("query"))
    if parsed is None:
        return "etb_library_tutor_oracle_target_not_supported"
    if int(parsed["count"]) != 1 or bool(parsed.get("up_to_count")):
        return "etb_library_tutor_oracle_count_not_supported"
    parsed["destination"] = "battlefield"
    parsed["enters_tapped"] = bool(match.group("tapped"))
    return parsed


def etb_library_tutor_to_top_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(oracle_text_after_leading_static_keywords(metadata))
    text = re.sub(r"\s+", " ", text).strip()
    if " if " in f" {text} " or " additional cost " in f" {text} ":
        return "etb_library_tutor_to_top_oracle_not_simple"
    match = re.fullmatch(
        r"(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+"
        r"(?P<body>(?:you may )?search your library for .+)",
        text,
    )
    if not match:
        return "etb_library_tutor_to_top_oracle_not_simple"
    body = re.sub(r"^you may\s+", "", match.group("body").strip(), flags=re.I)
    parsed = library_tutor_from_oracle({"oracle_text": body})
    if isinstance(parsed, str):
        return parsed.replace("library_tutor", "etb_library_tutor_to_top")
    if parsed.get("destination") != "library_top":
        return "etb_library_tutor_to_top_oracle_not_simple"
    if int(parsed["count"]) != 1 or bool(parsed.get("up_to_count")):
        return "etb_library_tutor_to_top_oracle_count_not_supported"
    return parsed


def etb_library_tutor_to_hand_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = strip_parenthetical_reminders(oracle_text_after_leading_static_keywords(metadata))
    text = re.sub(r"\s+", " ", text).strip()
    if " if " in f" {text} " or " additional cost " in f" {text} " or "players can't" in text.lower():
        return "etb_library_tutor_to_hand_oracle_not_simple"
    match = re.fullmatch(
        r"(?:when|whenever) [^.]* enters(?: the battlefield)?[, ]+"
        r"(?:you may )?search your library for (?P<query>.+?)"
        r"(?:, reveal (?:it|that card|them|those cards))?, put "
        r"(?:it|that card|them|those cards) into your hand, "
        r"then shuffle(?: your library)?\.?",
        text,
    )
    if not match:
        return "etb_library_tutor_to_hand_oracle_not_simple"
    parsed = parse_library_tutor_query(match.group("query"))
    if parsed is None:
        return "etb_library_tutor_to_hand_oracle_target_not_supported"
    parsed["destination"] = "hand"
    parsed["enters_tapped"] = False
    return parsed


def library_tutor_source_query(source: str) -> dict[str, Any] | None:
    text = source or ""
    static_specs: list[tuple[str, dict[str, Any]]] = [
        ("FILTER_CARD_BASIC_PLAINS", {"target": "basic_plains"}),
        ("FILTER_CARD_BASIC_LANDS", {"target": "basic_land"}),
        ("FILTER_CARD_BASIC_LAND", {"target": "basic_land"}),
        ("FILTER_CARD_LANDS", {"target": "land"}),
        ("FILTER_CARD_CREATURES", {"target": "creature", "target_card_types": ["creature"]}),
        ("FILTER_CARD_CREATURE", {"target": "creature", "target_card_types": ["creature"]}),
        ("FILTER_CARD_INSTANT_OR_SORCERY", {"target": "instant_or_sorcery"}),
        ("FILTER_CARD_INSTANTS", {"target": "instant", "target_card_types": ["instant"]}),
        ("FILTER_CARD_SORCERIES", {"target": "sorcery", "target_card_types": ["sorcery"]}),
        ("FILTER_CARD_ENCHANTMENTS", {"target": "enchantment", "target_card_types": ["enchantment"]}),
        ("FILTER_CARD_ENCHANTMENT", {"target": "enchantment", "target_card_types": ["enchantment"]}),
        ("FILTER_CARD_ARTIFACTS", {"target": "artifact", "target_card_types": ["artifact"]}),
        ("FILTER_CARD_ARTIFACT", {"target": "artifact", "target_card_types": ["artifact"]}),
    ]
    for marker, spec in static_specs:
        if marker in text:
            return dict(spec)
    if re.search(r"new\s+TargetCardInLibrary\s*\(\s*\)", text):
        return {"target": "any"}
    if re.search(r"new\s+FilterBasicCard\s*\(\s*SubType\.FOREST\s*\)", text):
        return {"target": "forest", "required_supertypes": ["basic"]}
    if "new FilterPlaneswalkerCard" in text:
        return {"target": "planeswalker", "target_card_types": ["planeswalker"]}
    if "new FilterCreatureCard" in text:
        base: dict[str, Any] = {"target": "creature", "target_card_types": ["creature"]}
    elif "new FilterArtifactCard" in text:
        base = {"target": "artifact", "target_card_types": ["artifact"]}
    elif "new FilterEnchantmentCard" in text:
        base = {"target": "enchantment", "target_card_types": ["enchantment"]}
    elif "new FilterLandCard" in text:
        base = {"target": "land", "target_card_types": ["land"]}
    elif "new FilterPermanentCard" in text:
        base = {
            "target": "any",
            "target_card_types": ["artifact", "creature", "enchantment", "planeswalker", "land", "battle"],
        }
    else:
        base = {}
    if "SuperType.BASIC" in text and "SubType.FOREST" in text and "SubType.ISLAND" in text:
        return {"target": "basic_forest_or_island"}
    if "ObjectColor.BLUE" in text and "CardType.INSTANT" in text:
        return {"target": "instant", "target_card_types": ["instant"], "target_colors": ["U"]}
    subtype_markers = {
        "SubType.AURA": "aura",
        "SubType.EQUIPMENT": "equipment",
        "SubType.VEHICLE": "vehicle",
        "SubType.DRAGON": "dragon",
        "SubType.ELF": "elf",
        "SubType.GOBLIN": "goblin",
        "SubType.MERFOLK": "merfolk",
        "SubType.MERCENARY": "mercenary",
        "SubType.REBEL": "rebel",
        "SubType.ARCANE": "arcane",
        "SubType.TRAP": "trap",
        "SubType.FOREST": "forest",
        "SubType.PLAINS": "plains",
        "SubType.ISLAND": "island",
    }
    source_subtypes = [
        subtype
        for marker, subtype in subtype_markers.items()
        if marker in text
    ]
    if source_subtypes:
        if set(source_subtypes) == {"forest", "island"} and "SuperType.BASIC" in text:
            return {"target": "basic_forest_or_island"}
        if set(source_subtypes) == {"forest", "plains"} and not base:
            base = {"target": "land", "target_card_types": ["land"]}
        if not base:
            if source_subtypes == ["plains"]:
                return {"target": "plains"}
            if source_subtypes == ["forest"]:
                return {"target": "forest"}
            base = {"target": "any"}
        if not (len(source_subtypes) == 1 and source_subtypes[0] in {"plains", "forest"} and base.get("target") in {"plains", "forest"}):
            base["target_subtypes"] = source_subtypes
    if re.search(r"SuperType\.LEGENDARY\.getPredicate\s*\(\s*\)", text):
        base.setdefault("target", "any")
        base["required_supertypes"] = ["legendary"]
    mana_value_match = re.search(
        r"ManaValuePredicate\s*\(\s*ComparisonType\.(?P<comparison>EQUAL_TO|FEWER_THAN|OR_LESS|OR_GREATER|MORE_THAN)\s*,\s*(?P<value>\d+)",
        text,
    )
    if mana_value_match:
        value = int(mana_value_match.group("value"))
        comparison = mana_value_match.group("comparison")
        if comparison == "EQUAL_TO":
            base["target_mana_value_min"] = value
            base["target_mana_value_max"] = value
        elif comparison in {"FEWER_THAN", "OR_LESS"}:
            base["target_mana_value_max"] = value - 1 if comparison == "FEWER_THAN" else value
        elif comparison in {"OR_GREATER", "MORE_THAN"}:
            base["target_mana_value_min"] = value if comparison == "OR_GREATER" else value + 1
    filter_match = re.search(
        r'new\s+Filter(?:Card|LandCard|CreatureCard|ArtifactCard|EnchantmentCard|PlaneswalkerCard|PermanentCard)\s*\(\s*"([^"]+)"\s*\)',
        text,
    )
    if filter_match:
        parsed = parse_library_tutor_query(filter_match.group(1))
        if parsed is not None:
            parsed = {key: value for key, value in parsed.items() if key not in {"count", "up_to_count"}}
            if base:
                merged = {**base, **parsed}
                if base.get("target_card_types") and "target_card_types" not in parsed:
                    merged["target_card_types"] = base["target_card_types"]
                return merged
            return parsed
    if base:
        base.setdefault("target", "any")
        return base
    return None


def library_tutor_target_from_source(source: str) -> str | None:
    spec = library_tutor_source_query(source)
    if spec is None:
        return None
    return str(spec.get("target") or "") or None


def library_tutor_count_from_source(source: str) -> tuple[int, bool]:
    match = re.search(
        r"TargetCard(?:WithDifferentName)?InLibrary\s*\(\s*0\s*,\s*(\d+)\s*,",
        source or "",
        re.S,
    )
    if match:
        return int(match.group(1)), True
    return 1, False


def library_tutor_from_source(source: str, effect_class: str) -> dict[str, Any] | str:
    text = source or ""
    if has_additional_cost(text):
        return "library_tutor_source_additional_cost_not_supported"
    if "TargetCardWithDifferentNameInLibrary" in text:
        return "library_tutor_source_distinct_names_not_supported"
    parsed_target = library_tutor_source_query(text)
    if parsed_target is None:
        return "library_tutor_source_target_not_supported"
    count, up_to = library_tutor_count_from_source(text)
    if effect_class == "SearchLibraryPutInPlayEffect":
        if "SearchLibraryPutInPlayEffect" not in text:
            return "library_tutor_source_effect_not_found"
        tapped_match = re.search(
            r"SearchLibraryPutInPlayEffect\s*\(\s*(?:new\s+TargetCardInLibrary\s*\([^)]*\)|\w+)\s*,\s*(true|false)",
            text,
            re.S,
        )
        return {
            **parsed_target,
            "count": count,
            "up_to_count": up_to,
            "destination": "battlefield",
            "enters_tapped": bool(tapped_match and tapped_match.group(1) == "true"),
        }
    if effect_class == "SearchLibraryPutOnLibraryEffect":
        if "SearchLibraryPutOnLibraryEffect" not in text:
            return "library_tutor_source_effect_not_found"
        return {
            **parsed_target,
            "count": count,
            "up_to_count": up_to,
            "destination": "library_top",
            "enters_tapped": False,
        }
    if effect_class == "SearchLibraryPutInHandEffect":
        if "SearchLibraryPutInHandEffect" not in text:
            return "library_tutor_source_effect_not_found"
        return {
            **parsed_target,
            "count": count,
            "up_to_count": up_to,
            "destination": "hand",
            "enters_tapped": False,
        }
    return "library_tutor_source_effect_not_supported"


def activated_library_tutor_to_battlefield_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = activated_ability_line_from_oracle(metadata)
    text = re.sub(r"\s+", " ", text).strip().lower()
    if text.count(":") != 1:
        return "activated_library_tutor_oracle_not_simple"
    cost_text, effect_text = [part.strip() for part in text.split(":", 1)]
    source_name = re.sub(r"\s+", " ", str(metadata.get("name") or "").strip().lower())
    if source_name:
        source_sacrifice_pattern = rf"(^|,\s*)sacrifice {re.escape(source_name)}(?=,|$)"
        cost_text = re.sub(
            source_sacrifice_pattern,
            lambda match: f"{match.group(1)}sacrifice this permanent",
            cost_text,
        )
    activation = activation_cost_from_oracle_prefix(cost_text, allow_source_sacrifice=True)
    if isinstance(activation, str):
        return str(activation).replace("activated_self_boost", "activated_library_tutor")
    match = re.match(
        r"^search your library for (?P<query>.+?)(?:,| and) put "
        r"(?:it|that card|them|those cards) onto the battlefield(?P<tapped> tapped)?, "
        r"then shuffle(?: your library)?\.(?: .*)?$",
        effect_text,
    )
    if not match:
        return "activated_library_tutor_oracle_not_simple"
    parsed = parse_library_tutor_query(match.group("query"))
    if parsed is None:
        return "activated_library_tutor_oracle_target_not_supported"
    parsed["destination"] = "battlefield"
    parsed["enters_tapped"] = bool(match.group("tapped"))
    return {**parsed, **activation}


def activated_library_tutor_to_battlefield_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    effect_matches = re.findall(r"SearchLibraryPutInPlayEffect\s*\(", text)
    if len(effect_matches) != 1:
        return "activated_library_tutor_source_effect_not_supported"
    effect_index = text.find("SearchLibraryPutInPlayEffect")
    window = text[max(0, effect_index - 500) : effect_index + 1800]
    if "SimpleActivatedAbility" not in window:
        return "activated_library_tutor_source_not_simple_activated"
    risky_cost_classes = {
        "CompositeCost",
        "DiscardCardCost",
        "DiscardTargetCost",
        "ExileFrom",
        "ExileSourceFromGraveCost",
        "PayLifeCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "SacrificeTargetCost",
        "TapTargetCost",
    }
    present_risky = sorted(cost for cost in risky_cost_classes if cost in window)
    if present_risky:
        return "activated_library_tutor_source_cost_not_supported"
    parsed_target = library_tutor_source_query(text)
    if parsed_target is None:
        return "activated_library_tutor_source_target_not_supported"
    count, up_to = library_tutor_count_from_source(text)
    tapped_match = re.search(
        r"SearchLibraryPutInPlayEffect\s*\(\s*(?:new\s+TargetCardInLibrary\s*\([^)]*\)|\w+)\s*,\s*(true|false)",
        text,
        re.S,
    )
    cost_text = "{0}"
    mana_match = re.search(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window)
    generic_match = re.search(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window)
    colored_match = re.search(r"ColoredManaCost\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)", window)
    if mana_match:
        cost_text = mana_match.group(1)
    elif generic_match:
        cost_text = "{" + generic_match.group(1) + "}"
    elif colored_match:
        cost_text = "{" + colored_match.group(1) + "}"
    cost_text = canonical_mana_cost_text(cost_text)
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_library_tutor_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    return {
        **parsed_target,
        "count": count,
        "up_to_count": up_to,
        "destination": "battlefield",
        "enters_tapped": bool(tapped_match and tapped_match.group(1) == "true"),
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": "TapSourceCost" in window,
        "activation_requires_sacrifice": "SacrificeSourceCost" in window,
    }


def activated_library_tutor_to_hand_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = activated_ability_line_from_oracle(metadata)
    text = re.sub(r"\s+", " ", text).strip().lower()
    if text.count(":") != 1:
        return "activated_library_tutor_to_hand_oracle_not_simple"
    cost_text, effect_text = [part.strip() for part in text.split(":", 1)]
    source_name = re.sub(r"\s+", " ", str(metadata.get("name") or "").strip().lower())
    if source_name:
        source_sacrifice_pattern = rf"(^|,\s*)sacrifice {re.escape(source_name)}(?=,|$)"
        cost_text = re.sub(
            source_sacrifice_pattern,
            lambda match: f"{match.group(1)}sacrifice this permanent",
            cost_text,
        )
    activation = activation_cost_from_oracle_prefix(cost_text, allow_source_sacrifice=True)
    if isinstance(activation, str):
        return str(activation).replace("activated_self_boost", "activated_library_tutor_to_hand")
    match = re.match(
        r"^search your library for (?P<query>.+?)"
        r"(?:, reveal (?:it|that card|them|those cards))?,? "
        r"(?:and )?put (?:it|that card|them|those cards) into your hand"
        r"(?:, then shuffle(?: your library)?\.?|\.? (?:then shuffle(?: your library)?\.?)?)"
        r"(?: .*)?$",
        effect_text,
    )
    if not match:
        return "activated_library_tutor_to_hand_oracle_not_simple"
    parsed = parse_library_tutor_query(match.group("query"))
    if parsed is None:
        return "activated_library_tutor_to_hand_oracle_target_not_supported"
    parsed["destination"] = "hand"
    parsed["enters_tapped"] = False
    return {**parsed, **activation}


